Infoshare.GroupPicker.Context = function Infoshare$GroupPicker$Context() { }
GPContext = Infoshare.GroupPicker.Context;

GPContext.GroupPickerProductId = 'E458D426-5B32-40A5-9951-D99DB2EEB778';
GPContext.InfoCallProductId    = 'F3A900E1-F857-4333-81CE-9F186DB33B56';

GPContext.SiteUrl       = null;
GPContext.WebUrl        = null;
GPContext.ConfigSiteUrl = null;
GPContext.LayoutsPath   = null;
GPContext.SourcesPath   = null;
GPContext.ImagesPath    = null;
GPContext.Language      = null;
GPContext.LanguageDir   = null;

GPContext.ListId = null;
GPContext.UserId = null;
GPContext.CurrentUser = null;

GPContext.IsHighContrastMode = null;

GPContext.License = null;
GPContext.GroupPickerLicense = null;
GPContext.InfoCallLicense = null;
GPContext.OrganizationManagementLicense = null;

GPContext.Configuration = null;

GPContext.Initialized  = false;
GPContext.Initializing = false;

GPContext.DefaultViewId = null;

GPContext.SelectedGroupId = null;
GPContext.SelectedGroup = null;
GPContext.SelectGroup = false;
GPContext.SearchField = null;
GPContext.SearchValue = null;

GPContext.SearchKeyword = null;
GPContext.UserFilterEnabled = null;
GPContext.GroupFilterEnabled = null;

GPContext.IsOnline = false;

// Outlook連携用設定
GPContext.GPOutlookExtension = {};
GPContext.GPOutlookExtension.PlatformType = {
    Outlook: "Outlook",
    OWA: "OWA"
};
GPContext.GPOutlookExtension.FormType = {
    Read: "Read",
    Edit: "Edit"
};
GPContext.GPOutlookExtension.ApplicationType = {
    Mail: "Mail",
    Appointment: "Appointment"
};

GPContext.GPOutlookExtension.Platform = null;
GPContext.GPOutlookExtension.Form = null;
GPContext.GPOutlookExtension.Application = null;
GPContext.GPOutlookExtension.IsVstoAddin = false;

GPContext.IsSiteAdmin = false;
GPContext.MasterListEntities = {
    Self: null,
    Directory: null,
    Recursive: null
};

// 初期化オプション（コンテキストに応じて、処理速度を向上させる為）
GPContext.InitializeOption = {
    EnsureLicense: true,
    EnsureConfiguration: true,
    EnsureResource: true,
    FileLoad: true,
    SiteConfigurationInitialize: true,
    EnsureSitePermission: false
}
GPContext.Initialize = function(callback)
{
    if (GPContext.Initialized)
    {
        ISTrace.TraceVerbose('Skipped GPContext.Initialize');
        if (callback)
        {
            callback();
        }        
        return;
    }
    else if (GPContext.Initializing)
    {
        if (callback)
        {
            GPContext.RegisterFunctionToNotifyInitialized(function() { callback(); });
        }
        return;
    }
    GPContext.Initializing = true;

    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] GPContext.Initialize');

    iVxContext.Initialize(function()
    {
        GPContext.SiteUrl     = iVxContext.SiteUrl;
        GPContext.WebUrl      = iVxContext.WebUrl;
        GPContext.LayoutsPath = ISString.TrimEnd(GPContext.WebUrl, '/') + "/_layouts";
        GPContext.SourcesPath = iVxContext.MasterSourcesPath;
        GPContext.ImagesPath  = iVxContext.MasterSourcesPath;
        GPContext.Language    = iVxContext.Language;
        GPContext.ListId      = iVxContext.GetListId();
        GPContext.UserId      = iVxContext.UserId;
        GPContext.CurrentUser = iVxContext.CurrentUser;
        GPContext.RootFolder  = iVxContext.RootFolder;
        GPContext.IsHighContrastMode = iVxContext.IsHighContrastMode;
        GPContext.LanguageDir = ISString.Equals(iVxContext.Language, 'ja-jp', true) ? "1041" : "1033";
        GPContext.IsOnline    = iVxContext.IsOnline();

		// サイトコレクション管理者
        if (iVxContext.CurrentUser &&
			ISBoolean.TryParse(iVxContext.CurrentUser.Properties.IsSiteAdmin, false))
        {
            GPContext.IsSiteAdmin = true;
        }
        
        // クエリストリングの設定情報の取得
        GPContext.EnsureQueryConfigration();

        // ファイルなどの設定情報の取得
        GPContext.InitializeRemoteResources(function()
        {
            ISTrace.TraceVerbose('[END] GPContext.Initialize (spent: ' + stopwatch.Stop() + ')');

            // スクリーン ブロッカーの表示間隔を設定
            iVxService.ScreenBlockDisplayInterval = GPContext.Configuration.GetSetting('ScreenBlockDisplayInterval');

            GPContext.Initialized  = true;
            GPContext.Initializing = false;
            GPContext.NotifyInitialized();
            if (callback)
            {
                callback();
            }
        });
    });
}
GPContext.InitializeRemoteResources = function(callback)
{
    var invocationContext = {
        LicenseLoaded:         false,
        ConfigLoaded:          false,
        ResourceLoaded:        false,
        FileLoaded:            false,
        SiteConfigLoaded:      false,
        SitePermissionEnsured: false,

        LoadCompleted: function()
        {
            return this.LicenseLoaded &&
                   this.ConfigLoaded &&
                   this.ResourceLoaded &&
                   this.FileLoaded &&
                   this.SiteConfigLoaded &&
                   this.SitePermissionEnsured;
        }
    };

    // ライセンス読み込み
    GPContext.EnsureLicense(function()
    {
        // GroupPicker機能の判断用にライセンスプロパティを作成（InfoCallライセンスのみ登録されている場合は、そちらを用いる）
        GPContext.License = GPContext.GroupPickerLicense;
        if (!GPContext.GroupPickerLicense ||
            !GPContext.GroupPickerLicense.Valid)
        {
            GPContext.License = GPContext.InfoCallLicense;
        }

        invocationContext.LicenseLoaded = true;
        if (invocationContext.LoadCompleted() &&
            callback)
        {
            callback();
        }
    });

    // 構成ファイル読み込み
    GPContext.EnsureConfiguration(function()
    {
        GPContext.LoadAdditionalResources(function()
        {
            invocationContext.ConfigLoaded = true;
            if (invocationContext.LoadCompleted() &&
                callback)
            {
                callback();
            }
        });
    });

    // リソースファイル読み込み
    GPContext.EnsureResource(function()
    {
        invocationContext.ResourceLoaded = true;
        if (invocationContext.LoadCompleted() &&
            callback)
        {
            callback();
        }
    });

    // 外部ファイルの読み込み（partial）
    var fileLoadCallback = function ()
    {
        invocationContext.FileLoaded = true;
        if (invocationContext.LoadCompleted() &&
            callback)
        {
            callback();
        }
    };
    if (GPContext.InitializeOption.FileLoad)
    {
        GPFileLoader.Load(function()
        {
            fileLoadCallback();
        }, true);
    }
    else
    {
        fileLoadCallback();
    }

    // 構成リストの読み込み
    var siteConfigurationCallback = function()
    {
        invocationContext.SiteConfigLoaded = true;
        if (invocationContext.LoadCompleted() &&
            callback)
        {
            callback();
        }
    }
    if (GPContext.InitializeOption.SiteConfigurationInitialize)
    {
        iSiteConfiguration.Initialize(function ()
        {
            siteConfigurationCallback();
        });
    }
    else
    {
        siteConfigurationCallback();
    }

    // サイトの権限情報の確認
    var sitePermissionCallback = function () 
    {
        invocationContext.SitePermissionEnsured = true;
        if (invocationContext.LoadCompleted() &&
            callback)
        {
            callback();
        }
    };
    if (GPContext.InitializeOption.EnsureSitePermission)
    {
        this.EnsureSitePermission(function ()
        {
            sitePermissionCallback();
        });
    }
    else
    {
        sitePermissionCallback();
    }
}
GPContext.EnsureLicense = function(callback)
{
    if (GPContext.InitializeOption.EnsureLicense)
    {
        iLicenseService.GetCurrent().AdminSiteUrl = iVxContext.MasterSiteAbsolutePath;
        iLicenseService.GetCurrent().GetLicenses(iFunction.CreateDelegate(function (licenses)
        {
            GPContext.Licenses                      = licenses;
            GPContext.GroupPickerLicense            = licenses.Get(iLicense.GroupPickerKey);
            GPContext.InfoCallLicense               = licenses.Get(iLicense.InfoCallKey);
            GPContext.OrganizationManagementLicense = licenses.Get(iLicense.InfoCallOrganizationManagementKey);
            GPContext.SmartphoneViewLicense         = licenses.Get(iLicense.InfoCallSmartphoneViewKey);
            GPContext.OutlookVSTOAddInLicense       = licenses.Get(iLicense.InfoCallOutlookVSTOAddInKey);
            GPContext.MemberSearchLicense           = licenses.Get(iLicense.InfoCallMemberSearchKey);
            if (callback)
            {
                callback();
            }
        }, this));
    }
    else
    {
        callback();
    }
}
GPContext.EnsureConfiguration = function(callback)
{
    if (GPContext.InitializeOption.EnsureConfiguration)
    {
        GPConfiguration.Initialize(function(config)
        {
            GPContext.Configuration = config;

            // IE8実行フラグの確認
            var enableIE8 = GPContext.Configuration.GetSetting('EnableIE8');
            if (!enableIE8 &&
                ISBrowser.IsIE() &&
                ISBrowser.GetDocumentVersion() <= 8)
            {
                ISTrace.TraceWarning('This browser is not suported version');
                return;
            }

            callback();
        });
    }
    else
    {
        callback();
    }
}

GPContext.EnsureQueryConfigration = function()
{
    // 既定のビュー
    GPContext.DefaultViewId = iQueryString.GetValue(GPConfiguration.QueryStringKeyName.DefaultViewId);

    // 組織ビュー設定
    GPContext.SelectedGroupId = iQueryString.GetValue(GPConfiguration.QueryStringKeyName.SelectedGroupId);
    GPContext.SelectGroup = iBoolean.TryParse(iQueryString.GetValue(GPConfiguration.QueryStringKeyName.SelectGroup), false);
    GPContext.SearchField = iQueryString.GetValue(GPConfiguration.QueryStringKeyName.SearchField);
    GPContext.SearchValue = iQueryString.GetValue(GPConfiguration.QueryStringKeyName.SearchValue);

    // 検索ビュー設定
    var searchKeyword      = iQueryString.GetValue(GPConfiguration.QueryStringKeyName.SearchKeyword);
    var userFilterEnabled  = iBoolean.TryParse(iQueryString.GetValue(GPConfiguration.QueryStringKeyName.UserFilterEnabled), false);
    var groupFilterEnabled = iBoolean.TryParse(iQueryString.GetValue(GPConfiguration.QueryStringKeyName.GroupFilterEnabled), false);
    if (!ISString.IsNullOrEmpty(searchKeyword))
    {
        GPContext.SearchKeyword = iUri.UnescapeComponent(searchKeyword);
    }
    if(userFilterEnabled == false && groupFilterEnabled == false)
    {
        GPContext.UserFilterEnabled = true;
    }
    else
    {
	    GPContext.UserFilterEnabled = userFilterEnabled;
	    GPContext.GroupFilterEnabled = groupFilterEnabled;
    }

    // Outlook関連設定
    var platform = ISQueryString.GetValue(GPConfiguration.QueryStringKeyName.OutlookPlatform);
    var formType = ISQueryString.GetValue(GPConfiguration.QueryStringKeyName.OutlookForm);
    var application = ISQueryString.GetValue(GPConfiguration.QueryStringKeyName.OutlookApplication);
    var isVstoAddin = ISQueryString.GetValue(GPConfiguration.QueryStringKeyName.OutlookIsVstoAddin);
    GPContext.GPOutlookExtension.Platform = platform;
    GPContext.GPOutlookExtension.Form = formType;
    GPContext.GPOutlookExtension.Application = application;
    GPContext.GPOutlookExtension.IsVstoAddin = ISBoolean.TryParse(isVstoAddin, false);
};

GPContext.EnsureResource = function(callback)
{
    if (GPContext.InitializeOption.EnsureResource)
    {
        // リソース読み込み
        // ToDo: フォールバックとしてニュートラルリソースも読み込むか検討
        var locators = new Array();

        // Infoshare
        var basePath = ISString.TrimEnd(GPContext.SourcesPath, '/') + '/Infoshare';
        var revisionSuffix = '?rev=' + ISPackageInfo.PackageTimestamp;

        locators.push(new iResxResourceLocator(basePath, 'Infoshare', GPContext.Language, revisionSuffix));
        //locators.push(new iResxResourceLocator(basePath, 'Infoshare', null, revisionSuffix));

        // Infoshare.GroupPicker
        basePath = ISString.TrimEnd(GPContext.SourcesPath, '/') + '/Infoshare.InfoCall';
        revisionSuffix = '?rev=' + GPPackageInfo.PackageTimestamp;

        locators.push(new iResxResourceLocator(basePath, 'Infoshare.GroupPicker', GPContext.Language, revisionSuffix));
        //locators.push(new iResxResourceLocator(basePath, 'Infoshare.GroupPicker', null, revisionSuffix));

        // 初期化
        iCompoundResource.Initialize(locators, function ()
        {
            if (callback) { callback(); }
        });
    }
    else
    {
        setTimeout(function ()
        {
            if (callback) { callback(); }
        }, 1)
    }
};
GPContext.LoadAdditionalResources = function(callback)
{
    var infos = GPContext.Configuration.Resources;
    if (infos.length <= 0)
    {
        callback();
        return;
    }

    var invocationCount = 0;
    GPContext.Configuration.Resources = new ISDictionary();
    for (var i = 0; i < infos.length; i++)
    {
        var info = infos[i];
        var url = ISString.TrimEnd(GPContext.SourcesPath, '/') 
                + ISString.Format('/{0}/{1}.{2}.resx.xml', info.Location, info.Id, GPContext.Language);
        var resource = new iResxResource();
        resource.Initialize(url, function()
        {
            invocationCount++;
            if (invocationCount >= infos.length)
            {
                callback();
            }
        });
        GPContext.Configuration.Resources.Add(info.Id, resource);
    }
}
GPContext.EnsureSitePermission = function(callback)
{
    // マスタリストからアイテムを取得してGPContext.MasterListEntitiesを設定する
    iVxService.GetListByUrlName(iVxContext.SiteUrl, "Permissions", function (list) 
    {
        if (list)
        {
            var query = GPContext.BuildPermissionMasterQuery();
            if (query) 
            {
                iVxService.RetrieveItems(iVxContext.SiteUrl, list, query, true, function (items) 
                {
                    if (items &&
                        items.length == 1) 
                    {
                        var property = items[0].Properties;
						var valueString = property.TargetEntityIds;
						if (!ISString.IsNullOrEmpty(valueString)) 
						{
							// スコープの確認：チェックボックス 0, 1の値が取得される
							var recursive = property.Recursive;
							if (ISBoolean.TryParse(recursive, false)) // 厳しい方で判断させる為、falseで
							{
								GPContext.MasterListEntities.Recursive = GPHierarchicalIdUtility.GetIdCollections(valueString);
							}
							else
							{
								GPContext.MasterListEntities.Directory = GPHierarchicalIdUtility.GetIdCollections(valueString);
							}
						}
                    }

                    callback();
                });
            }
            else callback();
        }
        else callback();
    });


    GPContext.MasterListEntities = {
        Self: null,
        Directory: null,
        Recursive: null
    };

}

GPContext.BuildPermissionMasterQuery = function() 
{
    var query = null;
    if (GPContext.CurrentUser &&
        GPContext.CurrentUser.LoginName) 
    {
        var principalName = GPContext.CurrentUser.LoginName;

        query = new ISSPQuery();
        query.Query = "<Query>"
                    +   "<Where>"
                    +     "<Eq>"
                    +       "<FieldRef Name='SpPrincipalName'/>"
                    +       "<Value Type='text'>{0}</Value>"
                    +     "</Eq>"
                    +   "</Where>"
                    + "</Query>";

        query.Query = ISString.Format(query.Query, principalName);
    }

    // ViewField設定
    var fieldRefs = '';
    query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);
        
    return query;
}

GPContext.Events = null;
GPContext.EventName = { Initialized: 'Initialized' };
GPContext.NotifyInitialized = function()
{
    if (GPContext.Events)
    {
        GPContext.Events.FireEventByName(GPContext.EventName.Initialized);
    }
}
GPContext.RegisterFunctionToNotifyInitialized = function(fn)
{
    if (!GPContext.Events)
    {
        GPContext.Events = new iEvent();
    }

    GPContext.Events.AddEvent(GPContext.EventName.Initialized, fn);
}

GPContext.IsSupportedBrowser = function()
{
    var supported = false;
    if ((iBrowser.IsWindows() && iBrowser.IsIE() &&
          (iBrowser.IsCompatibleMode()  && iBrowser.GetBrowserVersion() >= 10 && iBrowser.GetDocumentVersion() >= 10) ||
          (!iBrowser.IsCompatibleMode() && iBrowser.GetBrowserVersion() >= 11 && iBrowser.GetDocumentVersion() >= 11)) ||
        (iBrowser.IsWindows() && iBrowser.IsEdge()) ||
        (iBrowser.IsWindows() && iBrowser.IsChrome()) ||
        (iBrowser.IsiPad() && iBrowser.IsSafari()))
    {
        supported = true;
    }

    return supported;
}
GPContext.IsOfficeAddInSupportedBrowser = function()
{
    var supported = false;
    if ((iBrowser.IsWindows() && iBrowser.IsIE() && (iBrowser.GetBrowserVersion() >= 10 && iBrowser.GetDocumentVersion() >= 10)) ||
        (iBrowser.IsWindows() && iBrowser.IsEdgeLegacy()) ||
        (iBrowser.IsWindows() && iBrowser.IsEdge()))
    {
        supported = true;
    }

    return supported;
}
GPContext.IsMobileViewSupportedBrowser = function()
{
    var supported = false;
    if ((iBrowser.IsiPhone() && iBrowser.IsSafari()) ||
        (iBrowser.IsiPhone() && iBrowser.IsChrome()) ||
        (iBrowser.IsiPhone() && iBrowser.IsEdge()) ||
        (iBrowser.IsAndroid() && iBrowser.IsChrome()) ||
        (iBrowser.IsAndroid() && iBrowser.IsEdge()))
    {
        supported = true;
    }

    return supported;
}
GPContext.ValidateSupportedBrowser = function(validateFunction)
{
    if (iType.GetType(validateFunction) != iType.BuiltinType.Function)
    {
        validateFunction = GPContext.IsSupportedBrowser;
    }

    var valid = false;
    if (validateFunction())
    {
        valid = true;
    }
    else
    {
        valid = false;
        throw new Error('This browser does not supported.');
    }

    return valid;
}
GPContext.ValidateOfficeAddInSupportedBrowser = function()
{
    return GPContext.ValidateSupportedBrowser(GPContext.IsOfficeAddInSupportedBrowser);
}
GPContext.ValidateMobileViewSupportedBrowser = function ()
{
    return GPContext.ValidateSupportedBrowser(GPContext.IsMobileViewSupportedBrowser);
}
                            
