// -----------------------------------------------------------------------
//  ViewContext
// -----------------------------------------------------------------------
Infoshare.GroupPicker.ViewContext = function Infoshare$GroupPicker$ViewContext() { }
GPViewContext = Infoshare.GroupPicker.ViewContext;

GPViewContext.List = null;
GPViewContext.Item = null;
GPViewContext.DataSources = null;
GPViewContext.AuthrizedEntities = [];
GPViewContext.CurrentUserEntity = null;

GPViewContext.SupplementMasterList = null;

GPViewContext.Initialized  = false;
GPViewContext.Initializing = false;

// パーソナルルート組織設定のフィールド内部名
GPViewContext.PersonalRootGroupIdFieldName = "PersonalRootOrganization";

// 初期化オプション（コンテキストに応じて、処理速度を向上させる為）
GPViewContext.InitializeOption = {
    EnsureDataSource: true,
    FileLoad: true,
    EnsureSupplementMasterList: false
}
GPViewContext.Initialize = function(callback, partial)
{
    if (GPViewContext.Initialized ||
        GPViewContext.Initializing)
    {
        ISTrace.TraceVerbose('Skipped GPViewContext.Initialize');
        if (callback)
        {
            callback();
        }
        return;
    }
    GPViewContext.Initializing = true;

    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] GPViewContext.Initialize');

    GPViewContext.InitializeInternal(partial, function()
    {
        ISTrace.TraceVerbose('[END] GPViewContext.Initialize (spent: ' + stopwatch.Stop() + ')');
        GPViewContext.Initialized  = true;
        GPViewContext.Initializing = false;

        GPViewContext.NotifyInitialized();
        if (callback)
        {
            callback();
        }
    });
}
GPViewContext.InitializeInternal = function(partial, callback)
{
    var context = {
        ListsLoaded: false,
        FileLoaded: false,

        LoadCompleted: function()
        {
            return this.ListsLoaded &&
                   this.FileLoaded;
        }
    };

    GPViewContext.EnsureLists(function ()
    {
            context.ListsLoaded = true;
            if (context.LoadCompleted() &&
                typeof(callback) == 'function')
            {
                callback();
            }
    });

    // 外部ファイルの読み込み
    var fileLoadCallback = function()
    {
        context.FileLoaded = true;
        if (context.LoadCompleted() &&
            typeof(callback) == 'function')
        {
            callback();
        }
    };
    if (GPViewContext.InitializeOption.FileLoad)
    {
        GPFileLoader.Load(fileLoadCallback, partial)
    }
    else
    {
        fileLoadCallback();
    }
}

GPViewContext.EnsureLists = function(callback)
{
    var context = {
        EnsureSupplementMasterListLoaded: false,
        EnsurePersonalConfigurationListLoaded: false,

        LoadCompleted: function ()
        {
            return this.EnsureSupplementMasterListLoaded &&
                   this.EnsurePersonalConfigurationListLoaded;
        }
    };

    // データソースリスト、補助マスタ等を検証する
    var ensuredListsCallback = function ()
    {
        if (GPViewContext.InitializeOption.EnsureDataSource)
        {
            GPViewContext.EnsureDataSource(callback);
        }
        else
        {
            callback();
        }
    };

    // データソースリストは補助マスタに依存する為先に検証する
    if (GPViewContext.InitializeOption.EnsureSupplementMasterList)
    {
        // 非同期で権限チェックを行う（View上で使用するため、完了タイミングはとらない）
        var supplementMasterEnsuredCallback = function ()
        {
            context.EnsureSupplementMasterListLoaded = true;
            if (context.LoadCompleted())
            {
                ensuredListsCallback();
            }

		    // 権限チェックを行う
            var permissionService = new SRPermissionsService(iVxContext.SiteUrl, iVxContext.SiteUrl);
            permissionService.GetListEffectiveBasePermissions(ISGuid.TrimBrace(GPViewContext.SupplemenntMasterList.Id), function (effectiveBasePermissions)
            {
                SRPermissionsService.HasPermission(effectiveBasePermissions, iSPPermissionKind.ManageLists, function (hasPermission)
                {
                    GPViewContext.SupplemenntMasterList.HasEditPermission = hasPermission;
                });
            });             
        };

        GPViewContext.EnsureSupplementMasterList(supplementMasterEnsuredCallback);
    }
    else
    {
        context.EnsureSupplementMasterListLoaded = true;
        if (context.LoadCompleted())
        {
            ensuredListsCallback();
        }
    }

    // 非同期で権限チェックを行う（View上で使用するため、完了タイミングはとらない）
    var personalConfigurationListEnsuredCallback = function ()
    {
        context.EnsurePersonalConfigurationListLoaded = true;
        if (context.LoadCompleted())
        {
            ensuredListsCallback();
        }

        // 権限チェックを行う
        var permissionService = new SRPermissionsService(iVxContext.SiteUrl, iVxContext.SiteUrl);
        permissionService.GetListEffectiveBasePermissions(ISGuid.TrimBrace(GPViewContext.PersonalConfigurationList.Id), function (effectiveBasePermissions)
        {
            SRPermissionsService.HasPermission(effectiveBasePermissions, iSPPermissionKind.ManagePersonalViews, function (hasPermission)
            {
                iPersonalConfiguration.HasEditPermission = hasPermission;
            });
        });
    };

    GPViewContext.EnsurePersonalConfigurationList(personalConfigurationListEnsuredCallback);
}

GPViewContext.EnsureDataSource = function(callback)
{
    // 規定のデータソース及び、View毎に定義されたデータソースの情報をGPViewContext.DataSourcesに定義する
    GPViewContext.EnsureDataSourceInfomations();

    var dataSourcesCount = GPViewContext.DataSources.GetLength();
    // ターゲットデータソース毎にリスト、ルートアイテムを取得する
    var context = {
        EnsuredDataSourcesCount : 0,
        LoadCompleted: function()
        {
            var complete = dataSourcesCount == this.EnsuredDataSourcesCount;
            return complete;
        }
    };

    for (var i = 0; i < GPViewContext.DataSources.GetLength(); i++)
    {
        var info = GPViewContext.DataSources.Get(i);
        // データソースのリストを取得する
        GPViewContext.GetDataSourceList(info, function(list, dataSourceInfo)
        {
            if (!list)
            {
                context.EnsuredDataSourcesCount ++;
                ISTrace.TraceWarning('Failed to retrieve list');
                if (context.LoadCompleted())
                {
                    callback();
                }                
            }
            else
            {
                // コンテキストの更新
                var key = dataSourceInfo.GetKey();
                var dataSource = GPViewContext.DataSources.Get(key);
                dataSource.DataSourceList = list;

                // データソース内のアイテム情報の特定（ルート組織、CurrentUser）
                var completeEnsureDataSourceEntities = function(contextInternal)
                {
                    contextInternal.EnsuredDataSourcesCount ++;
                    if (contextInternal.LoadCompleted() &&
                        typeof(callback) == 'function')
                    {
                        callback();
                    }
                };

                GPViewContext.EnsureDataSourceEntities(context, dataSourceInfo, completeEnsureDataSourceEntities);
            }
        });
    }
}

GPViewContext.EnsureDataSourceInfomations = function(callback)
{
    GPViewContext.DataSources = new ISDictionary();
    
    var dataSourcesInfo = [];
    var siteUrl = GPContext.ConfigSiteUrl ? GPContext.ConfigSiteUrl : GPContext.SiteUrl;
    var baseListName = GPContext.Configuration.GetSetting('BaseListName');
    var defaultDataSourceInfo = new GPDataSourceInfo(siteUrl, baseListName, true);
    GPViewContext.DataSources.Add(defaultDataSourceInfo.GetKey(), defaultDataSourceInfo);

    // View毎のデータソース定義の取得
    for (var i = 0; i < GPContext.Configuration.Views.GetLength(); i++)
    {
        var view = GPContext.Configuration.Views.Get(i);
        var options = view.Options;
        if (!options)
        {
            continue;
        }

        var siteUrl = options.Get("DataSourceSiteUrl");
        var baseListName = options.Get("DataSourceListBaseName");
        if (!ISString.IsNullOrEmpty(siteUrl) &&
            !ISString.IsNullOrEmpty(baseListName))
        {
            var viewDataSourceInfo = new GPDataSourceInfo(siteUrl, baseListName, false);
            var key = viewDataSourceInfo.GetKey();
            if (!GPViewContext.DataSources.Contains(key))
            {
                GPViewContext.DataSources.Add(key, viewDataSourceInfo);
            }               
        }
    }

    // MobileView毎のデータソース定義の取得
    for (var i = 0; i < GPContext.Configuration.MobileViews.GetLength() ; i++)
    {
        var view = GPContext.Configuration.MobileViews.Get(i);
        var options = view.Options;
        if (!options)
        {
            continue;
        }

        var siteUrl = options.Get("DataSourceSiteUrl");
        var baseListName = options.Get("DataSourceListBaseName");
        if (!ISString.IsNullOrEmpty(siteUrl) &&
            !ISString.IsNullOrEmpty(baseListName))
        {
            var viewDataSourceInfo = new GPDataSourceInfo(siteUrl, baseListName, false);
            var key = viewDataSourceInfo.GetKey();
            if (!GPViewContext.DataSources.Contains(key))
            {
                GPViewContext.DataSources.Add(key, viewDataSourceInfo);
            }
        }
    }
}

GPViewContext.EnsureDataSourceEntities = function(parentContext, dataSourceInfo, callback)
{
    var targetUrl = dataSourceInfo.WebUrl;
    var context = {
        RootEntitiesLoaded: false,
        CurrentUserEntityLoaded: false,
        MobileDataSourceEntitiesLoaded: false,
        PersonalRootEntities: null,

        LoadCompleted: function()
        {
            return this.RootEntitiesLoaded &&
                   this.CurrentUserEntityLoaded &&
                   this.MobileDataSourceEntitiesLoaded;
        }
    };

    // ルートアイテムの取得
    GPViewContext.GetRootEntities(targetUrl, dataSourceInfo.DataSourceList, function(baseItems)
    {
        // 補助マスタの情報を参照
        GPViewContext.MargeRootEntities(baseItems, targetUrl, dataSourceInfo.DataSourceList, function (items)
        {
            // コンテキストの更新
            var key = dataSourceInfo.GetKey();
            var dataSource = GPViewContext.DataSources.Get(key);
            // パーソナルルート組織が設定済の場合には上書きしない
            if (context.PersonalRootEntities == null)
            {
                dataSource.RootTreeEntities = items;
            }
            context.RootEntitiesLoaded = true;
            if (context.LoadCompleted() &&
                typeof(callback) == 'function')
            {
                callback(parentContext);
            }
        });
    });

    // CurrentUserの取得
    GPViewContext.GetCurrentUserEntity(targetUrl, dataSourceInfo.DataSourceList, function(item)
    {
        var currentUserEntity = null;
        if (item)
        {            
            // ToDo : 複数取得されたケースの例外処理
            currentUserEntity = item;
            // それぞれのデータソース定義に値をセットする
            dataSourceInfo.CurrentUserEntity = currentUserEntity;
        }

        // デフォルトデータソースの値をGPViewContextにセットする
        if (dataSourceInfo.IsDefault)
        {
            GPViewContext.CurrentUserEntity = currentUserEntity;
        }

        // コールバック
        var privateCallBack = function ()
        {
            context.CurrentUserEntityLoaded = true;
            if (context.LoadCompleted() &&
                typeof(callback) == 'function')
            {
                callback(parentContext);
            }
        };

        // ユーザー設定のルート組織が設定されている場合
        var personalRootGroupIds = currentUserEntity ? currentUserEntity.Properties[GPViewContext.PersonalRootGroupIdFieldName]
                                                     : null;
        if (!ISString.IsNullOrEmpty(personalRootGroupIds))
        {
            GPViewContext.GetEntitiesByEntityIds(targetUrl, dataSourceInfo.DataSourceList, personalRootGroupIds, function (items)
            {
                if (items)
                {
                    context.PersonalRootEntities = items;
                    var key = dataSourceInfo.GetKey();
                    var dataSource = GPViewContext.DataSources.Get(key);
                    dataSource.RootTreeEntities = items;
                }
                privateCallBack();
            });
        }
        else
        {
            privateCallBack();
        }
    });

    // データソース内のMobileアイテム情報の特定
    GPViewContext.EnsureMobileDataSourceEntities(dataSourceInfo, function ()
    {
        context.MobileDataSourceEntitiesLoaded = true;
        if (context.LoadCompleted() &&
            typeof(callback) == 'function')
        {
            callback(parentContext);
        }
    });
}

GPViewContext.EnsureMobileDataSourceEntities = function (dataSourceInfo, callback)
{
    // MobileView以外
    if (!GPViewContext.InitializeOption.EnsureMobileDataSourceEntities)
    {
        setTimeout(function(){ callback(); }, 1);
        return;
    }
    
    var targetUrl = dataSourceInfo.WebUrl;

    // MobileIndexViewEntityの取得
    GPViewContext.GetEntitiesByEntityIds(targetUrl, dataSourceInfo.DataSourceList, 'MobileIndexViewEntity', function (items)
    {
        if (items.length > 0)
        {
            var key = dataSourceInfo.GetKey();
            var dataSource = GPViewContext.DataSources.Get(key);
            dataSource.MobileIndexViewEntity = items[0];
        }
        callback();
    });
}

GPViewContext.GetDataSourceList = function(dataSourceInfo, callback)
{
    iVxService.GetLists(dataSourceInfo.WebUrl, function(lists)
    {
        var dataSourceList = null;
        for (var i = 0; i < lists.length; i++)
        {
            var list = lists[i];

            // baseListNameで始まるリストの取得
            if (ISString.StartsWith(list.Title, dataSourceInfo.BaseListName, true) &&
                ISString.EndsWith(list.Title, '_Synced', true))
            {
                // 作成日時を比較して、最も新しいリストを取得する
                if (dataSourceList != null &&
                    dataSourceList.Properties.Created.replace(/\D/g, "") < list.Properties.Created.replace(/\D/g, ""))
                {
                    dataSourceList = list;
                }

                else if (dataSourceList == null)
                {
                    dataSourceList = list;
                }                
            }
        }

        // クライアントソート時にフィールド情報を利用するために再取得する
        if (dataSourceList != null)
        {
            var service = new SPListsService(dataSourceInfo.WebUrl);
            service.GetList(dataSourceList.Id, function (list)
            {
                dataSourceList = list;
                callback(dataSourceList, dataSourceInfo);
            });
        }
        else
        {
            callback(dataSourceList, dataSourceInfo);
        }        
    });
}
GPViewContext.GetRootEntities = function(webUrl, list, callback)
{
    var query = new ISSPQuery();
    query.Query = "<Query>"
                +   "<Where>"
                +     "<Eq>"
                +       "<FieldRef Name='IsRootOrganization'/>"
                +       "<Value Type='text'>true</Value>"
                +     "</Eq>"
                +   "</Where>"
                + "</Query>";

    // ViewField設定
    var fieldRefs = '';
    for(var i = 0; i < GPContext.Configuration.Fields.GetLength(); i++)
    {
        var field = GPContext.Configuration.Fields.Get(i);
        fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
    }
    query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

    ISTrace.TraceVerbose('[BEGIN] RootItemQuery');
    iVxService.RetrieveItems(webUrl, list, query, false, function(items)
    {
        ISTrace.TraceVerbose('[END] RootItemQuery');
        callback(items);
    });
}
GPViewContext.GetCurrentUserEntity = function(webUrl, list, callback)
{
    GPViewContext.GetEntityByPrincipalName(webUrl, list, GPContext.CurrentUser.LoginName, callback);
}
GPViewContext.GetEntityByPrincipalName = function(webUrl, list, principalName , callback)
{
    var query = new ISSPQuery();
    query.Query = "<Query>"
                +   "<Where>"
                +     "<Eq>"
                +       "<FieldRef Name='SpPrincipalName'/>"
                +       "<Value Type='text'>{0}</Value>"
                +     "</Eq>"
                +   "</Where>"
                + "</Query>";

    query.Query = ISString.Format(query.Query, principalName);

    // ViewField設定
    var fieldRefs = '';
    for(var i = 0; i < GPContext.Configuration.Fields.GetLength(); i++)
    {
        var field = GPContext.Configuration.Fields.Get(i);
        fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
    }
    query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

    ISTrace.TraceVerbose('[BEGIN] PrincipalNameQuery' + " : " + principalName);
    iVxService.RetrieveItems(webUrl, list, query, false, function(items)
    {
        ISTrace.TraceVerbose('[END] PrincipalNameQuery' + " : " + principalName);
        var item = null;
        if (items && items.length == 1)
        {
            item = items[0];
        }

        callback(item);
    });
}
GPViewContext.GetEntitiesByEntityIds = function (webUrl, list, idList, callback)
{
    if (typeof idList == "string")
    {
        // Arrayに変換
        idList = GPHierarchicalIdUtility.GetIdCollections(idList);
    }

    iVxService.RetrieveItemsByKeys(webUrl,
                                   list,
                                   idList,
                                   "EntityId",
                                   "text",
                                   [],
                                   callback);
}
GPViewContext.GetEntitiesByEntities = function (entities, webUrl, list, callback)
{
    var idList = [];
    for (var i = 0; i < entities.length; i++)
    {
        var id = entities[i].Properties.EntityId;
        idList.push(id);
    }

    GPViewContext.GetEntitiesByEntityIds(webUrl, list, idList, callback);
}

GPViewContext.EnsureAuthrizedEntities = function(callback)
{
    // リストまたはフォルダに閲覧権限を持つSPUserのPrincipal名を取得する
    var permissionsService = new iSSPermissionsService(GPContext.WebUrl);
    var permissionMask = iSPBasePermissions.ViewListItems;
    var context = this;
    
    GPViewContext.EnsureListAndItem(function()
    {
        // フォルダのパスを確定（リストの編集フォームの場合はアイテム情報から取得）
        var folderUrl = ISString.IsNullOrEmpty(GPContext.RootFolder) ? '' : decodeURIComponent(GPContext.RootFolder);
        if (ISString.IsNullOrEmpty(folderUrl) &&
            GPViewContext.Item && 
            GPViewContext.Item.Properties["FileDirRef"].split(';#').length == 2)
        {
            folderUrl = GPViewContext.Item.Properties["FileDirRef"].split(';#')[1];
        }

        // フォルダまたはリストに参照権限を持つものを取得
        if (!ISString.IsNullOrEmpty(folderUrl) &&
            !ISString.Equals(ISString.Trim(GPViewContext.List.Properties['RootFolder'], '/'), ISString.Trim(folderUrl, '/'))) 
        {
            permissionsService.GetAuthorizedPrincipalsForFolder(encodeURI(folderUrl), permissionMask, function (principals)
            {
                context.ProcessPrincipals(principals, callback);
            });
        }
        else
        {
            permissionsService.GetAuthorizedPrincipalsForList(GPContext.ListId, permissionMask, function (principals)
            {
                context.ProcessPrincipals(principals, callback);
            });
        }
    });
}
GPViewContext.EnsureListAndItem = function(callback)
{
    iVxService.GetList(iVxContext.WebUrl, iVxContext.GetListId(), function (list)
    {
        GPViewContext.List = list;
        if (iSPListFormExtender.IsTargetForm(iSPListFormExtender.FormFileName.ListForm.EditForm) &&
            list.ServerTemplate != ISSPListTemplateType.DocumentLibrary &&
            list.ServerTemplate != ISSPListTemplateType.PictureLibrary &&
            list.ServerTemplate != ISSPListTemplateType.XMLForm)
        {
            // 暫定対応（リストアイテムのキャッシュロジックの為別箇所で必要なContentTypeIdを取得する）
            // ToDo : ListFormExtenderのリスト取得箇所に実装を移す
            var viewFields = new ISDictionary;
            viewFields.Add("FileDirRef", list.Fields.Get("FileDirRef"));
            viewFields.Add("ContentTypeId", list.Fields.Get("ContentTypeId"));

            iVxService.RetrieveItemById(iVxContext.WebUrl, list, iVxContext.ItemId, viewFields, function(item)
            {
                GPViewContext.Item = item;
                callback();
            });
        }
        else
        {
            callback();
        }
    });
}

GPViewContext.ProcessPrincipals = function(principals, callback)
{
    if (!principals ||
        principals.length < 1)
    {
        ISTrace.TraceWarning('Failed to retrieve permissions');
        callback();
    }
    else
    {
        GPViewContext.GetAuthorizedEntities(GPViewContext.DataSourceList, principals, function(items)
        {
            GPViewContext.AuthrizedEntities = items;
            callback();
        });
    }
}
GPViewContext.GetAuthorizedEntities = function(list, principals, callback)
{
    // 条件が多すぎると呼び出しが失敗するため、クエリを分割する

    // 重複除去のためディクショナリを利用する
    var principalNames = new ISDictionary();
    for (var i = 0; i < principals.length; i++)
    {
        var principalName = principals[i];
        principalNames.Set(principalName, principalName);
    }
    principalNames = principalNames.GetValues();

    // 単位数ごとにまとめる
    var count = 100;
    var namesArray = new Array();
    var names = new Array();
    for (var i = 0; i < principalNames.length; i++)
    {
        var principalName = principalNames[i];
        names.push(principalName);

        if (names.length <= count)
        {
            namesArray.push(names);
            names = new Array();
        }
    }

    // 並列呼び出し
    var invocationCount = 0;
    var wholeItems = new Array();
    for (var i = 0; i < namesArray.length; i++)
    {
        var names = namesArray[i];
        GPViewContext.GetAuthorizedEntitiesCore(list, names, function(items)
        {
            wholeItems = wholeItems.concat(items);

            invocationCount++;
            if (namesArray.length <= invocationCount)
            {
                callback(wholeItems);
            }
        });
    }
}
GPViewContext.GetAuthorizedEntitiesCore = function(list, principals, callback)
{
    // 検索対象フィールド
    var fieldName = 'SpPrincipalName';

    // Where句: 
    var principalNameField = GPContext.Configuration.Fields.Get(fieldName);
    var principalFilter = '';
    for (var i = 0; i < principals.length; i++)
    {
        var principalName = principals[i];
        var condition = SPQueryBuilder.BuildEqualQueryCondition(principalNameField.InternalName, principalNameField.Type, principalName);
        if (principalFilter.length <= 0) { principalFilter = condition; }
        else                             { principalFilter = SPQueryBuilder.BuildOrQueryCondition(principalFilter + condition); }
    }
    var where = principalFilter;

    // ViewField設定
    var fieldRefs = '';
    for(var i = 0; i < GPContext.Configuration.Fields.GetLength(); i++)
    {
        var field = GPContext.Configuration.Fields.Get(i);
        fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
    }

    // クエリ組み立て
    var query = new ISSPQuery();
    query.Query        = SPQueryBuilder.BuildQuery(null, where);
    query.ViewFields   = SPQueryBuilder.BuildViewFields(fieldRefs);
    query.QueryOptions = SPQueryBuilder.BuildQueryOptions(SPQueryBuilder.BuildMandatoryColumnsOption(false));

    // Itemの取得
    ISTrace.TraceVerbose('[BEGIN] AurhorizedEntityQuery');
    iVxService.RetrieveItems(GPViewContext.WebUrl, list, query, false, function(items)
    {
        ISTrace.TraceVerbose('[END] AurhorizedEntityQuery');
        callback(items);
    }); 
}

GPViewContext.EnsureSupplementMasterList = function(callback)
{
    ISTrace.TraceVerbose('[BEGIN] GPViewContext.EnsureSupplementMasterList');
	iVxService.GetListByUrlName(iVxContext.MasterSiteAbsolutePath, "SupplementMaster", function (baseList) 
	{
		if (!baseList) 
		{
		    // Error
            ISTrace.TraceWarning('[Error] GPViewContext.EnsureSupplementMasterList. NotFound supplementer list.');
            callback();
		}

		// FieldInfoが必要になるので、再取得する
		iVxService.GetList(iVxContext.MasterSiteAbsolutePath, baseList.Id, function (list)
		{
            ISTrace.TraceWarning('[END] GPViewContext.EnsureSupplementMasterList');
			GPViewContext.SupplemenntMasterList = list;
            callback();
		});
	});
};

// AddressBookDataSourceのエンティティと、補助マスタのエンティティを互いに取得し、マージする
GPViewContext.MargeEntitiesForSupplementMasterEntities = function(baseEntities, supplementMasterEntities, webUrl, list, callback)
{
    // AddressBookDataSource, SupplementMasterからデータを取得してマージ、クライアントソートする
    var context = {
        // AddressBookDataSourceから取得されたEntities
        BaseEntities: baseEntities,
        // SupplementMasterから取得されたEntities
        SupplementMasterEntities: supplementMasterEntities,
        // SupplementMasterEntitiesをもとにAddressBookDataSourceから取得するEntities
        BaseReferenceEntities: null,
        // BaseEntitiesをもとにSupplementMasterから取得するEntities
        SupplementMasterReferenceEntities: null,

        BaseReferenceEntitiesEnsured: false,
        SupplementMasterReferenceEntitiesEnsured: false,

        Completed: function () {
            var complete = this.BaseReferenceEntitiesEnsured &&
                           this.SupplementMasterReferenceEntitiesEnsured;
            return complete;
        }
    };

    var completeCallback = function ()
    {
        if (context.Completed())
        {
            // マージする
            var effectiveEntities = GPViewContext.MargeEntities(
                context.BaseEntities,
                context.SupplementMasterEntities,
                context.BaseReferenceEntities,
                context.SupplementMasterReferenceEntities);        

            callback(effectiveEntities);
        }
    };

    GPViewContext.GetEntitiesByEntities(context.BaseEntities, iVxContext.MasterSiteAbsolutePath, GPViewContext.SupplemenntMasterList, function (supplementMasterReferenceEntities)
    {
        context.SupplementMasterReferenceEntitiesEnsured = true;
        context.SupplementMasterReferenceEntities = supplementMasterReferenceEntities;
        completeCallback();
    });

    GPViewContext.GetEntitiesByEntities(context.SupplementMasterEntities, webUrl, list, function (baseReferenceEntities)
    {
        context.BaseReferenceEntitiesEnsured = true;
        context.BaseReferenceEntities = baseReferenceEntities;
        completeCallback();
    });    
};

GPViewContext.MargeRootEntities = function(baseItems, webUrl, list, callback)
{
    // 通常のView
    if (!GPViewContext.InitializeOption.EnsureSupplementMasterList)
    {
        callback(baseItems);
    }
    // 補助マスタが有効の場合補助マスタの情報とマージする（組織管理関連のView）
    else
    {
        GPViewContext.MargeEntitiesForSupplementMasterEntities(baseItems, [], webUrl, list, function (items)
        {
            callback(items);
        });
    }    
};

GPViewContext.MargeEntities = function (baseEntities, supplementMasterEntities, baseReferenceEntities, supplementMasterReferenceEntities)
{
    var margeEntities = [];
    var entityIdList = [];

    // Dictionaryを作成
    var baseDicitonary = new ISDictionary();
    if (baseEntities)
    {
        for (var i = 0; i < baseEntities.length; i++)
        {
            var entity = baseEntities[i];
            var entityId = entity.Properties.EntityId;
            baseDicitonary.Set(entityId, entity);

            if (!ISArray.Contains(entityIdList, entityId))
            {
                entityIdList.push(entityId)
            }
        }
    }
    if (baseReferenceEntities)
    {
        for (var i = 0; i < baseReferenceEntities.length; i++)
        {
            var entity = baseReferenceEntities[i];
            var entityId = entity.Properties.EntityId;
            baseDicitonary.Set(entityId, entity);

            if (!ISArray.Contains(entityIdList, entityId))
            {
                entityIdList.push(entityId)
            }
        }
    }

    var supplementMasterDictionary = new ISDictionary();
    if (supplementMasterEntities)
    {
        for (var i = 0; i < supplementMasterEntities.length; i++)
        {
            var entity = supplementMasterEntities[i];
            var entityId = entity.Properties.EntityId;
            supplementMasterDictionary.Set(entity.Properties.EntityId, entity);

            if (!ISArray.Contains(entityIdList, entityId))
            {
                entityIdList.push(entityId)
            }
        }
    }
    if (supplementMasterReferenceEntities)
    {
        for (var i = 0; i < supplementMasterReferenceEntities.length; i++)
        {
            var entity = supplementMasterReferenceEntities[i];
            var entityId = entity.Properties.EntityId;
            supplementMasterDictionary.Set(entity.Properties.EntityId, entity);

            if (!ISArray.Contains(entityIdList, entityId))
            {
                entityIdList.push(entityId)
            }
        }
    }
    
    // SupplementMaseter > BaseEntities の優先度でマージする
    var entities = [];
    for (var i = 0; i < entityIdList.length; i++)
    {
        var entityId = entityIdList[i];
        var margedEntity = GPViewContext.MargeEntity(entityId, baseDicitonary, supplementMasterDictionary);
        if (margedEntity)
        {
            margeEntities.push(margedEntity);
        }        
    }

    entities = margeEntities;
    return entities;
};

GPViewContext.MargeEntity = function(entityId, baseDicitonary, supplementMasterDictionary)
{
    var margedEntity = null;

    var baseEntity = baseDicitonary.Get(entityId);
    var supplementMasterEntity = supplementMasterDictionary.Get(entityId);

    // 片方のみ存在する場合はそのままケース
    if (baseEntity && !supplementMasterEntity)
    {
        margedEntity = baseEntity;
    }
    else if (supplementMasterEntity && !baseEntity)
    {
        margedEntity = supplementMasterEntity;
    }
    // 両方存在するケース
    else if (baseEntity && supplementMasterEntity)
    { 
        margedEntity = { Properties: {}};

        // フィールドごとに値を設定する
        for (var i = 0; i < GPContext.Configuration.Fields.GetLength(); i++ )
        {
            var fieldInfo = GPContext.Configuration.Fields.Get(i);
            var fieldName = fieldInfo.InternalName;

            var primaryValue = supplementMasterEntity.Properties[fieldName];
            var secondaryValue = baseEntity.Properties[fieldName];

            var effectiveValue = primaryValue;
            if (ISString.IsNullOrEmpty(primaryValue))
            {
                effectiveValue = secondaryValue;
            }

            margedEntity.Properties[fieldName] = effectiveValue;
        }
    }

    // 補助マスタ関連の情報
    if (supplementMasterEntity)
    {
        // 補助マスタでのItemId
        margedEntity.Properties["SupplementMasterItemId"] = supplementMasterEntity.Id;

        // Original：削除ボタンや、表示の制御に使用
        margedEntity.Properties["Original"] = supplementMasterEntity.Properties["Original"];
    }

    return margedEntity;
};

GPViewContext.EnsurePersonalConfigurationList = function (callback)
{
    ISTrace.TraceVerbose('[BEGIN] GPViewContext.EnsurePersonalConfigurationList');
    iVxService.GetListByUrlName(iVxContext.MasterSiteAbsolutePath, iPersonalConfigurationService.ListUrlName, function (list)
	{
        if (!list)
		{
		    // Error
            ISTrace.TraceWarning('[Error] GPViewContext.EnsurePersonalConfigurationList. NotFound Personal Configuration List.');
            callback();
		}
		else
		{
		    ISTrace.TraceWarning('[END] GPViewContext.EnsurePersonalConfigurationList');
		    GPViewContext.PersonalConfigurationList = list;
		    callback();
		}
	});
};


GPViewContext.Events = null;
GPViewContext.EventName = { Initialized: 'Initialized' };
GPViewContext.NotifyInitialized = function()
{
    if (GPViewContext.Events)
    {
        GPViewContext.Events.FireEventByName(GPViewContext.EventName.Initialized);
    }
}
GPViewContext.RegisterFunctionToNotifyInitialized = function(fn)
{
    if (!GPViewContext.Events)
    {
        GPViewContext.Events = new iEvent();
    }

    GPViewContext.Events.AddEvent(GPViewContext.EventName.Initialized, fn);
}


