// -----------------------------------------------------------------------
ISNamespace.Register('Infoshare');
ISNamespace.Register('Infoshare.GroupPicker');


// -----------------------------------------------------------------------
//  ContextCloner
// -----------------------------------------------------------------------
Infoshare.GroupPicker.ContextCloner = function Infoshare$GroupPicker$ContextCloner(parentWindow)
{
    this.ParentWindow = parentWindow;
}
GPContextCloner = Infoshare.GroupPicker.ContextCloner;
GPContextCloner.prototype = {
    ParentWindow: null,
    LoadCSS: false,

    CloneToParent: function(callback)
    {
        // コンテキストが未初期化の場合は初期化後にクローン
        var cloner = this;
        cloner.ensureContext(function ()
        {
            // コンテキストが初期化済みの場合は複製しない
            if (cloner.parentContextInitialized())
            {
                callback();
                return;
            }

            // コンテキストを親へ設定しつつ必要なファイルを読み込む
            if (cloner.contextInitialized() &&
                cloner.ParentWindow)
            {        
                cloner.ParentWindow.GPContext     = GPContext;
                cloner.ParentWindow.GPViewContext = GPViewContext;
                cloner.ParentWindow.iVxContext    = iVxContext;
                cloner.ParentWindow.iVxService    = iVxService;
                cloner.ParentWindow.iResxResource = iResxResource;
                cloner.ParentWindow.GPFileLoader.LoadCoreCss = cloner.LoadCSS;
                cloner.ParentWindow.GPFileLoader.Load(function ()
                {
                    callback();
                });

                // iframe内で作成されたGPContexのインスタンスは、ダイアログ（共有ダイアログ、フォームのダイアログ）クローズ時に破棄され（変数としては保持される）
                // アクセスできなくなるので、再度初期化するようにする
                // http://typea.info/tips/wiki.cgi?page=%B3%AB%CA%FC%A4%B5%A4%EC%A4%BF%A5%B9%A5%AF%A5%EA%A5%D7%A5%C8%A4%AB%A4%E9%A5%B3%A1%BC%A5%C9%A4%F2%BC%C2%B9%D4%A4%C7%A4%AD%A4%DE%A4%BB%A4%F3
                // https://msdn.microsoft.com/ja-jp/library/gg622929(v=vs.85).aspx
                ISDomAccessor.AttachEvent(window, "beforeunload", function ()
                {
                    // 暫定対応（正しくはInfoshare.js, Infoshare.GroupPicker.jsのみ再度読み込む）
                    window.top.location.reload(false);
                });
            }
        });
    },

    CloneFromParent: function(callback)
    {
        // コンテキストが未初期化の場合は初期化後にクローン
        var cloner = this;
        cloner.ensureParentContext(function ()
        {
            // コンテキストが初期化済みの場合は複製しない
            if (cloner.contextInitialized())
            {
                callback();
                return;
            }

            // コンテキストを親から取得しつつ必要なファイルを読み込む
            if (cloner.parentContextInitialized())
            {
                GPContext     = cloner.ParentWindow.GPContext;
                GPViewContext = cloner.ParentWindow.GPViewContext;
                iVxContext    = cloner.ParentWindow.iVxContext;
                iVxService    = cloner.ParentWindow.iVxService;
                iResxResource = cloner.ParentWindow.iResxResource;
                GPFileLoader.LoadCoreCss = cloner.LoadCSS;

                var isIE8PickerInIframeFrom = ISBrowser.GetDocumentVersion() == 8 &&
                                              window != window.top;
                GPFileLoader.Load(function()
                {
                    callback();
                }, isIE8PickerInIframeFrom);
            }
        });
    },

    contextInitialized: function()
    {
        var initialized = false;
        if (GPContext &&
            GPContext.Initialized)
        {
            initialized = true;
        }

        return initialized;
    },

    parentContextInitialized: function()
    {
        var initialized = false;

        //TeamsからInfoCallを読み込むときParentWindowは
        //クロスドメインの関係で取得できないため例外処理
        try
        {
            if (this.ParentWindow &&
                this.ParentWindow.GPContext &&
                this.ParentWindow.GPContext.Initialized)
            {
                initialized = true;
            }
        }
        catch (e)
        {
        }

        return initialized;
    },

    ensureContext: function(callback)
    {
        var cloner = this;
        cloner.initializeContext(GPContext, function ()
        {
            cloner.initializeContext(GPViewContext, function ()
            {
                callback();
            });
        });
    },

    ensureParentContext: function(callback)
    {
        var cloner = this;
        cloner.initializeContext(cloner.ParentWindow.GPContext, function ()
        {
            cloner.initializeContext(cloner.ParentWindow.GPViewContext, function ()
            {
                callback();
            });
        });
    },

    initializeContext: function(context, callback)
    {
        if (!context.Initialized)
        {
            if (context.Initializing)
            {
                context.RegisterFunctionToNotifyInitialized(function()
                {
                    callback();
                });
            }
            else
            {
                context.Initialize(function()
                {
                    callback();
                });
            }
        }
        else
        {
            callback();
        }
    }
}
                            
