// -----------------------------------------------------------------------
//  ActionInfo
// -----------------------------------------------------------------------
Infoshare.GroupPicker.ActionInfo = function Infoshare$GroupPicker$ActionInfo(actionElement)
{
    if (!iType.IsNullOrUndefined(actionElement))
    {
        var actionInfo = GPActionInfo.Parse(actionElement);
        iObject.Clone(actionInfo, this);
    }
}
GPActionInfo = Infoshare.GroupPicker.ActionInfo;
GPActionInfo.TypeName = 'Infoshare.GroupPicker.ActionInfo';

GPActionInfo.Parse = function (info)
{
    // Action要素取得
    var actionElement = null;
    if      (iType.GetTypeName(info) == GPActionInfo.TypeName) { actionElement = info.ActionXml; }
    else if (iType.GetTypeName(info) == iType.BuiltinType.String && !iString.IsNullOrEmpty(info))
    {
        var doc = iXml.LoadXml(info);
        actionElement = iXml.GetDocumentElement(doc);
    }
    else if (iType.GetTypeName(info) == iType.BuiltinType.Object &&
             !iType.IsNullOrUndefined(info.tagName))
    {
        actionElement = info;
    }

    // 初期化
    var oInfo = new GPActionInfo();
    oInfo.ActionXml = actionElement;

    // 名前関連属性
    oInfo.Name                   = iXml.GetAttributeValue(actionElement, 'Name');
    oInfo.DisplayName            = iXml.GetAttributeValue(actionElement, 'DisplayName');
    oInfo.DisplayNameResourceKey = iXml.GetAttributeValue(actionElement, 'DisplayNameResourceKey');

    // クラス情報
    var cls = iXml.GetChildElementsByName(actionElement, 'Class')[0];
    var classInfo = iClass.CreateFromXml(cls);
    oInfo.Class = classInfo;

    // オプション情報
    var optionsElement = iXml.SelectNodeByPath(actionElement, 'Options');
    var options = (new iXConfigurationParser()).BuildOptionDictionary(optionsElement);
    oInfo.Options = options;

    return oInfo;
};

GPActionInfo.prototype = {
    TypeName: GPActionInfo.TypeName,

    ActionXml: null,

    Name: '',
    DisplayName: '',
    DisplayNameResourceKey: '',
    
    Class: null,
    Options: null
}


