// -----------------------------------------------------------------------
//  FileLoader
// -----------------------------------------------------------------------
Infoshare.GroupPicker.FileLoader = function Infoshare$GroupPicker$FileLoader() { }
GPFileLoader = Infoshare.GroupPicker.FileLoader;

GPFileLoader.LoadjQuery = true;
GPFileLoader.LoadCoreCss = false;
GPFileLoader.BaseFileLoaded = false;
GPFileLoader.ExtendedFileLoaded = false;

GPFileLoader.Load = function(callback, partial)
{
    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] GPFileLoader.Load');

    var context = {
        BaseLoaded: GPFileLoader.BaseFileLoaded,
        ExtendedLoaded: partial ? true : GPFileLoader.ExtendedFileLoaded,

        LoadCompleted: function()
        {
            return this.BaseLoaded &&
                   this.ExtendedLoaded;
        }
    };

    // すでに初期化済みの場合はすぐに戻す
    if (context.LoadCompleted() && callback)
    {
        ISTrace.TraceVerbose('[END] GPFileLoader.Load' + ' (spent: ' + stopwatch.Stop() + ')');
        callback();
        return;
    }

    // 基本ファイルセットの読み込み
    if (!context.BaseLoaded)
    {
        GPFileLoader.LoadBaseFiles(function()
        {
            context.BaseLoaded = true;
            GPFileLoader.BaseFileLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                ISTrace.TraceVerbose('[END] GPFileLoader.Load' + ' (spent: ' + stopwatch.Stop() + ')');
                callback();
            }
        });
    }

    // 拡張ファイルセットの読み込み
    if (!partial)
    {
        GPFileLoader.LoadExtendedFiles(function()
        {
            context.ExtendedLoaded = true;
            GPFileLoader.ExtendedFileLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                ISTrace.TraceVerbose('[END] GPFileLoader.Load' + ' (spent: ' + stopwatch.Stop() + ')');
                callback();
            }
        });
    }
}

GPFileLoader.LoadBaseFiles = function(callback)
{
    var context = {
        CssLoaded: false,
        jQueryLoaded: false,
        OfficeJsLoaded: false,

        LoadCompleted: function()
        {
            return this.CssLoaded &&
                   this.jQueryLoaded &&
                   this.OfficeJsLoaded;
        }
    };

    // CSS読み込み
    var sourcesPath = ISString.TrimEnd(GPContext.SourcesPath, '/');
    var css = [ sourcesPath + '/Infoshare/Infoshare.css' ];
    if (GPFileLoader.LoadCoreCss)
    {
        css = [ GPContext.LayoutsPath + '/15/' + GPContext.LanguageDir + '/styles/Themable/corev15.css'].concat(css);
    }

    ISScript.Load(css, null, function()
    {
        context.CssLoaded = true;
        if (context.LoadCompleted() && callback)
        {
            callback();
        }
    });

    // スクリプト読み込み
    if (GPFileLoader.LoadjQuery)
    {
        // jQueryパス
        var jqueryPath = sourcesPath + "/Infoshare/jquery.js";
        iQuery.Load(jqueryPath, function()
        {
            ISTrace.TraceVerbose('jQuery: Loaded ' + i$().jquery);

            context.jQueryLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    }
    else
    {
        context.jQueryLoaded = true;
    }

    // Office.js（Outlookクライアントから開かれた場合のみ読み込む
    if (GPContext.GPOutlookExtension.Platform == GPContext.GPOutlookExtension.PlatformType.Outlook &&
        !GPContext.GPOutlookExtension.IsVstoAddin)
    {
        var officeJsCDN = "https://appsforoffice.microsoft.com/lib/1/hosted/office.js";
        ISScript.Load(officeJsCDN, null, function()
        {
            // 以下の初期化メソッド定義にて、コンテキスト連携が可能
            Office.initialize = function (reason) {};            

            context.OfficeJsLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    }
    else
    {
        context.OfficeJsLoaded = true;
    }
}

GPFileLoader.LoadExtendedFiles = function(callback)
{
    var context = {
        CssLoaded:                 false,
        AditionalStyleSheetLoaded: false,
        ScriptLoaded:              false,
        AditionalScriptLoaded:     false,

        LoadCompleted: function()
        {
            return this.CssLoaded &&
                   this.AditionalStyleSheetLoaded &&
                   this.ScriptLoaded &&
                   this.AditionalScriptLoaded;
        }
    };
    var count = 0;

    // CSS読み込み
    var sourcesPath = ISString.TrimEnd(GPContext.SourcesPath, '/');
    var baseCss = [ sourcesPath + '/Infoshare.InfoCall/Infragistics/css/themes/yeti/infragistics.theme.css',
                    sourcesPath + '/Infoshare.InfoCall/Infragistics/css/structure/infragistics.css' ];
    ISScript.Load(baseCss, null, function()
    {
        // infragisticsのCSS読み込みの後に拡張CSSを読み込む
        var css = [ sourcesPath + '/Infoshare.InfoCall/Infoshare.GroupPicker.css',
                    sourcesPath + '/infoshare.InfoCall/infragistics.extension.css'];

        // IE8の場合は上書き用のCSSを追加で読み込む
        if (ISBrowser.GetDocumentVersion() == 8)
        {
            css.push(sourcesPath + '/Infoshare.InfoCall/Infoshare.GroupPicker.backcompat.css');
        }
        
        ISScript.Load(css, null, function()
        {
            context.CssLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    });

    // 追加CSS読み込み
    if (GPContext.Configuration.StyleSheets.length > 0)
    {
        var aditionalStyleSheets = new Array();
        for (var i = 0; i < GPContext.Configuration.StyleSheets.length; i++)
        {
            var styleSheet = GPContext.Configuration.StyleSheets[i];
            if (!ISString.StartsWith(styleSheet, 'http://', true) &&
                !ISString.StartsWith(styleSheet, 'ftp://', true))
            {
                styleSheet = sourcesPath + '/' + ISString.TrimStart(styleSheet, '/');
            }

            aditionalStyleSheets.push(styleSheet);
        }

        ISScript.Load(aditionalStyleSheets, null, function()
        {
            context.AditionalStyleSheetLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    }
    else
    {
        context.AditionalStyleSheetLoaded = true;
        if (context.LoadCompleted() && callback)
        {
            callback();
        }
    }

    // スクリプト読み込み
    var baseScript = sourcesPath + '/Infoshare.InfoCall/jquery.min.js';
    ISScript.Load(baseScript, null, function()
    {
        var script = [ sourcesPath + '/Infoshare.InfoCall/jquery-ui.min.js',
                       sourcesPath + '/Infoshare.InfoCall/Infragistics/js/infragistics.core.js',
                       sourcesPath + '/Infoshare.InfoCall/Infragistics/js/infragistics.lob.js' ];
        var type = [ '$.widget', '$.ig.Grid', '$.ig.regional.ja' ];
        ISScript.Load(script, type, function()
        {
            if ($ && typeof (ig$) == 'undefined')
            {
                // infragisticsのjs読み込み時に$が必要なため2段階でスクリプトを読み込み、$をクリアする
                ig$ = $.noConflict(true);
            }

            context.ScriptLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    });

    // 追加スクリプト読み込み
    if (GPContext.Configuration.Scripts.length > 0)
    {
        var aditionalScript = new Array();
        for (var i = 0; i < GPContext.Configuration.Scripts.length; i++)
        {
            var script = GPContext.Configuration.Scripts[i];
            if (!ISString.StartsWith(script, 'http://', true) &&
                !ISString.StartsWith(script, 'ftp://', true))
            {
                script = sourcesPath + '/' + ISString.TrimStart(script, '/');
            }

            aditionalScript.push(script);
        }

        ISScript.Load(aditionalScript, null, function()
        {
            context.AditionalScriptLoaded = true;
            if (context.LoadCompleted() && callback)
            {
                callback();
            }
        });
    }
    else
    {
        context.AditionalScriptLoaded = true;
        if (context.LoadCompleted() && callback)
        {
            callback();
        }
    }
}
                            
