// -----------------------------------------------------------------------
//  SearchKeyword
// -----------------------------------------------------------------------
Infoshare.GroupPicker.SearchKeyword = function InfoInfoshare$GroupPicker$SearchKeyword(keywords, synonyms, validateOption)
{
    this.OriginalString = keywords;

    if (!iObject.IsNullOrUndefined(synonyms))
    {
        this.Synonyms = synonyms;
    }

    if (!iObject.IsNullOrUndefined(validateOption) &&
        iType.GetTypeName(validateOption) == GPKeywordValidateOption.TypeName)
    {
        this.ValidateOption = validateOption;
    }

    this.Limitation    = new GPSearchKeywordLimitation();
    this.ReservedWords = new Array();
};
GPSearchKeyword = Infoshare.GroupPicker.SearchKeyword;
GPSearchKeyword.TypeName = 'Infoshare.GroupPicker.SearchKeyword';

GPSearchKeyword.prototype = {
    TypeName: GPSearchKeyword.TypeName,

    OriginalString: null,
    Keywords: null,

    Synonyms: null,
    ValidateOption: null,

    Limitation: null,
    ReservedWords: null,
    ErrorMessage: null,

    GetKeywords: function()
    {
        if (this.Keywords != null)
        {
            return this.Keywords;
        }

        // �L�[���[�h����
        var keywords = this.Split();

        // �o���f�[�V����
        var valid = this.Validate(this.OriginalString, keywords);

        // �L�[���[�h�o�^
        if (valid &&
            !iObject.IsNullOrUndefined(keywords) && keywords.length > 0)
        {
            this.Keywords = keywords;
        }
        else
        {
            this.Keywords = new Array();
        }

        return this.Keywords;
    },

    Split: function()
    {
        var splitter = new GPKeywordSplitter();
        splitter.Synonyms = this.Synonyms;

        var keywords = splitter.Split(this.OriginalString);

        return keywords;
    },

    Validate: function(originalString, keywords)
    {
        var validator = new GPKeywordValidator(this.ValidateOption);
        validator.ReservedWords = this.ReservedWords;
        validator.Limitation = this.Limitation;

        var valid = validator.Validate(originalString, keywords);
        this.ErrorMessage = validator.ErrorMessage;

        return valid;
    }
};


// -----------------------------------------------------------------------
//  KeywordSplitter
// -----------------------------------------------------------------------
Infoshare.GroupPicker.KeywordSplitter = function InfoInfoshare$GroupPicker$KeywordSplitter() { }
GPKeywordSplitter = Infoshare.GroupPicker.KeywordSplitter;

GPKeywordSplitter.prototype = {
    Splitter: null,

    KeywordSeparator: [' ', '\u3000'],
    KeywordDelimiter: null,
    Synonyms: null,

    Split: function(keyword)
    {
        this.Splitter = new iStringSplitter();
        this.Splitter.Separator = this.KeywordSeparator;
        this.Splitter.Delimiter = this.KeywordDelimiter;

        var keywords = this.Splitter.Split(keyword);
        if (keywords != null)
        {
            for (var i = 0; i < keywords.length; i++)
            {
                keywords[i] = this.ProcessSynonyms(keywords[i]);
            }
        }

        return keywords;
    },

    IsDelimiterOnly: function(keyword)
    {
        return this.Splitter.IsDelimiterOnly(keyword);
    },

    ProcessSynonyms: function(keyword)
    {
        if (this.Synonyms == null)
        {
            return keyword;
        }

        var processedKeyword = keyword;
        for (var i = 0; i < this.Synonyms.length; i++)
        {
            var synonymInfo = this.Synonyms[i];
            for (var j = 0; j < synonymInfo.Values.length; j++)
            {
                var synonymValue = synonymInfo.Values[j];
                processedKeyword = iString.Replace(processedKeyword, synonymValue, synonymInfo.RepresentingValue);
            }
        }

        return processedKeyword;
    }
}


// -----------------------------------------------------------------------
//  KeywordValidateOption
// -----------------------------------------------------------------------
Infoshare.GroupPicker.KeywordValidateOption = function InfoInfoshare$GroupPicker$KeywordValidateOption() { };
GPKeywordValidateOption = Infoshare.GroupPicker.KeywordValidateOption;
GPKeywordValidateOption.TypeName = 'Infoshare.GroupPicker.KeywordValidateOption';

GPKeywordValidateOption.prototype = {
    TypeName: GPKeywordValidateOption.TypeName,

    Empty:     true,
    Length:    true,
    Count:     true,
    Surrogate: true,
    Reserved:  true
};


// -----------------------------------------------------------------------
//  KeywordValidator
// -----------------------------------------------------------------------
Infoshare.GroupPicker.KeywordValidator = function InfoInfoshare$GroupPicker$KeywordValidator(option)
{
    if (!iObject.IsNullOrUndefined(option) &&
        iType.GetTypeName(option) == GPKeywordValidateOption.TypeName)
    {
        this.Option = option;
    }
};
GPKeywordValidator = Infoshare.GroupPicker.KeywordValidator;
GPKeywordValidator.TypeName = 'Infoshare.GroupPicker.KeywordValidator';

GPKeywordValidator.prototype = {
    TypeName: GPKeywordValidator.TypeName,

    Option: null,
    Lmitation: null,
    ReservedWords: null,
    ErrorMessage: null,

    Validate: function(originalString, keywords)
    {
        var valid = false;
        for (;;)
        {
            // �o���f�[�V�����w��Ȃ�
            if (iObject.IsNullOrUndefined(this.Option))
            {
                valid = true;
                break;
            }

            if (this.Option.Empty     && !this.ValidateEmpty(originalString, keywords))  { break; }
            if (this.Option.Length    && !this.ValidateLength(originalString, keywords)) { break; }
            if (this.Option.Count     && !this.ValidateCount(keywords))                  { break; }
            if (this.Option.Surrogate && !this.ValidateSurrogate(keywords))              { break; }
            if (this.Option.Reserved  && !this.ValidateReserved(keywords))               { break; }

            valid = true;
            break;
        }

        return valid;
    },

    ValidateEmpty: function(originalString, keywords)
    {
        if (this.Option.Empty)
        {
            if (iString.IsNullOrEmpty(originalString) ||
                iObject.IsNullOrUndefined(keywords) ||
                keywords.length <= 0)
            {
                this.ErrorMessage = iResxResource.GetString('PickerDialog.SearchView.EmptyKeywordErrorMessage');
                return false;
            }
        }

        return true;
    },

    ValidateLength: function(originalString, keywords)
    {
        if (this.Option.Length)
        {
            // �S�̂̒�����m�F
            if (!iString.IsNullOrEmpty(originalString) && originalString.length > this.Limitation.TextLength)
            {
                this.ErrorMessage = iString.Format(iResxResource.GetString('PickerDialog.SearchView.LengthKeywordErrorMessageFormat'), this.Limitation.TextLength);
                return false;
            }

            // �ʃL�[���[�h�̒�����m�F
            if (!iObject.IsNullOrUndefined(keywords) && keywords.length > 0)
            {
                for (var i = 0; i < keywords.length; i++)
                {
                    var keyword = keywords[i];
                    if (!iString.IsNullOrEmpty(keyword) && keyword.length > this.Limitation.WordLength)
                    {
                        this.ErrorMessage = iString.Format(iResxResource.GetString('PickerDialog.SearchView.LengthKeywordErrorMessageFormat'), this.Limitation.WordLength);
                        return false;
                    }
                }
            }
        }

        return true;
    },

    ValidateCount: function(keywords)
    {
        // ��
        if (this.Option.Count)
        {
            if (!iObject.IsNullOrUndefined(keywords) && keywords.length > this.Limitation.WordCount)
            {
                this.ErrorMessage = iString.Format(iResxResource.GetString('PickerDialog.SearchView.CountKeywordErrorMessageFormst'), this.Limitation.WordCount);
                return false;
            }
        }

        return true;
    },

    ValidateSurrogate: function(keywords)
    {
        if (this.Option.Surrogate)
        {
            // ���`�ꏈ�����ʂɊ܂܂�邩��m�F����K�v����
            if (!iObject.IsNullOrUndefined(keywords) && keywords.length > 0)
            {
                for (var i = 0; i < keywords.length; i++)
                {
                    var keyword = keywords[i];
                    if (iString.ContainsSurrogatePair(keyword))
                    {
                        this.ErrorMessage = iResxResource.GetString('PickerDialog.SearchView.SurrogatePairKeywordErrorMessage');
                        return false;
                    }
                }
            }
        }

        return true;
    },

    ValidateReserved: function(keywords)
    {
        if (this.Option.Reserved)
        {
            if (!iObject.IsNullOrUndefined(keywords) && keywords.length > 0)
            {
                for (var i = 0; i < keywords.length; i++)
                {
                    var keyword = keywords[i];
                    for (var j = 0; j < this.ReservedWords.length; j++)
                    {
                        var reservedWord = this.ReservedWords[j];
                        if (iString.Equals(keyword, reservedWord))
                        {
                            this.ErrorMessage = iResxResource.GetString('PickerDialog.SearchView.SystemKeywordErrorMessage');
                            return false;
                        }
                    }
                }
            }
        }

        return true;
    }
};
                            
