Infoshare.GroupPicker.PageExtender = function Infoshare$GroupPicker$PageExtender() { }
GPPageExtender = Infoshare.GroupPicker.PageExtender;
GPPageExtender.ExtendersInitialized = false;

GPPageExtender.Extend = function()
{
    ISTrace.TraceVerbose('[BEGIN] GPPageExtender.Extend');

    // 拡張するかどうかを判定する
    if (!GPPageExtender.CanExtend())
    {
        ISTrace.TraceVerbose('[CANCELLED] GPPageExtender.Extend');
        return;
    }

    // iFrameから開かれた場合は親コンテキストを初期化した後でフォームを拡張する
    if (window != window.top)
    {
        var cloner = new GPContextCloner(window.parent);
        cloner.CloneFromParent(function ()
        {
            if (GPContext.InitializeOption.SiteConfigurationInitialize)
            {
                // サイト構成リストの更新
                iSiteConfiguration.Refresh();
                iSiteConfiguration.Initialize(function ()
                {
                    GPPageExtender.ExtendInternal(); 
                });     
            }
            else
            {
                GPPageExtender.ExtendInternal(); 
            }       
        });
    }
    else
    {
        GPPageExtender.ExtendInternal();
    }
}
GPPageExtender.ExtendInternal = function()
{
    GPContext.LoadjQuery = true;
    GPContext.Initialize(function()
    {
        if (!GPPageExtender.ExtendersInitialized)
        {   
            // extender初期化
            for (var i = 0; i < GPContext.Configuration.Extenders.GetLength(); i++)
            {
                var classInfo = GPContext.Configuration.Extenders.Get(i);
                try
                {
                    // グローバル変数のExtenderクラスをInitializeし、ClassInfoプロパティを付与する
                    var expression = 'var info = GPContext.Configuration.Extenders.Get('
                                   + i
                                   + ');'
                                   + classInfo.Name
                                   + '.Initialize();'
                                   + classInfo.Name
                                   + '.ClassInfo = info;'
                    eval(expression);
                }
                catch(e)
                {                    
                    ISTrace.TraceVerbose('[FAILED] ' + classInfo.Name + '.Initialize()');
                    ISTrace.TraceVerbose('[FAILED] ' + e.message);
                }                    
            }

            // Extender初期化フラグを更新
            GPPageExtender.ExtendersInitialized = true;
        }

        // ページ拡張
        var extender = new iSPPageExtender();
        extender.Extend();
        ISTrace.TraceVerbose('[END] GPPageExtender.Extend');

        // ダイアログの初期化: フォームの初期化が始まった段階でダイアログの初期化も始める（ダイアログ表示高速化のため）
        // IE8では外部ファイルを読み込まない
        var isIE8 = ISBrowser.GetDocumentVersion() == 8;
        var partial = isIE8;
        GPViewContext.Initialize(null, partial);

        // ライセンス関連のメッセージの表示
        GPPageExtender.NotifyLicenseValidationInfo();
    });
}
GPPageExtender.CanExtend = function()
{
    var extend = false;
    
    // 機能が無効な場合には拡張しない
    if (typeof GPSettings == "undefined")
    {
        ISTrace.TraceWarning('[CANCELLED] GPPageExtender.Extend（GPSettings is not found）');
        return false;
    }

    if (!GPContext.IsSupportedBrowser())
    {
        ISTrace.TraceWarning('[CANCELLED] GPPageExtender.Extend（This browser is not supported）');
        return false;
    }

    // ピッカー機能
    if (GPSettings.PickerFeature)
    {
        // 拡張対象のフォームか否かの判断
        for (;;)
        {
            // 拡張対象の確認
            if (!GPPageExtender.IsTargetPage())
            {
                break;
            }

            // ユーザー列が存在する場合にのみ拡張
            if (!GPPageExtender.HasUserControl())
            {
                break;
            }

            extend = true;
            break;
        }
    }

    // 組織マスタリストで拡張
    if (GPSettings.OrganizationManagementFeature)
    {
        if (GPMasterListFormExtender.CanExtend()) 
        {
            extend = true;
            GPContext.InitializeOption.EnsureSitePermission = true;
            // サイト構成リストの読み込みは行わない
            // ToDo: ContextClonerで正しくキャッシュさせる
            GPContext.InitializeOption.SiteConfigurationInitialize = false;

            // 補助マスタリストキャッシュの有効化
            GPViewContext.InitializeOption.EnsureSupplementMasterList = true;

            // 即フォームをブロックする
            GPMasterListFormExtender.HideForm();
        }
    }
    
    // 初期化に時間がかかるため動的な判断はあきらめる
    //for (;;)
    //{
    //    // フォーム確認
    //    for (var i = 0; i < GPContext.Configuration.Extenders.GetLength(); i++)
    //    {
    //        var extenderClassName = GPContext.Configuration.Extenders.Get(i);
    //        var extender = eval(extenderClassName);
    //        if (extender.ExtenderType == iViewExtender.ExtenderType.Page &&
    //            extender.CanExtend())
    //        {
    //            extend = true;
    //            break;
    //        }
    //    }

    //    // コントロール確認
    //    for (var i = 0; i < GPContext.Configuration.Extenders.GetLength(); i++)
    //    {
    //        var extenderClassName = GPContext.Configuration.Extenders.Get(i);
    //        var extender = eval(extenderClassName);
    //        if (extender.ExtenderType == iViewExtender.ExtenderType.Control &&
    //            extender.CanExtend())
    //        {
    //            extend = true;
    //            break;
    //        }
    //    }

    //    break;
    //}    

    return extend;
}

GPPageExtender.IsTargetPage = function()
{
    var isTargetPage = false;
    if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Classic)
    {
        // 新規、編集フォーム、共有ダイアログ、Webパーツ編集ペイン、プロファイル編集ページで拡張
        isTargetPage = iSPListFormExtender.CanExtend() ||
                       iNFFormExtender.CanExtend() ||
                       iSPDialogExtender.CanExtend() ||
                       iSPWebPartEditorExtender.CanExtend() ||
                       iSPProfileFormExtender.CanExtend();
    }
    else if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Modern)
    {
        isTargetPage = iSPListFormExtender.CanExtend();
    }

    return isTargetPage;
}

GPPageExtender.HasUserControl = function()
{
    var hasUserControl = false;
    if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Classic)
    {
        hasUserControl = iUserFieldExtender.CanExtend() ||
                         iLegacyUserFieldExtender.CanExtend() ||
                         iNFUserFieldExtender.CanExtend() ||
                         iNFLegacyUserFieldExtender.CanExtend() ||
                         iUserControlExtender.CanExtend();
    }
    else if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Modern)
    {
        hasUserControl = iModernUserFieldExtender.CanExtend();
    }
                         
    return hasUserControl;
}

GPPageExtender.RegisterExtendMethod = function(functionName)
{
    var gpScriptPath = "";
    // MDS（ダウンロード最小化戦略）が有効化されている場合スクリプトのURLを取得する
    if (typeof g_mdsReady != "undefined")
    {
        if (_spPageContextInfo &&
            !ISString.IsNullOrEmpty(_spPageContextInfo.siteServerRelativeUrl))
        {
            var siteRelativePath = _spPageContextInfo.siteServerRelativeUrl;
            var gpScriptPath = ISString.TrimEnd(siteRelativePath, "/")
                                + "/InfoshareProductLibrary/Sources/Infoshare.InfoCall/Infoshare.GroupPicker.js";
        }    
    }

    iSPUtility.RegisterOnLoadFunctionForMDS(gpScriptPath, functionName);
}

GPPageExtender.NotifyLicenseValidationInfo = function()
{
    // ピッカー拡張
    if (GPPageExtender.IsTargetPage() &&
        GPPageExtender.HasUserControl())
    {
        GPPageExtender.NotifyLicenseValidationInfoInternal(GPContext.License);
    }

    // 組織マスタ拡張
    if (GPMasterListFormExtender.CanExtend())
    {
        GPPageExtender.NotifyLicenseValidationInfoInternal(GPContext.OrganizationManagementLicense);
    }
}

GPPageExtender.NotifyLicenseValidationInfoInternal = function(license)
{
    var message = (new iLicenseMessage()).BuildMessage(license);
    if (!iString.IsNullOrEmpty(message))
    {
        //iSPNotify.Notify(message, null, null, (new iLicenseMessage()).MessageDisplayTime);
        (new iNotifyer()).Notify(message, (new iLicenseMessage()).MessageDisplayTime);
    }
}
                            
