GPLegacyUserFieldExtender.prototype.OnClickPickerButton = GPUserFieldExtender.prototype.OnClickPickerButton;
GPLegacyUserFieldExtender.prototype.OnClickPickerButtonInternal = GPUserFieldExtender.prototype.OnClickPickerButtonInternal;

GPLegacyUserFieldExtender.prototype.ExtendChangeEvent = function ()
{
    if (!this.EditorElement)
    {
        this.EnsureEditor();
    }
    
    // エンティティの更新時の関数（entityeditor.js）
    var baseEntityEditorCallback = EntityEditorCallback;
    var newEntityEditorCallback = ISFunction.CreateDelegate(function(result, ctxParam, preventAutoPostBack)
    {
        // Base関数を実行
        baseEntityEditorCallback(result, ctxParam, preventAutoPostBack);

        
        // IDの確認
        // EditorElementのID　　　　　　　　　　　　　　　 ："ctl00_ctl33_g_d51bfce9_38af_4a89_9174_11e6d41f9822_ff71_ctl00_ctl00_UserField_upLevelDiv"
        // ctxParam（イベントのトリガになったコントロール）："ctl00_ctl33_g_d51bfce9_38af_4a89_9174_11e6d41f9822_ff71_ctl00_ctl00_UserField"
        var editorElmId = this.EditorElement.id.replace("_upLevelDiv", "");
        if (ISString.Equals(editorElmId, ctxParam, true))
        {
            // 他フィールド連携機能
            this.ExecuteFillRelatedField();     
        }     
    }, this);

    // 複数値が候補になった際に選択する際の関数（entityeditor.js）
    var baseReplaceFunction = EEReplace;
    var newReplaceFunction = ISFunction.CreateDelegate(function (clientID, key, id)
    {
        // Base関数を実行
        baseReplaceFunction(clientID, key, id);

        // IDの確認
        // EditorElementのID　　　　　　　　　　　　　　　 ："ctl00_ctl33_g_d51bfce9_38af_4a89_9174_11e6d41f9822_ff71_ctl00_ctl00_UserField_upLevelDiv"
        // clientID（イベントのトリガになったコントロール）："ctl00_ctl33_g_d51bfce9_38af_4a89_9174_11e6d41f9822_ff71_ctl00_ctl00_UserField"
        var editorElmId = this.EditorElement.id.replace("_upLevelDiv", "");
        if (ISString.Equals(editorElmId, clientID, true))
        {
            // 他フィールド連携機能
            this.ExecuteFillRelatedField();     
        } 
    }, this);

    // 関数を上書き
    EntityEditorCallback = newEntityEditorCallback;
    EEReplace = newReplaceFunction;
}

GPLegacyUserFieldExtender.prototype.ExecuteFillRelatedField = GPUserFieldExtender.prototype.ExecuteFillRelatedField;
GPLegacyUserFieldExtender.prototype.GetFillRelatedFieldSetting = GPUserFieldExtender.prototype.GetFillRelatedFieldSetting;
