{
    // ピッカーボタンの追加
    this.CreatePickerButton();
}

GPModernUserFieldExtender.prototype.CreatePickerButton = function()
{
    var pickerTopLevelDiv = i$('.ms-BasePicker-input', this.FormFieldInfo.BodyElement)[0];
    var addressbookImage = i$('img[src$="/addressbook.png"], img[src$="/addressbook-Press.png"], img[src$="/addressbook-Hover.png"]', this.FormFieldInfo.BodyElement);
    if (typeof (pickerTopLevelDiv) == "undefined" || addressbookImage.length > 0)
    {
        return;
    }

    var pickerFormBodyChildDiv = pickerTopLevelDiv.parentElement;

    // ボタン配置用のdivを用意
    var div = document.createElement('div');
    div.style.float       = 'left';
    div.style.paddingTop  = '4px';
    div.style.paddingLeft = '6px';
    // ユーザーフィールド要素の次に追加（説明のsapn要素が存在する場合その手前に挿入する）
    this.FormFieldInfo.BodyElement.insertBefore(div, pickerFormBodyChildDiv.nextSibling);

    // ボタンを配置
    var button = GPUserFieldExtenderUtility.CreatePickerButton(this);
    button.Render(div);
}

GPModernUserFieldExtender.prototype.OnClickPickerButton = GPUserFieldExtender.prototype.OnClickPickerButton;

GPModernUserFieldExtender.prototype.OnClickPickerButtonInternal = function (control)
{
    var dialog = window.top.GPDialog.CreatePickerDialog();
    dialog.EntitySelection = this.GetEntitySelection();
    dialog.ResolvedEntities = this.GetEntities();
       
    var extender = this;
    extender.Editor.EnableFormAutoClosing(true);
    extender.Editor.DisableReactStopPropagation(true);
    dialog.AddCloseEvent(function (result)
    {
        extender.Editor.EnableFormAutoClosing(false);
        extender.Editor.DisableReactStopPropagation(false);
        if (result.Result == iDialogResult.ResultType.OK)
        {            
            var entities = result.SelectedEntities;
  
            // オンプレミスの対象ユーザー列の場合には、識別名を名前解決用に用いる
            if (!GPContext.IsOnline &&
                extender.FieldInfo &&
                extender.FieldInfo.Type == "TargetTo")
            {
                for (var i = 0; i < entities.length; i++)
                {
                    var distinguishedName = entities[i].Properties["DistinguishedName"];
                    if (!ISString.IsNullOrEmpty(distinguishedName))
                    {
                        entities[i].Properties["SpResolveKey"] = distinguishedName;
                    }
                }
            }

            // エンティティをセット
            extender.SetEntities(entities);
        }
    });
    
    // モダンUIの場合、CoreCssが適用されずスタイルが崩れるため、CoreCssより作成したスタイルを適用する
    dialog.Dialog.Style.EnableClassName = "is-gp-ModernDialog-FromCoreCSS";

    window.top.GPDialog.Open(dialog);
}

