Infoshare.GroupPicker.ModernSharingFormExtender = function Infoshare$GroupPicker$ModernSharingFormExtender()
{
    Infoshare.SharePoint.ModernUserFieldExtender.apply(this, arguments);
}
GPModernSharingFormExtender = Infoshare.GroupPicker.ModernSharingFormExtender;
GPModernSharingFormExtender.TypeName = 'Infoshare.GroupPicker.ModernSharingFormExtender';

GPModernSharingFormExtender.Initialize = function ()
{
    if (!GPModernSharingFormExtender.Extenders)
    {
        GPModernSharingFormExtender.Extenders = new ISDictionary();
    }

    iBehaviorExtender.AddExtender(Infoshare.SharePoint.FunctionExtender, 'Infoshare.GroupPicker.ModernSharingFormExtender', 'Infoshare.GroupPicker.ModernSharingFormExtender');
}

GPModernSharingFormExtender.prototype = new Infoshare.SharePoint.ModernUserFieldExtender();
GPModernSharingFormExtender.prototype.TypeName = GPModernSharingFormExtender.TypeName;

GPModernSharingFormExtender.prototype.CanExtend = function()
{
    return true;
}

GPModernSharingFormExtender.prototype.Extend = function()
{
    this.CreateSharingPickerButton();
}


GPModernSharingFormExtender.prototype.CreateSharingPickerButtonInternal = function (sharingFormcontrol)
{
    var extender = this;
    if (typeof _spPageContextInfo == 'undefined')
    {
        _spPageContextInfo = {
            "siteAbsoluteUrl": iSettings.MasterSiteContext.ServerRelativePath,
            "webAbsoluteUrl": iSettings.MasterSiteContext.ServerRelativePath
        };
    }

    GPContext.Initialize(function()
    {
        var rootField = sharingFormcontrol;
        var coreField = rootField.getElementsByClassName("ms-BasePicker-text")[0];
        var inputField = iModernUserFieldExtender.FindFieldControls(rootField)[0];

        // ボタンが既に配置されている場合、スキップする
        var addressbookImage = i$('img[src$="/addressbook.png"], img[src$="/addressbook-Press.png"], img[src$="/addressbook-Hover.png"]', coreField);
        if (addressbookImage.length > 0)
        {
            return;
        }

        // ダウンレベルモード
        var guid = ISGuid.New();
        extender.FormFieldInfo = new iSPFormFieldInfo(guid, guid, "UserMulti");

        extender.FormFieldInfo.RowElement = rootField;
        extender.FormFieldInfo.BodyElement = coreField;

        // ボタン配置用のdivを用意
        var div = document.createElement('div');
        div.style.float = 'right';
        div.style.paddingTop = '4px';
        div.style.paddingRight = '4px';
        // ユーザーフィールド要素の次に追加（説明のsapn要素が存在する場合その手前に挿入する）
        coreField.insertBefore(div, inputField.parentElement.nextSibling);

        // ボタンを配置
        var pickerButton = GPUserFieldExtenderUtility.CreatePickerButton(extender);
        pickerButton.Render(div);

        // 共有ダイアログのイベントを設定
        if (document.getElementById('shareFrame')) {
            inputField.style.width = "90%";
            var sharingFormButton = sharingFormcontrol.querySelector('img[id^="Infoshare.Web.Control.Imagebutton"]');
            sharingFormButton.onclick = ISFunction.CreateDelegate(extender.OnClickPickerButton, extender);
            sharingFormButton.onmouseover = ISFunction.CreateDelegate(function () { sharingFormButton.src = pickerButton.Style.Images.EnableHover }, sharingFormButton);
            sharingFormButton.onmouseout = ISFunction.CreateDelegate(function () { sharingFormButton.src = pickerButton.Style.Images.Enable }, sharingFormButton);
        }

        // ダイアログの初期化: フォームの初期化が始まった段階でダイアログの初期化も始める（ダイアログ表示高速化のため）
        GPViewContext.Initialize(null, false);

    });
}

GPModernSharingFormExtender.prototype.CreateSharingPickerButton = function()
{
    // ピッカー（共有フィールド）
    var sharingFormcontrols = iModernUserFieldExtender.FindSharingFormControls();
    if (sharingFormcontrols.length == 1)
    {
        this.CreateSharingPickerButtonInternal(sharingFormcontrols[0]);
    }
};

GPModernSharingFormExtender.prototype.OnClickPickerButton = GPUserFieldExtender.prototype.OnClickPickerButton;

GPModernSharingFormExtender.prototype.OnClickPickerButtonInternal = GPModernUserFieldExtender.prototype.OnClickPickerButtonInternal

