GPUserControlExtender.prototype.CreatePickerButton = function()
{
    // 追加対象の要素
    var appendTargetElm = null;

    // ボタン配置用のdivを用意
    var gpButtonDiv = document.createElement('div');

    // ピッカー要素のTableCell
    var pickerTableCell = i$('.ms-tableCell.ms-fullWidth', document)[0];
    if (typeof pickerTableCell == "undefined")
    {
        return;
    }
    // 権限設定のセレクター
    var roleSelectorTableCell = i$(".ms-tableCell.ms-verticalAlignTop.ms-aclinv-simplified-roles-container", pickerTableCell.parentElement)[0];

    // 共有ダイアログ（セレクターが存在しない・非表示の場合）
    if (typeof roleSelectorTableCell == "undefined" ||
        ISArray.Contains(roleSelectorTableCell.classList, "ms-hide"))
    {
        // スタイルの設定
        gpButtonDiv.style.float       = 'left';
        gpButtonDiv.style.paddingLeft = '6px';

        // 追加対象の設定
        appendTargetElm = pickerTableCell.parentElement;   
    }
    // ドキュメントの共有
    else
    {
        // スタイルの設定
        gpButtonDiv.style.float      = 'left';
        gpButtonDiv.style.paddingTop = '6px';

        // 追加対象の設定
        appendTargetElm = roleSelectorTableCell;   
    }   

    // 要素に挿入
    appendTargetElm.appendChild(gpButtonDiv);

    // ボタンを配置
    var button = GPUserFieldExtenderUtility.CreatePickerButton(this);
    button.Render(gpButtonDiv);
}

