GPTargetToLegacyUserControlExtender.Initialize = function()
{
    // Webパーツエディタペイン
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.WebPartEditorExtender, 'TargetTo', 'Infoshare.GroupPicker.LegacyTargetToUserControlExtender');
}

GPTargetToLegacyUserControlExtender.prototype = new Infoshare.SharePoint.LegacyUserControlExtender();
GPTargetToLegacyUserControlExtender.prototype.TypeName = GPTargetToLegacyUserControlExtender.TypeName;

