GPTargetToLegacyUserControlExtender.prototype.CreatePickerButton = GPLegacyUserFieldExtender.prototype.CreatePickerButton;
GPTargetToLegacyUserControlExtender.prototype.OnClickPickerButton = GPLegacyUserFieldExtender.prototype.OnClickPickerButton;
GPTargetToLegacyUserControlExtender.prototype.OnClickPickerButtonInternal = GPLegacyUserFieldExtender.prototype.OnClickPickerButtonInternal;

GPTargetToLegacyUserControlExtender.prototype.EnsureEditor = function()
{
    if (this.EditorElement &&
        this.CheckNameButton)
    {
        return;
    }
    
    var baseTarget = this.ParentExtender.WebPartEditPane ? this.ParentExtender.WebPartEditPane
                                                         : document;
    // 詳細設定のdivを取得する
    var selector = "div[id$=_AdvancedCategory]";
    var target = i$(selector, baseTarget);
    if (target.length < 1)
    {
        return;
    }
    target = target[0];

    this.EditorElement = iLegacyUserFieldExtender.FindFieldControls(target)[0];
    if (this.EditorElement)
    {
        var anchors = target.getElementsByTagName('a');        
        for (var i = 0; i < anchors.length; i++)
        {
            var anchor = anchors[i];
            if (ISString.EndsWith(anchor.id, '_checkNames', true))
            {
                this.CheckNameButton = anchor;
            }
            if (ISString.EndsWith(anchor.id, '_browse', true))
            {
                this.BrowseDialogButton = anchor;
            }
        }

        // Formには紐づかないフィールドだが、GPUserFieldExtenderの名前解決ロジックで処理させるために、FieldInfo属性を付与する
        this.FieldInfo = {};
        this.FieldInfo.Type = "TargetTo";
    }
}

