// -----------------------------------------------------------------------
//  Dialog
// -----------------------------------------------------------------------
Infoshare.GroupPicker.Dialog = function Infoshare$GroupPicker$Dialog() { }
GPDialog = Infoshare.GroupPicker.Dialog;
GPDialog.Type = { Picker: 'Picker',
                  Finder: 'Finder',
                  Entity: 'Entity',
                  PickerSelectControl: 'PickerSelectControl',
                  EntityMaster: 'EntityMaster',
                  PermissionMaster: 'PermissionMaster'}

GPDialog.ActiveDialog = null;

GPDialog.Open = function(dialog)
{
    if (GPDialog.ActiveDialog && GPDialog.ActiveDialog.Info.Type != GPDialog.Type.Finder)
    {
        ISTrace.TraceWarning('[Infoshare.GroupPicker.Dialog] Dialog open conflict');
        return;
    }

    // ダイアログ種別によって確認するライセンスを切り替える
    var license = null;
    if (dialog.Info.Type == GPDialog.Type.Finder) 
    {
        license = GPContext.InfoCallLicense;
    }
    else if (dialog.Info.Type == GPDialog.Type.Picker ||
             dialog.Info.Type == GPDialog.Type.PickerSelectControl) 
    {
        license = GPContext.License;
    }
    else if (dialog.Info.Type == GPDialog.Type.EntityMaster ||
             dialog.Info.Type == GPDialog.Type.PermissionMaster) 
    {
        license = GPContext.OrganizationManagementLicense;
    }

    // ライセンス確認
    // 無効時にメッセージを表示しダイアログの初期化をやめる
    if (!license ||
        !license.Valid)
    {
        var message = (new iLicenseMessage()).BuildMessage(license);
        alert(message);
        return;
    }

    // ダイアログを開く
    // ViewContextが初期化済みの場合はそのまま、見初期化の場合は初期化後に開く
    if (GPViewContext.Initialized)
    {
        GPDialog.OpenInternal(dialog);
    }
    else
    {
        GPViewContext.RegisterFunctionToNotifyInitialized(function()
        {
            GPDialog.OpenInternal(dialog);
        });
    }
}
GPDialog.OpenInternal = function(dialog)
{
    GPDialog.ActiveDialog = dialog;
    dialog.AddCloseEvent(function()
    {
        GPDialog.ActiveDialog = null;
    });

    // 電話帳ダイアログはフッター領域を無効化
    if (dialog.Info.Type == GPDialog.Type.Finder)
    {
        dialog.Dialog.InitializeFooter = function(){};
    }

    dialog.Open();
}

GPDialog.CreatePickerDialog = function()
{
    return GPDialog.CreateDialog(GPDialog.Type.Picker);
}

GPDialog.CreateFinderDialog = function()
{
    return GPDialog.CreateDialog(GPDialog.Type.Finder);
}

GPDialog.CreatePickerSelectControlDialog = function()
{
    return GPDialog.CreateDialog(GPDialog.Type.PickerSelectControl);
}

GPDialog.CreateDialog = function(type)
{
    // ダイアログ情報取得
    var info = null;
    for (var i = 0; i < GPContext.Configuration.Dialogs.GetLength(); i++)
    {
        var dialogInfo = GPContext.Configuration.Dialogs.Get(i);
        if (dialogInfo.Type == type)
        {
            info = dialogInfo;
            break;
        }
    }
    if (!info)
    {
        return null;
    }

    // ダイアログ作成
    var dialog = iClass.New(info.Class.Name);

    // オプション設定
    var title    = !ISString.IsNullOrEmpty(info.DisplayName) ? info.DisplayName : iResxResource.GetString(info.DisplayNameResourceKey);
    var sizeText = info.Options.Get('DialogSize');
    
    var width    = dialog.DefaultWidth;
    try
    {
        width    = ISNumber.Parse(sizeText.split('x')[0]);
    }
    catch(e)
    {
    }

    var height   = dialog.DefaultHeight;
    try
    {
        height   = ISNumber.Parse(sizeText.split('x')[1]);
    }
    catch(e)
    {
    }

    var option   = new iDialogOption(title, width, height);
    option.Modal = true;
    
    dialog.Info   = info;
    dialog.Option = option;

    return dialog;
}


// -----------------------------------------------------------------------
//  FinderDialog
// -----------------------------------------------------------------------
Infoshare.GroupPicker.FinderDialog = function Infoshare$GroupPicker$FinderDialog() 
{
    this.Dialog = new iDialog();

    this.Dialog.AddEvent(iControl.ControlEventName.BeginPreRender, ISFunction.CreateDelegate(function()
    {
        // Resizeイベントを無効化（GroupPickerダイアログの最大化後にブラウザをリサイズした際にスタイルが崩れる問題の対応）
        this.Dialog.OnResize = function () { }; 
    }, this));
}
GPFinderDialog = Infoshare.GroupPicker.FinderDialog;

GPFinderDialog.prototype = {
    Info: null,

    Dialog: null,
    Option: null,
    Finder: null,

    DefaultWidth: 800,
    DefaultHeight: 600,

    EntitySelection: null,
    
    BaseOpen: function(option, callback)
    {
        // ダイアログ初期化: イメージボタン設定
        var imagesPath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
        this.Dialog.Style.HeaderStyle.WindowModeButtonStyle = new iImageButtonStyle(new iButtonImageInfo(imagesPath + 'WindowMode.Window.png',
                                                                                                    '',
                                                                                                    '',
                                                                                                    imagesPath + 'WindowMode.Window-Press.png',
                                                                                                    imagesPath + 'WindowMode.Window-Hover.png'));
        this.Dialog.Style.HeaderStyle.WindowCloseButtonStyle = new iImageButtonStyle(new iButtonImageInfo(imagesPath + 'x.png',
                                                                                                     '',
                                                                                                     '',
                                                                                                     imagesPath + 'x-Press.png',
                                                                                                     imagesPath + 'x-Hover.png'));
        
        // オプション設定
        if (!option)
        {
            option = this.Option;
        }
        // IE8の場合、infragisticsのライブラリを直接ロードするとフォーム保存時のvalidateで問題が発生する為、iframeを使ってGroupPickerを描画する
        // InfoCall の場合、validateは行われないのでiframeは使用しない
        var isIE8Picker = GPDialog.ActiveDialog.Info.Type == GPDialog.Type.Picker && ISBrowser.GetDocumentVersion() == 8;
        if (isIE8Picker)
        {
            option.Url = ISString.TrimEnd(GPContext.SourcesPath, '/') + '/Infoshare.InfoCall/Picker.aspx'
                       + '?' + GPFinder.InitialzeParameterKey.OpenBy      + '=' + GPFinder.OpenByType.InlineFrame;
                       + '&' + GPFinder.InitialzeParameterKey.FinderClass + '=' + this.Info.BodyClass;

            // viewの設定
            this.Dialog.AddEvent(iDialog.EventName.InlineFrameContentsLoaded, ISFunction.CreateDelegate(this.InitializeFinder, this));
        }

        // ダイアログを開く
        if (window == window.top)
        {
            this.Dialog.Open(option);

            // viewの設定
            if (!isIE8Picker)
            {
                this.InitializeFinderInternal(new GPFinder(), this.Dialog.Body);
            }

            callback();
        }
    },

    Open: function(option)
    {
        this.BaseOpen(option, ISFunction.CreateDelegate(function()
        {
            this.Dialog.AddEvent(iDialog.EventName.Close, ISFunction.CreateDelegate(this.OnClose, this));

            // MDS(ダウンロード最小化戦略)対応：ブラウザの戻る、進むボタン使用時にダイアログが残ってしまう問題修正
            if (typeof g_mdsReady != "undefined")
            {
                this.OnHashChangedFunctionCache = ISFunction.CreateDelegate(this.OnHashChanged, this);
                ISDomAccessor.AttachEvent(window, 'hashchange', this.OnHashChangedFunctionCache);
            }
        }, this));
    },

    Events: null,
    AddCloseEvent: function(fn)
    {
        if (this.Events == null)
        {
            this.Events = new iEvent();
        }

        this.Events.AddEvent('close', fn);
    },

    InitializeFinder: function()
    {
        var dialog = this;
        setTimeout(ISFunction.CreateDelegate(function()
        {
            var finder = dialog.Dialog.BodyInlineFrame.GetContentWindow().GPFinder.Instance;
            if (finder) { dialog.InitializeFinderInternal(finder); }
            else        { dialog.InitializeFinder(); }
        }, this), 256);
    },

    InitializeFinderInternal: function(finder, targetControl)
    {
        this.Finder = finder;
        this.Finder.Info = this.Info;
        this.Finder.EntitySelection = this.EntitySelection;

        this.Finder.Render(targetControl.Element, targetControl);
    },

    OnClose: function(result)
    {
        if (this.Events)
        {
            this.Events.FireEventByName('close', result);
        }
    },

    OnHashChangedFunctionCache: null,

    OnHashChanged: function()
    {
        // ダイアログを閉じる
        if (this.Dialog.ParentElement)
        {
            var CloseFunc = ISFunction.CreateDelegate(this.Dialog.Close, this.Dialog);
            CloseFunc();
        }

        // MDS(ダウンロード最小化戦略)対応：ブラウザの戻る、進むボタン使用時にダイアログが残ってしまう問題修正
        if (typeof g_mdsReady != "undefined" &&
            this.OnHashChangedFunctionCache)
        {           
            // イベントをデタッチ
            ISDomAccessor.DetachEvent(window, 'hashchange', this.OnHashChangedFunctionCache);
            this.OnHashChangedFunctionCache = null;
        }
    }
}


// -----------------------------------------------------------------------
//  PickerDialog
// -----------------------------------------------------------------------
Infoshare.GroupPicker.PickerDialog = function Infoshare$GroupPicker$PickerDialog()
{
    Infoshare.GroupPicker.FinderDialog.apply(this, arguments);
}
GPPickerDialog = Infoshare.GroupPicker.PickerDialog;

GPPickerDialog.prototype = new Infoshare.GroupPicker.FinderDialog();
GPPickerDialog.prototype.EntitySyncMode = null;
GPPickerDialog.prototype.ResolvedEntities = null;

GPPickerDialog.prototype.DefaultWidth = 800;
GPPickerDialog.prototype.DefaultHeight = 600;

GPPickerDialog.prototype.InitializeFinderInternal = function(finder, targetControl)
{
    this.Finder = finder;
    this.Finder.Info = this.Info;
    this.Finder.EntitySyncMode   = this.EntitySyncMode;
    this.Finder.EntitySelection  = this.EntitySelection;
    this.Finder.ResolvedEntities = this.ResolvedEntities;

    this.Finder.Render(targetControl.Element, targetControl);

    // ダイアログのボタンは、はじめは非アクティブ（エンティティが選択されていないため）
    this.Dialog.OKButton.Disable();

    // イベント登録
    // this.Finder.Render(target)内で非同期のタイミングでEntitySelectorが初期化される事があるので
    // 再帰呼び出しでイベントを定義する（IE8用実装）
    this.AddEntitySelectorEvent();
}

GPPickerDialog.prototype.AddEntitySelectorEvent = function()
{
    var dialog = this;
    setTimeout(ISFunction.CreateDelegate(function()
    {
        var selector = dialog.Finder.Selector;
        if (selector) { dialog.Finder.Selector.Events.AddEvent(iTagHolder.EventName.TagChanged, ISFunction.CreateDelegate(dialog.OnSelectedEntityChanged, dialog)); }
        else          { dialog.AddEntitySelectorEvent(); }
    }, this), 256);
}

GPPickerDialog.prototype.OnSelectedEntityChanged = function(args)
{
    // エンティティが選択されていない場合は、OKボタンを非アクティブ
    if (args &&
        args.Entities &&
        args.Entities.length > 0)
    {
        this.Dialog.OKButton.Enable();
    }
    else
    {
        this.Dialog.OKButton.Disable();
    }
}

GPPickerDialog.prototype.OnClose = function(result)
{
    if (this.Events)
    {
        result.Dialog = this;
        result.SelectedEntities = this.Finder.Selector.GetSelectedEntities();

        this.Events.FireEventByName('close', result);
    }
}
                            
