ISNamespace.Register('Infoshare.GroupPicker');


// -----------------------------------------------------------------------
//  Dialog
// -----------------------------------------------------------------------
Infoshare.GroupPicker.GridUtility = function Infoshare$GroupPicker$GridUtility() { }
GPGridUtility = Infoshare.GroupPicker.GridUtility;

GPGridUtility.DefaultColumnWidth = 100;
GPGridUtility.Columns = null;
GPGridUtility.BuildColumns = function (viewFields)
{
    var columns = new Array();
    for (var i = 0; i < viewFields.GetLength() ; i++)
    {
        // フィールド情報取得: ViewTypeとViewFieldWidthが指定されているもののみグリッドに表示する
        var field = viewFields.Get(i);
        if (ISString.IsNullOrEmpty(field.ViewType))
        {
            continue;
        }

        // グリッドカラムの初期化
        var column = { headerText: ISString.IsNullOrEmpty(field.DisplayName) ? iResxResource.GetString(field.DisplayNameResourceKey) : field.DisplayName,
                       key:        field.InternalName,
                       datatype:   'string',
                       width:      (ISString.IsNullOrEmpty(field.ViewFieldWidth) ? GPGridUtility.DefaultColumnWidth : field.ViewFieldWidth) + 'px' }
        if (field.ViewType.toUpperCase() == 'LINK')
        {
            // ToDo: httpの場合を考慮する
            var baseTemplate = "<a href= 'Mailto:${" + field.InternalName + "}'>${" + field.InternalName + "}</a>";
            
            // 空文字列を取得すると '[object Object]' と表示されるので分岐（Infragisticsのバグ?）
            var template = "{{if ${" + field.InternalName + "}" + " == '[object Object]' }}"
                         + " "
                         + "{{else}}"
                         + baseTemplate
                         + "{{/if}}";           

            column.template = template; 
        }
        else if (field.ViewType.toUpperCase() == 'MAIL')
        {
            var mailAction = new GPMailAction();
            var actionType = mailAction.GetActionType(field.ActionType);
            if (mailAction.IsValidActionType(actionType))
            {
                var linker = GPMailAction.CreateMailLinker({ To: [], CC: [], BCC: [] }, actionType);
                linker.To.push("${" + field.InternalName + "}");
                if (actionType == GPMailAction.ActionType.OutlookWeb)
                {
                    var baseTemplate = "<a href= '" + iUri.UnescapeComponent(linker.BuildUrl()) + "' target='_blank' rel='noopener noreferrer'>${" + field.InternalName + "}</a>";
                    column.template = this.ConvertToEmptyCharacterSupportTemplate(field.InternalName, baseTemplate);
                }
                else
                {
                    var baseTemplate = "<a href= '" + iUri.UnescapeComponent(linker.BuildUrl()) + "'>${" + field.InternalName + "}</a>";
                    column.template = this.ConvertToEmptyCharacterSupportTemplate(field.InternalName, baseTemplate);
                }
            }
            else
            {
                var message = '[GPGridUtility.BuildColumns] Invalid ActionType for mail hyperlink in configuration file.';
                ISTrace.TraceError(message);
            }
        }
        else if (field.ViewType.toUpperCase() == 'SIP')
        {
            var baseTemplate = "<a href= 'Sip:${" + field.InternalName + "}'>${" + field.InternalName + "}</a>";
            
            // 空文字列を取得すると '[object Object]' と表示されるので分岐（Infragisticsのバグ?）
            var template = "{{if ${" + field.InternalName + "}" + " == '[object Object]' }}"
                         + " "
                         + "{{else}}"
                         + baseTemplate
                         + "{{/if}}";

            column.template = template; 
        }
        else if (field.ViewType.toUpperCase() == 'IMAGE')
        {
            var template = "<img src='${ExtendedProperties.TypeImagePath}' "
                         +      "%AltanativeText% "
                         +      "onerror='this.parentNode.removeChild(this)' />";
            if (field.InternalName.toUpperCase() == 'Type'.toUpperCase()) { template = ISString.Replace(template, '%AltanativeText%', "alt='${Type}'"); }
            else                                                          { template = ISString.Replace(template, '%AltanativeText%', ""); }

            column.template = template;
        }
        else if (field.ViewType.toUpperCase() == 'HIDDEN')
        {
            column.hidden = true;
        }
        else if (field.ViewType.toUpperCase() == 'PROFILE')
        {
            // オンラインの外部ユーザーの場合には、レンダリングしないようにする
            if (GPContext.IsOnline &&
                iVxContext.CurrentUser &&
                iVxContext.CurrentUser.IsExternalUser())
            {
                continue;
            }

            var profileImagePath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/Profile.png';
            var profileHoverImagePath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/Profile-Hover.png';
            
            // 種別がUserの場合のみプロファイルリンクを表示する
            var profileTemplate = "<a href= '#' onClick= GPGridUtility.ProfOnclick(\"" + "${ExtendedProperties.ProfileLinkUserKey}" + "\"" + ")>"
                                +   "<img src='" + profileImagePath + "'" 
                                +       " alt='[Navigate to a user profile]' "
                                +       " onerror=\"this.parentNode.removeChild(this)\"" 
                                +       " onmouseover=\"this.src='" + profileHoverImagePath + "'\"" 
                                +       " onmouseout=\"this.src='" + profileImagePath + "'\"" +  "/>"
                                + "</a>";

            var emptyTemplate = "<div></div>";

            var template = "{{if ${SubType}.toUpperCase() == 'USER' || ${SubType}.toUpperCase() == 'MEMBER' }}"
                         + profileTemplate
                         + "{{else}}"
                         + emptyTemplate
                         + "{{/if}}";

            column.template = template;
        }
        else if (field.ViewType.toUpperCase() == 'CHECK')
        {
            column.template = "<input type='checkbox' ></input>";
        }
        // プレゼンス有効化設定に従ってレンダリングを切り替える
        // g_presenceEnabled：Webアプリケーション毎の設定により有効化・無効化が切り替えられるSharePoint実装内のフラグ値
        else if (field.ViewType.toUpperCase() == 'PRESENCE' && typeof g_presenceEnabled != 'undefined' && g_presenceEnabled)
        {
            var presenceLinkHTML = GPPresenceUtility.GetPresenceLinkHTMLTemplate();
            // 重複するIDを持つプレゼンスアイコンが存在する場合、正しく表示されない為guidを付与する
            var uniqueId = "${EntityId}" + "_" + ISGuid.New();

            presenceLinkHTML = ISString.Format(presenceLinkHTML, uniqueId, "${Sip}")
            column.template = presenceLinkHTML;
        }
        else if (field.ViewType.toUpperCase() == 'UcPresence'.toUpperCase())
        {
            var template = UCPresenceController.GetInstance().BuildPresenceLinkHtmlTemplate();
            template = ISString.Format(template,
                                       "${EntityId}" + "_" + ISGuid.New(),
                                       "${Sip}");

            column.template = template;
        }
        else if (field.ViewType.toUpperCase() == 'GraphPresence'.toUpperCase())
        {
            var template = GraphPresenceController.GetInstance().BuildPresenceLinkHtmlTemplate();
            template = ISString.Format(template,
                                       "${EntityId}" + "_" + ISGuid.New(),
                                       "${Sip}",
                                       "${EntityId}",
                                       "${SubType}");

            column.template = template;
        }
        else if (field.ViewType.toUpperCase() == 'POPUPIMAGE')
        {
            var departmentNumber = viewFields.Get('DepartmentNumber');
            var mail = viewFields.Get('Mail')
            if (!ISString.IsNullOrEmpty(departmentNumber) && !ISString.IsNullOrEmpty(mail))
            {
                var template = "<div onmouseover='PopupImage.Show(\""
                             + ISString.TrimEnd(iVxContext.MasterSiteAbsolutePath, "/")
                             + "/"
                             + PopupImage.MemberPhotoFolder
                             + "/"
                             + "\"+"
                             + "iSPUtility.EscapeForListUrl(\"${" + departmentNumber.InternalName + "}\")"
                             + "+\""
                             + "/"
                             + "${" + mail.InternalName + "}" + ".jpg"
                             + "\");'"
                             + " onmouseout='PopupImage.Hide();'>"
                             + "${" + field.InternalName + "}"
                             + "</div>";

                column.template = template;
            }
        }
        else if (field.ViewType.toUpperCase() == 'ProfileImage'.toUpperCase())
        {
        	// infragisticsのtd text-indent:2pxを考慮する
            var imageWidth = field.ViewFieldWidth - 2 + "px";
            if (GPContext.Configuration.GetSetting('ProfileImageAPI').toUpperCase() == 'SharePoint'.toUpperCase())
            {
                template = "<img src='" + GPContext.SiteUrl + "/_layouts/15/userphoto.aspx?size=S&accountname=${Mail}' height='" + imageWidth + "' />";
            }
            else if (GPContext.Configuration.GetSetting('ProfileImageAPI').toUpperCase() == 'Graph'.toUpperCase())
            {
                template = "<img id='profileImage_{0}' "
                         + "alt='ProfileImage' "
                         + "src='" + GPContext.SiteUrl + "/_layouts/15/images/personPlaceholder.96x96x32.png'"
                         + "entityId='{1}' "
                         + "onerror=\"this.src='" + GPContext.SiteUrl + "/_layouts/15/images/personPlaceholder.96x96x32.png" + "'\""
                         + "height='" + imageWidth + "' />";
                template = ISString.Format(template,
                                           "${EntityId}" + "_" + ISGuid.New(),
                                           "${EntityId}");
            }
            else
            {
                template = "<img src='" + GPContext.SiteUrl + "/_layouts/15/images/personPlaceholder.96x96x32.png' height='" + imageWidth + "' />";
            }
            column.template = template;
        }

        columns.push(column);
    }
    return columns;
};

GPGridUtility.ConvertToEmptyCharacterSupportTemplate = function (fieldInternalName, baseTemplate)
{
    // 空文字列を取得すると '[object Object]' と表示されるので分岐（Infragisticsのバグ?）
    var template = "{{if ${" + fieldInternalName + "}" + " == '[object Object]' }}"
                 + " "
                 + "{{else}}"
                 + baseTemplate
                 + "{{/if}}";           
    return template;
};

GPGridUtility.GetItems = function(dataSourceInfo, query, columns, callback)
{
    GPGridUtility.GetEntities(dataSourceInfo, query, function(entities)
    {
        var items = null;
        if (entities)
        {
            items = GPGridUtility.BuildGridItems(entities, columns);
        }
        
        callback(items);
    });
};

GPGridUtility.GetEntities = function(dataSourceInfo, query, callback)
{
    var targetUrl = dataSourceInfo.WebUrl;
    var list = dataSourceInfo.DataSourceList;
    iVxService.RetrieveItems(targetUrl, list, query, true, function(items)
    {
        callback(items);
    });
};

GPGridUtility.GetEntitiesParallel = function (dataSourceInfo, queries, callback)
{
    var targetUrl = dataSourceInfo.WebUrl;
    var list = dataSourceInfo.DataSourceList;
    iVxService.RetrieveItemsParallel(targetUrl, list, queries, true, function(items)
    {
        callback(items);
    });    
};

GPGridUtility.ImagePath = null;
GPGridUtility.GetGridItemImage = function(type)
{
    // ベースパスを設定
    if (ISString.IsNullOrEmpty(GPGridUtility.ImagePath))
    {
        GPGridUtility.ImagePath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
    }

    // 無効状態のエンティティのアイコンのURLを修正する為にフォーマットを持たせる
    var imagePath = GPGridUtility.ImagePath + type + '{0}' + '.png';

    return imagePath;
};

GPGridUtility.BuildGridItems = function(entities, columns)
{
    var items = new Array();
    for (var i = 0; i < entities.length; i++)
    {
        var entity = entities[i];
        var item = new Object();
        for (var j = 0; j < columns.length; j++)
        {
            var key = columns[j].key;
            var value = entity.Properties[key];
            if (key == "Type")
            {
                // 種別の場合はイメージのパスをExtendedProperties.TypeImagePathにキャッシュする
                // 無効なエンティティはimgのURL に-disableを付与
                var disableSuffix = entity.Valid === false ? "-disable" : "";

                var type = value;
                var subType = entity.Properties["SubType"] ? entity.Properties["SubType"]
                                                           : "";
                // 連絡先、備品、会議室（Type:User, SubType:Userではない）の場合にはサブタイプの画像を参照させる
                if (ISString.Equals(value, "User", true) &&
                    !ISString.Equals(subType, "User", true))
                {
                    type = entity.Properties["SubType"];
                }

                var imagePath = ISString.Format(GPGridUtility.GetGridItemImage(type), disableSuffix);
            }

            if (key == "SubType")
            {
                // SubTypeが空の場合は、プロファイルアイコンが表示できない為値を追加する
                if (ISString.IsNullOrEmpty(value))
                {
                    value = "UnKnown";
                }
            }
            item[key] = value;
        }

        // 非表示プロパティにEntityを保持させる（Selectionの際使用する）
        item["Entity"] = entity;

        // 非表示プロパティのExtendedPropertiesの初期化
        if (!item["ExtendedProperties"])
        {
            item["ExtendedProperties"] = {};
        }
        item["ExtendedProperties"].TypeImagePath = imagePath; 
        // プロファイルリンクに用いるユーザーの情報
        // オンプレミス: エスケープされたプリンシパル名
        // オンライン  : ObjectID or Mail(upn)
        item["ExtendedProperties"].ProfileLinkUserKey = escape(GPGridUtility.getProfileId(entity));

        items.push(item);
    }

    return items;
};

// Workaround: Delve接続の際に、メールアドレスでも動作するように暫定修正
// ToDo: プロファイルリンクに利用するフィールドを個別に用意すべき
GPGridUtility.getProfileId = function(entity)
{
    var profileId = ''
    if (GPContext.IsOnline)
    {
        var profileId = entity.Properties['EntityId'];
        if (iString.IsNullOrEmpty(profileId) ||
            !iString.Contains(profileId, '-') ||
            profileId.length != iGuid.New().length)
        {
            profileId = entity.Properties['Mail'];
        }
    }
    else
    {
        profileId = entity.Properties["SpPrincipalName"];
    }

    return profileId;
}

GPGridUtility.ProfOnclick = function(profileLinkUserKey)
{
    var baseUrl = "";
    var queryString = "";

    // オンライン（Delve）
    if (GPContext.IsOnline)
    {
        // Workaround: Delve接続の際に、メールアドレスでも動作するように暫定修正
        // ToDo: プロファイルリンクに利用するフィールドを個別に用意すべき
        if (iString.Contains(profileLinkUserKey, '@'))
        {
            // DelveページのURLの特定    
            // URLの例：https://tenantname-my.sharepoint.com/_layouts/15/me.aspx?p=someone@example.com
            baseUrl = ISString.TrimEnd(GPContext.Configuration.GetSetting('ProfileUrl'), '/');
            queryString = "?p=" + profileLinkUserKey;
        }
        else
        {
            // DelveページのURLの特定    
            // URLの例：https://tenantname-my.sharepoint.com/_layouts/15/me.aspx?u=76deaa6b-7adb-443c-bbaa-6761a6583258
            baseUrl = ISString.TrimEnd(GPContext.Configuration.GetSetting('ProfileUrl'), '/');
            queryString = "?u=" + profileLinkUserKey;
        }
    }
    // オンプレミス（ユーザープロファイルページ）
    else
    {
        // ProfleページのURLの特定    
        // URLの例：http://servername/my/Person.aspx?accountname=i%3A0%23%2Ew%7CdomainNetBiosName%5Caage%2Eting
        baseUrl = ISString.TrimEnd(GPContext.Configuration.GetSetting('ProfileUrl'), '/');
        queryString = "?accountname=" + profileLinkUserKey;
    }
    var url = baseUrl + queryString;
    
    // ProfilePageへ遷移
    var moveOption = GPContext.Configuration.GetSetting('ProfilePageMoveOption');
    if (moveOption.toUpperCase() == 'NAVIGATE')
    {
        window.location.href = url;
    }
    else if (moveOption.toUpperCase() == 'NEWWINDOW')
    {
        window.open(url);
    }

    // ToDo : ダイアログ遷移オプションの作成
    else if (moveOption.toUpperCase() == 'DIALOG')
    {

    }
};

GPGridUtility.DeleteHeaderBorder = function(headerId)
{
    var selector = "#" + headerId;

    var header = i$(selector);
    if (header.length < 1)
    {
        return;
    }

    header = header[0];
    var styleName = ISBrowser.GetDocumentVersion() == 8 ? "borderRight" : "border-right";
    header.style[styleName] = "none";
};

GPGridUtility.GetGridWidth = function (panel) {
    // 拡大率対応
    var ratio = 1;
    if (window.outerWidth < window.innerWidth) {
        ratio = Math.round((window.outerWidth / window.innerWidth) * 100) / 100;
    }
    // グリッドパネルの幅調整
    // -3/ratio : 拡大率によるborderサイズ(3px)の調整
    var width = ISNumber.Parse(ISString.TrimEnd(panel.Element.style.width, 'px'))
              - panel.Style.ContainerStyles[0].Size.Width
              - panel.Style.SeparatorSize
              - 3 / ratio;
    return width;
};

GPGridUtility.EnableDrag = function (evt) {
    evt.target.classList.value = evt.target.classList.value.replace('ui-iggrid-canceltextselection', '').replace('ui-iggrid-table', '');
};

GPGridUtility.AddGridElementClass = function (gridElementId, className) {
    var gridElement = i$("#" + gridElementId);
    if (gridElement.length < 1)
    {
        return;
    }
    gridElement[0].classList.add(className);
};                            
