// -----------------------------------------------------------------------
//  Finder
// -----------------------------------------------------------------------
Infoshare.GroupPicker.Finder = function Infoshare$GroupPicker$Finder() { }
GPFinder = Infoshare.GroupPicker.Finder;
GPFinder.TypeName = 'Infoshare.GroupPicker.Finder';

GPFinder.Instance = null;
GPFinder.InitialzeParameterKey = { OpenBy:      'OpenBy',
                                   FinderClass: 'FinderClass' };
GPFinder.OpenByType = { Window:      'Window',
                        InlineFrame: 'InlineFrame' };
GPFinder.prototype = {
    TypeName: GPFinder.TypeName,

    Info: null,
    Configuration: { Views:    null,
                     Selector: { SelectorClass:  null,
                                 ValidatorClass: null,
                                 ActionInfos:    null,
                                 Options:        null } },
    OpenBy: null,

    LayoutPanel: null,
    BodyPanel: null,
    ViewsTabPanel: null,

    Views: null,
    Header: null,
    HeaderActions: null,
    EnableViewHeader: false,
    Selector: null,

    EntitySyncMode: null,
    EntitySelection: null,
    ResolvedEntities: null,
    PageTitleResourceKey: "InfoCall.PhoneBook.Title",
    SearchViewClassName: "Infoshare.GroupPicker.SearchView",

    Render: function(parentElement, parentControl)
    {
        this.EnsureContext(ISFunction.CreateDelegate(function()
        {
            var stopwatch = new ISStopwatch();
            stopwatch.Start();
            ISTrace.TraceVerbose('[BEGIN] GPFinder.Render');
            
            // aspxページに場合には、タイトルを変更する
            if (this.OpenBy == GPFinder.OpenByType.Window)
            {
                document.title = iResxResource.GetString(this.PageTitleResourceKey);        
            }

            // ライセンス確認　aspxページの場合はライセンス確認を行う
            // ダイアログの場合はダイアログOpenメソッド内で確認済
            if (this.OpenBy == GPFinder.OpenByType.Window)
            {
                // ライセンス確認とメッセージの表示
                var message = (new iLicenseMessage()).BuildMessage(GPContext.Licenses);
                if ((new iLicenseValidator()).Validate(GPContext.Licenses, this.TypeName))
                {
                    // 利用可能な場合
                    if (!iString.IsNullOrEmpty(message))
                    {
                        //iSPNotify.Notify(messageText, null, null, (new iLicenseMessage()).MessageDisplayTime);
                        (new iNotifyer()).Notify(message, (new iLicenseMessage()).MessageDisplayTime);
                    }
                }
                else
                {
                    // 利用不可の場合
                    if (!iString.IsNullOrEmpty(message))
                    {
                        alert(message);
                    }
                    return;
                }
            }

            // モック用一時実装
            if (!this.Info &&
                !ISString.IsNullOrEmpty(this.TypeName) &&
                this.OpenBy == GPFinder.OpenByType.Window)
            {
                this.Info = GPContext.Configuration.Dialogs.Get(this.TypeName + 'Dialog');
            }

            // 構成情報の初期化            
            this.EnsureConfiguration();            
            this.EnsureViews();

            // レイアウトコントロールの初期化
            this.EnsureLayoutControls();
            this.LayoutPanel.Render(parentElement);
            if (parentControl)
            {
                // 親コントロール情報を追加（リサイズイベント通知の為）
                parentControl.AppendChildControl(this.LayoutPanel); 
            }

            //  選択コントロールの初期化
            this.EnsureSelector();
            if (this.Selector)
            {
                this.Selector.Render(this.BodyPanel.Containers[2]);
            }            

            // ヘッダーアクションのセパレータは非表示
            if (this.BodyPanel)
            {
                this.BodyPanel.Separators[0].Element.style.display = "none";
            }

            // ダイアログから開かれた場合には、Viewをレンダリングする
            // ページから開かれた場合には、Viewのレンダリングを後回しにする
            if (this.OpenBy != GPFinder.OpenByType.Window)
            {
                this.RenderViews();
            }           

            ISTrace.TraceVerbose('[END] GPFinder.Render (spent: ' + stopwatch.Stop() + ')');

        }, this));
    },

    RenderViews: function()
    {
        // GPViewContext情報の確認
        this.EnsureViewContextInfo();

        // ビューの初期化とイベント連携
        var defaultView = this.Views.Get(0);
        var activeTab = this.ViewsTabPanel.Tabs[0].Tab;
        for(var i = 0; i < this.Views.GetLength(); i++)
        {
            var view = this.Views.Get(i);
            view.SelectionChangedEventHandler = this.Selector ? ISFunction.CreateDelegate(this.Selector.OnViewSelectionChanged, this.Selector) : this.OnViewSelectionChanged ? ISFunction.CreateDelegate(this.OnViewSelectionChanged, this) : null;
            view.ItemSelectedEventHandler 　　= this.Selector ? ISFunction.CreateDelegate(this.Selector.OnViewItemSelected, this.Selector) : null;
            var tab = this.ViewsTabPanel.Tabs[i];
            tab.View = view;
            view.Render(tab.Container.GetElement(), tab.Container);

            // 既定Viewの設定
            // 複数設定されている場合は最後のDefaultViewを既定とする
            if (view.Info.Default)
            {
                defaultView = view;
                activeTab = this.ViewsTabPanel.Tabs[i].Tab;
            }
        }

        // 既定のViewを変更（URLパラメータ設定）
        if (!iString.IsNullOrEmpty(GPContext.DefaultViewId))
        {
            for (var i = 0; i < this.Views.GetLength() ; i++)
            {
                var view = this.Views.Get(i);
                if (iString.Equals(GPContext.DefaultViewId, view.Info.Id))
                {
                    defaultView = view;
                    activeTab = this.ViewsTabPanel.Tabs[i].Tab;

                    break;
                }
            }
        }

        // ヘッダーカスタムアクションの初期化
        this.RenderHeaderActionButton();

        // 電話帳Webパーツから開かれた場合
        var isSearchWebPart = !ISString.IsNullOrEmpty(GPContext.SearchKeyword);
        if (isSearchWebPart)
        {
            var keyword = GPContext.SearchKeyword;
            GPContext.SearchKeyword = null;
            var userFilterEnabled = GPContext.UserFilterEnabled;
            GPContext.UserFilterEnabled = null;
            var groupFilterEnabled = GPContext.GroupFilterEnabled;
            GPContext.GroupFilterEnabled = null;

            for (var i = 0; i < this.Views.GetLength(); i++)
            {
                var view = this.Views.Get(i);
                if (ISString.Equals(view.Info.Class.Name, this.SearchViewClassName))
                {
                    view.SearchTextBox.SetValue(keyword);
                    userFilterEnabled  ? view.UserFilter.CheckBox.Check()  : view.UserFilter.CheckBox.UnCheck();
                    groupFilterEnabled ? view.GroupFilter.CheckBox.Check() : view.GroupFilter.CheckBox.UnCheck();
                    defaultView = view;

                    activeTab = this.ViewsTabPanel.Tabs[i].Tab;
                    break;
                }
            }
        }
        
        // 既定のViewを設定
        if (this.Selector)
        {
            this.Selector.OnSelectedViewChanged(defaultView);
        }

        // 既定のViewのタブを開く
        this.ViewsTabPanel.ActivateTab(activeTab);

        // 電話帳Webパーツから開かれた場合は検索の実行
        if (isSearchWebPart)
        {
            defaultView.SearchTextBox.OnSearch();          
        }
    },

    EnsureConfiguration: function()
    {
        // ビュー情報を取得
        this.Configuration.Views = new Array();
        var viewsElement = iXml.SelectNodeByPath(this.Info.BodyClass.Configuration, 'Views');
        var viewElements = iXml.GetChildElementsByName(viewsElement, 'View');
        for (var i = 0; i < viewElements.length; i++)
        {
            var viewElement = viewElements[i];
            var viewInfo = new GPViewInfo(iXml.GetAttributeValue(viewElement, 'Id'),
                                          iXml.GetAttributeValue(viewElement, 'DisplayName'),
                                          iXml.GetAttributeValue(viewElement, 'DisplayNameResourceKey'),
                                          iXml.GetAttributeValue(viewElement, 'Default'));
            viewInfo.ViewXml = viewElement;

            this.Configuration.Views.push(viewInfo);
        }

        // セレクタ情報を取得
        var selectorElement = iXml.GetElementByTagName(this.Info.BodyClass.Configuration, 'SelectorClass');
        if (selectorElement)
        {
            var selectorClassInfo = iClass.CreateFromXml(selectorElement);
            this.Configuration.Selector.SelectorClass = selectorClassInfo;
            this.EnableEntitySelector = true;
        }

        // バリデータ情報を取得
        var validatorElement = iXml.GetElementByTagName(this.Info.BodyClass.Configuration, 'ValidatorClass');
        if (validatorElement)
        {
            var validatorClassInfo = iClass.CreateFromXml(validatorElement);
            this.Configuration.Selector.ValidatorClass = validatorClassInfo;
        }

        // カスタムアクション情報を取得
        this.Configuration.Selector.ActionInfos = new Array();
        var actionsElement = iXml.SelectNodeByPath(this.Info.BodyClass.Configuration, 'Selector/Actions');
        if (actionsElement)
        {
            var actionElements = iXml.GetChildElementsByName(actionsElement, 'Action');
            for (var i = 0; i < actionElements.length; i++)
            {
                var actionElement = actionElements[i];
                var actionInfo = GPActionInfo.Parse(actionElement);

                this.Configuration.Selector.ActionInfos.push(actionInfo);
            }
        }

        // ヘッダーカスタムアクション情報を取得
        this.Configuration.Header = {};
        this.Configuration.Header.ActionInfos = new Array();
        var headerActionsElement = iXml.SelectNodeByPath(this.Info.BodyClass.Configuration, 'DialogHeaderActions');
        if (headerActionsElement)
        {
            var headerActionElements = iXml.GetChildElementsByName(headerActionsElement, 'DialogHeaderAction');
            for (var i = 0; i < headerActionElements.length; i++)
            {
                var headerActionElement = headerActionElements[i];
                var actionInfo = GPActionInfo.Parse(headerActionElement);

                this.Configuration.Header.ActionInfos.push(actionInfo);
            }
        }

        // オプション情報
        var options = new ISDictionary();
        var optionsElement = iXml.SelectNodeByPath(this.Info.BodyClass.Configuration, 'Selector/Options');
        if (optionsElement)
        {
            var optionElements = iXml.GetChildElementsByName(optionsElement, 'Option');
            if (optionElements)
            {
                for (var i = 0; i < optionElements.length; i++)
                {
                    var optionElement = optionElements[i];
                    options.Add(iXml.GetAttributeValue(optionElement, 'Key'),
                                iXml.GetAttributeValue(optionElement, 'Value'));
                }
            }
        }
        this.Configuration.Selector.Options = options;
    },

    EnsureViews: function()
    {
        // ビューの初期化
        var defaultView = null;
        this.Views = new ISDictionary();
        for (var i = 0; i < this.Configuration.Views.length; i++)
        {
            var viewRef = this.Configuration.Views[i];
            var viewInfo = GPContext.Configuration.Views.Get(viewRef.Id);
            viewInfo.Default                = ISString.IsNullOrEmpty(viewRef.Default)                ? viewInfo.Default                : ISBoolean.Parse(viewRef.Default);
            viewInfo.DisplayName            = ISString.IsNullOrEmpty(viewRef.DisplayName)            ? viewInfo.DisplayName            : viewRef.DisplayName;
            viewInfo.DisplayNameResourceKey = ISString.IsNullOrEmpty(viewRef.DisplayNameResourceKey) ? viewInfo.DisplayNameResourceKey : viewRef.DisplayNameResourceKey;
            if (ISString.IsNullOrEmpty(viewInfo.DisplayName))
            {
                viewInfo.DisplayName = iResxResource.GetString(viewInfo.DisplayNameResourceKey);
            }

            // ライセンスされたViewのみ初期化対象とする
            if (!(new iLicenseValidator()).Validate(GPContext.Licenses, viewInfo.Class))
            {
                ISTrace.TraceWarning('GPFinder.EnsureViews: Skipped initialize the view class (' + viewInfo.Class.Name + '), since it is not licensed.');
                continue;
            }

            // ビュー初期化
            var view = iClass.New(viewInfo.Class);
            view.Info = viewInfo;
            this.Views.Add(viewInfo.Id, view);
        }
    },

    EnsureViewContextInfo: function()
    {
        // ビューの初期化
        var defaultView = this.Views.Get(0);
        for (var i = 0; i < this.Views.GetLength(); i++)
        {
            var view = this.Views.Get(i);
            var viewInfo = view.Info;
            // データソース設定：View毎の設定されたデータソースを取得する（未設定の場合はデフォルトのデータソースを使用する）
            var viewDataSource = null;
            for (var j = 0; j < GPViewContext.DataSources.GetLength(); j++)
            {
                var dataSource = GPViewContext.DataSources.Get(j);
                if (dataSource.IsDefault)
                {                    
                    viewDataSource = dataSource;
                    break;
                }
            }
            var options = viewInfo.Options;
            if (options &&
                options.GetLength() > 0)
            {
                var siteUrl = options.Get("DataSourceSiteUrl");
                var baseListName = options.Get("DataSourceListBaseName");
                if (!ISString.IsNullOrEmpty(siteUrl) &&
                    !ISString.IsNullOrEmpty(baseListName))
                {
                    var key = ISString.TrimEnd(siteUrl, '/')
                            + '/'
                            + baseListName;
                    if (GPViewContext.DataSources.Contains(key))
                    {
                        viewDataSource = GPViewContext.DataSources.Get(key);
                    }               
                }
            }
            view.DataSource = viewDataSource;


            // 既定Viewの設定
            // 一つも設定されていない場合は、最初のviewを既定とする
            // 複数設定されている場合は最後のDefaultViewを既定とする
            if (view.Info.Default)
            {
                defaultView = view;
            }
        }

        // 既定Viewの設定
        this.DefaultView = defaultView;
    },

    EnsureLayoutControls: function()
    {
        // 単体ページでのみ、ヘッダー領域の拡張を行う
        // デフォルト値
        var saparatorSize = 1;
        var headPanelStyle = new iPanelStyle();
        var headHeight = 0;
        if (this.OpenBy == GPFinder.OpenByType.Window)
        {
            saparatorSize = 0;
            headPanelStyle = new GPHeadPanelStyle();
            headHeight = 50;
        }


        // ---------------------------------------------------------------
        //  レイアウト用 分割パネル: ヘッダ、ボディ、フッタ
        // ---------------------------------------------------------------
        // 分割パネル
        var layoutPanel = new iSplitPanel();
        layoutPanel.Style.SeparatorSize = saparatorSize;
        layoutPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
        layoutPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;

        // 分割パネル: ヘッダ、ボディ、フッタの3分割
        layoutPanel.Style.ContainerStyles = [headPanelStyle, new iPanelStyle(), new iPanelStyle()];
        layoutPanel.Style.ContainerStyles[0].Size.Height = headHeight;
        layoutPanel.Style.ContainerStyles[2].Size.Height = 0;

        // ---------------------------------------------------------------
        //  ヘッダ用パネル：製品ロゴ、企業ロゴ
        // ---------------------------------------------------------------                
        if (this.OpenBy == GPFinder.OpenByType.Window)
        {
        var productImgPanelStyle = new GPHeadPanelProductImgStyle();
        var productImgPanel = new iPanel(productImgPanelStyle);
            productImgPanel.Style.Size.Height = headHeight;

        var companyImgPanelStyle = new GPHeadPanelCompanyImgStyle();
        var companyImgPanel = new iPanel(companyImgPanelStyle);
            companyImgPanel.Style.Size.Height = headHeight;

        layoutPanel.AppendChildControlForContainer(0, productImgPanel);
        layoutPanel.AppendChildControlForContainer(0, companyImgPanel);
        }

        // ---------------------------------------------------------------
        //  ボディ用 分割パネル: ヘッダーアクション、ビュー、セレクタ
        // ---------------------------------------------------------------
        // 分割パネル
        var bodyPanel = new iSplitPanel();
        bodyPanel.Style.SeparatorSize = 1;
        bodyPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
        bodyPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;

        // 分割パネル: ヘッダーアクション、ビュー、セレクタの2分割
        bodyPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle(), new iPanelStyle()];
        bodyPanel.Style.ContainerStyles[0].Size.Height = this.EnableViewHeader     ? 40 : 0;
        bodyPanel.Style.ContainerStyles[2].Size.Height = this.EnableEntitySelector ? 80 : 0;
        
        if (this.Configuration.Selector.ActionInfos.length > 0)
        {
            bodyPanel.Style.ContainerStyles[2].Size.Height = this.EnableEntitySelector ? 125 : 0;
        }

        // レイアウトのボディ部分にタブパネルを追加
        layoutPanel.AppendChildControlForContainer(1, bodyPanel);
        this.LayoutPanel = layoutPanel;
            
        // ---------------------------------------------------------------
        //  ボディ用 タブパネル: ビュー
        // ---------------------------------------------------------------
        // タブパネル
        var tabPanel = new iTabPanel();
        tabPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
        tabPanel.AddEvent(iTabPanel.EventName.SelectedTabChanged, ISFunction.CreateDelegate(this.OnSelectedTabChanged, this));
            
        // タブの初期化
        for(var i = 0; i < this.Views.GetLength(); i++)
        {
            var view = this.Views.Get(i);
            var tabInfo = new iTabInfo(null, view.Info.DisplayName)
            tabPanel.Tabs.push(tabInfo);
        }

        // ビュー部分にタブパネルを追加
        bodyPanel.AppendChildControlForContainer(1, tabPanel);
        
        this.BodyPanel = bodyPanel;
        this.ViewsTabPanel = tabPanel;
    },

    EnsureSelector: function()
    {
        if (!this.Configuration.Selector ||
            !this.Configuration.Selector.SelectorClass)
        {
            return;
        }

        //  選択コントロールを追加
        var selector = iClass.New(this.Configuration.Selector.SelectorClass);
        selector.EntitySyncMode   = this.EntitySyncMode ? this.EntitySyncMode : this.Configuration.Selector.Options.Get('SyncMode');
        selector.ResolvedEntities = this.ResolvedEntities;

        var validator = this.Configuration.Selector.ValidatorClass;
        selector.EntitySelection  = !ISString.IsNullOrEmpty(validator) ? this.EntitySelection : new iUserFieldEntitySelection();
        selector.EntitySelectionValidatorClassName = !ISString.IsNullOrEmpty(validator) ? validator.Name : null;

        if (this.Configuration.Selector.ActionInfos.length > 0)
        {
            selector.Actions = new Array();

            for (var i = 0; i < this.Configuration.Selector.ActionInfos.length; i++)
            {
                var actionInfo = this.Configuration.Selector.ActionInfos[i];

                // ライセンスされた Action クラスのみ初期化対象とする
                if (!(new iLicenseValidator()).Validate(GPContext.Licenses, actionInfo.Class))
                {
                    ISTrace.TraceWarning('GPFinder.EnsureSelector: Skipped initialize the action class (' + actionInfo.Class.Name + '), since it is not licensed.');
                    continue;
                }

                // アクション初期化
                var action = iClass.New(actionInfo.Class.Name);
                action.ActionInfo = actionInfo;
                selector.Actions.push(action);
            }
        }

        this.Selector = selector;
    },

    EnsureContext: function(callback)
    {
        // IE8Picker：Picker.aspxを読み込む場合には、
        // CoreCSSおよび拡張ファイルを読み込む
        if (ISBrowser.GetDocumentVersion() == 8 &&
            iSPListFormExtender.IsTargetForm("Picker.aspx"))
        {
            var baseCallback = callback;
            callback = function ()
            {
                // ファイルのロード
                GPFileLoader.BaseFileLoaded = false;
                GPFileLoader.LoadCoreCss = true;
                GPFileLoader.Load(baseCallback, false);
            };            
        }

        this.EnsureContextInternal(callback);
    },

    EnsureContextInternal: function(callback)
    {
        // コンテキストが初期化済みの場合は再初期化しない
        var cloner = new GPContextCloner(window.parent);
        if (cloner.contextInitialized())
        {
            callback();
            return;
        }

        // iframeで開かれた場合を想定: コンテキストを親から取得しつつ必要なファイルを読み込む
        if (cloner.parentContextInitialized())
        {
            cloner.CloneFromParent(callback);
        }
        else // ページ単体で開かれた場合を想定: コンテキストを初期化する
        {
            this.OpenBy = GPFinder.OpenByType.Window;
            GPFileLoader.LoadCoreCss = true;

            var finder = this;            
            cloner.initializeContext(GPContext, function ()
            {
                // ページから開かれた場合には、フレームを先にレンダリングし、ViewContextの初期化後にViewをレンダリングする
                callback();

                // スクリーンブロッカー設定
                var requestInvoking = true;
                var isScreenBlockerShown = false;
                var screenBllockerDisplayInterval = GPContext.Configuration.GetSetting('ScreenBlockDisplayInterval');
                                
                cloner.initializeContext(GPViewContext, function ()
                {
                    requestInvoking = false;
                    if (isScreenBlockerShown)
                    {
                        iScreenBlockerUtility.Hide();
                    }

                    finder.RenderViews();
                });

                // 指定秒数以内にリクエストが返ってこない場合は画面をブロックする
                setTimeout(function()
                {
                    if (requestInvoking)
                    {
                        iScreenBlockerUtility.Show();
                        isScreenBlockerShown = true;
                    }
                }, screenBllockerDisplayInterval);
            });
        }
    },    

    OnSelectedTabChanged: function (control)
    {
        var tab = control.SelectedTab;
        var activeView = tab.View;        
        
        // スタイル調整
        activeView.ParentPanel.OnResize();

        // 初回表示関数の実行
        if (activeView &&
            typeof activeView.InitializeView == 'function' &&
            !activeView.Initialized)
        {
            activeView.InitializeView();
        }


        // エンティティセレクタにTabChangedイベントの通知
        if (this.Selector)
        {
            this.Selector.OnSelectedViewChanged(activeView);
        }

        // ヘッダーアクションにTabChangedイベントの通知
        if (this.HeaderActions)
        {
            for (var i = 0; i < this.HeaderActions.length; i++)
            {
                var action = this.HeaderActions[i];
                action.OnSelectedTabChanged(activeView);
            }
        }
    },

    // 旧実装（TICOの際に実装したタブ上のカスタムのボタンを表示する際に使用しています）
    // タブ行に表示するか、タブ行の上のに表示するかは分離できていた方がよいですが、クラスによって分離させます
    // そもそもこのカスタムのボタンは構成ファイルで定義できる必要性が低いので、組織管理アドインではハードコードさせています
    RenderHeaderActionButton: function()
    {
        var buttonDiv = document.createElement("div");
        var tabPanel = this.ViewsTabPanel.Header.GetElement();
        tabPanel.appendChild(buttonDiv);

        // カスタムアクションボタン
        if (this.Configuration.Header.ActionInfos != null &&
            this.Configuration.Header.ActionInfos.length > 0)
        {
            var headerActions = [];
            // Actionボタンを作成する
            for (var i = 0; i < this.Configuration.Header.ActionInfos.length; i++)
            {
                // Actionクラスをnewする
                var action = null;
                var actionInfo = this.Configuration.Header.ActionInfos[i];

                // ライセンスされた Action クラスのみ初期化対象とする
                if (!(new iLicenseValidator()).Validate(GPContext.Licenses, actionInfo.Class))
                {
                    ISTrace.TraceWarning('GPFinder.RenderHeaderActionButton: Skipped initialize the action class (' + actionInfo.Class.Name + '), since it is not licensed.');
                    continue;
                }

                // アクション初期化
                try
                {
                    action = iClass.New(actionInfo.Class);
                }
                catch(e)
                {
                    var errorMessageFormat = "[RenderHeaderActionButton] {0} is not defined";
                    var errorMessage = iString.Format(errorMessageFormat, actionInfo.Class.Name);
                    ISTrace.TraceWarning(errorMessage)
                }

                if (action)
                {
                    action.ActionInfo = actionInfo;
                    action.View = this;
                    headerActions.push(action);
                    var actionButton = action.CreateButton();
                    actionButton.Render(buttonDiv);
                }
            }

            this.HeaderActions = headerActions;
        }      
    }
}


// -----------------------------------------------------------------------
//  OutlookAddinFinder
// -----------------------------------------------------------------------
Infoshare.GroupPicker.OutlookAddinFinder = function Infoshare$GroupPicker$OutlookAddinFinder() { }
GPOutlookAddinFinder = Infoshare.GroupPicker.OutlookAddinFinder;
GPOutlookAddinFinder.OnClose = function()
{
    if (GPContext.GPOutlookExtension.Platform == GPContext.GPOutlookExtension.PlatformType.Outlook)
    {
        if (GPContext.GPOutlookExtension.IsVstoAddin)
        {
            
            window.external.Close();
        }
        else
        {
            // Office.jsのクローズイベントを実行
            // 空のEntityを返すようにする
            Office.context.ui.messageParent("");
        }
    }
    else
    {
        // 親ウィンドウのクローズイベントをコールする
        if (window.opener &&
            window.opener.GPOutlookExtension)
        {
            window.opener.GPOutlookExtension.Close();
        }
    }
};
GPOutlookAddinFinder.prototype = new GPFinder();

GPOutlookAddinFinder.prototype.Render = function(parentElement)
{
    this.EnsureContext(ISFunction.CreateDelegate(function()
    {
        var stopwatch = new ISStopwatch();
        stopwatch.Start();
        ISTrace.TraceVerbose('[BEGIN] GPOutlookAddinFinder.Render');

        // OWAの場合にはタイトルを変更する（OutlookはOfficeダイアログの実装でタイトルが付く）
        if (GPContext.GPOutlookExtension.Platform == GPContext.GPOutlookExtension.PlatformType.OWA)
        {
            document.title = iResxResource.GetString("InfoCall.PhoneBook.Title");        
        }

        // ライセンス確認　aspxページの場合はライセンス確認を行う
        // ダイアログの場合はダイアログOpenメソッド内で確認済

        // ライセンス確認とメッセージの表示
        var license = GPContext.InfoCallLicense;

        // 製品ライセンスの整合性を取るため、所属検索ライセンスのみでの利用を停止（InfoCallとの組み合わせでのみ動作）
        // ToDo(skomatsu): 所属検索ライセンスのみで運用している組織向けの対応が必要。
        //if (license == null)
        //{
        //    // ADViewerからの製品販売の流れで
        //    // 所属検索ライセンスのみの場合でも利用可能とする
        //    // ただし、ADViewerの利用者以外には販売しない（営業対応）
        //    license = GPContext.MemberSearchLicense;
        //}

        var message = (new iLicenseMessage()).BuildMessage(license);
        if (license && license.Valid)
        {
            // 利用可能な場合
            if (!iString.IsNullOrEmpty(message))
            {
                //iSPNotify.Notify(messageText, null, null, 5000);
                (new iNotifyer()).Notify(message, (new iLicenseMessage()).MessageDisplayTime);
            }
        }
        else
        {
            // 利用不可の場合
            if (!iString.IsNullOrEmpty(message))
            {
                alert(message);
            }
            return;
        }

        // モック用一時実装
        this.Info = GPContext.Configuration.Dialogs.Get('Infoshare.GroupPicker.OutlookAddinDialog');

        // 構成情報の初期化            
        this.EnsureConfiguration();            
        this.EnsureViews();

        // レイアウトコントロールの初期化
        this.EnsureLayoutControls();
        this.LayoutPanel.Render(parentElement);

        //  選択コントロールの初期化
        this.EnsureSelector();
        this.Selector.Render(this.BodyPanel.Containers[1]);

        ISTrace.TraceVerbose('[END] GPOutlookAddinFinder.Render (spent: ' + stopwatch.Stop() + ')');

    }, this));
};

GPOutlookAddinFinder.prototype.RenderViews = function()
{
    // GPViewContext情報の確認
    this.EnsureViewContextInfo();

    // ビューの初期化とイベント連携
    var defaultView = this.Views.Get(0);
    var activeTab = this.ViewsTabPanel.Tabs[0].Tab;
    for(var i = 0; i < this.Views.GetLength(); i++)
    {
        var view = this.Views.Get(i);
        view.SelectionChangedEventHandler = this.Selector ? ISFunction.CreateDelegate(this.Selector.OnViewSelectionChanged, this.Selector) : null;
        view.ItemSelectedEventHandler 　　= this.Selector ? ISFunction.CreateDelegate(this.Selector.OnViewItemSelected, this.Selector) : null;
        var tab = this.ViewsTabPanel.Tabs[i];
        tab.View = view;
        view.Render(tab.Container.GetElement(), tab.Container);

        // 既定Viewの設定
        // 複数設定されている場合は最後のDefaultViewを既定とする
        if (view.Info.Default)
        {
            defaultView = view;
            activeTab = this.ViewsTabPanel.Tabs[i].Tab;
        }
    }

    // ヘッダーカスタムアクションの初期化
    this.RenderHeaderActionButton();

    // 既定のViewを設定
    if (this.Selector)
    {
        this.Selector.OnSelectedViewChanged(defaultView);
    }

    // 既定のViewのタブを開く
    this.ViewsTabPanel.ActivateTab(activeTab);
};

GPOutlookAddinFinder.prototype.EnsureLayoutControls = function()
{
    // ヘッダは表示しない
    var saparatorSize = 0;
    var headPanelStyle = new iPanelStyle();
    var headHeight = 0;

    // ---------------------------------------------------------------
    //  レイアウト用 分割パネル: ヘッダ、ボディ、フッタ
    // ---------------------------------------------------------------
    // 分割パネル
    var layoutPanel = new iSplitPanel();
    layoutPanel.Style.SeparatorSize = saparatorSize;
    layoutPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
    layoutPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;

    // 分割パネル: ヘッダ、ボディ、フッタの3分割
    layoutPanel.Style.ContainerStyles = [headPanelStyle, new iPanelStyle(), new iPanelStyle()];
    layoutPanel.Style.ContainerStyles[0].Size.Height = headHeight;
    layoutPanel.Style.ContainerStyles[2].Size.Height = 0;

    // ---------------------------------------------------------------
    //  ボディ用 分割パネル: ビュー、セレクタ
    // ---------------------------------------------------------------
    // 分割パネル
    var bodyPanel = new iSplitPanel();
    bodyPanel.Style.SeparatorSize = 1;
    bodyPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
    bodyPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;

    // 分割パネル: ビュー、セレクタの2分割
    bodyPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
    bodyPanel.Style.ContainerStyles[1].Size.Height = this.EnableEntitySelector ? 80 : 0;
    bodyPanel.Style.ContainerStyles[1].Size.Height = this.EnableEntitySelector ? 125 : 0;

    // レイアウトのボディ部分にタブパネルを追加
    layoutPanel.AppendChildControlForContainer(1, bodyPanel);
    this.LayoutPanel = layoutPanel;

    // ---------------------------------------------------------------
    //  ボディ用 タブパネル: ビュー
    // ---------------------------------------------------------------
    // タブパネル
    var tabPanel = new iTabPanel();
    tabPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
    tabPanel.AddEvent(iTabPanel.EventName.SelectedTabChanged, ISFunction.CreateDelegate(this.OnSelectedTabChanged, this));
            
    // タブの初期化
    for(var i = 0; i < this.Views.GetLength(); i++)
    {
        var view = this.Views.Get(i);
        var tabInfo = new iTabInfo(null, view.Info.DisplayName)
        tabPanel.Tabs.push(tabInfo);
    }

    // ビュー部分にタブパネルを追加
    bodyPanel.AppendChildControlForContainer(0, tabPanel);
    this.BodyPanel = bodyPanel;
    this.ViewsTabPanel = tabPanel;
};

GPOutlookAddinFinder.prototype.EnsureSelector = function()
{
    if (!this.Configuration.Selector ||
        !this.Configuration.Selector.SelectorClass)
    {
        return;
    }

    //  選択コントロールを追加
    var selector = iClass.New(this.Configuration.Selector.SelectorClass);

    var validator = this.Configuration.Selector.ValidatorClass;
    selector.EntitySelection  = !ISString.IsNullOrEmpty(validator) ? this.EntitySelection : new iUserFieldEntitySelection();
    selector.EntitySelectionValidatorClassName = !ISString.IsNullOrEmpty(validator) ? validator.Name : null;

    // アクション
    selector.Actions = new Array();
    var action = null;        
    // Mailフォーム
    if (GPContext.GPOutlookExtension.Application == GPContext.GPOutlookExtension.ApplicationType.Mail)
    {
        action = new Infoshare.GroupPicker.OutlookAddinMailAction();
    }
    // 予定表フォーム
    else  if (GPContext.GPOutlookExtension.Application == GPContext.GPOutlookExtension.ApplicationType.Appointment)
    {
        action = new Infoshare.GroupPicker.OutlookAddinScheduleAction();
    }
    if (action)
    {
        // キャンセルアクションを追加
        var cancelAction = new Infoshare.GroupPicker.CancelAction();
        cancelAction.Action = GPOutlookAddinFinder.OnClose;
        selector.Actions.push(cancelAction);

        // アクションを追加
        selector.Actions.push(action);
    }

    // アクション用のラベルを非表示にする
    selector.ShowActionLabel = false;
    this.Selector = selector;
};

