// -----------------------------------------------------------------------
//  EntitySelector
// -----------------------------------------------------------------------
Infoshare.GroupPicker.EntitySelector = function InfoInfoshare$GroupPicker$EntitySelector()
{
    this.Tags = new ISDictionary();

    if (this.Events == null)
    {
        this.Events = new iEvent();
    }
}
GPEntitySelector = Infoshare.GroupPicker.EntitySelector;
GPEntitySelector.SyncMode = { None:     'None',
                              Partial:  'Partial',
                              Complete: 'Complete' }
GPEntitySelector.prototype = {
    SelectButton: null,
    RemoveButton: null,
    CandidateContainer: null,
    DisableTagItemDeleteButton: false,

    EntitySyncMode: GPEntitySelector.SyncMode.None,
    EntitySelection: null,
    EntitySelectionValidator: null,
    EntitySelectionValidatorClassName: null,

    Events: null,

    Actions: null,
    ShowActionLabel: true,

    Render: function(parentControl)
    {
        var parentElement = parentControl.GetElement();

        // モック用一時実装
        var layoutPanel = new iSplitPanel();
        layoutPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
        layoutPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
        layoutPanel.Style.ContainerStyles = [new iPanelStyle(), new GPActionButtonPanelStyle()];
        layoutPanel.Style.ContainerStyles[0].Size.Height = 80;

        // 分割パネルを挿入
        var splitPanel = new iSplitPanel();
        splitPanel.Style.Mode = iSplitPanelStyle.Mode.Vertical;
        splitPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
        splitPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
        splitPanel.Style.ContainerStyles[0].Size.Width = 80;
        if (this.Actions != null &&
            this.Actions.length > 0)
        {
            layoutPanel.AppendChildControlForContainer(0, splitPanel);
        }

        // 選択ボタン
        var selectButton = new iButton(new iEntitySelectorButtonStyle());
        selectButton.Title = iResxResource.GetString('PickerDialog.EntitySelector.SelectButton.Title');
        selectButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.AddCandidate, this));
        selectButton.Disabled = true;
        splitPanel.AppendChildControlForContainer(0, selectButton);
        this.SelectButton = selectButton;

        // 削除ボタン
        var removeButton = new iButton(new iEntitySelectorButtonStyle());
        removeButton.Title = iResxResource.GetString('PickerDialog.EntitySelector.DeleteButton.Title');
        removeButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.RemoveCandidate, this));
        removeButton.Disabled = true;
        splitPanel.AppendChildControlForContainer(0, removeButton);
        this.RemoveButton = removeButton;

        // 選択コントロール
        this.CandidateContainer = new iTagHolder(new iEntitySelectorCandidateContainerStyle());
        this.CandidateContainer.Style.StretchOption = iPanelStyle.StretchOption.Both;
        
        // 選択コントロール: イメージボタン設定
        var imagesPath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
        this.CandidateContainer.Style.ItemCloseButtonStyle = new iImageButtonStyle(new iButtonImageInfo(imagesPath + 'x.png',
                                                                                                        '',
                                                                                                        '',
                                                                                                        imagesPath + 'x-Press.png',
                                                                                                        imagesPath + 'x-Hover.png'));

        // 選択コントロール: イベント
        this.CandidateContainer.AddEvent(iTagHolder.EventName.SelectionChanged, ISFunction.CreateDelegate(this.OnTagHolderSelectionChanged, this));
        this.CandidateContainer.AddEvent(iTagHolder.EventName.TagChanged, ISFunction.CreateDelegate(this.OnTagChanged, this));
        splitPanel.AppendChildControlForContainer(1, this.CandidateContainer);

        // カスタムアクションボタン
        if (this.Actions != null &&
            this.Actions.length > 0)
        {
            // Actionボタンを作成する
            for (var i = 0; i < this.Actions.length; i++)
            {
                var action = this.Actions[i];
                action.EntitiesForAction = this.GetSelectedEntities();
                var actionButton = action.CreateButton();

                // ボタンをDisableにする（CancelアクションはEnable）
                var enable = action.ActionButtonInfo.Enable ? true : false; 
                actionButton.Enabled = enable;

                layoutPanel.AppendChildControlForContainer(1, actionButton);

                // エンティティセレクター： イベント（タグが変化した場合にボタンの有効・無効状態を変化させる）
                this.Events.AddEvent(iTagHolder.EventName.TagChanged, ISFunction.CreateDelegate(action.OnEntitiesSelectionChanged, action));
            }

            // アクション用のラベル（Outlookアドインからは表示しないようにする）
            if (this.ShowActionLabel)
            {
            // アクションボタンパネルにラベルを作成する
            var labelStyle = new GPActionButtonPanelLabelStyle();
            var actionButtonPanelLabel = new iLabel(labelStyle);
            var message = iResxResource.GetString('PickerDialog.ActionButtonPanelLabel');
            actionButtonPanelLabel.Text = message;
            layoutPanel.AppendChildControlForContainer(1, actionButtonPanelLabel);
        }
        }

        // 分割パネル: レンダリング
        if (this.Actions != null &&
            this.Actions.length > 0)
        {
            layoutPanel.Render(parentElement);

            // 親コントロール情報を追加
            parentControl.AppendChildControl(layoutPanel); 
        }
        else
        {
            splitPanel.Render(parentElement);

            // 親コントロール情報を追加
            parentControl.AppendChildControl(splitPanel); 
        }

        // 初期描画時にボタンを無効可する
        this.SelectButton.Disable();
        this.RemoveButton.Disable();

        this.SyncEntities();
    },

    SyncEntities: function()
    {
        if (!this.EntitySyncMode ||
            this.EntitySyncMode == GPEntitySelector.SyncMode.None ||
            !this.ResolvedEntities ||
            this.ResolvedEntities.length <= 0)
        {
            return;
        }

        if (this.EntitySyncMode == GPEntitySelector.SyncMode.Partial)
        {
            //部分同期の場合表示名の参照を行わずにCandidateContainerに追加する
            this.AddCandidateInternal(this.ResolvedEntities);
        }
        else if (this.EntitySyncMode == GPEntitySelector.SyncMode.Complete)
        {
            // 完全同期の場合表示名の参照を行った後にCandidateContainerに追加する
            var selector = this;
            this.RetrieveResolvedEntities(this.ResolvedEntities, function(entities)
            {
                // PickerEntitiesから取得できたEntityを更新する
                for (var i = 0; i < selector.ResolvedEntities.length; i++)
                {
                    var resolvedEntity = selector.ResolvedEntities[i];
                    for (var j = 0; j < entities.length; j++)
                    {
                        if (ISString.Equals(resolvedEntity.Properties.SpPrincipalName, entities[j].Properties["SpResolveKey"], true))
                        {
                            selector.ResolvedEntities[i] = entities[j];
                            break;
                        }
                    }
                }

                selector.AddCandidateInternal(selector.ResolvedEntities);
            }); 
        }
    },

    CurrentView: null,
    OnSelectedViewChanged: function(view)
    {
        this.CurrentView = view;
        this.OnViewSelectionChanged();
    },

    OnViewSelectionChanged: function()
    {
        var entities = this.CurrentView.GetSelectedItems();
        if (entities && entities.length > 0)
        {
            this.SelectButton.Enable();
        }
        else
        {
            this.SelectButton.Disable();
        }
    },

    OnViewItemSelected: function()
    {
        this.AddCandidate();
    },

    OnTagHolderSelectionChanged: function()
    {
        var tags = this.CandidateContainer.GetSelectedTags();
        if (tags && tags.length > 0)
        {
            this.RemoveButton.Enable();
        }
        else
        {
            this.RemoveButton.Disable();
        }
    },

    GetSelectedEntities: function()
    {
        var entities = new Array();
        for (var i = 0; i < this.CandidateContainer.Controls.GetLength() ; i++)
        {
            var tag = this.CandidateContainer.Controls.Get(i);
            if (!tag || !tag.Entity)
            {
                continue;
            }

            entities.push(tag.Entity);
        }

        return entities;
    },

    GetSelectedItemsWithViewInfo: function()
    {
        // 選択されたViewの情報と、アイテム一覧を持つオブジェクトの作成
        var selectedItemsInfo = {
            Items: null,
            ViewInfo: null,
            View: null
        };

        // 選択情報の取得
        selectedItemsInfo.Items = this.CurrentView.GetSelectedItems();
        selectedItemsInfo.ViewInfo = this.CurrentView.Info;
        selectedItemsInfo.View = this.CurrentView;

        return selectedItemsInfo;
    },

    AddCandidate: function()
    {
        // 選択項目を取得
        var items = this.CurrentView.GetSelectedItems();
        if (!items && items.length <= 0)
        {
            return;
        }

        // 検証（inValidなEntityが含まれる場合、追加しない）
        var valid = this.ValidateEntities(items);
        if (!valid)
        {
            return;
        }

        this.AddCandidateInternal(items);
    },

    AddCandidateInternal: function(items)
    {
        var tags = new Array();
        for (var i = 0; i < items.length; i++)
        {
            var item = items[i];

            // 重複確認: 重複して選択されたものは追加しない
            if (this.ContainsEntity(item))
            {
                continue;
            }

            // タグを生成
            var tag = new iTagItem();
            tag.Title = item.Properties.EntityDisplayName;
            tag.DisableDeleteButton = this.DisableTagItemDeleteButton;

            // アイコン画像
            var imageType = item.Properties.Type;

            // 連絡先、備品、会議室（Type:User, SubType:Userではない）の場合にはサブタイプの画像を参照させる
            if (ISString.Equals(imageType, "User", true) &&
                !ISString.Equals(item.Properties["SubType"], "User", true))
            {
                imageType = item.Properties["SubType"];
            }
            
            tag.TitleImage = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/' + imageType + '.png';
            tag.Entity = item;
            tags.push(tag);
        }

        this.CandidateContainer.AddTag(tags);
    },

    ValidateEntities: function(entities)
    {
        if (!this.EntitySelectionValidator)
        {
            var className = this.EntitySelectionValidatorClassName;
            if (ISString.IsNullOrEmpty(className))
            {
                className = 'Infoshare.GroupPicker.EntitySelectionValidator';
            }
            this.EntitySelectionValidator = eval('new ' + className + '(this.EntitySelection);');
        }

        var valid = this.EntitySelectionValidator.TryValidateWithAlert(entities, this.CandidateContainer.Controls.GetLength());

        return valid;
    },

    RemoveCandidate: function()
    {
        var tags = this.CandidateContainer.GetSelectedTags();
        this.CandidateContainer.RemoveTag(tags);
        this.RemoveButton.Disable();
    },

    ContainsEntity: function(entity)
    {
        var contains = false;
        for (var i = 0; i < this.CandidateContainer.Controls.GetLength() ; i++)
        {
            var tag = this.CandidateContainer.Controls.Get(i);
            if (!tag || !tag.Entity)
            {
                continue;
            }

            if (tag.Entity.Properties.EntityId == entity.Properties.EntityId)
            {
                contains = true;
                break;
            }

            var principalName = entity.Properties["SpPrincipalName"];
            var tagPrinsipalName = tag.Entity.Properties["SpPrincipalName"];
            if (principalName && tagPrinsipalName &&
                ISString.Equals(tag.Entity.Properties["SpPrincipalName"], entity.Properties["SpPrincipalName"], true))
            {
                contains = true;
                break;
            }
        }

        return contains;
    },

    RetrieveResolvedEntities: function(resolvedEntities, callback)
    {
        var query = new ISSPQuery();               
        var queryTemplete   = "<Query>"
                            +   "<Where>"
                            +       "%WhareValue%"
                            +   "</Where>"
                            + "</Query>";

        var whreQuery = "";
        var principalNameField = GPContext.Configuration.Fields.Get('SpPrincipalName');
        var mailField          = GPContext.Configuration.Fields.Get('Mail');
        for (i = 0; i < resolvedEntities.length; i++)
        {
            var principalName = resolvedEntities[i].Properties["SpPrincipalName"];
            var field = ISString.Contains(principalName, "@", true) ? mailField : principalNameField;
            var condition = SPQueryBuilder.BuildEqualQueryCondition(field.InternalName, field.Type, principalName);

            if (whreQuery.length <= 0) { whreQuery = condition; }
            else                       { whreQuery = SPQueryBuilder.BuildOrQueryCondition(whreQuery + condition); }
        }
        query.Query = queryTemplete.replace("%WhareValue%", whreQuery);

        // ViewField設定 
        var fieldRefs = '';
        for(var i = 0; i < GPContext.Configuration.Fields.GetLength(); i++)
        {
            var field = GPContext.Configuration.Fields.Get(i);
            fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
        }
        query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

        GPGridUtility.GetEntities(query, function(entities)
        {
            callback(entities);
        });
    },

    OnTagChanged: function()
    {
        var tags = this.CandidateContainer.Controls;
        var hasTags = tags && tags.GetLength() > 0 ? true : false;

        var args = { "Entities" : this.GetSelectedEntities()};

        this.Events.FireEventByName(iTagHolder.EventName.TagChanged, args);
    }
}


