// -----------------------------------------------------------------------
//  EntityActionValidator
// -----------------------------------------------------------------------
Infoshare.GroupPicker.EntityActionValidator = function Infoshare$GroupPicker$EntityActionValidator()
{
    this.InValidInfo = new ISDictionary();
}
GPEntityActionValidator = Infoshare.GroupPicker.EntityActionValidator;

GPEntityActionValidator.prototype = {

    ValidatedEntitiesChach: null,

    GetInValidInfo: function()
    {        
        return this.InValidInfo;
    },

    GetValidEntities: function(entities)
    {
        var validEntities = [];

        if (!entities && this.ValidatedEntitiesChach)
        {
            entities = this.ValidatedEntitiesChach;
        }
        
        for (var i = 0; i < entities.length ; i++)
        {
            if (entities[i].Valid)
            {
                validEntities.push(entities[i]);
            }
        }

        return validEntities;
    },

    Validate: function(entities)
    {
        var keys = this.ValidateInfo.GetKeys();
        for (var i = 0; i < keys.length; i++)
        {
            var key   = keys[i];
            var info  = this.ValidateInfo.Get(key);
            var valid = info.ValidateFunction(entities);

            if (!valid)
            {
                // InValidなEntityが存在する場合
                this.InValidInfo.Set(key, info)
            }
        }

        this.ValidatedEntitiesChach = entities;
    }
}


// -----------------------------------------------------------------------
//  EntitySelector.Action
// -----------------------------------------------------------------------
Infoshare.GroupPicker.Action = function InfoInfoshare$GroupPicker$GPAction()
{
    this.ValidateInfo = new ISDictionary();

    if (!GPAction.Instances)
    {
        GPAction.Instances = new iDictionary();
    }

    this.InstanceId = iGuid.New();
    GPAction.Instances.Add(this.InstanceId, this);
}
GPAction = Infoshare.GroupPicker.Action;
GPAction.TypeName = 'Infoshare.GroupPicker.Action';

GPAction.Instances = null;
GPAction.GetInstance = function (id)
{
    var instance = null;
    if (GPAction.Instances && GPAction.Instances.Contains(id))
    {
        instance = GPAction.Instances.Get(id);
    }

    return instance;
}

GPAction.prototype = {
    TypeName: GPAction.TypeName,

    ActionInfo: null,
    ActionDialog: null,
    Validator: null,
    ValidateInfo: null,
    ActionDialogClassName: '',
    SkipActionDialog: false,
    ActionButton: null,
    ActionButtonInfo : null,
    EntitiesForAction : null,

    CreateButton: function()
    {
        if (ISString.IsNullOrEmpty(this.ActionButtonInfo.Text))
        {
            var text = this.ActionInfo.DisplayName;
            if (iString.IsNullOrEmpty(text))
            {
                var key = this.ActionInfo.DisplayNameResourceKey;
                text = iResxResource.GetString(key);
            }
            
            this.ActionButtonInfo.Text = text;
        }

        var actionButton = this.CreateButtonInternal();

        actionButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.Action, this));
        actionButton.AddEvent(iControl.ControlEventName.PostRender, ISFunction.CreateDelegate(this.PostRender, this));

        this.ActionButton = actionButton;
        return actionButton;
    },

    CreateButtonInternal: function()
    {
        var buttonStyle = null;
        var actionButton = null;

        switch(this.ActionButtonInfo.Type)
        {
            case 'SVG'   : buttonStyle = new GPActionButtonStyle();
                           actionButton = new GPSVGActionButton(buttonStyle, this.ActionButtonInfo.SVGRederMethod);
                           actionButton.Text = this.ActionButtonInfo.Text;
                           break;
            case 'Text'  : buttonStyle = new GPTextActionButtonStyle();
                           actionButton = new iButton(buttonStyle);
                           actionButton.Title = this.ActionButtonInfo.Text;
                           break;
            case 'Image' : var imagePath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/infoshare.GroupPicker/' + this.ActionButtonInfo.Image;
                           buttonStyle = new iImageButtonStyle(new iButtonImageInfo(imagePath));
                           actionButton = new iImageButton(buttonStyle);
                           break;
        }

        return actionButton;
    },

    PostRender: function(control)
    {
        var element = control.GetElement();
        element.style.float      = 'right';
    },

    Action: function()
    {
        // オブジェクトが参照渡しされる為、別オブジェクトにコピーする
        // メモリの使用量が肥大になる場合、別方法を検討する（参照部分と、独自のプロパティを分離する）
        var entities = [];
        var nativeEntities = this.EntitiesForAction;
        i$.extend(true, entities, nativeEntities);

        // アクションが実行可能かどうかを判断するValidatorの初期化
        this.InitializeValidator();

        if (entities.length > 0)
        {
            // ValidatorによりInValidなEntityを判断（entityにValidプロパティを付与する）
            this.Validator.Validate(entities);            
            var inValidInfo = this.Validator.GetInValidInfo();

            // Workaround
            // ToDo(skomatsu): Action, Validatorの構造を適正化
            if (this.SkipActionWhenNoValidEntity)
            {
                var existValidEntity = false;
                for (var i = 0; i < entities.length; i++)
                {
                    var entity = entities[i];
                    if (entity.Valid)
                    {
                        existValidEntity = true;
                        break;
                    }
                }

                if (!existValidEntity)
                {
                    return;
                }
            }

            if (!this.SkipActionDialog) // ダイアログ表示が必須の場合
            {
                // ダイアログの初期化
                this.InitializeActionDialog(entities);

                // ダイアログ開く
                this.ActionDialog.Open();
            }

            else                          
            {
                if (inValidInfo.GetLength() > 0) // 無効なEntityが含まれる
                {
                    // ダイアログの初期化
                    this.InitializeActionDialog(entities);

                    // ダイアログ開く
                    this.ActionDialog.Open();
                }
                else
                {
                    // ValidなEntityの取得
                    var validEntities = this.Validator.GetValidEntities(entities);
                    
                    // ダイアログを開かずにアクションを実行
                    this.ExecuteAction(validEntities);
                }
            }
        }
    },

    ExecuteAction: function(entities)
    {
        // 各継承クラスで実装
    },

    InitializeActionDialog: function(entities)
    {
        // ダイアログクラスの作成
        this.CreateActionDialog(entities);
        // バリデータークラスをダイアログに付与
        this.ActionDialog.Validator = this.Validator;
        // Dialogのクローズイベントを登録
        this.ActionDialog.AddCloseEvent(ISFunction.CreateDelegate(this.OnCloseActionDialog, this));        
        // Button情報を付与
        this.ActionDialog.ActionButtonInfo = this.ActionButtonInfo;
    },

    OnCloseActionDialog: function(result)
    {
        if (result.Result == iDialogResult.ResultType.OK)
        {
            if (result.Entities)
            {
                this.ExecuteAction(result.Entities);
            }
            else
            {
                this.ExecuteAction(result.Dialog.Option.Entities);
            }
        }
    },

    CreateActionDialog: function(entities)
    {
        // Dialogクラスをnewする
        if (!ISString.IsNullOrEmpty(this.ActionDialogClassName))
        {
            this.ActionDialog = iClass.New(this.ActionDialogClassName);
            var info = GPContext.Configuration.Dialogs.Get(this.ActionDialogClassName);
            this.ActionDialog.Info = info; 

            // オプション設定
            var title    = !ISString.IsNullOrEmpty(info.DisplayName) ? info.DisplayName : iResxResource.GetString(info.DisplayNameResourceKey);
            var sizeText = info.Options.Get('DialogSize');

            var width    = this.ActionDialog.DefaultWidth;
            try
            {
                width = ISNumber.Parse(sizeText.split('x')[0]);
            }
            catch(e)
            {
            }

            var height   = this.ActionDialog.DefaultHeight;
            try
            {
                height = ISNumber.Parse(sizeText.split('x')[1]);
            }
            catch(e)
            {
            }            
            
            var option   = new iDialogOption(title, width, height);
            option.Modal = true;
            option.AllowMaximize = false;
            option.Entities = entities;

            this.ActionDialog.Option = option;
        }
    },

    InitializeValidator: function()
    {
        var validator = new GPEntityActionValidator();
        validator.ValidateInfo = this.ValidateInfo;
        
        this.Validator = validator;
    },

    OnEntitiesSelectionChanged: function(selectionChangedInfo)
    {
        // エンティティの更新
        this.EntitiesForAction = selectionChangedInfo.Entities;
        // 一つ以上候補がある場合ボタンを有効化する
        var enableButton = false;
        enableButton = this.EntitiesForAction != null && this.EntitiesForAction.length > 0 ? true : false;
                
        // ボタンの状態を変更
        if (enableButton)
        {
            this.ActionButton.Enable();
        }
        else
        {
            this.ActionButton.Disable();
        }        
    }
}


// -----------------------------------------------------------------------
//  EntitySelector.MailAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.MailAction = function InfoInfoshare$GroupPicker$GPMailAction()
{
    Infoshare.GroupPicker.Action.apply(this, arguments);

    this.ValidateInfo.Set('MailAddress', {
        'ValidateFunction' : this.IsValidMailAddress,
        'InValidMessageKey': 'GPMailDialog.Alert.MailAddress',
        'Valid'            : true
    });
    this.ValidateInfo.Set('IsNotResource', {
        'ValidateFunction' : this.IsNotResource,
        'InValidMessageKey': 'GPMailDialog.Alert.IsNotResource',
        'Valid'            : true
    });

    this.ActionDialogClassName = 'Infoshare.GroupPicker.MailDialog';

    this.SkipActionDialog = false;

    this.ActionButtonInfo = {
        'Type'  : 'SVG',
        'Image' : 'Action.Mail.png',
        'Text'  : '', // コンストラクタの初期化タイミングではActionInfoが取得できない為CreateButtonのタイミングで設定する
        'SVGRederMethod' : GPSVGActionButton.prototype.RenderMailSVGMarkup,
        'ActionType'     : GPMailAction.ActionType.Mail // コンストラクタの初期化タイミングではActionInfoが取得できない為OnEntitiesSelectionChangedのタイミングで設定する
    };
}
GPMailAction = Infoshare.GroupPicker.MailAction;
GPMailAction.TypeName = 'Infoshare.GroupPicker.MailAction';

GPMailAction.ActionType = {
    Mail:          'Mail',
    OutlookWeb:    'OutlookWeb',
    OutlookMobile: 'OutlookMobile'
};

GPMailAction.CreateMailLinker = function (entities, actionType)
{
    var linker = new iMailLinker();
    if (actionType == GPMailAction.ActionType.OutlookWeb)
    {
        linker = new iOutlookWebMailLinker();
    }
    else if (actionType == GPMailAction.ActionType.OutlookMobile)
    {
        linker = new iOutlookApplicationMailLinker();
    }

    linker.To = new Array();
    linker.CC = new Array();
    linker.BCC = new Array();

    for (var i = 0; i < entities.To.length; i++)
    {
        var mail = entities.To[i].Properties["Mail"];
        linker.To.push(mail);
    }
    for (var i = 0; i < entities.CC.length; i++)
    {
        var mail = entities.CC[i].Properties["Mail"];
        linker.CC.push(mail);
    }
    for (var i = 0; i < entities.BCC.length; i++)
    {
        var mail = entities.BCC[i].Properties["Mail"];
        linker.BCC.push(mail);
    }
    
    return linker;
}

GPMailAction.prototype = new GPAction();
GPMailAction.prototype.TypeName = GPMailAction.TypeName;

GPMailAction.prototype.ExecuteAction = function(entities)
{
    var linker = GPMailAction.CreateMailLinker(entities, this.ActionButtonInfo.ActionType);
    linker.Open();
}

GPMailAction.prototype.GetActionType = function(actionTypeString)
{
    var actionType = null;
    var settings = new Array();
    var actionTypes = new Array();
    if (actionTypeString)
    {
        if (iString.Contains(actionTypeString, ','))
        {
            settings = actionTypeString.split(',');
        }
        else
        {
            settings.push(actionTypeString);
        }

        for (var i = 0; i < settings.length; i++)
        {
            var action = settings[i];
            var device = null;
            if (iString.Contains(settings[i], ':'))
            {
                action = settings[i].split(':')[1];
                device = settings[i].split(':')[0];
            }
            actionTypes.push({ device: device, action: action });
        }

        var device = iBrowser.GetOperatingSystemName();
        for (var i = 0; i < actionTypes.length; i++)
        {
            if (actionTypes[i].device == null)   { actionType = actionTypes[i].action; }
            if (actionTypes[i].device == device) { actionType = actionTypes[i].action; break; }
        }
    }
    return actionType;
}

GPMailAction.prototype.OnEntitiesSelectionChanged = function(selectionChangedInfo)
{
    // ActionTypeを設定
    if (this.ActionInfo)
    {
        var actionType = this.GetActionType(this.ActionInfo.Options.Get('ActionType'));
        if (actionType)
        {
            this.ActionButtonInfo.ActionType = actionType;
        }
    }

    // エンティティの更新
    this.EntitiesForAction = selectionChangedInfo.Entities;
    // 一つ以上候補がありActionTypeが有効な場合ボタンを有効化する
    var enableButton = false;
    enableButton = this.EntitiesForAction != null && this.EntitiesForAction.length > 0 ? true : false;
                
    // ボタンの状態を変更
    if (enableButton)
    {
        if (this.IsValidActionType(this.ActionButtonInfo.ActionType))
        {
            this.ActionButton.Enable();
        }
        else
        {
            var message = '[GPMailAction.OnEntitiesSelectionChanged] Invalid ActionType for action button in configuration file.';
            ISTrace.TraceError(message);
        }
    }
    else
    {
        this.ActionButton.Disable();
    }        
}

GPMailAction.prototype.IsValidActionType = function (actionType)
{
    var valid = true;

    if (actionType == GPMailAction.ActionType.OutlookMobile && iBrowser.IsWindows())
    {
        valid = false;
    }

    return valid;
}

GPMailAction.prototype.IsValidMailAddress = function (entities)
{
    var valid = true;

    for (var i = 0; i < entities.length; i++)
    {
        var entityIsValid = true;
        var entity = entities[i];
            
        if (ISString.IsNullOrEmpty(entity.Properties.Mail))
        {
            entityIsValid = false;
            valid = false;                
        }

        // 複数のValidatorからフラグ付けされる為、すでに無効と判断されているエンティティはフラグを更新しない
        if (entity.Valid === false)
        {
            continue;
        }
        entity.Valid = entityIsValid;
    }

    return valid;
};
GPMailAction.prototype.IsNotResource = function(entities)
{
    var valid = true;

    for (var i = 0; i < entities.length; i++)
    {
        var entityIsNotResource = true;
        var entity = entities[i];
            
        if (ISString.Equals(entity.Properties.Type, 'user', true) &&
            ISString.Equals(entity.Properties.SubType, 'RoomMailbox', true) ||
            ISString.Equals(entity.Properties.SubType, 'EquipmentMailbox', true))
        {
            entityIsNotResource = false;
            valid = false;                
        }

        // 複数のValidatorからフラグ付けされる為、すでに無効と判断されているエンティティはフラグを更新しない
        if (entity.Valid === false)
        {
            continue;
        }
        entity.Valid = entityIsNotResource;    
    }

    return valid;
};

// -----------------------------------------------------------------------
