//  EntitySelector.SkypeAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.SkypeAction = function InfoInfoshare$GroupPicker$GPSkypeAction()
{ 
    Infoshare.GroupPicker.Action.apply(this, arguments);

    this.Image = 'Action.Skype.png';

    this.ValidateInfo.Set('Type', {
        'ValidateFunction': this.IsUser,
        'InValidMessageKey': 'GPSkypeDialog.Alert.Type',
        'Valid': true
    });
    this.ValidateInfo.Set('Sip', {
        'ValidateFunction' : this.IsValidSip,
        'InValidMessageKey': 'GPSkypeDialog.Alert.Sip',
        'Valid'            : true
    });
    // ライセンスチェックは無効化（同期ツールに実装が入ったら検討）
    //this.ValidateInfo.Set('License', {
    //    'ValidateFunction' : GPEntityActionValidator.IsValidSkypeLicense,
    //    'InValidMessageKey': 'GPSkypeDialog.Alert.LiscenceInValid',
    //    'Valid'            : true
    //});
    this.ValidateInfo.Set('CurrentUser', {
        'ValidateFunction' : this.IsNotCurrentUser,
        'InValidMessageKey': 'GPSkypeDialog.Alert.CurrentUser',
        'Valid'            : true
    });

    this.ActionDialogClassName = 'Infoshare.GroupPicker.SkypeDialog';

    this.SkipActionDialog = true;

    this.ActionButtonInfo = {
        'Type'  : 'SVG',
        'Image' : 'Action.Skype.png',
        'Text'  : '', // コンストラクタの初期化タイミングではActionInfoが取得できない為CreateButtonのタイミングで設定する
        'SVGRederMethod' : GPSVGActionButton.prototype.RenderSkypeSVGMarkup
    };
}
GPSkypeAction = Infoshare.GroupPicker.SkypeAction;
GPSkypeAction.TypeName = 'Infoshare.GroupPicker.SkypeAction';

GPSkypeAction.prototype = new Infoshare.GroupPicker.Action();
GPSkypeAction.prototype.TypeName = GPSkypeAction.TypeName;

GPSkypeAction.prototype.ExecuteAction = function(entities)
{
    entities = this.Validator.GetValidEntities(entities);

    var sipAddresses = new Array();
    for (i = 0; i < entities.length; i++)
    {
        var entity = entities[i];
        var sip = entity.Properties["Sip"];
        if (iString.IsNullOrEmpty(sip))
        {
            continue;
        }

        sipAddresses.push(sip);
    }

    var linker = new iUnifiedCommunicationLinker();
    linker.SipAddresses = sipAddresses;
    linker.Open();
};

GPSkypeAction.prototype.IsUser = function(entities)
{
    var valid = true;

    for (var i = 0; i < entities.length; i++)
    {
        var entityIsValid = true;
        var entity = entities[i];

        if (!ISString.Equals(entity.Properties.Type, 'user', true))
        {
            if (!ISString.Equals(entity.Properties.SubType, 'user', true) ||  // ユーザー
                !ISString.Equals(entity.Properties.SubType, 'contact', true)) // 連絡先
            {
                entityIsValid = false;
                valid = false;
            }
        }

        // 複数のValidatorからフラグ付けされる為、すでに無効と判断されているエンティティはフラグを更新しない
        if (entity.Valid === false)
        {
            continue;
        }
        entity.Valid = entityIsValid;
    }

    return valid;
};

GPSkypeAction.prototype.IsValidSip = function(entities)
{
    var valid = true;

    for (var i = 0; i < entities.length; i++)
    {
        var entityIsValid = true;
        var entity = entities[i];

        // Sipの有無に関するチェックを行う為、ユーザーのみをチェックする
        if (!ISString.Equals(entity.Properties.Type, 'user', true))
        {
            continue;
        }

        if (ISString.IsNullOrEmpty(entity.Properties.Sip))
        {
            entityIsValid = false;
            valid = false;
        }

        // 複数のValidatorからフラグ付けされる為、すでに無効と判断されているエンティティはフラグを更新しない
        if (entity.Valid === false)
        {
            continue;
        }
        entity.Valid = entityIsValid;
    }

    return valid;
};

GPSkypeAction.prototype.IsNotCurrentUser = function(entities)
{
    var valid = true;
    // CurrentUserが特定できていない場合は判断しない（valid=trueを返す）
    if (!GPContext.CurrentUser)
    {
        return valid;
    }

    for (var i = 0; i < entities.length; i++)
    {
        var entityIsValid = true;
        var entity = entities[i];

        if (entity.Properties["SpPrincipalName"] &&
            ISString.Equals(entity.Properties["SpPrincipalName"], GPContext.CurrentUser.LoginName, true))
        {
            entityIsValid = false;
            valid = false;
        }

        // 複数のValidatorからフラグ付けされる為、すでに無効と判断されているエンティティはフラグを更新しない
        if (entity.Valid === false)
        {
            continue;
        }
        entity.Valid = entityIsValid;
    }

    return valid;
};


