Infoshare.GroupPicker.TeamsAction = function InfoInfoshare$GroupPicker$GPTeamsAction()
{
    Infoshare.GroupPicker.Action.apply(this, arguments);

    this.Image = 'Action.Teams.png';

    // ライセンスチェックは無効化（同期ツールに実装が入ったら検討）
    //this.ValidateInfo.Set('License', {
    //    'ValidateFunction' : GPEntityActionValidator.IsValidTeamsLicense,
    //    'InValidMessageKey': 'GPTeamsDialog.Alert.LiscenceInValid',
    //    'Valid'            : true
    //});

    this.SkipActionDialog = true;
}
GPTeamsAction = Infoshare.GroupPicker.TeamsAction;
GPTeamsAction.TypeName = 'Infoshare.GroupPicker.TeamsAction';

GPTeamsAction.prototype = new Infoshare.GroupPicker.Action();
GPTeamsAction.prototype.TypeName = GPTeamsAction.TypeName;

GPTeamsAction.ActionType = { Chat:    'Chat',
                             Meeting: 'Meeting' };

GPTeamsAction.prototype.ClientTypeAutoDetection = false;
GPTeamsAction.prototype.ClientType = null;
GPTeamsAction.prototype.ActionType = null;

GPTeamsAction.prototype.ExecuteAction = function (entities)
{
    entities = this.Validator.GetValidEntities(entities);

    var mailAddresses = new Array();
    for (i = 0; i < entities.length; i++)
    {
        var entity = entities[i];
        var mail = entity.Properties.Mail;
        if (iString.IsNullOrEmpty(mail))
        {
            continue;
        }

        mailAddresses.push(mail);
    }

    // ToDo: 初期化場所検討
    iTeams.ScriptBaseUrl = iString.Format('{0}/Infoshare/Teams/',
                                          iString.TrimEnd(GPContext.SourcesPath, '/'));

    this.EnsureClientType();
    if (this.ActionType == GPTeamsAction.ActionType.Chat)
    {
        var linker = new iTeamsChatLinker(this.ClientType);
        linker.ClientTypeAutoDetection = this.ClientTypeAutoDetection
        linker.Users = mailAddresses;
        linker.Open();
    }
    else if (this.ActionType == GPTeamsAction.ActionType.Meeting)
    {
        var linker = new iTeamsMeetingLinker(this.ClientType);
        linker.ClientTypeAutoDetection = this.ClientTypeAutoDetection
        linker.Attendees = mailAddresses;
        linker.Open();
    }
    else
    {
        var message = iString.Format('[GPTeamsAction.ExecuteAction] Could not execute action, caused by invalid instance type ({0}) was running.', iType.GetTypeName(this));
        ISTrace.TraceError(message);
    }
};

GPTeamsAction.prototype.EnsureClientType = function()
{
    var clientType = this.ActionInfo.Options.Get('ClientType');
    if (!iString.IsNullOrEmpty(clientType))
    {
        if      (iString.Equals(clientType, iTeamsContext.HostClientType.Web,     true)) { this.ClientType = iTeamsContext.HostClientType.Web; }
        else if (iString.Equals(clientType, iTeamsContext.HostClientType.Desktop, true)) { this.ClientType = iTeamsContext.HostClientType.Desktop; }
    }

    var autoDetection = this.ActionInfo.Options.Get('ClientTypeAutoDetection');
    if (!iString.IsNullOrEmpty(autoDetection))
    {
        this.ClientTypeAutoDetection = iBoolean.TryParse(autoDetection, true);
    }
};

GPTeamsAction.prototype.IsUser = GPSkypeAction.prototype.IsUser;
GPTeamsAction.prototype.IsValidMailAddress = GPMailAction.prototype.IsValidMailAddress;
GPTeamsAction.prototype.IsNotCurrentUser = GPSkypeAction.prototype.IsNotCurrentUser;

GPTeamsAction.prototype.IsNotMailContact = function (entities)
{
    var valid = true;

    for (var i = 0; i < entities.length; i++)
    {
        var entityIsValid = true;
        var entity = entities[i];

        if (ISString.Equals(entity.Properties.SubType, 'contact', true)) // 連絡先
        {
            entityIsValid = false;
            valid = false;
        }

        // 複数のValidatorからフラグ付けされる為、すでに無効と判断されているエンティティはフラグを更新しない
        if (entity.Valid === false)
        {
            continue;
        }
        entity.Valid = entityIsValid;
    }

    return valid;
};


