GPTeamsChatAction.prototype.IsMaximumNumberOfContact = function (entities)
{
    var numberOfContact = 0;
    for (var i = 0; i < entities.length; i++)
    {
        entity = entities[i];
        if (iString.Equals(entity.Properties.Type, 'user', true))
        {
            numberOfContact++;
        }
        if (numberOfContact > GPTeamsChatAction.MaximumNumberOfContact)
        {
            entity.Valid = false;
        }
    }

    var valid = true;
    if (numberOfContact > GPTeamsChatAction.MaximumNumberOfContact)
    {
        valid = false;
    }
    return valid;
}


