Infoshare.GroupPicker.OutlookAddinMailAction = function InfoInfoshare$GroupPicker$OutlookAddinMailAction()
{
    Infoshare.GroupPicker.MailAction.apply(this, arguments);

    this.ValidateInfo.Set('MailAddress', {
        'ValidateFunction' : this.IsValidMailAddress,
        'InValidMessageKey': 'GPMailDialog.Alert.MailAddress',
        'Valid'            : true
    });

    this.ActionDialogClassName = 'Infoshare.GroupPicker.MailDialog';

    this.SkipActionDialog = false;

    this.ActionButtonInfo = {
        'Type'  : 'Text',
        'Image' : '',
        'Text'  : 'OK'
    };
}
GPOutlookAddinMailAction = Infoshare.GroupPicker.OutlookAddinMailAction;
GPOutlookAddinMailAction.TypeName = 'Infoshare.GroupPicker.OutlookAddinMailAction';

GPOutlookAddinMailAction.prototype = new GPMailAction();
GPOutlookAddinMailAction.prototype.TypeName = GPOutlookAddinMailAction.TypeName;

GPOutlookAddinMailAction.prototype.ExecuteAction = function(entities)
{
    // コンテキストの確認（Outlookアドインから開かれたかどうかの確認）
    var openByOutlookAddin = !ISString.IsNullOrEmpty(GPContext.GPOutlookExtension.Platform) &&
                             !ISString.IsNullOrEmpty(GPContext.GPOutlookExtension.Form) &&
                             !ISString.IsNullOrEmpty(GPContext.GPOutlookExtension.Application);

    if (!ISString.IsNullOrEmpty(GPContext.GPOutlookExtension.Form) &&
        GPContext.GPOutlookExtension.Form == GPContext.GPOutlookExtension.FormType.Edit)
    {
        this.AppendEntitiesToOutlookForm(entities);
    }
}
GPOutlookAddinMailAction.prototype.AppendEntitiesToOutlookForm = function(entities)
{    
    // Mail
    if (!ISString.IsNullOrEmpty(GPContext.GPOutlookExtension.Application &&
        GPContext.GPOutlookExtension.Application == GPContext.GPOutlookExtension.ApplicationType.Mail))
    {
        // Outlook
        if (GPContext.GPOutlookExtension.Platform == GPContext.GPOutlookExtension.PlatformType.Outlook)
        {
            var stringEntities = this.GetEntitiesForOutlookClient(entities);
            if (GPContext.GPOutlookExtension.IsVstoAddin)
            {
                window.external.SetEntities(stringEntities);
            }
            else
            {
                Office.context.ui.messageParent(stringEntities);
            }            
        }
        // OWA
        else
        {
            // 開かれたウィンドウのメソッドを呼ぶ
            var parentWindow = window.opener;
            parentWindow.GPOutlookExtension.SetMailItems(entities);
        }
    }   
}
GPOutlookAddinMailAction.prototype.GetEntitiesForOutlookClient = function(entities)
{
    // ストリングに変換する
    var to = "[ToItems]";
    var cc = "[CCItems]";
    var bcc = "[BCCItems]";
    for (var i = 0; i < entities.To.length; i++)
    {
        var mail = entities.To[i].Properties["Mail"];                
        to += mail + ";";
    }
    for (var i = 0; i < entities.CC.length; i++)
    {
        var mail = entities.CC[i].Properties["Mail"];                
        cc += mail + ";";
    }
    for (var i = 0; i < entities.BCC.length; i++)
    {
        var mail = entities.BCC[i].Properties["Mail"];                
        bcc += mail + ";";
    }

    var stringEntities = to + cc + bcc
    return stringEntities;
};


