//  EntitySelectionValidator
// -----------------------------------------------------------------------
Infoshare.GroupPicker.EntitySelectionValidator = function Infoshare$GroupPicker$EntitySelectionValidator(entitySelection)
{
    this.EntitySelection = entitySelection;
}
GPEntitySelectionValidator = Infoshare.GroupPicker.EntitySelectionValidator;
GPEntitySelectionValidator.prototype = {
    EntitySelection: null,

    Validate: function(entities, selectedCount)
    {
        var valid = this.IsValidCount(entities, selectedCount) &&
                    this.IsValidType(entities) &&
                    this.IsValidSubType(entities) &&
                    this.IsValidPrincipal(entities);

        return valid;
    },

    TryValidate: function(entities, selectedCount)
    {
        var valid = false;
        try
        {
            valid = this.Validate(entities, selectedCount);
        }
        catch(e)
        {
            valid = false;
            ISTrace.TraceWarning(e.message);
        }

        return valid;
    },

    TryValidateWithAlert: function(entities, selectedCount)
    {
        var valid = false;
        try
        {
            valid = this.Validate(entities, selectedCount);
        }
        catch(e)
        {
            valid = false;
            alert(e.message);
        }

        return valid;
    },

    IsValidCount: function(entities, selectedCount)
    {
        var valid = false;
        var message = '';
        selectedCount = ISNumber.IsNumber(selectedCount) ? selectedCount : 0;
        if (this.EntitySelection.AllowMultipleSelection)
        {
            // 以下6行はIsValidCountを判断するロジック（this.EntitySelection.MaxSelectionCountが正しく取得できない為コメントアウト）
            //valid = this.EntitySelection.MaxSelectionCount == 0 ||
            //        this.EntitySelection.MaxSelectionCount >= (entities.length + selectedCount);
            //if (!valid)
            //{
            //    message = ISString.Format(iResxResource.GetString('PickerDialog.EntitiySelector.Validation.Max'), 
            //                              this.EntitySelection.MaxSelectionCount);  
            //}

            // 暫定対応 : 複数選択の場合IsValidCountをtrueにセットする
            valid = true;
        }
        else
        {
            valid = (entities.length + selectedCount) == 1;
            if (!valid)
            {
                message = iResxResource.GetString('PickerDialog.EntitiySelector.Validation.Multi');
            }
        }

        if (!valid)
        {
            throw new Error(message);
        }

        return valid;
    },

    IsValidType: function(entities)
    {
        var valid = true;
        var invalidTypeName = '';
        for (var i = 0; i < entities.length; i++)
        {
            var entity = entities[i];
            if (ISString.Equals(entity.Properties.Type, 'user', true) && !this.EntitySelection.AllowUserSelection)
            {
                valid = false;
                invalidTypeName = iResxResource.GetString('PickerDialog.EntityType.User');  
                break;
            }        
            if (ISString.Equals(entity.Properties.Type, 'group', true) && !this.EntitySelection.AllowSecurityGroupSelection)
            {
                valid = false;
                invalidTypeName = iResxResource.GetString('PickerDialog.EntityType.SecurityGroup');  
                break;
        }
        }

        if (!valid)
        {
            var message = ISString.Format(iResxResource.GetString('PickerDialog.EntitiySelector.Validation.Type'), invalidTypeName);
            throw new Error(message);
        }

        return valid;
    },

    IsValidSubType: function(entities)
    {
        var valid = true;
        var invalidTypeName = '';
        for (var i = 0; i < entities.length; i++)
        {
            var entity = entities[i];
            // 連絡先は選択不可
            if (ISString.Equals(entity.Properties.Type, 'user', true) &&
                entity.Properties.SubType &&
                ISString.Equals(entity.Properties.SubType, 'contact', true))
            {
                valid = false;
                invalidTypeName = iResxResource.GetString('PickerDialog.EntityType.Contact');  
                break;
            }

            // 配布グループは選択不可
            if (ISString.Equals(entity.Properties.Type, 'group', true) &&
                entity.Properties.SubType &&
                ISString.Equals(entity.Properties.SubType, 'Distribution', true))
            {
                valid = false;
                invalidTypeName = iResxResource.GetString('PickerDialog.EntityType.DistributionList');  
                break;
            }
        }

        if (!valid)
        {
            var message = ISString.Format(iResxResource.GetString('PickerDialog.EntitiySelector.Validation.Type'), invalidTypeName);
            throw new Error(message);
        }

        return valid;
    },

    IsValidPrincipal: function(entities)
    {
        var valid = true;
        for (var i = 0; i < entities.length; i++)
        {
            var entity = entities[i];
            if (ISString.IsNullOrEmpty(entity.Properties["SpResolveKey"]))
            {
                valid = false;
                break;
            }        
        }

        if (!valid)
        {
            var message = ISString.Format(iResxResource.GetString('PickerDialog.EntitiySelector.Validation.InvalidPrincipal'), entity.Properties.EntityDisplayName);
            throw new Error(message);
        }

        return valid;
    }
}


