// -----------------------------------------------------------------------
//  EntitySearcher
// -----------------------------------------------------------------------
Infoshare.GroupPicker.EntitySearcher = function InfoInfoshare$GroupPicker$EntitySearcher(datasource, viewFields, sortOrders, columns)
{
    // ToDo(skomatsu): 偏った初期化のため汎化の際に実装を検討する
    this.DataSource = datasource;
    this.ViewFields = viewFields;
    this.SortOrders = sortOrders;
    this.Columns    = columns; // GridColumn < 依存関係最悪

    this.Synonyms = ISBoolean.Parse(GPContext.Configuration.GetSetting('EnableSynonymHandling')) ? GPContext.Configuration.Synonyms : null;
    this.ReservedWords = ["|", GPSearchView.SearchTypePrefixGroup, GPSearchView.SearchTypePrefixUser];

    // 検索対象フィールドを確定（同義語検索の有効・無効で切り替え）
    var fieldName = 'SearchKey';
    if (ISBoolean.Parse(GPContext.Configuration.GetSetting('EnableSynonymHandling')))
    {
        fieldName = 'SynonymSearchKey';
    }
    this.SearchKeyField = GPContext.Configuration.Fields.Get(fieldName);
    this.SearchKeyFieldName = fieldName;
}
GPEntitySearcher = Infoshare.GroupPicker.EntitySearcher;
GPEntitySearcher.TypeName = 'Infoshare.GroupPicker.EntitySearcher';

GPEntitySearcher.EntityType = { Group: 'group',
                                User:  'user' }

GPEntitySearcher.prototype = {
    TypeName: GPEntitySearcher.TypeName,

    Keyword: null,
    Filter: null,

    // ToDo(skomatsu): 構成ファイルに設定値を置く?
    MaxKeywordLength: 255,
    MaxKeywordsCount: 5,

    Synonyms: null,
    ReservedWords: null,

    SearchKeyFieldName: null,
    SearchKeyField: null,

    DataSource: null,
    ViewFields: null,
    SortOrders: null,


    Search: function(keyword, filter, callback)
    {
        // 同一条件での検索は行わない
        if (this.isSameCondition(keyword, filter))
        {
            ISTrace.TraceVerbose('Skipped search since the keywords and filters are same as previous one.');
            setTimeout(function ()
            {
                // 同一条件などで検索を中止した場合は、undefinedを返す
                // ToDo(skomatsu): 結果の意図が伝達できるように修正
                callback(undefined);
            }, 0);
            return;
        }

        // 条件をキャッシュ
        this.Keyword = keyword;
        this.Filter  = filter;

        // キーワード分割と同義語処理
        var splitter = new GPKeywordSplitter();
        splitter.Synonyms = this.Synonyms;
        var keywords = splitter.Split(keyword);

        // フィルタ処理
        if (!filter)
        {
            filter = new GPEntitySearcherFilter(true, true);
        }

        // キーワード検証
        if (this.isValidKeyword(this.Keyword, keywords) &&
            this.isValidFilter(filter))
        {
            this.query(keywords, filter, callback);
        }
        else
        {
            setTimeout(function ()
            {
                // 検索を中止した場合は、undefinedを返す
                // ToDo(skomatsu): 結果の意図が伝達できるように修正
                callback(undefined);
            }, 0);
        }
    },

    isSameCondition: function (keyword, filter)
    {
        var isSame = true;
        for (;;)
        {
            // キーワードを確認
            if (this.Keyword != keyword)
            {
                isSame = false;
                break;
            }

            // フィルタを確認
            if (filter)
            {
                // フィルタ指定ありの場合
                if (!this.Filter ||
                    !this.Filter.Equals(filter))
                {
                    isSame = false;
                    break;
                }
            }
            else
            {
                // フィルタ指定無しの場合
                if (this.Filter)
                {
                    isSame = false;
                    break;
                }
            }

            break;
        }

        return isSame;
    },

    isValidKeyword: function(rawKeywords, keywords)
    {
        var valid = true;

        for (;;)
        {
            // 空文字列
            if (keywords == null ||
                keywords.length <= 0 ||
                iString.IsNullOrEmpty(rawKeywords))
            {
                alert(iResxResource.GetString('PickerDialog.SearchView.EmptyKeywordErrorMessage'));
                valid = false;
                break;
            }

            // キーワード長
            if (rawKeywords.length > this.MaxKeywordLength)
            {
                alert(ISString.Format(iResxResource.GetString('PickerDialog.SearchView.LengthKeywordErrorMessageFormat'), this.MaxKeywordLength));
                valid = false;
                break;
            }

            // キーワード数
            var maxCount = 5;
            if (keywords.length > this.MaxKeywordsCount)
            {
                alert(ISString.Format(iResxResource.GetString('PickerDialog.SearchView.CountKeywordErrorMessageFormst'), this.MaxKeywordsCount));
                valid = false;
                break;
            }

            // 予約語
            for (var i = 0; i < keywords.length; i++)
            {
                var keyword = keywords[i];
                for (var j = 0; j < this.ReservedWords.length; j++)
                {
                    var reservedWord = this.ReservedWords[j]
                    if (iString.Equals(keyword, reservedWord))
                    {
                        alert(iResxResource.GetString('PickerDialog.SearchView.SystemKeywordErrorMessage'));
                        valid = false;
                        break;
                    }
                }
            }

            // サロゲートペア
            for (var i = 0; i < keywords.length; i++)
            {
                var keyword = keywords[i];
                if (iString.ContainsSurrogatePair(keyword))
                {
                    alert(iResxResource.GetString('PickerDialog.SearchView.SurrogatePairKeywordErrorMessage'));
                    valid = false;
                    break;
                }
            }

            break;
        }

        return valid;
    },

    isValidFilter: function(filter)
    {
        var valid = filter &&
                    (filter.IncludeGroup ||
                     filter.IncludeUser)
        if (!valid)
        {
            alert(iResxResource.GetString('PickerDialog.SearchView.FilterEmpty'));
        }

        return valid;
    },

    query: function(keywords, filter, callback)
    {
        // Where句
        var where = this.buildWhereQuery(keywords, filter, true);

        // OrderBy句
        var orderby = '';
        for (var i = 0; i < this.SortOrders.length; i++)
        {
            var order = this.SortOrders[i];
            orderby += SPQueryBuilder.BuildOrderByFieldRef(order.FieldName, order.Ascending);
        }

        // ViewField設定 
        // ToDo(skomatsu): 組織マスタの場合はViewFieldsを設定せず全ての列を取得する(拡張した列などに対応する為)
        var fieldRefs = '';
        for (var i = 0; i < this.ViewFields.GetLength() ; i++)
        {
            var field = this.ViewFields.Get(i);
            fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
        }
        // ソートに利用するフィールドを考慮（分割クエリ対応）
        for (var i = 0; i < this.SortOrders.length; i++)
        {
            var fieldName = this.SortOrders[i].FieldName;
            if (GPContext.Configuration.Fields.Contains(fieldName))
            {
                continue;
            }
            fieldRefs += SPQueryBuilder.BuildFieldRef(fieldName);
        }

        // クエリ組み立て
        var query = new ISSPQuery();
        query.Query        = SPQueryBuilder.BuildQuery(orderby, where);
        query.ViewFields   = SPQueryBuilder.BuildViewFields(fieldRefs);
        query.QueryOptions = SPQueryBuilder.BuildQueryOptions(SPQueryBuilder.BuildMandatoryColumnsOption(false));

        // 閾値を超えるアイテムのクエリを設定する
        query.EnableIterativeQueries = ISBoolean.TryParse(GPContext.Configuration.GetSetting('EnableLargeSearchQuery'), false);

        GPGridUtility.GetItems(this.DataSource, query, this.Columns, callback);
    },

    buildWhereQuery: function(keywords, filter)
    {
        // Where句: キーワード

        // 構成ファイル定義ではなく、実際のリストのフィールドを確認する
        var keywordField = this.SearchKeyField;
        if (this.DataSource &&
            this.DataSource.DetaSourceList &&
            this.DataSource.DataSourceList.Fields)
        {
            keywordField = this.DataSource.DataSourceList.Fields.Get(fieldName);
            keywordField.InternalName = keywordField.Name;
        }

        var keywordFilter = '';
        for (var i = 0; i < keywords.length; i++)
        {
            var keyword = keywords[i];
            var condition = SPQueryBuilder.BuildContainsQueryCondition(keywordField.InternalName, keywordField.Type, keyword);
            if (keywordFilter.length <= 0) { keywordFilter = condition; }
            else                           { keywordFilter = SPQueryBuilder.BuildAndQueryCondition(keywordFilter + condition); }
        }

        // Where句: 種別
        // 種別はORでつないでいく
        // フィルター処理
        var filters = [];
        if (filter.IncludeGroup) { filters.push(GPEntitySearcher.EntityType.Group); }
        if (filter.IncludeUser)  { filters.push(GPEntitySearcher.EntityType.User); }

        var typeFilter = '';
        for (var i = 0; i < filters.length; i++)
        {
            var typePrefix = "|{0}|";
            var typeToken = "";
            var type = filters[i];
            if (iString.Equals(type, GPEntitySearcher.EntityType.User, true))
            {
                typeToken = GPSearchView.SearchTypePrefixUser;
            }
            else if (iString.Equals(type, GPEntitySearcher.EntityType.Group, true))
            {
                typeToken = GPSearchView.SearchTypePrefixGroup;
            }
            typePrefix = iString.Format(typePrefix, typeToken);

            var condition = SPQueryBuilder.BuildContainsQueryCondition(keywordField.InternalName, keywordField.Type, typePrefix);
            if (typeFilter.length <= 0) { typeFilter = condition; }
            else                        { typeFilter = SPQueryBuilder.BuildOrQueryCondition(typeFilter + condition); }
        }

        // Where句: where
        // キーワードと種別とHierarchicaIdをANDでつなぐ
        var where = SPQueryBuilder.BuildAndQueryCondition(keywordFilter + typeFilter);

        // ToDo:ShowInView
        /*
        var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "SearchView");
        var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
        var showInViewQuery = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);
        where = SPQueryBuilder.BuildAndQueryCondition(where + showInViewQuery);
        */

        // EnableVisibleGroups=trueの場合、CurrentUserのVisibleGroupsを検索条件に追加する
        var enableVisibleGroups = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableVisibleGroups'), false);
        if (enableVisibleGroups)
        {
            where = GPCamlQueryCondition.AddVisibleGroupsCondition(where, GPViewContext.CurrentUserEntity);
        }

        return where;
    }
}

