Infoshare.GroupPicker.ActionDialog = function Infoshare$GroupPicker$ActionDialog()
{
    Infoshare.Web.Control.Dialog.apply(this, arguments);

    this.AddEvent(iDialog.EventName.Close, ISFunction.CreateDelegate(this.OnClose, this));
}
GPActionDialog = Infoshare.GroupPicker.ActionDialog;

GPActionDialog.prototype = new iDialog();

GPActionDialog.prototype.Info = null;
GPActionDialog.prototype.Option = null;
GPActionDialog.prototype.Validator = null;
GPActionDialog.prototype.ActionEvents = null;

GPActionDialog.prototype.ActionButton = null;

GPActionDialog.prototype.BaseOpen = GPActionDialog.prototype.Open;
GPActionDialog.prototype.Open = function()
{
    // 親ダイアログ情報をキャッシュ   
    var parentDialogElem = GPDialog.ActiveDialog ? GPDialog.ActiveDialog.Dialog.Element : null;
    this.ParentElement = parentDialogElem;

    // ダイアログ初期化: イメージボタン設定
    var imagesPath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
    this.Style.HeaderStyle.WindowCloseButtonStyle = new iImageButtonStyle(new iButtonImageInfo(imagesPath + 'x.png',
                                                                                                    '',
                                                                                                    '',
                                                                                                    imagesPath + 'x-Press.png',
                                                                                                    imagesPath + 'x-Hover.png'));

    // ダイアログを開く
    this.BaseOpen(this.Option);
        
    // Viewのレンダリング
    var entities = this.Option.Entities;
    this.InitializeView(entities);        
};

GPActionDialog.prototype.AddCloseEvent = function(fn)
{
    if (this.ActionEvents == null)
    {
        this.ActionEvents = new iEvent();
    }

    this.ActionEvents.AddEvent('close', fn);
};

GPActionDialog.prototype.OnClose = function(result)
{
    this.ActionEvents.FireEventByName('close', result);
};

GPActionDialog.prototype.GetAlertLabels = function(entities)
{
    var alertLabels = [];

    // InValidの確認
    var info = this.Validator.GetInValidInfo(entities);

    for (var i = 0; i < info.GetLength(); i++)
    {
        var alertMessage = iResxResource.GetString(info.GetValues()[i].InValidMessageKey);
        alertLabels.push(alertMessage);
    }

    return alertLabels;
};

GPActionDialog.prototype.InitializeView = function(entities)
{
    var view = this.CreateView();
    view.Info.AlertLabels = this.GetAlertLabels(entities);
    view.Info.IGGridFeatures = [{
        name: "Resizing",
        allowDoubleClickToResize: true,
        columnSettings: [{ columnKey: "Type", allowResizing: false },
                            { columnKey: "To", allowResizing: false },
                            { columnKey: "CC", allowResizing: false },
                            { columnKey: "BCC", allowResizing: false }]
    }];

    var body = this.Body;
    view.Render(this.Body);
    view.UpdateGrid(entities);

    this.View = view;
};

GPActionDialog.prototype.CreateView = function ()
{
    var viewClassName = this.Info.BodyClass.Name;
    var view = iClass.New(viewClassName);

    view.Dialog = this;
    view.Info = GPContext.Configuration.Views.Get(viewClassName);

    return view;
};

GPActionDialog.prototype.InitializeFooter = function ()
{
    if (!this.Option.FooterEnabled)
    {
        return;
    }

    // フッタ
    this.Footer = new iPanel(this.Style.FooterStyle);
    this.AppendChildControl(this.Footer);
    
    // アクション ボタン
    var actioneButton = this.CreateActionButton();
    actioneButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OKClose, this));
    this.ActionButton = actioneButton;
    // 有効なEntityが存在しない場合、ボタンを無効化
    if (this.Validator.GetValidEntities() < 1)
    {
        this.ActionButton.Disable();
    }

    // キャンセル ボタン
    var cancelButton = new iButton(new GPActionDialogButtonStyle());
    cancelButton.Title = 'Cancel';
    cancelButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.CancelClose, this));
    
    // ボタンエリア
    this.FooterButtonArea = new iPanel(this.Style.FooterStyle.ButtonAreaStyle);
    this.FooterButtonArea.AppendChildControl(actioneButton);
    this.FooterButtonArea.AppendChildControl(cancelButton);
    this.Footer.AppendChildControl(this.FooterButtonArea);
};

GPActionDialog.prototype.CreateActionButton = function()
{
    var actionButton = this.CreateButtonInternal();

    return actionButton;
};

GPActionDialog.prototype.CreateButtonInternal = GPAction.prototype.CreateButtonInternal;

