Infoshare.GroupPicker.Navigation = function Infoshare$GroupPicker$Navigation() { }
GPNavigation = Infoshare.GroupPicker.Navigation;
GPNavigation.TypeName = 'Infoshare.GroupPicker.Navigation';

GPNavigation.SearchUITransitionOption = {
    ShowModalDialog : '0',
    Redirect        : '1',
    OpenWindow      : '2'
};

GPNavigation.InitializeContext = function(callback)
{
    GPContext.LoadjQuery = true;
    GPContext.Initialize(function () 
    {
        var css = ISString.TrimEnd(GPContext.SourcesPath, '/') + '/Infoshare/Infoshare.css';
        ISScript.Load(css, null, function () {
            // nothing to do...
        });

        GPViewContext.Initialize(callback, false);
    });
}

GPNavigation.RenderHyperLink = function(parentElement)
{
    GPNavigation.InitializeContext(function()
    {
        var link = new iLinkButton();
        link.Title = '電話帳';
        link.Render(parentElement);
        link.AddEvent(iControl.DomEventName.Click, function(control)
        {
            var url = ISString.TrimEnd(GPContext.SourcesPath, '/') + '/Infoshare.InfoCall/InfoCall.aspx'
                    + '?' + GPFinder.InitialzeParameterKey.OpenBy      + '=' + GPFinder.OpenByType.Window;
                    + '&' + GPFinder.InitialzeParameterKey.FinderClass + '=' + 'Infoshare.GroupPicker.Finder';

            iNavigation.Navigate(url);
        });
    });
}

GPNavigation.RenderSearchUI = function(parentElementId, transitionOption, description)
{
    // 機能が無効な場合には拡張しない
    if (typeof GPSettings == "undefined" ||
        !GPSettings.PhoneBookFeature)
    {
        // リソースをハードコードする（高速表示の為）
        var culture = _spPageContextInfo.currentUICultureName;
        var errorMessage = ISString.Equals(culture, 'ja-jp', true) ? "電話帳機能が無効になっています":
                                                                     "Phonebook feature is inactive";
        GPNavigation.RenderSearchUIErrorLabel(parentElementId, errorMessage);
        ISTrace.TraceWarning('[CANCELLED] GPNavigation.RenderSearchUI（Phonebook feature is inactive）');
        return;
    }

    if (!GPContext.IsSupportedBrowser())
    {
        // リソースをハードコードする（高速表示の為）
        var culture = _spPageContextInfo.currentUICultureName;
        var errorMessage = ISString.Equals(culture, 'ja-jp', true) ? "サポートされていないブラウザです" :
                                                                     "This browser is not supported";
        GPNavigation.RenderSearchUIErrorLabel(parentElementId, errorMessage);
        ISTrace.TraceWarning('[CANCELLED] GPNavigation.RenderSearchUI（This browser is not supported）');
        return;
    }

    GPNavigation.InitializeContext(function()
    {
        // ライセンス確認とメッセージの表示
        var message = (new iLicenseMessage()).BuildMessage(GPContext.Licenses, GPNavigation.TypeName);
        if ((new iLicenseValidator()).Validate(GPContext.Licenses, GPNavigation.TypeName))
        {
            // 利用可能な場合
            if (!iString.IsNullOrEmpty(message))
            {
                //iSPNotify.Notify(messageText, null, null, (new iLicenseMessage()).MessageDisplayTime);
                (new iNotifyer()).Notify(message, (new iLicenseMessage()).MessageDisplayTime);
            }

            GPNavigation.RenderSearchUIInternal(parentElementId, transitionOption, description);
        }
        else
        {
            // 利用不可の場合
            if (!iString.IsNullOrEmpty(message))
            {
                GPNavigation.RenderSearchUIErrorLabel(parentElementId, message);
            }
            return;
        }
    });
}

GPNavigation.RenderSearchUIErrorLabel = function(parentElementId, errorMessage)
{
        var parentElement = document.getElementById(parentElementId);
        var label = document.createElement("Div");
        label.innerText = errorMessage;
        label.style['color'] = "red";
        parentElement.appendChild(label);
}

GPNavigation.RenderSearchUIInternal = function(parentElementId, transitionOption, description)
{
    // panel
    var panel = new iSplitPanel(new GPSearchViewSplitPanelStyle());
    panel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
    panel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle(), new iPanelStyle()];
    panel.RenderingMode = iControl.RenderingMode.Append;
    panel.Style.ContainerStyles[0].Size.Height = 25;
    panel.Style.ContainerStyles[1].Size.Height = 25;
    panel.Style.ContainerStyles[2].Size.Height = 25;
       
    // filter - person
    var userFilter = new iDescribedCheckBox();
    userFilter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
    userFilter.Description = iResxResource.GetString('PickerDialog.SearchView.UserFilter.Title');        	
    panel.AppendChildControlForContainer(0, userFilter);
    // filter - organization
    var groupFilter = new iDescribedCheckBox();
    groupFilter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
    groupFilter.Description = iResxResource.GetString('PickerDialog.SearchView.GroupFilter.Title');
    panel.AppendChildControlForContainer(0, groupFilter);

    // searchbox
    var searchBox = new iSearchTextBox();
    var imagesPath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
    searchBox.Style.TextBoxStyle = new GPSearchTextBoxTextBoxStyle();
    searchBox.Style.ButtonStyle = new iSearchTextBoxImageButtonStyle(new iButtonImageInfo(imagesPath + 'Loupe.png',
                                                                                        '',
                                                                                        '',
                                                                                        imagesPath + 'Loupe-Press.png',
                                                                                        imagesPath + 'Loupe-Hover.png'));
    searchBox.Watermark = iResxResource.GetString('PickerDialog.SearchView.SearchTextBox.Watermark');        
    panel.AppendChildControlForContainer(1, searchBox);

    // description
    var descriptionForSearchBox = new iLabel();
    descriptionForSearchBox.Text = description;
    panel.AppendChildControlForContainer(2, descriptionForSearchBox);

    // add event handler for search
    searchBox.AddEvent(iSearchTextBox.EventName.Search, function(control)
    {
        var searchKeyword = control.GetValue();
        var userFilterEnabled = userFilter.IsChecked();
        var groupFilterEnabled = groupFilter.IsChecked();            
        var pageUrl = ISString.TrimEnd(GPContext.SiteUrl, '/')
                    + '/InfoshareProductLibrary/Sources/Infoshare.InfoCall/InfoCall.aspx';
          
        var searchKeywordSpaceTrimed = ISString.Trim(ISString.Trim(searchKeyword, " "), "　");
        if (!ISString.IsNullOrEmpty(searchKeywordSpaceTrimed))
        {            
            pageUrl += '?' + GPConfiguration.QueryStringKeyName.SearchKeyword + '=' + encodeURIComponent(searchKeyword);
            pageUrl += '&' + GPConfiguration.QueryStringKeyName.UserFilterEnabled + '=' + userFilterEnabled;
            pageUrl += '&' + GPConfiguration.QueryStringKeyName.GroupFilterEnabled + '=' + groupFilterEnabled;
            
            // ダイアログで開く場合には、GPContextに検索条件をキャッシュさせる
            if (transitionOption == GPNavigation.SearchUITransitionOption.ShowModalDialog)
            {
            GPContext.SearchKeyword = searchKeyword;
            if(userFilterEnabled == false && groupFilterEnabled == false)
            {
                GPContext.UserFilterEnabled = true;                                     
            }
            else
            {
                GPContext.UserFilterEnabled = userFilterEnabled;
                GPContext.GroupFilterEnabled = groupFilterEnabled;
            }
        }
        }
        else
        {
            alert(iResxResource.GetString('PickerDialog.SearchView.EmptyKeywordErrorMessage'));
            return;
        }

        switch (transitionOption)
        {
            case GPNavigation.SearchUITransitionOption.ShowModalDialog:
                var dialog = GPDialog.CreateFinderDialog();
                if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Modern)
                {
                    // モダンUIの場合、CoreCssが適用されずスタイルが崩れるため、CoreCssより作成したスタイルを適用する
                    dialog.Dialog.Style.EnableClassName = "is-gp-ModernDialog-FromCoreCSS";
                }
                GPDialog.Open(dialog);
                break;
            case GPNavigation.SearchUITransitionOption.Redirect:
                document.location.href = pageUrl;
                break;
            case GPNavigation.SearchUITransitionOption.OpenWindow:
                window.open(pageUrl);
                break;
	        default:    // unexpected
                return;
        }

        // ダイアログ起動の後にコントロールのフォーカスを外す
        control.Element.children[0].blur();
    });

    // render controls
    panel.Render(parentElementId);
    userFilter.CheckBox.Check();
}


// -----------------------------------------------------------------------
//  SearchControl
// -----------------------------------------------------------------------
Infoshare.GroupPicker.SearchControl = function Infoshare$GroupPicker$SearchControl(){ };
GPSearchControl = Infoshare.GroupPicker.SearchControl;

GPSearchControl.prototype = {
    ParentElementId: null,
    ParentElement: null,

    TransitionMode: iNavigation.TransitionType.OpenWindow,
    Watermark: null,
    Description: null,

    FilterEnabled: true,
    
    UserFilter: null,
    GroupFilder: null,
    SearchBox: null,


    Render: function()
    {
        if (!this.validate())
        {
            return;
        }

        // 遷移オプションによって初期化
        if (this.TransitionMode == iNavigation.TransitionType.Dialog)
        {
            // 同一 DOM 内（同一ウィンドウ内）での処理となるため、コンテキストの初期化が必要
            var ref = this;
            GPNavigation.InitializeContext(function ()
            {
                // ライセンス確認とメッセージの表示
                var message = (new iLicenseMessage()).BuildMessage(GPContext.Licenses, GPNavigation.TypeName);
                if ((new iLicenseValidator()).Validate(GPContext.Licenses, GPNavigation.TypeName))
                {
                    // 利用可能な場合
                    if (!iString.IsNullOrEmpty(message))
                    {
                        //iSPNotify.Notify(messageText, null, null, (new iLicenseMessage()).MessageDisplayTime);
                        (new iNotifyer()).Notify(message, (new iLicenseMessage()).MessageDisplayTime);
                    }

                    ref.renderControl();
                }
                else
                {
                    // 利用不可の場合
                    if (!iString.IsNullOrEmpty(message))
                    {
                        ref.renderError(message);
                    }
                }
            });
        }
        else
        {
            // 別DOM（別ウィンドウ）への遷移となるため、基本的にはコンテキストの初期化は不要
            // ただし、コンテキスト初期化時に設定されるいくつかの値と、リソースは画面描画に必要
            // ToDo: 以下2点、対応検討
            //  1. 最低限の初期化
            //  2. ライセンスチェックの要否を検討（遷移先でチェックされるので不要か）

            GPContext.SiteUrl    = _spPageContextInfo.siteAbsoluteUrl;
            GPContext.ImagesPath = iString.TrimEnd(GPContext.SiteUrl, '/') + '/InfoshareProductLibrary/Sources/';

            var res = { Resources: null,
                        GetString: function (key) { return this.Resources.Get(key); }};
            res.Resources = new iDictionary();
            res.Resources.Add('PickerDialog.SearchView.UserFilter.Title',         '人');
            res.Resources.Add('PickerDialog.SearchView.GroupFilter.Title',        '組織');
            res.Resources.Add('PickerDialog.SearchView.EmptyKeywordErrorMessage', 'キーワードに空文字列を指定することはできません');
            res.Resources.Add('PickerDialog.SearchView.SearchTextBox.Watermark',  '検索キーワードを入力');
            iCompoundResource.GetInstance().Resources.Add(0, res);

            this.renderControl();
        }
    },

    renderControl: function()
    {
        // レイアウトパネル
        var panel = new iSplitPanel(new GPSearchViewSplitPanelStyle());
        panel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
        panel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle(), new iPanelStyle()];
        panel.RenderingMode = iControl.RenderingMode.Append;
        panel.Style.ContainerStyles[0].Size.Height = 25;
        panel.Style.ContainerStyles[1].Size.Height = 25;
        panel.Style.ContainerStyles[2].Size.Height = 25;
       
        // フィルタ - 人
        var userFilter = new iDescribedCheckBox();
        userFilter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
        userFilter.Description = iResxResource.GetString('PickerDialog.SearchView.UserFilter.Title');
        panel.AppendChildControlForContainer(0, userFilter);
        this.UserFilter = userFilter;

        // フィルタ - 組織
        var groupFilter = new iDescribedCheckBox();
        groupFilter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
        groupFilter.Description = iResxResource.GetString('PickerDialog.SearchView.GroupFilter.Title');
        panel.AppendChildControlForContainer(0, groupFilter);
        this.GroupFilder = groupFilter;

        // 検索テキストボックス
        var searchBox = new iSearchTextBox();
        var imagesPath = iString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
        searchBox.Style.TextBoxStyle = new GPSearchTextBoxTextBoxStyle();
        searchBox.Style.ButtonStyle = new iSearchTextBoxImageButtonStyle(new iButtonImageInfo(imagesPath + 'Loupe.png',
                                                                                            '',
                                                                                            '',
                                                                                            imagesPath + 'Loupe-Press.png',
                                                                                            imagesPath + 'Loupe-Hover.png'));
        searchBox.Watermark = this.getWatermarkText();
        panel.AppendChildControlForContainer(1, searchBox);
        this.SearchBox = searchBox;

        // 説明
        var descriptionForSearchBox = new iLabel();
        descriptionForSearchBox.Text = this.Description;
        panel.AppendChildControlForContainer(2, descriptionForSearchBox);

        // イベント登録
        searchBox.AddEvent(iSearchTextBox.EventName.Search, iFunction.CreateDelegate(this.onSearch, this));

        // コントロール描画
        panel.Render(this.getParentElement());
        userFilter.CheckBox.Check();

        // フィルタ/説明 - コントロール非表示
        if (!this.FilterEnabled)                     { panel.Containers[0].Hide(); }
        if (iString.IsNullOrEmpty(this.Description)) { panel.Containers[2].Hide(); }
    },

    onSearch: function(control)
    {
        var searchKeyword      = this.SearchBox.GetValue();
        var userFilterEnabled  = this.UserFilter.IsChecked();
        var groupFilterEnabled = this.GroupFilder.IsChecked();            
        var url = iString.TrimEnd(GPContext.SiteUrl, '/')
                + '/InfoshareProductLibrary/Sources/Infoshare.InfoCall/InfoCall.aspx';
        
        // 検索条件処理
        var searchKeywordSpaceTrimed = iString.Trim(iString.Trim(searchKeyword, " "), "　");
        if (!iString.IsNullOrEmpty(searchKeywordSpaceTrimed))
        {            
            if (this.TransitionMode == iNavigation.TransitionType.Dialog)
            {
                // ダイアログで開く場合には、GPContextに検索条件をキャッシュさせる
                GPContext.SearchKeyword = searchKeywordSpaceTrimed;
                if(userFilterEnabled == false && groupFilterEnabled == false)
                {
                    GPContext.UserFilterEnabled = true;                                     
                }
                else
                {
                    GPContext.UserFilterEnabled  = userFilterEnabled;
                    GPContext.GroupFilterEnabled = groupFilterEnabled;
                }
            }
            else
            {
                // 別DOM（別ウィンドウ）への遷移する場合、URLにパラメーターを設定する
                var parameter = new iUriParameter();
                parameter.Set(GPConfiguration.QueryStringKeyName.SearchKeyword,      searchKeywordSpaceTrimed);
                parameter.Set(GPConfiguration.QueryStringKeyName.UserFilterEnabled,  userFilterEnabled);
                parameter.Set(GPConfiguration.QueryStringKeyName.GroupFilterEnabled, groupFilterEnabled);
                url += '?' + parameter.ToString();
            }
        }
        else
        {
            alert(iResxResource.GetString('PickerDialog.SearchView.EmptyKeywordErrorMessage'));
            return;
        }

        // 遷移
        switch (this.TransitionMode)
        {
            case iNavigation.TransitionType.Navigate: // fall through
            case iNavigation.TransitionType.Redirect:
                iNavigation.Navigate(url);
                break;

            case iNavigation.TransitionType.OpenWindow: // fall through
            case iNavigation.TransitionType.NewWindow:
                iNavigation.OpenWindow(url);
                break;

            case iNavigation.TransitionType.Dialog:
                var dialog = GPDialog.CreateFinderDialog();
                GPDialog.Open(dialog);
                break;

            default: // unexpected
                // ToDo: エラーメッセージ出力を検討
                break;
        }

        // 遷移後、コントロールのフォーカスを外す
        control.Element.children[0].blur();
    },

    // ToDo: 関数名検討
    validate: function()
    {
        var errorMessage = '';

        // 機能の状態を確認
        if (typeof GPSettings == 'undefined' || !GPSettings.PhoneBookFeature)
        {
            // ToDo: メッセージをリソースに移動、表示言語の取得方法を調整
            var culture  = _spPageContextInfo.currentUICultureName;
            errorMessage = iString.Equals(culture, 'ja-jp', true) ? '電話帳機能が無効になっています' :
                                                                    'Phonebook feature is inactive';

            ISTrace.TraceWarning('[CANCELLED] GPSearchControl.Render（Phonebook feature is inactive）');
        }

        // ブラウザを確認
        if (!GPContext.IsSupportedBrowser())
        {
            // ToDo: メッセージをリソースに移動、表示言語の取得方法を調整
            var culture  = _spPageContextInfo.currentUICultureName;
            errorMessage = iString.Equals(culture, 'ja-jp', true) ? 'サポートされていないブラウザです' :
                                                                    'This browser is not supported';

            ISTrace.TraceWarning('[CANCELLED] GPSearchControl.Render（This browser is not supported）');
        }

        // エラー表示
        if (!iString.IsNullOrEmpty(errorMessage))
        {
            this.renderError(errorMessage);
        }

        // メッセージ未設定の場合は、検証成功
        return iString.IsNullOrEmpty(errorMessage)
    },

    renderError: function(message)
    {
        var element = document.createElement('Div');
        label.innerText      = message;
        label.style['color'] = 'red';

        this.getParentElement().appendChild(element);
    },

    getParentElement: function()
    {
        if (!this.ParentElement)
        {
            this.ParentElement = document.getElementById(this.ParentElementId);
        }

        return this.ParentElement;
    },

    getWatermarkText: function()
    {
        var watermark = this.Watermark;
        if (iString.IsNullOrEmpty(watermark))
        {
            watermark = iResxResource.GetString('PickerDialog.SearchView.SearchTextBox.Watermark');
        }

        return watermark;
    }
};
                            
