Infoshare.GroupPicker.PresenceUtility = function Infoshare$GroupPicker$PresenceUtility() { }
GPPresenceUtility = Infoshare.GroupPicker.PresenceUtility;

GPPresenceUtility.GetPresenceLinkHTMLTemplate = function ()
{    
    var outerHtml = "<span class='ms-imnSpan'>"
                  +     "<a class='ms-imnlink ms-spimn-presenceLink' href='#'>"
                  +         "<span class='ms-spimn-presenceWrapper ms-imnImg ms-spimn-imgSize-10x10'>"
                  +             "<img name='imnmark' class='ms-spimn-img ms-spimn-presence-disconnected-10x10x32' id='imn_{0}' alt='" + Strings.STS.L_UserFieldNoUserPresenceAlt + "' src='{ImageURL}' showofflinepawn='1' sip='{1}'>"
                  +         "</span>"
                  +     "</a>"
                  + "</span>";

    var imageUrl = ISString.TrimEnd(GPContext.LayoutsPath, '/') + "/15/images/spimn.png";
    outerHtml = ISString.Replace(outerHtml, "{ImageURL}", imageUrl, true);

    return outerHtml;
};

GPPresenceUtility.OnClickPresenceLink = function ()
{
    IMNImageOnClick(event);
    return false;
};

GPPresenceUtility.UpdatePresenceLink = function (parentElementId)
{
    // クリックイベントを追加
    GPPresenceUtility.UpdatePresenceOnClick(parentElementId);

    // 選択行のスタイル修正(Class属性を含むTemplateを付与した際のIGGridの挙動によるバグ)
    GPPresenceUtility.AddParentTdClassName(parentElementId);

    // ProcessImn関数が存在しない場合
    if (typeof(ProcessImn) != "function")
    {
        return;
    }

    // SP2016はプレゼンスの表示にユーザーIDが必要になった
    // ページ単体で開かれた場合は_spPageContextInfoが作成されずユーザーIDを持たない為、一時的に設定する
    if (typeof _spPageContextInfo !== 'undefined')
    {
        // 初期化メソッドを呼ぶ
        ProcessImn();
    }
    else
    {
        iVxService.GetSPVersion(function (version) {
            if (version === '16')
            {
                iVxService.GetCurrentUser(function (user) {
                    _spPageContextInfo = { userId: user.Id };
                    // 初期化メソッドを呼ぶ
                    ProcessImn();
                    _spPageContextInfo = undefined;
                });
            }
            else
            {
                // 初期化メソッドを呼ぶ
                ProcessImn();
            }
        });
    }
};

GPPresenceUtility.UpdatePresenceOnClick = function (parentElementId)
{
    var selector = "#" + parentElementId 
                 + " "
                 + ".ms-spimn-presenceLink";

    var presenceLinks = i$(selector);
    if (presenceLinks.length < 1)
    {
        return;
    }

    presenceLinks.on('click', GPPresenceUtility.OnClickPresenceLink);
};

GPPresenceUtility.AddParentTdClassName = function (parentElementId)
{
    var selector = "#" + parentElementId 
                 + " "
                 + ".ui-iggrid-selectedcell.ui-state-active.ms-imnSpan";

    var presenceLinks = i$(selector);
    if (presenceLinks.length < 1)
    {
        return;
    }
    
    for (var i = 0; i < presenceLinks.length; i++)
    {
        var parentTd = presenceLinks[i].parentElement;

        if (ISString.IsNullOrEmpty(parentTd.className))
        {
            parentTd.className = 'ui-iggrid-selectedcell ui-state-active';
        }
    }
};
                            
