Infoshare.GroupPicker.IcWebPartEditorExtender = function Infoshare$GroupPicker$IcWebPartEditorExtender()
{
    Infoshare.SharePoint.WebPartEditorExtender.apply(this, arguments);
}
GPIcWebPartEditorExtender = Infoshare.GroupPicker.IcWebPartEditorExtender;
GPIcWebPartEditorExtender.TypeName = 'Infoshare.GroupPicker.IcWebPartEditorExtender';
GPIcWebPartEditorExtender.ClassInfo = null;

GPIcWebPartEditorExtender.Initialize = function(){}

GPIcWebPartEditorExtender.CanExtend = function ()
{
    var canExtend = false;

    // InfoCallWP設定用のコントロールの存在確認
    var icSettingInput = document.getElementById("Infoshare.WP.Settings.TransitionOption");
    if (icSettingInput)
    {
        canExtend = true;
    }

    return canExtend;
}

GPIcWebPartEditorExtender.prototype = new Infoshare.SharePoint.WebPartEditorExtender();
GPIcWebPartEditorExtender.prototype.ClassNamePrefix = "is-InfoCallWP";
GPIcWebPartEditorExtender.prototype.SelectElmName = "is-InfoCallWP-TransitionOptionSelect";
GPIcWebPartEditorExtender.prototype.DescriptionTextAreaElmName = "is-InfoCallWP-DescriptionTextArea";
GPIcWebPartEditorExtender.prototype.Extend = function ()
{
    this.WebPartEditPane = this.ParentExtender.WebPartEditPane;
    this.BorderTR = this.ParentExtender.BorderTR;
    this.SettingDiv = this.ParentExtender.SettingDiv;
    this.WebPartSaveActionButtons = this.ParentExtender.WebPartSaveActionButtons;

    this.ExtendInternal();
    this.PostExtend();
}

GPIcWebPartEditorExtender.prototype.CanExtend = GPIcWebPartEditorExtender.CanExtend;

GPIcWebPartEditorExtender.prototype.ExtendInternal = function ()
{
    if (!this.SettingDiv)
    {
        return;
    }

    // タイトルの差し替え
    this.OverwriteCaption();

    // コンテンツの差し替え
    this.OverwriteContent();

    // コンテンツを一回折りたたみ再度開いた時に発生するスタイルずれを修正
    if (this.BorderTR)
    {
        this.BorderTR.style.border = "none";
    }

    // OK、適応ボタンの動作の差し替え
    this.OverwriteSaveAction();
}

GPIcWebPartEditorExtender.prototype.PostExtend = function ()
{
    // 遷移オプションの初期表示変更
    var selectElemnt = document.getElementById(this.SelectElmName);
    // 設定値の取得
    var settingValue = document.getElementById("Infoshare.WP.Settings.TransitionOption").value;
    if (!settingValue)
    {
        settingValue = 0;
    }
    selectElemnt.selectedIndex = settingValue;

    // 説明文テキストの設定値の表示
    var descriptionTextareaElement = document.getElementById(this.DescriptionTextAreaElmName);
    var descriptionSettingValue = document.getElementById("Infoshare.WP.Settings.Description").innerText;
    descriptionTextareaElement.value = descriptionSettingValue;
}

GPIcWebPartEditorExtender.prototype.OverwriteCaption = function ()
{
    var captionSpan = document.getElementById('MSOTlPn_TlPnCaptionSpan');
    captionSpan.innerHTML = iResxResource.GetString("InfoCallWebPart.Title");        

    var titleDivElm = this.WebPartEditPane.getElementsByClassName("ms-TPTitle");
    if (titleDivElm.length != 1)
    {
        return;
    }

    var titleSpan = titleDivElm[0].children[0].children[0];
    if (titleSpan)
    {
        titleSpan.innerHTML = iResxResource.GetString("InfoCallWebPart.Category");            
    }
}

GPIcWebPartEditorExtender.prototype.OverwriteContent = function ()
{
    var builder = new Array();
    
    builder[builder.length] = "<div class='ms-TPBody'>";
    builder[builder.length] =   "<div>";
    builder[builder.length] =     "<table style='width: 100%;'>";
    builder[builder.length] =       "<tbody>";

    // 遷移オプションtr
    builder[builder.length] = "<tr>";
    builder[builder.length] =   "<div style='padding-bottom: 5px;'>";
    builder[builder.length] =     "<span title='" + iResxResource.GetString("InfoCallWebPart.WebDescription.TransitionOption") +  "'>";
    builder[builder.length] =     iResxResource.GetString("InfoCallWebPart.WebDisplayName.TransitionOption")
    builder[builder.length] =     "</span>";
    builder[builder.length] =   "</div>";
    builder[builder.length] =   "<div style='padding-bottom: 5px;'>";
    builder[builder.length] =     "<div>";
    builder[builder.length] =       "<select id='" + this.SelectElmName + "' name='" + this.SelectElmName + "'>";
    builder[builder.length] =         "<option value='0'>";
    builder[builder.length] =         iResxResource.GetString("InfoCallWebPart.TransitionOption.ShowModalDialog");
    builder[builder.length] =         "</option>";
    builder[builder.length] =         "<option value='1'>";
    builder[builder.length] =         iResxResource.GetString("InfoCallWebPart.TransitionOption.Redirect");
    builder[builder.length] =         "</option>";
    builder[builder.length] =         "<option value='2'>";
    builder[builder.length] =         iResxResource.GetString("InfoCallWebPart.TransitionOption.OpenWindow");
    builder[builder.length] =         "</option>";
    builder[builder.length] =       "</select>";
    builder[builder.length] =     "</div>";
    builder[builder.length] =   "</div>";
    builder[builder.length] =   "<div class='UserDottedLine' style='width: 100%;'>";
    builder[builder.length] =   "</div>";
    builder[builder.length] = "</tr>";

    // 説明文tr
    builder[builder.length] = "<tr>";
    builder[builder.length] =   "<div style='padding-bottom: 5px;'>";
    builder[builder.length] =     "<span title='" + iResxResource.GetString("InfoCallWebPart.WebDescription.Description") +  "'>";
    builder[builder.length] =     iResxResource.GetString("InfoCallWebPart.WebDisplayName.Description")
    builder[builder.length] =     "</span>";
    builder[builder.length] =   "</div>";
    builder[builder.length] =   "<div style='padding-bottom: 5px;'>";
    builder[builder.length] =     "<div>";
    builder[builder.length] =       "<textarea id='" + this.DescriptionTextAreaElmName + "' >";
    builder[builder.length] =       "</select>";
    builder[builder.length] =     "</div>";
    builder[builder.length] =   "</div>";
    builder[builder.length] = "</tr>";
    
    builder[builder.length] =       "</tbody>";
    builder[builder.length] =     "</table>";
    builder[builder.length] =   "</div>";
    builder[builder.length] = "</div>";

    this.SettingDiv.innerHTML = builder.join('');
}

GPIcWebPartEditorExtender.prototype.OverwriteSaveAction = function ()
{
    var extender = this;
    for (var i = 0; i < this.WebPartSaveActionButtons.length; i++)
    {
        var button = this.WebPartSaveActionButtons[i];
        var baseOnclick = button.onclick;

        var onclick = function(event)
        {
            extender.UpdateSettings();
            baseOnclick(event);
        };

        button.onclick = onclick;
    }
}

GPIcWebPartEditorExtender.prototype.UpdateSettings = function ()
{
    // 遷移オプションの上書き
    var selectElemnt = document.getElementById(this.SelectElmName);
    var currentValue = selectElemnt.options[selectElemnt.selectedIndex].value;
    document.getElementById("Infoshare.WP.Settings.TransitionOption").value = currentValue;

    // 説明文の上書き
    var descriptionTextareaElement = document.getElementById(this.DescriptionTextAreaElmName);
    document.getElementById("Infoshare.WP.Settings.Description").innerText = descriptionTextareaElement.value;
}
								  
