// -----------------------------------------------------------------------
//  HierarchicalIdUtility
// -----------------------------------------------------------------------
Infoshare.GroupPicker.HierarchicalIdUtility = function Infoshare$GroupPicker$HierarchicalIdUtility() { }
GPHierarchicalIdUtility = Infoshare.GroupPicker.HierarchicalIdUtility;

GPHierarchicalIdUtility.Separator = '|';
GPHierarchicalIdUtility.Connector = '_';

GPHierarchicalIdUtility.GetMemberOfString = function(entities) 
{
    var memberOfString = "";
    if (entities.length > 0) 
    {
        memberOfString += GPHierarchicalIdUtility.Separator;
        for (var i = 0; i < entities.length; i++)
        {
            memberOfString += entities[i].Properties.EntityId;
            memberOfString += GPHierarchicalIdUtility.Separator;
        }
    }

    return memberOfString;
}

GPHierarchicalIdUtility.CreateHierarchialId = function (baseEntities, entityId) 
{
    var hierarchicalId = "";

    for (var i = 0; i < baseEntities.length; i++) 
    {
        var entity = baseEntities[i];
        var baseHierarchicalId = entity.Properties.HierarchicalId;

        hierarchicalId += GPHierarchicalIdUtility.AppendHierarchialId(baseHierarchicalId, entityId);
    }

    // ||セパレータが複数ある箇所を修正する
    ISString.Replace(hierarchicalId, GPHierarchicalIdUtility.Separator + GPHierarchicalIdUtility.Separator, GPHierarchicalIdUtility.Separator);
    return hierarchicalId;
}

GPHierarchicalIdUtility.AppendHierarchialId = function (baseId, entityId) 
{
    var idArray = GPHierarchicalIdUtility.GetIdCollections(baseId);
    var hierarchicalId = GPHierarchicalIdUtility.Separator;
    for (var i = 0; i < idArray.length; i++) 
    {
        hierarchicalId += idArray[i];
        hierarchicalId += GPHierarchicalIdUtility.Connector;
        hierarchicalId += entityId;
        hierarchicalId += GPHierarchicalIdUtility.Separator;
    }

    return hierarchicalId;
}

GPHierarchicalIdUtility.GetIdCollections = function (hierarchicalIdString)
{
    var hierarchicalId = null;

    var hierarchicalIdArray = [];
    if (!ISString.IsNullOrEmpty(hierarchicalIdString)) 
    {
        var hierarchicalIdArrayContainsSpace = hierarchicalIdString.split(GPHierarchicalIdUtility.Separator);
        for (var i = 0; i < hierarchicalIdArrayContainsSpace.length; i++)
        {
            var id = hierarchicalIdArrayContainsSpace[i];
            if (!ISString.IsNullOrEmpty(id))
            {
                hierarchicalIdArray.push(id);
            }
        }
    }

    return hierarchicalIdArray;
};


GPHierarchicalIdUtility.GetIdByIndex = function (hierarchicalIdString, index)
{
    var hierarchicalId = null;

    var hierarchicalIdArray = GPHierarchicalIdUtility.GetIdCollections(hierarchicalIdString);
    hierarchicalId = hierarchicalIdArray.length > index - 1 ? hierarchicalIdArray[index] : hierarchicalId;

    return hierarchicalId;
};

GPHierarchicalIdUtility.GetLevel = function (hierarchicalId)
{
    var level = 0;

    var regString = ISString.Format("/{0}/g", GPHierarchicalIdUtility.Connector);
    var regEx = eval(regString);
    var matchResults = hierarchicalId.match(regEx);
    if (matchResults)
    {
        level = matchResults.length;
    }

    return level;
};

GPHierarchicalIdUtility.GetParentId = function (hierarchicalId)
{
    // 含まれない場合は""を返す
    var lastIndex = hierarchicalId.lastIndexOf(GPHierarchicalIdUtility.Connector);
    var parentId  = hierarchicalId.substring(0, lastIndex)
    
    return parentId;
};

GPHierarchicalIdUtility.GetChildId = function (hierarchicalId, targetId)
{
    // targetId以下の階層IDを返す   
    // 例：hierarchicalId：S-1-5-21-958660677-781208019-2833013274-338178_S-1-5-21-958660677-781208019-2833013274-14937_S-1-5-21-958660677-781208019-2833013274-36123
    //     targetId　　　：S-1-5-21-958660677-781208019-2833013274-14937
    //     return        ：S-1-5-21-958660677-781208019-2833013274-14937_S-1-5-21-958660677-781208019-2833013274-36123

    // 含まれない場合は""を返す
    var childId = "";

    var targetIndex = hierarchicalId.lastIndexOf(targetId);
    if (targetIndex != -1)
    {
        childId  = hierarchicalId.substring(targetIndex, hierarchicalId.length)
    }
    
    return childId;
};

GPHierarchicalIdUtility.GetEntityIdCollection = function(singleHierarchicalId)
{
    // 階層IDからEntityIDの分離する
    // 例：|A_B_C_D_Entity|
    // [A, B, C, D, Entity]
    var entityIdCollection = [];
    if (!ISString.IsNullOrEmpty(singleHierarchicalId))
    {
        singleHierarchicalId = ISString.Trim(singleHierarchicalId, GPHierarchicalIdUtility.Separator);
        entityIdCollection = singleHierarchicalId.split(GPHierarchicalIdUtility.Connector);
    }   

    return entityIdCollection;
};

GPHierarchicalIdUtility.IsMemberOfHierarcy = function(singleHierarchicalId, entityId)
{
    var entityIdCollection = GPHierarchicalIdUtility.GetEntityIdCollection(singleHierarchicalId);
    var isMemberOf = ISArray.Contains(entityIdCollection, entityId);

    return isMemberOf;
};

GPHierarchicalIdUtility.GetEntitiesByHierarchicalId = function(view, singleHierarchicalId, retrieveSiblingEntity, targetRootEntity, callback)
{
    // 階層IDからエンティティのコレクションを取得する
    var entityIdCollection = GPHierarchicalIdUtility.GetEntityIdCollection(singleHierarchicalId);

    // 階層レベル毎のDictionaryの作成
    var entityLevelDictionary = new ISDictionary();

    // 非同期コンテキスト
    var getEntitiesContext = {
        ensuredCount: 0,
        Completed: function()
        {
            return this.ensuredCount == entityIdCollection.length;
        }
    }

    // エンティティ取得後のコールバック処理
    var entitiesEnsuredCallback = function (entityLevel, entities)
    {        
        var levelString = entityLevel.toString();
        var levelGroupArray = entities;
        entityLevelDictionary.Add(levelString, levelGroupArray);

        getEntitiesContext.ensuredCount++;
        if (getEntitiesContext.Completed())
        {
            callback(entityLevelDictionary);
        }        
    };

    // エンティティの取得
    for(var i = 0; i < entityIdCollection.length; i++)
    {
        // Rootノードの場合には、データソース定義からエンティティを取得する
        var entityId = entityIdCollection[i];
        if (ISString.Equals(entityId, targetRootEntity.Properties["EntityId"]))
        {
            var entities = [];
            var entity = targetRootEntity;
            entities.push(entity);
            entitiesEnsuredCallback(i, entities);
        }
        // それ以外のエンティティはクエリを発行し、エンティティを取得する
        else
        {
            // 兄弟エンティティを取得する場合には
            // 親エンティティのMemberOfでクエリする
            if (retrieveSiblingEntity)
            {
                (function (entityLevel)
                {
                    GPHierarchicalIdUtility.GetMemberOfEntities(view, entityIdCollection[i - 1], function (entities)
                    {
                        entitiesEnsuredCallback(entityLevel, entities);
                    });
                }(i));
            }
            else
            {
                (function (entityLevel)
                {
                    GPHierarchicalIdUtility.GetEntity(view, entityId, function (entity)
                    {
                        entitiesEnsuredCallback(entityLevel, entity);
                    });
                }(i));
            }
        }
    }
};

GPHierarchicalIdUtility.GetMemberOfEntities = function(view, parentEntityId, callback)
{
    // Temporary Fix
    // ToDo(skomatsu): クエリ処理の統一が急務
    // 高速化クエリ（MemberOfId多重クエリ）が有効な場合とその他でスイッチする
    var fieldName = 'MemberOf';
    var multiplicity = iNumber.TryParse(view.Info.Options.Get('MemberOfIdQueryMultiplicity'), 0);
    if (multiplicity == 1)
    {
        fieldName = 'MemberOfId1';
    }

    var query = GPHierarchicalIdUtility.BuildQuery(fieldName, view, parentEntityId);

    // 組織管理アドオンが有効の場合
    if (GPViewContext.SupplemenntMasterList)
    {
        // AddressBookデータソース、補助マスタに問い合わせてマージする
        var context = {
            // AddressBookDataSourceから取得されたEntities
            BaseEntities: null,
            // SupplementMasterから取得されたEntities
            SupplementMasterEntities: null,

            BaseEntitiesEnsured: false,
            SupplementMasterEntitiesEnsured: false,

            Completed: function () {
                var complete = this.BaseEntitiesEnsured &&
                               this.SupplementMasterEntitiesEnsured;
                return complete;
            }
        };

        var completeCallback = function()
        {
            if (context.Completed())
            {
                // マージする
                GPViewContext.MargeEntitiesForSupplementMasterEntities(
                context.BaseEntities,
                context.SupplementMasterEntities,
                view.DataSource.WebUrl,
                view.DataSource.DataSourceList,
                function (effectiveEntities)
                {
                    // 属性を更新する
                    effectiveEntities = view.OverWriteEntities(effectiveEntities);
                    
                    // ソートする
                    effectiveEntities = view.SortEntities(effectiveEntities);

                    // コールバック
                    callback(effectiveEntities);
                });    
            }
        };

        // AddressBookData
        iVxService.RetrieveItems(view.DataSource.WebUrl, view.DataSource.DataSourceList, query, true, function(baseEntities)
        {
            context.BaseEntitiesEnsured = true;
            context.BaseEntities = baseEntities;
            completeCallback();      
        });    

        // SupplementMaster
        iVxService.RetrieveItems(iVxContext.MasterSiteAbsolutePath, GPViewContext.SupplemenntMasterList, query, true, function(supllementMasterEntities)
        {
            context.SupplementMasterEntitiesEnsured = true;
            context.SupplementMasterEntities = supllementMasterEntities;
            completeCallback();
        });    
    }
    else
    {
        GPGridUtility.GetEntities(view.DataSource, query, function(items)
        {
            callback(items);
        });    
    }
};

GPHierarchicalIdUtility.GetEntity = function(view, entityId, callback)
{
    var query = GPHierarchicalIdUtility.BuildQuery("EntityId", view, entityId);
    GPGridUtility.GetEntities(view.DataSource, query, function(items)
    {
        callback(items);
    });
};

GPHierarchicalIdUtility.BuildQuery = function(queryType, view, entityId)
{
    var query = new ISSPQuery();
    query.TryQuery = false;

    var queryTemplete   = "<Query>"
                        +   "<Where>"
                        +     "%Where%"
                        +   "</Where>"
                        +   "<OrderBy>"
                        +     "%OrderByConfigs%"
                        +   "</OrderBy>"
                        + "</Query>";

    // Whare句
    var whereQuery = "";

    // MemberOfQuery組み立て
    if (queryType == "MemberOf")
    {
        var parentId = "|" + entityId + "|";
        var memberOfQuery = SPQueryBuilder.BuildContainsQueryCondition("MemberOf", "Note", parentId);

        // ShowInViewQuery組み立て
        // ToDo: View定義からIDを連携するように改修
        var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "OrganizationView:Tree");
        var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
        showInTreeQuery = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);
        whereQuery = SPQueryBuilder.BuildAndQueryCondition(memberOfQuery + showInTreeQuery);

        // パフォーマンス関連の設定
        // クエリ順序の設定（ShowInTreeを先に実行し、TryQueryを発行する）
        var showInTreeFieldInfo = GPContext.Configuration.Fields.Get("ShowInTree");
        if (showInTreeFieldInfo.Indexed)
        {
            whereQuery = SPQueryBuilder.BuildAndQueryCondition(showInTreeQuery + memberOfQuery);
            query.TryQuery = true;
        }
    }

    // Temporary Fix
    // ToDo(skomatsu): クエリ処理の統一が急務
    // MemberOfIdQuery組み立て
    else if (queryType == 'MemberOfId1')
    {
        var memberOfQuery = SPQueryBuilder.BuildEqualQueryCondition("MemberOfId1", "Text", entityId);
        // ToDo: View定義からIDを連携するように改修
        var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "OrganizationView:Tree");
        var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
        showInTreeQuery = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);
        whereQuery = SPQueryBuilder.BuildAndQueryCondition(memberOfQuery + showInTreeQuery);
        query.TryQuery = true;
    }

    // EntityIdQuery組み立て
    else if (queryType == "EntityId")
    {        
        var entityIdQuery = SPQueryBuilder.BuildEqualQueryCondition("EntityId", "Text", entityId);
        whereQuery = entityIdQuery;
    }
            
    // EnableVisibleGroups=trueの場合、CurrentUserのVisibleGroupsを検索条件に追加する
    var enableVisibleGroups = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableVisibleGroups'), false);
    if (enableVisibleGroups)
    {
        whereQuery = GPCamlQueryCondition.AddVisibleGroupsCondition(whereQuery, GPViewContext.CurrentUserEntity);
    }

    // Query句の設定
    query.Query = queryTemplete.replace("%Where%", whereQuery);

    // OrderByのquery組み立て
    var orderByConfigs = "";
    for (var i = 0; i < view.Info.SortOrders.length; i++)
    {
        var orderByTemplete = "<FieldRef Name='%OrderByName%' Ascending='%OrderByAscending%'/>";
        orderByTemplete = orderByTemplete.replace("%OrderByName%", view.Info.SortOrders[i].FieldName);
        orderByTemplete = orderByTemplete.replace("%OrderByAscending%", view.Info.SortOrders[i].Ascending);
        orderByConfigs += orderByTemplete;
    }
    query.Query = query.Query.replace("%OrderByConfigs%", orderByConfigs);

    // ViewField設定 
    var fieldRefs = '';
    for(var i = 0; i < view.Info.ViewFields.GetLength(); i++)
    {
        var field = view.Info.ViewFields.Get(i);
        fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
    }        
    query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

    return query;
};                            
