Infoshare.GroupPicker.FunctionExtender = function Infoshare$GroupPicker$FunctionExtender(){}
GPFunctionExtender = Infoshare.GroupPicker.FunctionExtender;
GPFunctionExtender.TypeName = 'Infoshare.GroupPicker.FunctionExtender';
GPFunctionExtender.ClassInfo = null;
GPFunctionExtender.ExtendersInitialized = false;

GPFunctionExtender.Extend = function()
{
    ISTrace.TraceVerbose('[BEGIN] GPFunctionExtender.Extend');

    // 拡張するかどうかを判定する
    if (!GPFunctionExtender.CanExtend())
    {
        ISTrace.TraceVerbose('[CANCELLED] GPFunctionExtender.Extend');
        return;
    }

    GPFunctionExtender.ExtendInternal();
}

GPFunctionExtender.ExtendInternal = function()
{
    try
    {
        if (!GPFunctionExtender.ExtendersInitialized)
        {
            // extender初期化
            for (var i = 0; i < GPSettings.GPFunctionExtender.FunctionExtenderClassNames.length; i++)
            {
                var className = GPSettings.GPFunctionExtender.FunctionExtenderClassNames[i];
                try
                {
                    eval(className + '.Initialize();');
                }
                catch(e)
                {
                    ISTrace.TraceVerbose('[FAILED] ' + classInfo.Name + '.Initialize()');
                    ISTrace.TraceVerbose('[FAILED] ' + e.message);
                }                    
            }

            // Extender初期化フラグを更新
            GPFunctionExtender.ExtendersInitialized = true;
        }

        // 関数拡張
        var extender = new iSPFunctionExtender();
        extender.Extend();
        ISTrace.TraceVerbose('[END] GPFunctionExtender.Extend');
    }
    catch (e) { }
}

GPFunctionExtender.CanExtend = function()
{
    var extend = false;
    if (!GPContext.IsSupportedBrowser())
    {
        ISTrace.TraceWarning('[CANCELLED] GPFunctionExtender.Extend（This browser is not supported）');
        return false;
    }

    // 設定JSファイルにて拡張設定が定義されている場合拡張する
    try
    {
        if (GPSettings.GPFunctionExtender.CanExtend)
        {
            extend = true;
        }
    }
    catch (e) { }

    // クラシックの場合、ピッカー機能が無効な場合には拡張しない
    // モダンの場合、ピッカー機能の有効/無効が判断出来ないため、アプリの展開が完了していたら拡張する
    if (typeof GPSettings == "undefined"||
        (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Classic && !GPSettings.PickerFeature))
    {
        ISTrace.TraceWarning('[CANCELLED] GPPageExtender.Extend（Picker feature is inactive）');
        return false;
    }

    return extend;
}

