// -----------------------------------------------------------------------
Infoshare.GroupPicker.SharingFunctionExtender = function Infoshare$GroupPicker$SharingFunctionExtender()
{
    Infoshare.SharePoint.SharingFunctionExtender.apply(this, arguments);
}
GPSharingFunctionExtender = Infoshare.GroupPicker.SharingFunctionExtender;
GPSharingFunctionExtender.TypeName = 'Infoshare.GroupPicker.SharingFunctionExtender';
GPSharingFunctionExtender.ClassInfo = null;

GPSharingFunctionExtender.Initialize = function()
{
    if (!GPSharingFunctionExtender.Extenders)
    {
        GPSharingFunctionExtender.Extenders = new ISDictionary();
    }

    iBehaviorExtender.AddExtender(Infoshare.SharePoint.SharingFunctionExtender, 'DisplayClientSharingDialog', 'Infoshare.GroupPicker.SharingFunctionExtender');
}
GPSharingFunctionExtender.CanExtend = function()
{
    return iSPFunctionExtender.ScriptExist(iSPSharingFunctionExtender.ScriptName);
}

GPSharingFunctionExtender.prototype = new Infoshare.SharePoint.SharingFunctionExtender();
GPSharingFunctionExtender.prototype.TypeName = GPSharingFunctionExtender.TypeName;

GPSharingFunctionExtender.prototype.Extend = function ()
{
    if (!this.CanExtend())
    {
        return;
    }

    if (typeof this.PreExtend      == 'function') { this.PreExtend(); }
    if (typeof this.ExtendCore == 'function') { this.ExtendCore(); }
    // PostExecuteのタイミングでExtendChildrenを実行するために、このタイミングではExtendChildrenを実行しない
    if (typeof this.PostExtend     == 'function') { this.PostExtend(); }
}
GPSharingFunctionExtender.prototype.ExtendCore = function ()
{
    this.HookFunction('DisplayClientSharingDialog');
}

// 拡張関数が実行される前に実行される関数定義
GPSharingFunctionExtender.prototype.PreExecute = function ()
{
    // iFrame内からコールされた場合の処理（SharePointのバグ対応）
    // iframe内の同関数を呼び出すと正しく動作しないため、iframeの外の関数を呼び出す。
    var originalFunction = this.OriginalFunction;
    if (window != window.top)
    {
        originalFunction = window.top.DisplayClientSharingDialog;
    }

    this.OriginalFunction = originalFunction;
}
// 拡張関数が実行されたあとに実行される関数定義
GPSharingFunctionExtender.prototype.PostExecute = function ()
{
    var extender = this;
    GPContext.LoadjQuery = true;
    GPContext.Initialize(function()
    {
        // ダイアログが表示されるまで待機
        var timeOut = 5000;
        var timer = 0;
        var interval = 256;

        var polingFunction = function ()
        {
            if (timeOut < timer)
            {
                ISTrace.TraceVerbose('[CANCELED] GPSharingFunctionExtender.PostExecute: Extend is timeout.');
                return;
            }

            if (extender.CanExtend() &&
                extender.ControlRendered())
            {
                extender.ExtendChildren();
            }
            else
            {
                timer += interval;
                setTimeout(polingFunction, interval);
            }          
        };
        // ポーリング開始
        polingFunction();

        // ダイアログの初期化: フォームの初期化が始まった段階でダイアログの初期化も始める（ダイアログ表示高速化のため）
        GPViewContext.Initialize(null, false);
    });
}

GPSharingFunctionExtender.prototype.ControlRendered = function ()
{
    var rendered = GPUserControlExtender.CanExtend();
    return rendered;
}

                            
