GPWebPart.ExtendInfoCallSearchWebPart = function()
{
    var icWebPartElementId = "InfoCallSearchPart";

    // 表示モード
    if (!iSPWebPartEditorExtender.IsWebPartEditPage())
    {
        var transitionOption = document.getElementById("Infoshare.WP.Settings.TransitionOption").value;
        var descriptionText = document.getElementById("Infoshare.WP.Settings.Description").innerText;
        // spanタグ内で改行が反映されないため、改行コードに置換する
        descriptionText = ISString.Replace(descriptionText, "\r\n", "<br>");
        descriptionText = ISString.Replace(descriptionText, "\n", "<br>");

        // 検索ボックスを表示する（スタイル調整の為,InfoCallSearchPartの親要素を対象とする）
        var searchTextBoxDiv = document.getElementById(icWebPartElementId);
        searchTextBoxDiv.id = "";
        searchTextBoxDiv.parentElement.id = icWebPartElementId;

        // 描画
        // ToDo: 描画高度を切り替え（GPNavigation → GPSearchControl）
        GPNavigation.RenderSearchUI(icWebPartElementId, transitionOption, descriptionText);

        //var transitionMode = iNavigation.TransitionType.Dialog;
        //if      (transitionOption == GPNavigation.SearchUITransitionOption.ShowModalDialog) { transitionMode = iNavigation.TransitionType.Dialog; }
        //else if (transitionOption == GPNavigation.SearchUITransitionOption.Redirect)        { transitionMode = iNavigation.TransitionType.Navigate; }
        //else if (transitionOption == GPNavigation.SearchUITransitionOption.OpenWindow)      { transitionMode = iNavigation.TransitionType.OpenWindow; }

        //var control = new GPSearchControl();
        //control.ParentElementId = icWebPartElementId;
        //control.TransitionMode  = transitionMode,
        //control.Description     = descriptionText;
        //control.Render();
    }

    // 編集モードの場合（iSPWebPartEditorExtenderにより拡張する）
    else
    {
        // WebパーツIDの確認（ICWP以外のパーツでは拡張しない）
        var editorPaneWebPartId = iSPWebPartEditorExtender.GetCurrentEditorPaneWebPartId();
        var icwpWebPartId = iSPWebPartEditorExtender.GetWebPartId(icWebPartElementId);
        // editor要素はelementのidなのでicwpWebPartIdのIDを置換して比較する
        // editorPaneWebPartId：ToolPartctl00_MSOTlPn_EditorZone_Edit0g_d269db9c_8a0a_4eed_bb7c_53b7d804630e
        // icwpWebPartId      ：d269db9c-8a0a-4eed-bb7c-53b7d804630e
        if (ISString.IsNullOrEmpty(editorPaneWebPartId) ||
            ISString.IsNullOrEmpty(icwpWebPartId))
        {
            return;
        }
        else
        {
            icwpWebPartId = ISString.Replace(icwpWebPartId, "-", "_");
            if (!ISString.EndsWith(editorPaneWebPartId, icwpWebPartId, true))
            {
                return;
            }
        }

        // コンテキストの初期化
        iVxContext.Initialize(function ()
        {
            // リソース読み込み
            var basePath = ISString.TrimEnd(iVxContext.MasterSourcesPath, '/') + '/Infoshare.InfoCall';
            var revisionSuffix = '?rev=' + GPPackageInfo.PackageTimestamp;

            var locator = new iResxResourceLocator(basePath, 'Infoshare.GroupPicker', iVxContext.Language, revisionSuffix);
            iCompoundResource.Initialize([locator], function ()
            {
                var webPartEditorExtender = new iSPWebPartEditorExtender();
                webPartEditorExtender.Extenders = new ISDictionary();
                webPartEditorExtender.Extenders.Add(GPIcWebPartEditorExtender.TypeName, GPIcWebPartEditorExtender.TypeName);

                webPartEditorExtender.Extend();
            });
        });
    }
}
                            
