GPPickerSelectControl.prototype.InputEventHandler = null; 
GPPickerSelectControl.prototype.OnInput = function()
{
    if (this.InputEventHandler)
    {
        this.InputEventHandler(this);
    }
}

GPPickerSelectControl.prototype.TagChangedEventHandler = null; 

GPPickerSelectControl.prototype.OnTagChanged = function ()
{
    // Dirtyフラグ管理
    this.Dirty = true;

    // 外部定義のイベント
    if (this.TagChangedEventHandler)
    {
        this.TagChangedEventHandler(this);
    }
}

GPPickerSelectControl.prototype.OnClickPickerButton = function ()
{
    // ダイアログ起動前の関数（設定の更新などで利用）
    this.BeforeOnclickPickerButton();

    var dialog = window.top.GPDialog.CreateDialog(this.DialogType);
    dialog.EntitySelection = this.GetEntitySelection();
    dialog.ResolvedEntities = this.GetEntities();

    var pickerSelectControl = this;
    dialog.AddCloseEvent(function (result)
    {
        if (result.Result == iDialogResult.ResultType.OK)
        {
            var entities = result.SelectedEntities;

            pickerSelectControl.SetEntities(entities);

            // Inputイベントを呼ぶ
            pickerSelectControl.OnInput();
        }
    });

    window.top.GPDialog.Open(dialog);
};

GPPickerSelectControl.prototype.BeforeOnclickPickerButton = function()
{
    // それぞれのインスタンスを作成したクラスで実装する
}

GPPickerSelectControl.prototype.GetEntitySelection = function ()
{
    return this.EntitySelection;
}

GPPickerSelectControl.prototype.GetEntities = function ()
{
    var entities = [];
    var tags = this.CandidateContainer.Controls;
    for (var i = 0; i < tags.GetLength() ; i++)
    {
        var tag = tags.Get(i);
        var entity = tag.Entity;
        entities.push(entity);
    }

    return entities;
}

GPPickerSelectControl.prototype.SetEntities = function (entities)
{
    // 単数選択列は既存のエンティティを削除する
    if (!this.EntitySelection.AllowMultipleSelection)
    {
        this.ClearEntities();
    }
    // 複数選択列は既存のエンティティを取得して、ユニークな値のみ追加対象とする
    else
    {
        entities = this.GetUniqueEntities(entities);
    }

    // CandidateContainerに追加する
    this.AddCandidateInternal(entities);
}

GPPickerSelectControl.prototype.ClearEntities = function ()
{
    // CandidateContainerのエンティティを削除する
    this.CandidateContainer.ClearTag();
}

GPPickerSelectControl.prototype.GetUniqueEntities = function (entities)
{
    // 現在設定されているエンティティを取得する
    var baseEntities = this.GetEntities();
    // EntityIdをキーにして、重複チェック時に利用する
    var keys = [];
    for (var i = 0; i < baseEntities.length; i++)
    {
        var baseEntity = baseEntities[i];
        var key = baseEntity.Properties["EntityId"];

        if (ISArray.Contains(keys, key, true))
        {
            continue;
        }

        keys.push(key);
    }

    // 重複したエンティティは除去する
　  var uniqueArray = [];
    for (var i = 0; i < entities.length; i++)
    {
        var entityId = entities[i].Properties["EntityId"];
        if (ISArray.Contains(keys, entityId, true))
        {
            continue;
        }

        uniqueArray.push(entities[i]);
    }

    return uniqueArray;
};

