// -----------------------------------------------------------------------
Infoshare.GroupPicker.UnifiedCommunicationsPresenceController = function Infoshare$GroupPicker$UnifiedCommunicationsPresenceController(service)
{
    this.Service  = service;
    this.Controls = new ISDictionary();
}
UCPresenceController = Infoshare.GroupPicker.UnifiedCommunicationsPresenceController;
UCPresenceController.Instance = null;
UCPresenceController.GetInstance = function()
{
    var instance = UCPresenceController.Instance;
    if (!instance)
    {
        // ToDo: 初期化場所検討
        UCService.ScriptBaseUrl = ISString.Format('{0}/Infoshare/UnifiedCommunications/',
                                                  ISString.TrimEnd(GPContext.SourcesPath, '/'));
        var clientId   = GPContext.Configuration.GetSetting('UnifiedCommunicationsClientId');
        var domainName = GPContext.Configuration.GetSetting('UnifiedCommunicationsDomainName');
        if (iString.IsNullOrEmpty(domainName))
        {
            domainName = GPContext.Configuration.GetSetting('SkypeServerDomainName');
        }

        // プラットフォーム、CDN 利用有無、バージョンを確認
        var platform = UCPlatform.Online;
        if (iString.IsNullOrEmpty(clientId) && !iString.IsNullOrEmpty(domainName))
        {
            platform = UCPlatform.OnPremise;
        }
        var useCDN = iBoolean.TryParse(GPContext.Configuration.GetSetting('UnifiedCommunicationsUseCDN'), true);
        var version = GPContext.Configuration.GetSetting('UnifiedCommunicationsVersion');

        // インスタンス生成、初期化
        var service = new UCService(platform, useCDN, version);
        if      (platform == UCPlatform.Online)    { service.ClientId   = clientId; }
        else if (platform == UCPlatform.OnPremise) { service.DomainName = domainName; }

        instance = new UCPresenceController(service);
        UCPresenceController.Instance = instance;
    }

    return instance;
}

UCPresenceController.prototype = {
    Service: null,
    Controls: null,


    BuildPresenceLinkHtmlTemplate: function()
    {
        var template = "<img id='uc_{0}' "
                     +      "alt='Presence' "
                     +      "src='%ImageURL%' "
                     +      "sip='{1}' />";

        var imageUrl = ISString.Format('{0}/Infoshare/Presence.Offline.png',
                                       ISString.TrimEnd(GPContext.ImagesPath, '/'));
        template = ISString.Replace(template, "%ImageURL%", imageUrl, true);

        return template;
    },

    UpdatePresenceStyles: function (target, callback)
    {
        // 指定範囲内のimg要素を取得
        var images = ISDomAccessor.GetElementsByTagName('img', target);

        // sipアドレスをキーにimg要素を紐づけ
        var presenceImages = new ISDictionary();
        for (var i = 0; i < images.length; i++)
        {
            var image = images[i];
            var sipAddress = image.getAttribute('sip');
            if (!sipAddress)
            {
                continue;
            }

            var imageElements = new Array();
            if (presenceImages.Contains(sipAddress))
            {
                imageElements = presenceImages.Get(sipAddress);
            }

            imageElements.push(image);
            presenceImages.Set(sipAddress, imageElements);
        }

        // ユーザーを取得
        (function (controller, images)
        {
            if (images.GetLength() <= 0)
            {
                return;
            }

            var keys = images.GetKeys();
            var uncashedSipAddresses = controller.filterToUncached(keys);

            if (!uncashedSipAddresses || uncashedSipAddresses.length <= 0)
            {
                // PresenceControlのimg要素を更新
                var keys = images.GetKeys();
                for (var i = 0; i < keys.length; i++)
                {
                    var key = keys[i];
                    if (!controller.Controls.Contains(key)) {
                        continue;
                    }

                    var imageElements = presenceImages.Get(key);
                    var control = controller.Controls.Get(key);
                    control.PresenceElement = imageElements;
                    control.Update();
                }
            }
            else
            {
                controller.Service.GetUsers(uncashedSipAddresses, function (users)
                {
                    var userHash = new ISDictionary();
                    if (users && users.length > 0)
                    {
                        userHash.AddRange(users);
                    }

                    // PresenceControlで、userとimg要素を紐づけ
                    var keys = images.GetKeys();
                    for (var i = 0; i < keys.length; i++)
                    {
                        var key = keys[i];
                        var imageElements = presenceImages.Get(key);

                        if (controller.Controls.Contains(key))
                        {
                            var control = controller.Controls.Get(key);
                            control.PresenceElement = imageElements;
                            control.Update();
                        }
                        else
                        {
                            var user = userHash.Get(key);
                            if (user)
                            {
                                var control = new UCPresenceControl();
                                control.Initialize(user, imageElements);

                                controller.Controls.Add(key, control);
                            }
                        }
                    }
                });
            }
        })(this, presenceImages);
    },

    filterToUncached: function(sipAddresses)
    {
        var uncached = new Array();
        for (var i = 0; i < sipAddresses.length; i++)
        {
            var sipAddress = sipAddresses[i];
            if (this.Controls.Contains(sipAddress))
            {
                continue;
            }

            uncached.push(sipAddress);
        }

        return uncached;
    }
}


// -----------------------------------------------------------------------
//  UnifiedCommunicationsPresenceControl
// -----------------------------------------------------------------------
Infoshare.GroupPicker.UnifiedCommunicationsPresenceControl = function Infoshare$GroupPicker$UnifiedCommunicationsPresenceControl() { }
UCPresenceControl = Infoshare.GroupPicker.UnifiedCommunicationsPresenceControl;
UCPresenceControl.prototype = {
    User: null,
    PresenceElement: null,

    Initialize: function(user, element)
    {
        if (this.User)
        {
            throw new Error('Already initialized.');
        }

        this.User = user;
        this.PresenceElement = element;

        this.User.RegisterFunctionForStatusChanged(ISFunction.CreateDelegate(this.OnPresenceStatusChanged, this));
    },

    Update: function()
    {
        if (!ISString.IsNullOrEmpty(this.User.Status))
        {
            this.OnPresenceStatusChanged(this.User.Status);
        }
    },

    OnPresenceStatusChanged: function(status)
    {
        if (this.PresenceElement)
        {
            var oStatus = new UCPresenceStatus(status);
            var imageUrl = ISString.Format('{0}/Infoshare/Presence.{1}.png',
                                           ISString.TrimEnd(GPContext.ImagesPath, '/'),
                                           oStatus.Category);

            if (ISObject.TypeOf(this.PresenceElement) == 'array')
            {
                for (var i = 0; i < this.PresenceElement.length; i++)
                {
                    var presenceElement = this.PresenceElement[i];
                    presenceElement.src       = imageUrl;
                    presenceElement.alt       = oStatus.Caption;
                    presenceElement.title     = oStatus.Caption;
                }
            }
            else
            {
                this.PresenceElement.src       = imageUrl;
                this.PresenceElement.alt       = oStatus.Caption;
                this.PresenceElement.title     = oStatus.Caption;
            }
        }
    },

    BuildPresenceStatusIconUrl: function(status)
    {
        ISString.Format(GPContext.ImagesPath, status.toLowerCase());
    }
}
                                  
