// -----------------------------------------------------------------------
Infoshare.GroupPicker.GraphPresenceController = function Infoshare$GroupPicker$GraphPresenceController(service)
{
    this.Service  = service;
}
GraphPresenceController = Infoshare.GroupPicker.GraphPresenceController;
GraphPresenceController.GraphPolling = 0;
GraphPresenceController.FailedCount = 0;
GraphPresenceController.RetryCount = 0;
GraphPresenceController.ResultGridElementId = null;
GraphPresenceController.Instance = null;
GraphPresenceController.GetInstance = function()
{
    var instance = GraphPresenceController.Instance;
    if (!instance)
    {
        // ToDo: 初期化場所検討
        var clientId = GPContext.Configuration.GetSetting('GraphClientId');
        var tenantId = GPContext.Configuration.GetSetting('GraphTenantId');
        var version = GPContext.Configuration.GetSetting('GraphVersion');

        // インスタンス生成、初期化
        var service = new GraphService(clientId, tenantId, version);
        instance = new GraphPresenceController(service);
        GraphPresenceController.Instance = instance;

    }

    return instance;
}

GraphPresenceController.prototype = {
    Service: null,


    BuildPresenceLinkHtmlTemplate: function()
    {
        var template = "<img id='graph_{0}' "
                     +      "alt='Presence' "
                     +      "src='%ImageURL%' "
                     +      "sip='{1}' "
                     +      "entityId='{2}' "
                     +      "subType='{3}' />";

        var imageUrl = ISString.Format('{0}/Infoshare/Presence.Offline.png',
                                       ISString.TrimEnd(GPContext.ImagesPath, '/'));
        template = ISString.Replace(template, "%ImageURL%", imageUrl, true);

        return template;
    },

    UpdatePresenceStyles: function (target, callback)
    {
        // 前回のポーリングがある場合、停止する
        if (this.GraphPolling)
        {
            clearInterval(this.GraphPolling);
        }

        this.FailedCount = 0;
        this.RetryCount = ISNumber.Parse(GPContext.Configuration.GetSetting('GraphSignedInRetryCount'));
        this.ResultGridElementId = target;
        var updated = this.UpdateGraphPresenceStyles();

        // プレゼンス更新があり、プレゼンスポーリングが設定されている場合、ポーリングを開始する
        if (updated && ISBoolean.Parse(GPContext.Configuration.GetSetting('GraphPresencePolling')))
        {
            // ToDo: プレゼンス取得対象のResultGridElementIdを引数渡しが出来なかったため、グローバル変数で持つようにしたが問題ないか。
            this.GraphPolling = setInterval(ISFunction.CreateDelegate(this.UpdateGraphPresenceStyles, this), GPContext.Configuration.GetSetting('GraphPresencePollingInterval'));
        }
        callback();
    },

    UpdateGraphPresenceStyles: function ()
    {
        var controller = this;

        // 指定範囲内のimg要素を取得
        var images = ISDomAccessor.GetElementsByTagName('img', this.ResultGridElementId);

        // EntityId（識別子ID）をキーにsipアドレスを紐づけ
        var sipAddresses = new ISDictionary();
        // sipアドレスをキーにimg要素を紐づけ
        var presenceImages = new ISDictionary();
        for (var i = 0; i < images.length; i++)
        {
            var image = images[i];
            var sipAddress = image.getAttribute('sip');
            var subType = image.getAttribute('subType');
            // sipアドレスが空、またはサブタイプがuser以外の場合、プレゼンス表示を行わない
            if (!sipAddress || !ISString.Equals(subType, 'user', true))
            {
                continue;
            }

            var imageElements = new Array();
            if (presenceImages.Contains(sipAddress))
            {
                imageElements = presenceImages.Get(sipAddress);
            }

            imageElements.push(image);
            presenceImages.Set(sipAddress, imageElements);
            sipAddresses.Set(image.getAttribute('entityId'), sipAddress);
        }

        if (presenceImages.GetLength() <= 0)
        {
            return false;
        }

        // 識別子IDで一括ユーザー取得を行う
        controller.Service.GetUsersById(sipAddresses.GetKeys(), function (usersById, errors)
        {
            if (controller.Service.SignedIn)
            {
                controller.FailedCount = 0;
            }
            else
            {
                controller.FailedCount += 1;
                if (controller.RetryCount < controller.FailedCount)
                {
                    clearInterval(controller.GraphPolling)
                }
                return;
            }

            // 識別子IDで一括ユーザー取得が出来なかった場合、UPNで1件ずつユーザー取得を行う
            if (errors.length > 0)
            {
                // ユーザー一括取得時の1000件エラーが発生している場合、後続処理を行わない
                if (errors[0].Error.code == "Request_BadRequest")
                {
                    return;
                }
                
                var errorKeys = [];
                for  (var i = 0; i < errors.length; i++)
                {
                    var errorKey = sipAddresses.Get(errors[i].Key);
                    if (!ISArray.Contains(errorKeys, errorKey, true))
                    {
                        errorKeys.push(errorKey);
                    }
                }
                controller.Service.GetUsersByUPN(errorKeys, function (usersByUPN, errors)
                {
                    var users = usersById.concat(usersByUPN);
                    controller.UpdateGraphPresenceStylesInternal(users, presenceImages);
                });
            }
            else
            {
                controller.UpdateGraphPresenceStylesInternal(usersById, presenceImages);
            }
        });

        return true;
    },

    UpdateGraphPresenceStylesInternal: function (users, presenceImages)
    {
        var userHash = new ISDictionary();
        if (users && users.length > 0)
        {
            for (var i = 0; i < users.length; i++)
            {
                var user = users[i];
                if (!userHash.Contains(user.Id))
                {
                    userHash.Add(user.Id, user);
                }
            }
        }
        
        // PresenceControlで、userとimg要素を紐づけ
        var keys = presenceImages.GetKeys();
        for (var i = 0; i < keys.length; i++)
        {
            var key = keys[i];
            var imageElements = presenceImages.Get(key);
            var user = userHash.Get(key);
            if (user)
            {
                var control = new GraphPresenceControl();
                control.Initialize(user, imageElements);
            }
            else
            {
                ISTrace.TraceWarning('GraphPresenceController.UpdateGraphPresenceStylesInternal:Presence could not be updated because sipAddress is invalid.' + '(' + key + ')');
            }
        }
    }
}


