GraphProfileImageController.prototype = {
    Service: null,

    UpdateGraphProfileImages: function (target)
    {
        var controller = this;

        // 指定範囲内のimg要素を取得
        var images = ISDomAccessor.GetElementsByTagName('img', target);

        // EntityId（識別子ID）をキーにimg要素を紐づけ
        var entityIdImages = new ISDictionary();
        for (var i = 0; i < images.length; i++)
        {
            var image = images[i];
            if (ISString.StartsWith(image.id, 'profileImage_', true))
            {
                entityIdImages.Set(image.getAttribute('entityId'), image);
            }
        }

        if (entityIdImages.GetLength() <= 0)
        {
            return false;
        }

        controller.Service.GetGraphProfileImages(entityIdImages.GetKeys(), function (results)
        {
            var resultHash = new ISDictionary();
            if (results && results.length > 0)
            {
                resultHash.AddRange(results);
                var keys = entityIdImages.GetKeys();
                for (var i = 0; i < keys.length; i++)
                {
                    var dataUrl = "data:image/png;base64," + resultHash.Get(keys[i]).Object;
                    entityIdImages.Get(keys[i]).setAttribute('src', dataUrl);
                }
                return true;
            }
            else
            {
                return false;
            }
        });
    },

    UpdateGraphProfileImage: function (id, target)
    {
        var controller = this;
        controller.Service.GetGraphProfileImages(new Array(id), function (results)
        {
            if (results && results.length > 0)
            {
                var dataUrl = "data:image/png;base64," + results[0].Object;
                target.setAttribute('src', dataUrl);
                return true;
            }
            else
            {
                return false;
            }
        });
    }
}
                            
