GPIcFeature.prototype = new Infoshare.SharePoint.Administration.FeatureControl();
GPIcFeature.prototype.TypeName = GPIcFeature.TypeName;
GPIcFeature.prototype.UserCustomActionInfos = null;
GPIcFeature.prototype.ExistUserCustomActions = [];
GPIcFeature.prototype.Status =iFeatureControl.Status.Unknown;
GPIcFeature.prototype.DependenceParentFeatureIds = ["Feature.InfoshareCommon"];
GPIcFeature.prototype.DependenceChildFeatureIds = [
    "Feature.InfoCall.Picker",
    "Feature.InfoCall.WebPart",
    "Feature.OrganizationManagement"
];
GPIcFeature.prototype.RequiredLicenses = null;
GPIcFeature.prototype.RequiredLicenseIds = [iLicense.GroupPickerKey, iLicense.InfoCallKey];
