GPIcFeature.prototype.RequiredLicenseIds = [iLicense.GroupPickerKey, iLicense.InfoCallKey, iLicense.InfoCallMemberSearchKey]; // ADViewerからの製品販売の流れで、所属検索ライセンスのみでも利用可能とする

GPIcFeature.prototype.InitializeInternal = function()
{
    // ユーザーカスタムアクション情報の設定
    if (!this.UserCustomActionInfos)
    {
        this.UserCustomActionInfos = GPIcFeature.UserCustomActionInfos;
    }
};

GPIcFeature.prototype.EnsureActiveStatusInternal = function(callback)
{
    // それぞれの要素事に状態の確認
    // Infoshare製品ライブラリにファイルのコピー    
    // Infoshare InfoCall UserCustomAction

    var feature = this;
    var ensureContext = {
        ProductLibraryComplete: false,
        UserCustomActionComplete: false,

        ProductLibraryIsActive: false,
        UserCustomActionIsActive: false,
        Completed: function()
        {
            return this.ProductLibraryComplete &&
                   this.UserCustomActionComplete;
        },

        AllFeatureIsActive: function()
        {
            return this.ProductLibraryIsActive &&
                   this.UserCustomActionIsActive;
        }
    };
    var ensureCompleted = function ()
    {
        if (ensureContext.Completed())
        {
            callback(ensureContext.AllFeatureIsActive());
        }
    };

    // Infoshare製品ライブラリ
    this.EnsureActiveStatusForProductLibrary(function (isActive)
    {
        ensureContext.ProductLibraryComplete = true;
        ensureContext.ProductLibraryIsActive = isActive;
        ensureCompleted();
    });
    
    // UserCustomAction
    this.EnsureActiveStatusForUserCustomAction(function (isActive)
    {
        ensureContext.UserCustomActionComplete = true;
        ensureContext.UserCustomActionIsActive = isActive;
        ensureCompleted();
    });   
};
GPIcFeature.prototype.EnsureActiveStatusForProductLibrary = function (callback)
{
    // Infoshare.InfoCallのフォルダが存在するか確認
    var folderUrl = ISString.TrimEnd(this.TargetSiteRelativeUrl, '/')
                  + "/InfoshareProductLibrary/Sources/Infoshare.InfoCall";

    this.FolderService.Exists(folderUrl, function (exists, status)
    {
        callback(exists);
    });
}
GPIcFeature.prototype.EnsureActiveStatusForUserCustomAction = iInfoshareCommonFeature.prototype.EnsureActiveStatusForUserCustomAction;

GPIcFeature.prototype.Activate = function(callback)
{
    // 以下二つの要素をアクティベートする
    // Infoshare製品ライブラリにファイルのコピー
    // Infoshare InfoCall UserCustomAction
    // コンテキスト
    var activateContext = {
        ProductLibraryComplete: false,
        UserCustomActionComplete: false,
        Completed: function()
        {
            return this.ProductLibraryComplete &&
                   this.UserCustomActionComplete;
        }
    };
    var activateCompleted = function ()
    {
        if (activateContext.Completed())
        {
            callback();
        }
    };

    // Infoshare製品ライブラリ
    // 管理サイトに対しては、ライブラリ操作を行わない
    if (this.TargetIsMasterSite)
    {
        activateContext.ProductLibraryComplete = true;
        activateCompleted()
    }
    else
    {
        this.ActivateProductLibrary(function ()
        {
            activateContext.ProductLibraryComplete = true;
            activateCompleted()
        });
    }

    // UserCustomAction
    this.ActivateUserCustomAction(function ()
    {
        activateContext.UserCustomActionComplete = true;
        activateCompleted()
    });
};
GPIcFeature.prototype.ActivateProductLibrary = function(callback)
{
    var feature = this;
    var targetSourcesFolderUrl = ISString.TrimEnd(this.TargetSiteRelativeUrl, '/')
                               + "/InfoshareProductLibrary/Sources";

    // Infoshare.InfoCallフォルダ
    var targetInfoCallFolderUrl = targetSourcesFolderUrl + "/Infoshare.InfoCall";
    this.FolderService.Create(targetInfoCallFolderUrl, function ()
    {
        feature.CopyFiles(callback);
    });
};
GPIcFeature.prototype.ActivateUserCustomAction = iInfoshareCommonFeature.prototype.ActivateUserCustomAction;

GPIcFeature.prototype.Deactivate = function(callback)
{
    // 以下二つの要素をディアクティベートする
    // Infoshare製品ライブラリにファイルのコピー
    // Infoshare InfoCall UserCustomAction
    // コンテキスト
    var deactivateContext = {
        ProductLibraryComplete: false,
        UserCustomActionComplete: false,
        Completed: function()
        {
            return this.ProductLibraryComplete &&
                   this.UserCustomActionComplete;
        }
    };
    var deactivateCompleted = function ()
    {
        if (deactivateContext.Completed())
        {
            callback();
        }
    };

    // Infoshare製品ライブラリ
    // 管理サイトに対しては、ライブラリ操作を行わない
    if (this.TargetIsMasterSite)
    {
        deactivateContext.ProductLibraryComplete = true;
        deactivateCompleted();
    }
    else
    {
        this.DeactivateProductLibrary(function ()
        {
            deactivateContext.ProductLibraryComplete = true;
            deactivateCompleted();
        });
    }
    
    // UserCustomAction
    this.DeactivateUserCustomAction(function ()
    {
        deactivateContext.UserCustomActionComplete = true;
        deactivateCompleted();
    });
};
GPIcFeature.prototype.DeactivateProductLibrary = function(callback)
{
    // InfoshareInfoCallフォルダを削除する
    var targetSourcesFolderUrl = ISString.TrimEnd(this.TargetSiteRelativeUrl, '/')
                               + "/InfoshareProductLibrary/Sources";

    // Infoshare.InfoCallフォルダ
    var targetInfoCallFolderUrl = targetSourcesFolderUrl + "/Infoshare.InfoCall";
    this.FolderService.Delete(targetInfoCallFolderUrl, callback);
};
GPIcFeature.prototype.DeactivateUserCustomAction = iInfoshareCommonFeature.prototype.DeactivateUserCustomAction;

GPIcFeature.prototype.CopyFiles = function(callback)
{
    // コンテキスト
    var copyFilesContext = {
        ConfigurationsFolderComplete: false,
        SourcesFolderComplete: false,
        Completed: function ()
        {
            return this.ConfigurationsFolderComplete &&
                   this.SourcesFolderComplete;
        }
    };
    var folderAndFilesCreated = function ()
    {
        if (copyFilesContext.Completed())
        {
            callback();
        }
    };

    var feature = this;
    var targetProductLibraryUrl = ISString.TrimEnd(this.TargetSiteRelativeUrl, '/')
                                + "/InfoshareProductLibrary";
    // Configurationsフォルダ
    var targetConfigurationsFolderUrl = targetProductLibraryUrl + "/Configurations";
    // Configuration.InfoCall.Redirect.xmlのコピー
    var fileUrl = iVxContext.MasterConfigurationsPath + "/Configuration.InfoCall.Redirect.xml";
    var targetFileUrl = targetConfigurationsFolderUrl + "/Configuration.InfoCall.xml";
    this.FileService.Download(fileUrl, function(downloadResult, contents, downloadStatus)
    {
        // ConfiguSiteUrlの値を置換する
        var replacedContents = ISString.Replace(contents, "%ConfigSiteUrl%", iVxContext.MasterSiteRelativePath);
        feature.FileService.Upload(targetFileUrl, replacedContents, function (uploadResult, uploadStatud)
        {
            copyFilesContext.ConfigurationsFolderComplete = true;
            folderAndFilesCreated();
        });
    });

    // Sourcesフォルダ（スクリプトリンクの指定で絶対URLを指定できない為、利用するサイトコレクションにjsをコピーする）
    var targetSourcesFolderUrl = targetProductLibraryUrl + "/Sources";
    this.FolderService.Create(targetSourcesFolderUrl, function ()
    {
        var targetSourcesFolderUrl = ISString.TrimEnd(feature.TargetSiteRelativeUrl, '/')
                                   + "/InfoshareProductLibrary/Sources";
        var targetInfoCallFolderUrl = targetSourcesFolderUrl + "/Infoshare.InfoCall";
        feature.FolderService.Create(targetInfoCallFolderUrl, function ()
        {
            feature.CopyFolderFiles(GPIcFeature.InfoshareInfoCallFiles, function ()
            {
                copyFilesContext.SourcesFolderComplete = true;
                folderAndFilesCreated();
            });
        });
    });
};
GPIcFeature.prototype.CopyFolderFiles = iInfoshareCommonFeature.prototype.CopyFolderFiles;
GPIcFeature.prototype.CopyFile = iInfoshareCommonFeature.prototype.CopyFile;

