GPOmFeature.prototype.InitializeInternal = function()
{
    // ユーザーカスタムアクション情報の設定
    if (!this.UserCustomActionInfos)
    {
        this.UserCustomActionInfos = GPOmFeature.UserCustomActionInfos;
    }
};

GPOmFeature.prototype.EnsureActiveStatusInternal = function(callback)
{
    // それぞれの要素事に状態の確認
    // リスト（補助マスタ、アクセス権マスタ）
    // UserCustomAction

    var feature = this;
    var ensureContext = {
        ListsComplete: false,
        UserCustomActionComplete: false,

        ListsIsActive: false,
        UserCustomActionIsActive: false,
        Completed: function()
        {
            return this.ListsComplete &&
                   this.UserCustomActionComplete;
        },

        AllFeatureIsActive: function()
        {
            return this.ListsIsActive &&
                   this.UserCustomActionIsActive;
        }
    };
    var ensureCompleted = function ()
    {
        if (ensureContext.Completed())
        {
            callback(ensureContext.AllFeatureIsActive());
        }
    };

    // リスト（補助マスタ、アクセス権マスタ、役職マスタ）
    this.EnsureActiveStatusForLists(function (isActive)
    {
        ensureContext.ListsComplete = true;
        ensureContext.ListsIsActive = isActive;
        ensureCompleted();
    });
    
    // UserCustomAction
    this.EnsureActiveStatusForUserCustomAction(function (isActive)
    {
        ensureContext.UserCustomActionComplete = true;
        ensureContext.UserCustomActionIsActive = isActive;
        ensureCompleted();
    });   
};
GPOmFeature.prototype.EnsureActiveStatusForLists = function (callback)
{
    var ensureContext = {
        SupplementMasterListComplete: false,
        PermissionsListComplete: false,
        TitlesListComplete: false,

        SupplementMasterListIsActive: false,
        PermissionsListIsActive: false,
        TitlesListIsActive: false,
        Completed: function()
        {
            return this.SupplementMasterListComplete &&
                   this.PermissionsListComplete &&
                   this.TitlesListComplete;
        },

        AllListIsActive: function()
        {
            return this.SupplementMasterListIsActive &&
                   this.PermissionsListIsActive &&
                   this.TitlesListIsActive;
        }
    };

    var ensureCompleted = function ()
    {
        if (ensureContext.Completed())
        {
            callback(ensureContext.AllListIsActive());
        }
    };

    // 補助マスタ
    var feature = this;
    this.EnsureActiveStatusForList(GPOmFeature.SupplementMasterListName, function (isActive, list)
    {
        feature.SupplementMasterList = list;

        ensureContext.SupplementMasterListComplete = true;
        ensureContext.SupplementMasterListIsActive = isActive;
        ensureCompleted();
    });   

    // アクセス権マスタ
    this.EnsureActiveStatusForList(GPOmFeature.PermissionsListName, function (isActive, list)
    {
        feature.PermissionsList = list;

        ensureContext.PermissionsListComplete = true;
        ensureContext.PermissionsListIsActive = isActive;
        ensureCompleted();
    });

    // 役職マスタ
    this.EnsureActiveStatusForList(GPOmFeature.TitlesListName, function (isActive, list)
    {
        feature.TitlesList = list;

        ensureContext.TitlesListComplete = true;
        ensureContext.TitlesListIsActive = isActive;
        ensureCompleted();
    });  
}

GPOmFeature.prototype.EnsureActiveStatusForList = function (listInternalName, callback)
{
    var feature = this;
    this.ListService.GetListByUrlName(this.TargetSiteRelativeUrl, listInternalName, function (list)
    {
        // アクティブ状態
        if (list)
        {
            callback(true, list);
        }
        // 非アクティブ状態 
        else
        {
            callback(false, list);
        }
    });
}
GPOmFeature.prototype.EnsureActiveStatusForUserCustomAction = iInfoshareCommonFeature.prototype.EnsureActiveStatusForUserCustomAction;

GPOmFeature.prototype.Activate = function(callback)
{
    // 以下二つの要素をアクティベートする
    // リスト（補助マスタ、アクセス権マスタ、役職マスタ）
    // UserCustomAction
    // コンテキスト
    var activateContext = {
        ListsComplete: false,
        UserCustomActionComplete: false,
        Completed: function()
        {
            return this.ListsComplete &&
                   this.UserCustomActionComplete;
        }
    };
    var activateCompleted = function ()
    {
        if (activateContext.Completed())
        {
            callback();
        }
    };

    // リスト（補助マスタ、アクセス権マスタ、役職マスタ）
    this.ActivateLists(function ()
    {
        activateContext.ListsComplete = true;
        activateCompleted()
    });

    // UserCustomAction
    this.ActivateUserCustomAction(function ()
    {
        activateContext.UserCustomActionComplete = true;
        activateCompleted()
    });
};

GPOmFeature.prototype.ActivateLists = function(callback)
{
    var activateContext = {
        SupplementMasterListComplete: false,
        PermissionsListComplete: false,
        TitlesListComplete: false,
        Completed: function()
        {
            return this.SupplementMasterListComplete &&
                   this.PermissionsListComplete &&
                   this.TitlesListComplete;
        }
    };
    var activateCompleted = function ()
    {
        if (activateContext.Completed())
        {
            callback();
        }
    };

    // 補助マスタ
    if (this.SupplementMasterList)
    {
        activateContext.SupplementMasterListComplete = true;
        activateCompleted();
    }
    else
    {
        var supplementMasterListTitle = this.Resource.GetString("OrganizationManagement.SupplementMasterList.Title");
        this.ActivateList(GPOmFeature.SupplementMasterListName, GPOmFeature.SupplementMasterListFieldsInfo, supplementMasterListTitle, function ()
        {       
            activateContext.SupplementMasterListComplete = true;
            activateCompleted();
        });
    }

    // アクセス権マスタ    
    if (this.PermissionsList)
    {
        activateContext.PermissionsListComplete = true;
        activateCompleted();
    }
    else
    {
        var permissionsListTitle = this.Resource.GetString("OrganizationManagement.PermissionsList.Title");
        this.ActivateList(GPOmFeature.PermissionsListName, GPOmFeature.PermissionsListFieldsInfo, permissionsListTitle, function ()
        {       
            activateContext.PermissionsListComplete = true;
            activateCompleted();
        });
    }

    // 役職マスタ    
    if (this.TitlesList)
    {
        activateContext.TitlesListComplete = true;
        activateCompleted();
    }
    else
    {
        var titlesListTitle = this.Resource.GetString("OrganizationManagement.TitlesList.Title");
        this.ActivateList(GPOmFeature.TitlesListName, GPOmFeature.TitlesListFieldsInfo, titlesListTitle, function ()
        {       
            activateContext.TitlesListComplete = true;
            activateCompleted();
        });
    }
};
GPOmFeature.prototype.ActivateList = function(listInternalName, fieldsInfo, listTitle,  callback)
{
    // リストデータの作成
    var listData = new ISSPList();

    listData.Properties = [];
    listData.Properties["Title"] = listInternalName;
    listData.Properties["ServerTemplate"] = ISSPListTemplateType.GenericList;
    listData.Properties["Description"] = "";

    // フィールドデータの作成
    var fields = this.GetFields(fieldsInfo);
    listData.Fields = fields;
    var viewFields = this.GetViewFields(fieldsInfo);

    // Title列の必須プロパティを無効化して、非表示にする
    var titleField = new ISSPField();
    titleField.Properties = [];
    titleField.Properties["Name"]               = "Title";
    titleField.Properties["DisplayName"]        = "Title";
    titleField.Properties["Type"]               = ISSPFieldType.Text;                 
    titleField.Properties["Required"]           = "FALSE";
    titleField.Properties["ShowInNewForm"]      = "FALSE";
    titleField.Properties["ShowInEditForm"]     = "FALSE";
    titleField.Properties["ShowInDisplayForm "] = "FALSE";
    listData.UpdateFields = [titleField];

    var feature = this;
    this.CreateList(listData, listTitle, function (list)
    {
        if (viewFields &&
            viewFields.length > 0)
        {
            // Viewの設定
            feature.ListViewService.GetViewByViewFileName(listTitle, "AllItems.aspx", function (view)
            {
                feature.ListViewService.UpdateView(list.Id, view.Name, viewFields, callback);
            });

        }
        else
        {
            callback(list);
        }               
    });
};
GPOmFeature.prototype.ActivateUserCustomAction = iInfoshareCommonFeature.prototype.ActivateUserCustomAction;

GPOmFeature.prototype.Deactivate = function(callback)
{
    // UserCustomActionのみ非アクティブ化する
    // マスタリストは削除しない
    this.DeactivateUserCustomAction(function ()
    {
        callback();
    });
};

GPOmFeature.prototype.DeactivateUserCustomAction = iInfoshareCommonFeature.prototype.DeactivateUserCustomAction;
           
