Infoshare.GroupPicker.CamlQueryCondition = function Infoshare$GroupPicker$CamlQueryCondition() { }
GPCamlQueryCondition = Infoshare.GroupPicker.CamlQueryCondition;
GPCamlQueryCondition.TypeName = 'Infoshare.GroupPicker.CamlQueryCondition';

GPCamlQueryCondition.AddVisibleGroupsCondition = function (query, currentUserEntity)
{
    var conditionQuery = '';
    if (currentUserEntity && currentUserEntity.Properties.VisibleGroups != undefined)
    {
        var groups = currentUserEntity.Properties.VisibleGroups.split(",");
        for (var i = 0; i < groups.length; i++)
        {
            var visibleGroupsContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("VisibleGroups", "Text", groups[i]);
            if (conditionQuery)
            {
                conditionQuery = SPQueryBuilder.BuildOrQueryCondition(conditionQuery + visibleGroupsContainsQuery);
            }
            else
            {
                conditionQuery = visibleGroupsContainsQuery;
            }
        }
        var visibleGroupsEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("VisibleGroups");
        conditionQuery = SPQueryBuilder.BuildOrQueryCondition(conditionQuery + visibleGroupsEmptyQuery);
        query = SPQueryBuilder.BuildAndQueryCondition(query + conditionQuery);
    }
    else
    {
        var visibleGroupsEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("VisibleGroups");
        query = SPQueryBuilder.BuildAndQueryCondition(query + visibleGroupsEmptyQuery);
    }

    return query;
}
                             
