Infoshare.GroupPicker.ExtendedOrganizationView = function InfoInfoshare$GroupPicker$ExtendedOrganizationView() { }
GPExtendedOrganizationView = Infoshare.GroupPicker.ExtendedOrganizationView;
GPExtendedOrganizationView.TypeName = 'Infoshare.GroupPicker.ExtendedOrganizationView';

GPExtendedOrganizationView.prototype = new GPOrganizationView();
GPExtendedOrganizationView.prototype.TypeName = GPExtendedOrganizationView.TypeName;

GPExtendedOrganizationView.prototype.ExtendedOrganizationSplitPanel = null;
GPExtendedOrganizationView.prototype.ExtendedOrganizationSplitPaneHeight = 206;
GPExtendedOrganizationView.prototype.ExtendedOrganizationSplitPanelMargin = 10;
GPExtendedOrganizationView.prototype.ExtendedOrganizationTableTitleHeight = 25;
GPExtendedOrganizationView.prototype.MemberPhotoFolder = 'MemberPhoto';

GPExtendedOrganizationView.prototype.Render = function (parentElement, parentControl) {
    this.ParentPanel = parentControl;
    this.ParentElement = parentElement;

    // 固有のIDの設定
    var replacedId = this.Info.Id.replace(/\./g, '_');
    this.GridElementId = replacedId + '_Grid_' + ISGuid.New();
    this.TreeElementId = replacedId + '_Tree_' + ISGuid.New();

    // 組織ビュー用のタブパネルに分割パネルを挿入
    var extendedOrganizationSplitPanel = new iSplitPanel();
    this.ExtendedOrganizationSplitPanel = extendedOrganizationSplitPanel;
    extendedOrganizationSplitPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
    extendedOrganizationSplitPanel.DisplayType = iPanelStyle.DisplayType.Block;
    extendedOrganizationSplitPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
    extendedOrganizationSplitPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
    extendedOrganizationSplitPanel.Style.SeparatorSize = 0;
    // 拡張組織ペインのサイズ設定
    extendedOrganizationSplitPanel.Style.ContainerStyles[0].Size.Height = this.ExtendedOrganizationSplitPaneHeight;
    extendedOrganizationSplitPanel.Style.ContainerStyles[1].Size.Height = this.ParentElement.parentElement.clientHeight
                                                                        - extendedOrganizationSplitPanel.Style.ContainerStyles[0].Size.Height
                                                                        - this.ExtendedOrganizationSplitPanelMargin * 2;

    var orgSplitPanel = new iSplitPanel();
    this.OrgSplitPanel = orgSplitPanel;
    orgSplitPanel.Style.Mode = iSplitPanelStyle.Mode.Vertical;
    orgSplitPanel.DisplayType = iPanelStyle.DisplayType.Block;

    orgSplitPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
    orgSplitPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
    var orgSplitPanelMargin = 10;
    // ツリーペインの幅
    orgSplitPanel.Style.ContainerStyles[0].Size.Width = this.ParentElement.parentElement.clientWidth * 0.30;
    var stringPaneWidth = GPContext.Configuration.GetSetting("OrganizationViewTreePaneWidth");
    var paneWidth = ISNumber.TryParse(stringPaneWidth);
    if (paneWidth &&
        paneWidth > 10)
    {
        orgSplitPanel.Style.ContainerStyles[0].Size.Width = paneWidth;
    }

    // -6の内訳 : orgSplitPanel.Element.style.border * 2 + orgSplitPanel.Separators[0].Style.Size.Width
    orgSplitPanel.Style.ContainerStyles[1].Size.Width = this.ParentElement.parentElement.clientWidth
                                                      - orgSplitPanel.Style.ContainerStyles[0].Size.Width
                                                      - orgSplitPanelMargin * 2
                                                      - 6;
    extendedOrganizationSplitPanel.AppendChildControlForContainer(1, orgSplitPanel);

    // グリッドとページャー用の分割パネルを用意
    var gridSplitPanel = new iSplitPanel();
    this.GridSplitPanel = gridSplitPanel;
    gridSplitPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
    gridSplitPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
    gridSplitPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
    gridSplitPanel.Style.ContainerStyles[1].Size.Height = 25;
    orgSplitPanel.AppendChildControlForContainer(1, gridSplitPanel);

    // Pagerの作成
    this.Pager = new iPager();
    this.Pager.RenderingMode = iControl.RenderingMode.Append;
    this.Pager.EnableSummary = false;
    this.Pager.PageSize = ISNumber.Parse(GPContext.Configuration.GetSetting('DefaultPageSize'));
    this.Pager.AddEvent(iPager.EventName.SelectedPageChanged, ISFunction.CreateDelegate(this.OnPageChanged, this));

    var candidates = new Array();
    for (var i = 1; i < 10; i++)
    {
        var candidateText = GPContext.Configuration.GetSetting('PageSizeCandidate' + i);
        if (!ISString.IsNullOrEmpty(candidateText))
        {
            var candidate = ISNumber.Parse(candidateText);
            candidates.push(candidate);
        }
    }
    this.Pager.PageSizeCandidates = candidates;
    gridSplitPanel.AppendChildControlForContainer(1, this.Pager);

    // 分割パネルレンダリングとスタイル微調整
    extendedOrganizationSplitPanel.Render(parentElement);
    if (parentControl)
    {
        // 親コントロール情報を追加（リサイズイベント通知の為）
        parentControl.AppendChildControl(extendedOrganizationSplitPanel);
    }
    orgSplitPanel.Element.style.border = "1px #ababab solid";
    orgSplitPanel.Separators[0].GetElement().style.backgroundColor = "#ffffff";
    // パネルリサイズの操作が可能なようにパネルのサイズを多めに取り、セパレーターとしては見た目上1pxだけ右側にボーダーをレンダリングをする
    orgSplitPanel.Separators[0].Style.Size.Width = 3;
    orgSplitPanel.Separators[0].GetElement().style.cursor = "e-resize";
    orgSplitPanel.Separators[0].GetElement().style.borderWidth = "0px 1px 0px 0px";
    orgSplitPanel.Separators[0].GetElement().style.borderStyle = "none solid none none";
    orgSplitPanel.Separators[0].GetElement().style.borderColor = "#ffffff #ababab #ffffff #ffffff";
    this.Pager.Element.style.paddingRight = "5px";

    // セパレーターをResizableオブジェクトに変換
    var separatorElm = orgSplitPanel.Separators[0].GetElement();
    var resizableExtender = new iResizableExtender(orgSplitPanel,
                                                   orgSplitPanel.Separators[0],
                                                   iPanelStyle.StretchOption.Horizontal,
                                                   orgSplitPanel.Containers[0],
                                                   orgSplitPanel.Containers[1],
                                                   10,
                                                   550);
    resizableExtender.Extend();

    // 親リサイズイベントにアタッチ
    orgSplitPanel.AddEvent(iControl.ControlEventName.BeginResizeChildren, ISFunction.CreateDelegate(this.OrgViewResize, this));
    orgSplitPanel.AddEvent(iControl.ControlEventName.EndResize, ISFunction.CreateDelegate(this.OrgViewResize, this));

    // treeインスタンスの作成
    var treeDiv = document.createElement("div");
    treeDiv.oncontextmenu = function () { return false; }; // コンテキストメニューを無効化
    var treeList = document.createElement("ul");
    this.TreeList = treeList;
    treeList.id = this.TreeElementId;
    treeList.style.height = orgSplitPanel.Containers[0].GetElement().style.height;
    treeList.style.margin = "0px";
    treeList.style.paddingTop = "2px";
    treeDiv.appendChild(treeList);

    // gridインスタンスの作成
    var gridDiv = document.createElement("div");
    gridDiv.oncontextmenu = function () { return false; }; // コンテキストメニューを無効化
    var gridTable = document.createElement("table");
    gridTable.id = this.GridElementId;
    gridTable.style.whiteSpace = "nowrap"; // 折り返しを禁止
    gridDiv.appendChild(gridTable);

    // ToDo: treeDivとgridDivをpanelにして、appendChildからRenderイベントでレンダリングする
    orgSplitPanel.Containers[0].GetElement().appendChild(treeDiv);
    gridSplitPanel.Containers[0].GetElement().appendChild(gridDiv);

    // 拡張組織ペインの作成
    var extendedOrganizationDiv = document.createElement("div");
    extendedOrganizationDiv.oncontextmenu = function (){ return false; }; // コンテキストメニューを無効化
    extendedOrganizationDiv.innerHTML = this.ExtendedOrganizationPane();
    extendedOrganizationSplitPanel.Containers[0].GetElement().appendChild(extendedOrganizationDiv);
    extendedOrganizationSplitPanel.Containers[0].GetElement().style.overflow = "hidden";

    extendedOrganizationSplitPanel.Element.style.margin = this.ExtendedOrganizationSplitPanelMargin + "px";

    var tableCellHeight = (this.ExtendedOrganizationSplitPaneHeight - this.ExtendedOrganizationTableTitleHeight - 1) + "px";
    var buildingDepartmentInfoCell = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.Cell");
    buildingDepartmentInfoCell.style.overflowY = "scroll";
    buildingDepartmentInfoCell.style.height = tableCellHeight;

    var managerImage = document.getElementById("ExtendedOrganizationView.Manager.Image");
    managerImage.style.height = tableCellHeight;

    var overviewCell = document.getElementById("ExtendedOrganizationView.Overview.Cell");
    overviewCell.style.overflowY = "scroll";
    overviewCell.style.height = tableCellHeight;

    // スタイル調整の為にResizeメソッドを呼ぶ
    extendedOrganizationSplitPanel.OnResize();

    this.Initialize();
    this.TreeInit();

    this.GridInit(gridSplitPanel.Containers[0].GetElement());
}

GPExtendedOrganizationView.prototype.OnTreeSelectionChanged = function (evt, ui)
{
    (function ($, view)
    {
        // 選択アイテムのクリア
        view.SelectedTreeEntity = ui.selectedNodes[0].data.Entity;
        // 拡張組織設定
        view.SetExtendedOrganization(view.SelectedTreeEntity);

        // Active状態のセット
        view.ActiveControl = "Tree";
        // 選択状態の変更メソッドを呼ぶ
        view.OnSelectionChanged();
    }(ig$, this));
}

