GPExtendedOrganizationView.prototype.SetExtendedOrganization = function (entity)
{
    // 拡張組織ペインの情報を表示する
    // 拠点名
    var buildingName = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.BuildingName");
    buildingName.innerText = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.BuildingName))
    {
        buildingName.innerText = entity.Properties.BuildingName;
    }
    // フロア
    var floor = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.Floor");
    floor.innerText = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.Floor))
    {
        floor.innerText = entity.Properties.Floor;
    }
    // 拠点番号
    var buildingNumber = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.BuildingNumber");
    buildingNumber.innerText = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.BuildingNumber))
    {
        buildingNumber.innerText = entity.Properties.BuildingNumber;
    }
    // 部店名
    var departmentName = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.DepartmentName");
    departmentName.innerText = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.DepartmentName))
    {
        departmentName.innerText = entity.Properties.DepartmentName;
    }
    // 外線番号
    var phoneNumber = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.PhoneNumber");
    phoneNumber.innerText = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.PhoneNumber))
    {
        phoneNumber.innerText = entity.Properties.PhoneNumber;
    }
    // FAX番号
    var fax = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.Fax");
    fax.innerText = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.Fax))
    {
        fax.innerText = entity.Properties.Fax;
    }
    // その他
    var others = document.getElementById("ExtendedOrganizationView.BuildingDepartmentInfo.Others");
    others.innerHTML = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.Others))
    {
        others.innerHTML = entity.Properties.Others;
    }
    // 従業員情報（従業員情報の編集）
    var membersInfoEdit = document.getElementById("ExtendedOrganizationView.MembersInfo.Edit");
    var photoFolder = "";
    membersInfoEdit.innerText = ""; 
    membersInfoEdit.href = ""; 
    if (!ISString.IsNullOrEmpty(entity.Properties.DepartmentNumber))
    {
        membersInfoEdit.innerText = iResxResource.GetString("ExtendedOrganizationView.MembersInfo.Edit.Text");
        membersInfoEdit.href = ISString.TrimEnd(GPContext.WebUrl, '/') + '/Lists/Members_' + iSPUtility.EscapeForListUrl(entity.Properties.DepartmentNumber);

        photoFolder = ISString.TrimEnd(iVxContext.MasterSiteAbsolutePath, '/') + '/' + this.MemberPhotoFolder + '/' + iSPUtility.EscapeForListUrl(entity.Properties.DepartmentNumber);
    }
    // 従業員情報（従業員の写真登録）
    var pictureRegist = document.getElementById('ExtendedOrganizationView.MembersInfo.PictureRegist');
    pictureRegist.innerText = "";
    pictureRegist.href = "";
    // ToDo: 現状では使用しない機能のため、コメントアウト
    //if (!ISString.IsNullOrEmpty(entity.Properties.DepartmentNumber))
    //{
    //    pictureRegist.innerText = iResxResource.GetString("ExtendedOrganizationView.MembersInfo.PictureRegist.Text");
    //    pictureRegist.href = photoFolder;
    //}
    // 部店長（顔写真）
    var managerImage = document.getElementById('ExtendedOrganizationView.Manager.Image');
    managerImage.src = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.Manager))
    {
        var imagePath = photoFolder + "/" + entity.Properties.Manager + ".jpg";
        if (this.CheckImage(imagePath))
        {
            managerImage.src = imagePath;
        }
    }
    // 部店概要
    var overview = document.getElementById('ExtendedOrganizationView.Overview.TextAria');
    overview.innerText = "";
    if (!ISString.IsNullOrEmpty(entity.Properties.Overview))
    {
        overview.innerText = entity.Properties.Overview;
    }

    // 従業員情報がない場合、表示しない
    if (ISString.IsNullOrEmpty(entity.Properties.DepartmentNumber))
    {
        document.getElementById('ExtendedOrganizationView.BuildingDepartmentInfo.MembersInfo').innerText = "";
    }
    else
    {
        document.getElementById('ExtendedOrganizationView.BuildingDepartmentInfo.MembersInfo').innerText = iResxResource.GetString("ExtendedOrganizationView.BuildingDepartmentInfo.MembersInfo");
    }
}

GPExtendedOrganizationView.prototype.OrgViewResize = function ()
{
    this.ExtendedOrganizationSplitPanel.Style.ContainerStyles[1].Size.Height = this.ParentElement.parentElement.clientHeight
                                                                             - this.ExtendedOrganizationSplitPanel.Style.ContainerStyles[0].Size.Height
                                                                             - this.ExtendedOrganizationSplitPanelMargin * 2;
    // Treeの高さ調整
    var treeContainer = this.OrgSplitPanel.Containers[0].GetElement();
    var containerHeight = treeContainer.style.height.replace("px", "");
    if (containerHeight > 0)
    {
        this.TreeList.style.height = containerHeight - 5 + "px";
    }

    // グリッドパネルの幅調整
    var width = GPGridUtility.GetGridWidth(this.OrgSplitPanel);
    this.OrgSplitPanel.Style.ContainerStyles[1].Size.Width = width;
    
    // グリッドのサイズ調整
    (function ($, view)
    {
        // IE8(ブラウザバージョン8互換の場合のスタイルずれの補正
        var height = ISDomAccessor.GetInnerHeight(view.GridSplitPanel.Containers[0].GetElement());
        if (ISBrowser.GetBrowserVersion() == 7)
        {
            height -= 17;
        }
        // グリッドが初期化済みの場合サイズ変更する
        if ($('#' + view.GridElementId).data("igGrid") != null)
        {
            $('#' + view.GridElementId).igGrid({
                width: width,
                height: height
            });
        }
    }(ig$, this));
}

GPExtendedOrganizationView.prototype.HideExtendedOrganizationPane = function (hide)
{
    if (hide)
    {
        this.ExtendedOrganizationSplitPanel.Style.ContainerStyles[0].Size.Height = 0;
        this.ExtendedOrganizationSplitPanel.Containers[0].GetElement().style.display = "none";
    }
    else
    {
        this.ExtendedOrganizationSplitPanel.Style.ContainerStyles[0].Size.Height = this.ExtendedOrganizationSplitPaneHeight;
        this.ExtendedOrganizationSplitPanel.Containers[0].GetElement().style.display = "";
    }

    this.ExtendedOrganizationSplitPanel.Style.ContainerStyles[1].Size.Height = this.ParentElement.parentElement.clientHeight
                                                                             - this.ExtendedOrganizationSplitPanel.Style.ContainerStyles[0].Size.Height
                                                                             - this.ExtendedOrganizationSplitPanelMargin * 2;
    this.ExtendedOrganizationSplitPanel.OnResize();
}

GPExtendedOrganizationView.prototype.CheckImage = function (url)
{
    var request = new XMLHttpRequest();
    request.onerror = function ()
    {
        return false;
    };
    request.open('HEAD', url, false);
    request.send();
    return request.status != 404;
}

