//  PopupImage
// -----------------------------------------------------------------------
Infoshare.GroupPicker.ExtendedOrganizationView.PopupImage = function InfoInfoshare$GroupPicker$ExtendedOrganizationView$PopupImage() { }
PopupImage = Infoshare.GroupPicker.ExtendedOrganizationView.PopupImage;

PopupImage.PopupImageAreaId = 'popupImageArea';
PopupImage.MemberPhotoDivId = 'memberPhotoDiv';
PopupImage.MemberPhotoFolder = 'MemberPhoto';

PopupImage.Show = function (url)
{
    var popupImageAreaId = this.PopupImageAreaId;
    if (!new GPExtendedOrganizationView().CheckImage(url))
    {
        url = '';
    }

    var builder = new Array();
    builder[builder.length] = "<img id='" + popupImageAreaId + "' ";
    builder[builder.length] =      "src='" + url + "' ";
    builder[builder.length] =      "height='200px' ";
    builder[builder.length] =      "style='position: absolute; ";
    builder[builder.length] =             "top:  " + (event.pageY + 3) + "px; ";
    builder[builder.length] =             "left: " + (event.pageX + 3) + "px; ";
    builder[builder.length] =             "opacity: 0; ";
    builder[builder.length] =             "box-shadow: 3px 3px 8px 0 RGBA(0, 0, 0, .5); ";
    builder[builder.length] =             "z-index: 10000;' />";

    var markup = builder.join('');
    var extendedOrganizationViewMemberPhoto = document.getElementById(this.MemberPhotoDivId);
    if (!extendedOrganizationViewMemberPhoto)
    {
        // 顔写真表示用のdivを追加
        var memberPhotoDiv = document.createElement('div');
        memberPhotoDiv.id = this.MemberPhotoDivId;
        document.body.appendChild(memberPhotoDiv);
        extendedOrganizationViewMemberPhoto = document.getElementById(this.MemberPhotoDivId);
    }
    
    extendedOrganizationViewMemberPhoto.innerHTML = markup;

    setTimeout(function ()
    {
        var element = document.getElementById(popupImageAreaId);
        if (element)
        {
            element.style.transitionProperty = 'opacity';
            element.style.transitionDuration = '500ms';
            element.style.opacity = 1;
        }
    }, 100);
}

PopupImage.Hide = function ()
{
    var element = document.getElementById(this.PopupImageAreaId);
    if (element)
    {
        element.parentElement.removeChild(element);
    }
}
                                  
