ISNamespace.Register('Infoshare.GroupPicker');


// -----------------------------------------------------------------------
//  SearchView
// -----------------------------------------------------------------------
Infoshare.GroupPicker.SearchView = function InfoInfoshare$GroupPicker$SearchView() { }
GPSearchView = Infoshare.GroupPicker.SearchView;
GPSearchView.TypeName = 'Infoshare.GroupPicker.SearchView';

// 検索用プレフィックス（^ を回数ごとに変える）
GPSearchView.SearchTypePrefixUser = "^";
GPSearchView.SearchTypePrefixGroup = "^^";

GPSearchView.prototype = {
    TypeName: GPSearchView.TypeName,
    ParentPanel: null,
    SplitPanel: null,
    UserFilter: null,
    GroupFilter: null,
    SearchTextBox: null,
    MessageLabel: null,
    SelectedGridSids: [],
    GridDataSource: [],
    TempGridItems: [],
    Pager: null,
    ParentPanel: null,

    GridParentElement: null,
    GridElementId: null,

    ValidateDataSource : GPOrganizationView.ValidateDataSource,

    KeywordValidateOption :{
        SameKeyword: true,
        EmptyKeyword: true,
        SystemKeyword: true,
        SurrogatePair: true,
        LengthKeyword: true,
        CountKeyword: true
    },

    Features:
    [{ name: "Selection",
       multipleSelection: true},
     { name: "Resizing",
       allowDoubleClickToResize: true,
       columnSettings: [{ columnKey: "Type", allowResizing: false },
                        { columnKey: "Presence", allowResizing: false },
                        { columnKey: "Profile", allowResizing: false },
                        { columnKey: "ProfileImage", allowResizing: false }]
     }],

    // ビューの初回表示メソッド
    InitializeView: function ()
    {
        if (this.Initialized)
        {
            return;
        }

        // データソースのバリデーション
        var valid = this.ValidateDataSource(this.DataSource);
        if (!valid)
        {
            this.Initialized = true;
            return;
        }

        this.Initialized = true;
    },

    Render: function(parentElement, parentControl)
    {
        this.ParentPanel = parentControl;

        // 固有のIDの設定
        var replacedId = this.Info.Id.replace(/\./g, '_');        
        this.GridElementId = replacedId + '_Grid_' + ISGuid.New();

        // 分割パネル
        var panel = new iSplitPanel(new GPSearchViewSplitPanelStyle());
        this.SplitPanel = panel;
        panel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
        panel.Style.StretchOption = iPanelStyle.StretchOption.Both;

        // 分割パネル: フィルタ、検索ボックス、グリッド、Pagerの4分割
        panel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle(), new GPSearchViewGridContainerPanelStyle(), new iPanelStyle()];
        panel.Style.ContainerStyles[0].Size.Height = 25;
        panel.Style.ContainerStyles[1].Size.Height = 25;
        panel.Style.ContainerStyles[3].Size.Height = 15;

        // フィルター: 人
        this.UserFilter = new iDescribedCheckBox();
        this.UserFilter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
        this.UserFilter.Description = iResxResource.GetString('PickerDialog.SearchView.UserFilter.Title');
        panel.AppendChildControlForContainer(0, this.UserFilter);

        // フィルター: 組織
        this.GroupFilter = new iDescribedCheckBox();
        this.GroupFilter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
        this.GroupFilter.Description = iResxResource.GetString('PickerDialog.SearchView.GroupFilter.Title');
        panel.AppendChildControlForContainer(0, this.GroupFilter);

        // 検索ボックス
        this.SearchTextBox = new iSearchTextBox();

        var imagesPath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
        this.SearchTextBox.Style.TextBoxStyle = new GPSearchTextBoxTextBoxStyle();
        this.SearchTextBox.Style.ButtonStyle = new iSearchTextBoxImageButtonStyle(new iButtonImageInfo(imagesPath + 'Loupe.png',
                                                                                                       '',
                                                                                                       '',
                                                                                                       imagesPath + 'Loupe-Press.png',
                                                                                                       imagesPath + 'Loupe-Hover.png'));
        this.SearchTextBox.Watermark = iResxResource.GetString('PickerDialog.SearchView.SearchTextBox.Watermark');
        this.SearchTextBox.AddEvent(iSearchTextBox.EventName.Search, ISFunction.CreateDelegate(this.OnSearch, this));
        panel.AppendChildControlForContainer(1, this.SearchTextBox);

        // Pagerの作成
        this.Pager = new iPager();
        this.Pager.RenderingMode = iControl.RenderingMode.Append;
        this.Pager.EnableSummary = false;
        this.Pager.PageSize = ISNumber.Parse(GPContext.Configuration.GetSetting('DefaultPageSize'));
        this.Pager.AddEvent(iPager.EventName.SelectedPageChanged, ISFunction.CreateDelegate(this.OnPageChanged, this));

        var candidates = new Array();
        for (var i = 1; i < 10; i++)
        {
            var candidateText = GPContext.Configuration.GetSetting('PageSizeCandidate' + i);
            if (!ISString.IsNullOrEmpty(candidateText))
            {
                var candidate = ISNumber.Parse(candidateText);
                candidates.push(candidate);
            }
        }
        this.Pager.PageSizeCandidates = candidates;

        panel.AppendChildControlForContainer(3, this.Pager);

        // 分割パネルレンダリング
        panel.Render(parentElement);
        if (parentControl)
        {
            // 親コントロール情報を追加（リサイズイベント通知の為）
            parentControl.AppendChildControl(panel); 
        }

        // デフォルトで人フィルターを有効にする
        this.UserFilter.CheckBox.Check();

        // グリッド初期化
        this.GridParentElement = panel.Containers[2].GetElement();
        if (!iBoolean.TryParse(this.Info.Options.Get('EnableContextMenu'), false))
        {
            this.GridParentElement.oncontextmenu = function () { return false; };  // コンテキストメニューを無効化
        }
        this.RenderGrid();

        // スタイル調整のためにResizeメソッドを呼ぶ
        this.ParentPanel.OnResize();
    },

    RenderGrid: function()
    {
        // グリッド用のテーブルを描画
        var table = document.createElement('table');
        table.id = this.GridElementId;
        if (!iBoolean.TryParse(this.Info.Options.Get('EnableContextMenu'), false))
        {
            table.oncontextmenu = function() { return false; }; // コンテキストメニューを無効化
        }
        table.style.whiteSpace = "nowrap"; // 折り返しを禁止
        this.GridParentElement.appendChild(table);

        // テーブル内にMessage表示用のlabelを追加
        this.MessageLabel = document.createElement('label');
        this.MessageLabel.style.visibility = 'hidden';
        table.appendChild(this.MessageLabel);

        // グリッド描画
        (function($, view)
        {
            // DataSourceの初期化
            view.GridDataSource.clear();
            view.Columns = GPGridUtility.BuildColumns(view.Info.ViewFields);

            // igGridを描画
            $('#' + view.GridElementId).igGrid({
                columns: view.Columns,
                width:  ISDomAccessor.GetInnerWidth(view.GridParentElement)  + 'px',
                height: "100px", // 値に意味は無し（Headerを固定する為に指定する必要がある）
                dataSource: view.GridDataSource,
                alternateRowStyles: false,
                autofitLastColumn : false,
                primaryKey: "EntityId",
                features: view.Features,
                dataRendered: function (evt, ui)
                {
                    if (iBoolean.TryParse(view.Info.Options.Get('EnableContextMenu'), false))
                    {
                        GPGridUtility.EnableDrag(evt);
                    }
                }
            });

            // 種別ヘッダーのスタイルを修正（表示名列と結合して見えるようにborder-rightを削除する）
            // CSSから実装を移行
            GPGridUtility.DeleteHeaderBorder(view.GridElementId + "_Type");
            GPGridUtility.DeleteHeaderBorder(view.GridElementId + "_Presence");

            // グリッドにProfileImage列がある場合、グリッド内の行の高さを指定するクラスを追加する
            if (view.Info.ViewFields.Contains('ProfileImage'))
            {
                GPGridUtility.AddGridElementClass(view.GridElementId, "is-gp-InfoCall-GridElement");
            }

            // SelectionChangeのイベント
            $('#' + view.GridElementId).on("iggridselectionrowselectionchanged", ISFunction.CreateDelegate(view.OnGridSelectionChanged, view));
            // ダブルクリックイベント定義

            var disable = iBoolean.TryParse(view.Info.Options.Get('DisableGridDoubleClick'), false);
            if (!disable)
            {
                $('#' + view.GridElementId).dblclick(function (event)
                {
                    view.OnItemSelected();
                });
            }

        }(ig$, this));

        // リサイズイベント
        this.SplitPanel.AddEvent(iControl.ControlEventName.BeginResizeChildren, ISFunction.CreateDelegate(this.OnResize, this));
        this.SplitPanel.AddEvent(iControl.ControlEventName.EndResize, ISFunction.CreateDelegate(this.OnResize, this));

        // サイズ調整のためリサイズ
        this.OnResize();
    },

    OnGridSelectionChanged: function(evt)
    {
        (function ($, view)
        {
            // 複数回呼ばれるイベントをキャンセルする
            // DataBindを実行するたびにイベント（iggridselectionrowselectionchanged）が登録される為、二回目以降のイベントを処理しない
            evt.preventDefault();

            // 選択アイテムのクリア
            view.SelectedGridSids.clear();
            var selectedRows = $('#' + view.GridElementId).igGridSelection("selectedRows");

            for (var i = 0; i < selectedRows.length; i++)
            {
                // 選択アイテムに追加
                view.SelectedGridSids.push(selectedRows[i].id);
            }

            // 選択メソッドを呼ぶ
            view.OnSelectionChanged();               
        }(ig$, this));
    },

    OnResize: function()
    {
        // IE8(ブラウザバージョン8互換の場合のスタイルずれの補正
        var height = ISDomAccessor.GetInnerHeight(this.GridParentElement);
        if (ISBrowser.GetBrowserVersion() == 7)
        {
            height -= 17;
        }

        (function($, view)
        {
            $('#' + view.GridElementId).igGrid({
                width: ISDomAccessor.GetInnerWidth(view.GridParentElement) + 'px',
                height: height + 'px'
            });
        })(ig$, this);
    },

    PreviousUserFilterState: null,
    PreviousGroupFilterState: null,
    PreviousKeyword: null,
    OnSearch: function()
    {
        // データソースが存在しない場合は検索しない
        if (!this.DataSource ||
            !this.DataSource.DataSourceList)
        {
            return;
        }

        var searchText = this.SearchTextBox.TextBox.GetValue();

        // 同一条件での再検索を止める
        if (this.PreviousUserFilterState  === this.UserFilter.IsChecked() &&
            this.PreviousGroupFilterState === this.GroupFilter.IsChecked() &&
            this.PreviousKeyword === searchText)
        {
            ISTrace.TraceVerbose('Skipped search since the keywords are same as previous one.');
            return false;
        }
        this.PreviousUserFilterState  = this.UserFilter.IsChecked();
        this.PreviousGroupFilterState = this.GroupFilter.IsChecked();
        this.PreviousKeyword = searchText;

        var keyword = this.GetKeyword(searchText);
        var keywords = keyword.GetKeywords();

        // 検索
        if (!iObject.IsNullOrUndefined(keywords) &&
            keywords.length > 0)
        {
            // フィルター処理
            var filters = [];
            if (this.UserFilter.IsChecked())  { filters.push('user'); }
            if (this.GroupFilter.IsChecked()) { filters.push('group'); }

            // 検索
            if (filters.length > 0)
            {
                this.GetItems(filters, keywords, iFunction.CreateDelegate(this.UpdateGridDataSource, this));
            }
            else
            {
                alert(iResxResource.GetString('PickerDialog.SearchView.FilterEmpty'));
            }
        }
        else
        {
            alert(keyword.ErrorMessage);
        }
    },

    GetKeyword: function(searchText)
    {
        // 同義語
        var synonyms = null;
        var enableSynonymHandling = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableSynonymHandling'), false);
        if (enableSynonymHandling && 
            !iObject.IsNullOrUndefined(GPContext.Configuration.Synonyms) &&
            GPContext.Configuration.Synonyms.length > 0)
        {
            synonyms = GPContext.Configuration.Synonyms;
        }

        // 検証オプション
        var validateOption = new GPKeywordValidateOption();

        // キーワード分割、検証
        var keyword = new GPSearchKeyword(searchText, synonyms, validateOption);
        keyword.Limitation = new GPSearchKeywordLimitation(GPContext.Configuration.GetSetting('MaxSearchTextLength'), 
                                                           GPContext.Configuration.GetSetting('MaxSearchWordLength'),
                                                           GPContext.Configuration.GetSetting('MaxSearchWordCount'));
        keyword.ReservedWords = [ GPSearchView.SearchTypePrefixUser,
                                  GPSearchView.SearchTypePrefixGroup,
                                  '|' ];

        return keyword;
    },

    UpdateGridDataSource: function(items)
    {
        (function ($, view)
        {            
            // DataBindの際に定義したArrayを参照するので配列要素を詰め替える
            view.GridDataSource.clear();

            // 閾値を超えて検索結果が取得されるケースは items nullが取得される
            var tempGridItems = items ? items : [];
            // 検索結果をキャッシュ
            view.TempGridItems = tempGridItems;
            view.Pager.ItemCount = tempGridItems.length;

            // Page1を表示
            view.Pager.ChangePage(1);
            
            // データソースを更新したので選択状態の変更イベントを発行
            view.OnSelectionChanged();
            
            if (items == null || items.length <= 0)
            {
                $("#" + view.GridElementId).igGrid("dataBind");

                var message = '';
                if (items == null) // 閾値を超えて検索
                {
                    message = iResxResource.GetString('PickerDialog.SearchView.MessageLabel.ThresholdOverResults');
                    
                }
                else if (items.length <= 0) // 検索結果ゼロ
                {
                    message = ISString.Format(iResxResource.GetString('PickerDialog.SearchView.MessageLabel.ResultNull'),
                                              view.SearchTextBox.TextBox.GetValue());
                }

                view.MessageLabel.innerText = message;
                view.MessageLabel.style.visibility = "visible";
            }
            else 
            {
                view.MessageLabel.innerText = "";
                view.MessageLabel.style.visibility = "hidden";
            }
        })(ig$, this);
    },

    UpdateGrid: function()
    {
        (function ($, view)
        {            
            // DataBindの際に定義したArrayを参照するので配列要素を詰め替える
            view.GridDataSource.clear();

            var items = view.TempGridItems;            
            var startItemIndex = (view.Pager.CurrentPageNumber - 1) * view.Pager.PageSize;
            var endItemIndex   = items.length > view.Pager.CurrentPageNumber * view.Pager.PageSize ?  view.Pager.CurrentPageNumber * view.Pager.PageSize : items.length;

            for (var i = startItemIndex ; i < endItemIndex ; i++)
            {
                view.GridDataSource.push(items[i]);
            }                        

            $("#" + view.GridElementId).igGrid("dataBind");
        })(ig$, this);

        // プレゼンスの更新
        if (this.Info.ViewFields.ContainsBy('Presence', 'ViewType'))
        {
            GPPresenceUtility.UpdatePresenceLink(this.GridElementId);
        }
        if (this.Info.ViewFields.ContainsBy('UcPresence', 'ViewType'))
        {
            UCPresenceController.GetInstance().UpdatePresenceStyles(this.GridElementId, function ()
            {
                // ToDo:
            });
        }
        if (this.Info.ViewFields.ContainsBy('GraphPresence', 'ViewType'))
        {
            GraphPresenceController.GetInstance().UpdatePresenceStyles(this.GridElementId, function ()
            {
                // ToDo:
            });
        }

        // ProfileImageの更新
        if (this.Info.ViewFields.ContainsBy('ProfileImage', 'ViewType') && GPContext.Configuration.GetSetting('ProfileImageAPI').toUpperCase() == 'Graph'.toUpperCase())
        {
            GraphProfileImageController.GetInstance().UpdateGraphProfileImages(this.GridElementId);
        }
    },

    SelectionChangedEventHandler: null,
    OnSelectionChanged: function ()
    {
        // 選択状態の変更を通知
        if (this.SelectionChangedEventHandler)
        {
            this.SelectionChangedEventHandler(this);
        }
    },

    ItemSelectedEventHandler: null,
    OnItemSelected: function()
    {
        // 選択状態の変更を通知
        if (this.ItemSelectedEventHandler)
        {
            this.ItemSelectedEventHandler(this);
        }
    },

    GetSelectedItems: function()
    {
        var returnItems = [];
        (function ($, view)
        {
            var selectedEntities = [];
            
            for (var i = 0; i < view.TempGridItems.length; i++)
            {
                for (j = 0; j < view.SelectedGridSids.length; j++)
                {
                    if (view.TempGridItems[i]["EntityId"] == view.SelectedGridSids[j])
                    {
                        selectedEntities.push(view.TempGridItems[i]["Entity"]);
                    }
                }
            }

            returnItems = selectedEntities;
        })(ig$, this);

        return returnItems;
    },

    GetItems: function(typeValue, keywords, callback)
    {
        // Where句
        var where = this.BuildWhereQuery(typeValue, keywords, true);

        // OrderBy句
        var orderby = '';
        for (var i = 0; i < this.Info.SortOrders.length; i++)
        {
            var order = this.Info.SortOrders[i];
            orderby += SPQueryBuilder.BuildOrderByFieldRef(order.FieldName, order.Ascending);
        }

        // ViewField設定 
        var fieldRefs = '';

        // 組織マスタの場合はViewFieldsを設定せず全ての列を取得する
        // 拡張した列などに対応する為
        if (this.Info.Id != "Infoshare.GroupPicker.OrganizationManagement.SearchView")
        {
            for(var i = 0; i < this.Info.ViewFields.GetLength(); i++)
            {
                var field = this.Info.ViewFields.Get(i);
                fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
            }
            // ソートに利用するフィールドを考慮（分割クエリ対応）
            for (var i = 0; i < this.Info.SortOrders.length; i++)
            {
                var fieldName = this.Info.SortOrders[i].FieldName;
                if (GPContext.Configuration.Fields.Contains(fieldName))
                {
                    continue;
                }
                fieldRefs += SPQueryBuilder.BuildFieldRef(fieldName);
            }
        }       

        // クエリ組み立て
        var query = new ISSPQuery();
        query.Query        = SPQueryBuilder.BuildQuery(orderby, where);
        query.ViewFields   = SPQueryBuilder.BuildViewFields(fieldRefs);
        query.QueryOptions = SPQueryBuilder.BuildQueryOptions(SPQueryBuilder.BuildMandatoryColumnsOption(false));

        // 閾値を超えるアイテムのクエリを設定する
        query.EnableIterativeQueries = ISBoolean.TryParse(GPContext.Configuration.GetSetting('EnableLargeSearchQuery'), false);

        GPGridUtility.GetItems(this.DataSource, query, this.Columns, callback);
    },

    BuildWhereQuery: function(typeValue, keywords, enableHierarchicalIdFilter)
    {
        // 検索対象フィールドを確定（同義語検索の有効・無効で切り替え）
        var fieldName = 'SearchKey';
        if (ISBoolean.Parse(GPContext.Configuration.GetSetting('EnableSynonymHandling')))
        {
             fieldName = 'SynonymSearchKey';
        }

        // Where句: キーワード
        // 検索キーワードをANDでつないでいく
        var keywordField = GPContext.Configuration.Fields.Get(fieldName);

        // 構成ファイル定義ではなく、実際のリストのフィールドを確認する
        if (this.DataSource.DataSourceList.Fields)
        {
            keywordField = this.DataSource.DataSourceList.Fields.Get(fieldName);
            keywordField.InternalName = keywordField.Name;
        }

        var keywordFilter = '';
        for (var i = 0; i < keywords.length; i++)
        {
            var keyword = keywords[i];
            var condition = SPQueryBuilder.BuildContainsQueryCondition(keywordField.InternalName, keywordField.Type, keyword);
            if (keywordFilter.length <= 0) { keywordFilter = condition; }
            else                           { keywordFilter = SPQueryBuilder.BuildAndQueryCondition(keywordFilter + condition); }
        }

        // Where句: 種別
        // 種別はORでつないでいく
        var typeFilter = '';
        for (var i = 0; i < typeValue.length; i++)
        {
            var typePrefix = "|{0}|";
            var typeToken = "";
            var type = typeValue[i];
            if (ISString.Equals(type, "User", true))
            {
                typeToken = GPSearchView.SearchTypePrefixUser;

            }
            else if (ISString.Equals(type, "Group", true))
            {
                typeToken = GPSearchView.SearchTypePrefixGroup;
            }
            typePrefix = ISString.Format(typePrefix, typeToken);

            var condition = SPQueryBuilder.BuildContainsQueryCondition(keywordField.InternalName, keywordField.Type, typePrefix);
            if (typeFilter.length <= 0) { typeFilter = condition; }
            else { typeFilter = SPQueryBuilder.BuildOrQueryCondition(typeFilter + condition); }
        }

        // Where句: HierarchicalId（ルート組織からたどれるエンティティのみを取得する）
        if (enableHierarchicalIdFilter)
        {            
            var rootTreeEntities = this.DataSource.RootTreeEntities;
            var hierarchicalIdField = GPContext.Configuration.Fields.Get('HierarchicalId');
            // 複数のルート組織をOr条件でつなげる
            var hierarchicalIdFilter = '';

            for (var i = 0; i < rootTreeEntities.length; i++)
            {
                var rootTreeEntity = rootTreeEntities[i];
                var rootEntityHierarchicalId = rootTreeEntity.Properties.HierarchicalId;
                var rootEntityHierarchicalIdArray = rootEntityHierarchicalId.split("|");
                var rootQuery = '|' + rootEntityHierarchicalIdArray[1];
                var condition = SPQueryBuilder.BuildContainsQueryCondition(hierarchicalIdField.InternalName, hierarchicalIdField.Type, rootQuery);
                if (hierarchicalIdFilter.length <= 0) { hierarchicalIdFilter = condition; }
                else { hierarchicalIdFilter = SPQueryBuilder.BuildOrQueryCondition(hierarchicalIdFilter + condition); }
            }

            // Rootが見つからない場合、0件の結果のアイテムを返す
            // nullの場合は、閾値のエラーとして処理される為
            if (ISString.IsNullOrEmpty(hierarchicalIdFilter))
            {
                callback([]);
                return;
            }
        }

        // Where句: where
        // キーワードと種別とHierarchicaIdをANDでつなぐ
        var where = SPQueryBuilder.BuildAndQueryCondition(keywordFilter + typeFilter);
        if (enableHierarchicalIdFilter)
        {
            where = SPQueryBuilder.BuildAndQueryCondition(where + hierarchicalIdFilter);
        }        

        // Where句: ShowInView
        searchViewFilter = '';
        // ToDo: View定義からIDを連携するように改修
        var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "SearchView");
        var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
        searchViewFilter = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);

        // EnableVisibleGroups=trueの場合、CurrentUserのVisibleGroupsを検索条件に追加する
        var enableVisibleGroups = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableVisibleGroups'), false);
        if (enableVisibleGroups)
        {
            searchViewFilter = GPCamlQueryCondition.AddVisibleGroupsCondition(searchViewFilter, GPViewContext.CurrentUserEntity);
        }

        where = SPQueryBuilder.BuildAndQueryCondition(where + searchViewFilter);

        return where;
    },

    OnPageChanged: function ()
    {
        if (this.TempGridItems.length > 0)
        {
            this.UpdateGrid();
        }
    }
}

// -----------------------------------------------------------------------
//  SearchViewPanelStyle
// -----------------------------------------------------------------------
Infoshare.GroupPicker.SearchViewSplitPanelStyle = function Infoshare$GroupPicker$SearchViewSplitPanelStyle()
{
    Infoshare.Web.Control.SplitPanelStyle.apply(this);

    this.ClassName        = 'is-gp-SearchViewSplitPanel';
    this.EnableClassName  = 'is-gp-SearchViewSplitPanel-Enable';
    this.DisableClassName = 'is-gp-SearchViewSplitPanel-Disable';

    this.ActiveClassName  = 'is-gp-SearchViewSplitPanel-Active';
}
