// -----------------------------------------------------------------------
Infoshare.GroupPicker.MemberSearchView = function InfoInfoshare$GroupPicker$MemberSearchView() { }
GPMemberSearchView = Infoshare.GroupPicker.MemberSearchView;
GPMemberSearchView.TypeName = 'Infoshare.GroupPicker.MemberSearchView';

GPMemberSearchView.prototype = {
    TypeName: GPMemberSearchView.TypeName,

    ParentPanel: null,
    ParentElement: null,

    LayoutPanel: null,
    ResultAreaPanel: null,
    ResultGridPanel: null,

    UserFilter: null,
    GroupFilter: null,
    SearchTextBox: null,

    ActiveControl: null,

    ResultListElementId: null,
    ResultList: null,

    ResultGridElementId: null,
    ResultGrid: null,
    ResultGridPager: null,

    ListData: [],
    SelectedListEntity: null,

    GridData: [],
    SelectedGridSids: [],
    TempGridItems: [],

    MemberOfIdFields: null,

    Initialized: false,


    Features:
    [{ name: "Selection",
       multipleSelection: true},
     { name: "Resizing",
       allowDoubleClickToResize: true,
       columnSettings: [{ columnKey: "Type",     allowResizing: false },
                        { columnKey: "Presence", allowResizing: false },
                        { columnKey: "Profile",  allowResizing: false },
                        { columnKey: "ProfileImage", allowResizing: false }]
     }],

    
    ValidateDataSource: GPOrganizationView.ValidateDataSource,


    InitializeView: function ()
    {
        if (this.Initialized)
        {
            return;
        }

        // データソースのバリデーション
        var valid = this.ValidateDataSource(this.DataSource);
        if (!valid)
        {
            this.Initialized = true;
            return;
        }
    },

    Render: function (parentElement, parentControl)
    {
        this.ParentPanel   = parentControl;
        this.ParentElement = parentElement;

        // 固有のIDの設定
        var replacedId = this.Info.Id.replace(/\./g, '_');        
        this.ResultListElementId = replacedId + '_ResultList_' + ISGuid.New();
        this.ResultGridElementId = replacedId + '_ResultGrid_' + ISGuid.New();

        // レイアウト
        // 【LayoutPanel】
        // ----------------------------------
        // | [人選択] [組織選択]            |
        // ----------------------------------
        // | [検索テキストボックス]         |
        // ----------------------------------
        // |【ResultAreaPanel】             |
        // |--------------------------------|
        // || [リスト] |【ResultGridPanel】||
        // ||          |-------------------||
        // ||　　　　　|| [グリッド]      |||
        // ||          |-------------------||
        // ||          || [ページャー]    |||
        // ||          |-------------------||
        // |--------------------------------|
        // ----------------------------------

        // レイアウトパネル
        var panel = new iSplitPanel(new GPSearchViewSplitPanelStyle());
        panel.DisplayType           = iPanelStyle.DisplayType.Block;
        panel.Style.Mode            = iSplitPanelStyle.Mode.Horizontal;
        panel.Style.StretchOption   = iPanelStyle.StretchOption.Both;
        panel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle(), new iPanelStyle()];
        panel.Style.ContainerStyles[0].Size.Height = 25;
        panel.Style.ContainerStyles[1].Size.Height = 25;
        this.LayoutPanel = panel;

        if (this.ParentPanel)
        {
            // ToDo(skomatsu): 要否確認
            // 親コントロール情報を追加（リサイズイベント通知の為）
            this.ParentPanel.AppendChildControl(this.LayoutPanel);
        }

        // フィルター: 人選択
        var filter = new iDescribedCheckBox();
        filter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
        filter.Description       = iResxResource.GetString('PickerDialog.SearchView.UserFilter.Title');
        this.UserFilter = filter;
        this.LayoutPanel.AppendChildControlForContainer(0, this.UserFilter);

        // フィルター: 組織選択
        var filter = new iDescribedCheckBox();
        filter.Style.DisplayType = iPanelStyle.DisplayType.Inline;
        filter.Description       = iResxResource.GetString('PickerDialog.SearchView.GroupFilter.Title');
        this.GroupFilter = filter;
        this.LayoutPanel.AppendChildControlForContainer(0, this.GroupFilter);

        // 検索テキストボックス
        var textbox = new iSearchTextBox();
        var imagesPath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/Infoshare.InfoCall/';
        textbox.Style.TextBoxStyle = new GPSearchTextBoxTextBoxStyle();
        textbox.Style.ButtonStyle = new iSearchTextBoxImageButtonStyle(new iButtonImageInfo(imagesPath + 'Loupe.png',
                                                                                            '',
                                                                                            '',
                                                                                            imagesPath + 'Loupe-Press.png',
                                                                                            imagesPath + 'Loupe-Hover.png'));
        textbox.Watermark = iResxResource.GetString('PickerDialog.SearchView.SearchTextBox.Watermark');
        textbox.AddEvent(iSearchTextBox.EventName.Search, iFunction.CreateDelegate(this.OnSearch, this));
        this.SearchTextBox = textbox;
        this.LayoutPanel.AppendChildControlForContainer(1, this.SearchTextBox);


        this.RenderResultArea();

        this.LayoutPanel.Render(this.ParentElement);

        this.RenderGrids();

        this.GroupFilter.Check();
        this.UserFilter.Check();

        // スタイル調整の為にResizeメソッドを呼ぶ
        this.LayoutPanel.OnResize();
    },

    RenderResultArea: function()
    {
        // レイアウト
        // 【LayoutPanel】
        // ----------------------------------
        // | [人選択] [組織選択]            |
        // ----------------------------------
        // | [検索テキストボックス]         |
        // ----------------------------------
        // |【ResultAreaPanel】             |
        // |--------------------------------|
        // || [リスト] |【ResultGridPanel】||
        // ||          |-------------------||
        // ||　　　　　|| [グリッド]      |||
        // ||          |-------------------||
        // ||          || [ページャー]    |||
        // ||          |-------------------||
        // |--------------------------------|
        // ----------------------------------

        // 検索結果パネル
        var panel = new iSplitPanel();
        panel.DisplayType           = iPanelStyle.DisplayType.Block;
        panel.Style.Mode            = iSplitPanelStyle.Mode.Vertical;
        panel.Style.StretchOption   = iPanelStyle.StretchOption.Both;
        panel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];

        // リストペインの幅を調整（規定値: 親要素の幅の25%）
        var listWidth = this.ParentElement.parentElement.clientWidth * 0.25;
        for (;;)
        {
            if (!this.Info.Options.Contains('ResultListPaneWidth'))
            {
                break;
            }

            var widthText = this.Info.Options.Get('ResultListPaneWidth');
            if (iString.IsNullOrEmpty(widthText))
            {
                break;
            }

            var width = ISNumber.TryParse(widthText);
            if (width && width > 10)
            {
                listWidth = width;
            }

            break;
        }

        // グリッドペインの幅を計算
        // -6の内訳 : panel.Element.style.border * 2 + panel.Separators[0].Style.Size.Width
        var margin = 10;
        var gridWidth = this.ParentElement.parentElement.clientWidth
                      - listWidth
                      - margin * 2
                      - 6;

        panel.Style.ContainerStyles[0].Size.Width = listWidth;
        panel.Style.ContainerStyles[1].Size.Width = gridWidth;

        this.ResultAreaPanel = panel;
        this.LayoutPanel.AppendChildControlForContainer(2, this.ResultAreaPanel);

        // グリッドとページャー用の分割パネルを用意
        var panel = new iSplitPanel();
        panel.DisplayType           = iPanelStyle.DisplayType.Block;
        panel.Style.Mode            = iSplitPanelStyle.Mode.Horizontal;
        panel.Style.StretchOption   = iPanelStyle.StretchOption.Both;
        panel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
        panel.Style.ContainerStyles[1].Size.Height = 25;

        this.ResultGridPanel = panel;
        this.ResultAreaPanel.AppendChildControlForContainer(1, this.ResultGridPanel);

        // ページャー作成
        var pager = new iPager();
        pager.RenderingMode = iControl.RenderingMode.Append;
        pager.EnableSummary = false;
        pager.PageSize      = ISNumber.Parse(GPContext.Configuration.GetSetting('DefaultPageSize'));
        pager.AddEvent(iPager.EventName.SelectedPageChanged, iFunction.CreateDelegate(this.OnPageChanged, this));

        // ページャー: 表示件数オプションの初期化
        var candidates = new Array();
        for (var i = 1; i < 10; i++)
        {
            var candidateText = GPContext.Configuration.GetSetting('PageSizeCandidate' + i);
            if (!iString.IsNullOrEmpty(candidateText))
            {
                var candidate = ISNumber.Parse(candidateText);
                candidates.push(candidate);
            }
        }
        pager.PageSizeCandidates = candidates;

        this.ResultGridPager = pager;
        this.ResultGridPanel.AppendChildControlForContainer(1, this.ResultGridPager);
    },

    RenderGrids: function()
    {
        // レイアウトパネルのスタイル調整
        var margin = 10;
        //this.ResultAreaPanel.GetElement().style.margin = margin + 'px';
        this.ResultAreaPanel.GetElement().style.border = '1px #ababab solid';

        // リサイズ操作を容易にするためパネルサイズを増やす
        // セパレーターとしては見た目上1pxだけ右側にボーダーをレンダリングをする
        this.ResultAreaPanel.Separators[0].Style.Size.Width = 3; //
        this.ResultAreaPanel.Separators[0].GetElement().style.backgroundColor = '#ffffff';
        this.ResultAreaPanel.Separators[0].GetElement().style.cursor          = 'e-resize';
        this.ResultAreaPanel.Separators[0].GetElement().style.borderWidth     = '0px 1px 0px 0px';
        this.ResultAreaPanel.Separators[0].GetElement().style.borderStyle     = 'none solid none none';
        this.ResultAreaPanel.Separators[0].GetElement().style.borderColor     = '#ffffff #ababab #ffffff #ffffff';

        // セパレーター操作によるリサイズを可能にする
        var extender = new iResizableExtender(this.ResultAreaPanel,
                                              this.ResultAreaPanel.Separators[0],
                                              iPanelStyle.StretchOption.Horizontal,
                                              this.ResultAreaPanel.Containers[0],
                                              this.ResultAreaPanel.Containers[1],
                                              10,
                                              550);
        extender.Extend();

        // 親リサイズイベントにアタッチ
        this.ResultAreaPanel.AddEvent(iControl.ControlEventName.BeginResizeChildren, iFunction.CreateDelegate(this.OnResultPaneResize, this));
        this.ResultAreaPanel.AddEvent(iControl.ControlEventName.EndResize, iFunction.CreateDelegate(this.OnResultPaneResize, this));

        // ページャーのスタイル調整
        this.ResultGridPager.GetElement().style.paddingRight = '5px';


        // 結果リストの初期化
        var div = document.createElement('div');
        div.oncontextmenu = function () { return false; }; // コンテキストメニューを無効化
        this.ResultAreaPanel.Containers[0].GetElement().appendChild(div); // ToDo: divをPanelControlに変更

        var list = document.createElement('ul');
        list.id               = this.ResultListElementId;
        list.style.height     = this.LayoutPanel.Containers[0].GetElement().style.height;
        list.style.margin     = '0px';
        list.style.paddingTop = '2px';
        div.appendChild(list);

        this.ResultList = list;

        // 結果グリッドの初期化
        var div = document.createElement('div');
        if (!iBoolean.TryParse(this.Info.Options.Get('EnableContextMenu'), false))
        {
            div.oncontextmenu = function () { return false; }; // コンテキストメニューを無効化
        }
        this.ResultGridPanel.Containers[0].GetElement().appendChild(div); // ToDo: divをPanelControlに変更

        var table = document.createElement('table');
        table.id               = this.ResultGridElementId;
        table.style.whiteSpace = 'nowrap'; // 折り返しを禁止
        div.appendChild(table);

        this.ResultGrid = table;

        // スタイル調整の為にResizeメソッドを呼ぶ
        this.ResultAreaPanel.OnResize();

        this.Initialize();

        this.ListInit();
        this.GridInit(this.ResultGridPanel.Containers[0].GetElement());
    },

    Initialize: function ()
    {
        // GroupImageのPathの設定
        this.groupImagePath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/infoshare.InfoCall/group.png';

        // UserImageのPathの設定
        this.userImagePath = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/infoshare.InfoCall/user.png';

        //var rootTreeEntities = this.DataSource.RootTreeEntities;
        //// Treeのデータ初期化
        //try // ルートエントリが存在しない場合の暫定対応
        //{            
        //    var treeDatarouce = [];
        //    var rootObject = new GPMemberSearchViewTreeObject(rootTreeEntities[0]);
        //    treeDatarouce.push(rootObject);

        //    this.TreeDataSource = treeDatarouce;
        //}
        //catch (e) { }
    },


    ListInit: function ()
    {
        (function ($, view)
        {
            $('#' + view.ResultListElementId).igTree({
                dataSource: view.ListData,
                bindings: {
                    textKey:           'GroupName',
                    primaryKey:        'EntityId',
                    imageUrlKey:       'ImageUrl',
                    childDataProperty: 'Groups',
                    bindings: {
                        textKey:           'GroupName',
                        primaryKey:        'EntityId',
                        imageUrlKey:       'ImageUrl',
                        childDataProperty: 'Groups'
                    }
                }
            });

            view.ListEventInit();
        }(ig$, this)); 
    },

    ListEventInit: function ()
    {
        (function ($, view)
        {
            $('#' + view.ResultListElementId).on("igtreeselectionchanged", iFunction.CreateDelegate(view.OnListSelectionChanged, view));
            $('#' + view.ResultListElementId).on("igtreenodeclick",        iFunction.CreateDelegate(view.OnListItemClick,        view));

            var disable = iBoolean.TryParse(view.Info.Options.Get('DisableListDoubleClick'), false);
            if (!disable)
            {
                $('#' + view.ResultListElementId).on("igtreenodedoubleclick",  iFunction.CreateDelegate(view.OnListItemDoubleClick,  view));
            }
        }(ig$, this));
    },

    OnListSelectionChanged: function (evt, ui)
    {
        (function ($, view) 
        {
            // 選択アイテムのクリア
            view.SelectedListEntity = ui.selectedNodes[0].data.Entity;

            view.ActiveControl = "Tree";
            view.OnSelectionChanged();
        }(ig$, this));
    },

    OnListItemClick: function (evt, ui)
    {       
        (function ($, view) 
        {
            if (ui.node.data.GridItems)
            {
                view.UpdateGridData(ui.node.data);
            }
            else
            {
                if (iString.Equals(ui.node.data.Entity.Properties['Type'], 'group', true))
                {
                    view.GetChildEntities(ui.node.data.Entity, function (entities)
                    {
                        // 子要素情報をノードに持たせる
                        ui.node.data.GridItems = entities;
                        view.UpdateGridData(ui.node.data);
                    });
                }
                else if (iString.Equals(ui.node.data.Entity.Properties['Type'], 'user', true))
                {
                    var ent = ui.node.data.Entity;
                    view.GetParentEntities(ui.node.data.Entity, function (entities)
                    {
                        // 子要素情報をノードに持たせる
                        ui.node.data.GridItems = entities;
                        view.UpdateGridData(ui.node.data);
                    });
                }
            }

            view.ActiveControl = "Tree";
            view.OnSelectionChanged();
        }(ig$, this));
    },

    OnListItemDoubleClick: function (evt, ui)
    {
        this.OnItemSelected();
    },

    UpdateListData: function(items)
    {
        (function ($, view)
        {            
            // DataBindの際に定義したArrayを参照するので配列要素を詰め替える
            view.ListData.clear();

            var data = new Array();
            if (items != null && items.length > 0)
            {
                for (var i = 0; i < items.length; i++)
                {
                    var item = items[i];
                    var listData = new GPMemberSearchViewTreeObject(item.Entity);
                    data.push(listData);
                }
            }
            view.ListData = data;

            // レンダリング
            ig$('#' + view.ResultListElementId).igTree({ dataSource: view.ListData });
        })(ig$, this);
    },


    GridInit: function (gridParentElement)
    {
        (function ($, view)
        {
            // DataSourceの初期化
            view.GridData.clear();
            view.Columns = GPGridUtility.BuildColumns(view.Info.ViewFields);

            // グリッドを作成する
            $(function ()
            {
                $('#' + view.ResultGridElementId).igGrid({
                    columns:            view.Columns,
                    width:              gridParentElement.style.width,
                    height:             "100px", // 値に意味は無し（Headerを固定する為に指定する必要がある）
                    primaryKey:         'EntityId',
                    dataSource:         view.GridData,
                    alternateRowStyles: false,
                    autofitLastColumn:  false,
                    features:           view.Features,
                    dataRendered: function (evt, ui)
                    {
                        if (iBoolean.TryParse(view.Info.Options.Get('EnableContextMenu'), false))
                        {
                            GPGridUtility.EnableDrag(evt);
                        }
                    }
                });
            });

            //// 初回表示時にRootのアイテムをグリッドに表示する
            //if (ISBoolean.Parse(view.Info.Options.Get('ExpandRootNode')))
            //{
            //    var rootNodeElement = $('#' + view.TreeElementId).igTree("nodeByPath", "0")[0];
            //    var node = $('#' + view.TreeElementId).igTree("findNodesByText", rootNodeElement.innerText)[0];
            //    view.InitializeRootGridItem(node);
            //}

            // 種別ヘッダーのスタイルを修正（表示名列と結合して見えるようにborder-rightを削除する）
            // CSSから実装を移行
            GPGridUtility.DeleteHeaderBorder(view.ResultGridElementId + "_Type");
            GPGridUtility.DeleteHeaderBorder(view.ResultGridElementId + "_Presence");

            // グリッドにProfileImage列がある場合、グリッド内の行の高さを指定するクラスを追加する
            if (view.Info.ViewFields.Contains('ProfileImage'))
            {
                GPGridUtility.AddGridElementClass(view.ResultGridElementId, "is-gp-InfoCall-GridElement");
            }
        }(ig$, this));

        this.GridEventInit();
    },

    GridEventInit: function ()
    {
        (function ($, view)
        {
            $('#' + view.ResultGridElementId).on("iggridselectionrowselectionchanged", iFunction.CreateDelegate(view.OnGridSelectionChanged, view));

            var disable = iBoolean.TryParse(view.Info.Options.Get('DisableGridDoubleClick'), false);
            if (!disable)
            {
                $('#' + view.ResultGridElementId).on("dblclick", iFunction.CreateDelegate(function ()
                {
                    view.ActiveControl = "Grid";
                    view.OnItemSelected();
                }, view));
            }

            $('#' + view.ResultGridElementId).on("click", iFunction.CreateDelegate(function ()
            {
                view.ActiveControl = "Grid";
                //view.OnItemSelected(); 不要？？？
            }, view));

            if (iString.EndsWith(window.location.href, 'GroupPicker.aspx', true))
            {
                iDomAccessor.AttachEvent(document, 'mousemove', function(event)
                {
                    view.HoverEventElement = event.srcElement;
                });
            }
        }(ig$, this));
    },

    OnGridSelectionChanged: function (evt, ui)
    {
        (function ($, view) 
        {
            // 複数回呼ばれるイベントをキャンセルする
            // DataBindを実行するたびにイベント（iggridselectionrowselectionchanged）が登録される為、二回目以降のイベントを処理しない
            evt.preventDefault();

            // 選択アイテムのクリア
            view.SelectedGridSids.clear();
            var selectedRows = $('#' + view.ResultGridElementId).igGridSelection("selectedRows");

            for (var i = 0; i < selectedRows.length; i++)
            {
                // 選択アイテムに追加
                view.SelectedGridSids.push(selectedRows[i].id);
            }

            view.ActiveControl = "Grid";
            view.OnSelectionChanged();               
        }(ig$, this));
    },

    UpdateGridData: function(data)
    {
        (function ($, view)
        {
            // グリッドの子要素が不明な場合警告を出力
            if (!data.GridItems)
            {
                var nodeDisplayName = data.Entity.Properties.EntityDisplayName;
                var errorMessage = iString.Format("[Warning] GPMemberSearchView.UpdateGridData（Grid data of {0} is undefined）", nodeDisplayName);
                ISTrace.TraceWarning(errorMessage);
                return;
            }

            // DataBindの際に定義したインスタンスを参照するので配列要素を詰め替える
            view.GridData.clear();
            var items = GPGridUtility.BuildGridItems(data.GridItems, view.Columns);
            for (var i = 0; i < items.length; i++)
            {
                view.GridData.push(items[i]);
            }

            // 検索結果をキャッシュ
            view.TempGridItems = items;
            view.ResultGridPager.ItemCount = items.length;

            // Page1を表示
            view.ResultGridPager.ChangePage(1);
        })(ig$, this);
    },

    ClearGridData: function()
    {
        (function ($, view)
        {
            view.TempGridItems = new Array();
            view.UpdateGrid();
        })(ig$, this);
    },

    UpdateGrid: function()
    {
        (function ($, view)
        {            
            // DataBindの際に定義したArrayを参照するので配列要素を詰め替える
            view.GridData.clear();

            var items = view.TempGridItems;            
            var startItemIndex = (view.ResultGridPager.CurrentPageNumber - 1) * view.ResultGridPager.PageSize;
            var endItemIndex   = items.length > view.ResultGridPager.CurrentPageNumber * view.ResultGridPager.PageSize ? view.ResultGridPager.CurrentPageNumber * view.ResultGridPager.PageSize : items.length;

            for (var i = startItemIndex ; i < endItemIndex ; i++)
            {
                view.GridData.push(items[i]);
            }                        

            $('#' + view.ResultGridElementId).igGrid('dataBind');
        })(ig$, this);

        // プレゼンスの更新
        if (this.Info.ViewFields.ContainsBy('Presence', 'ViewType'))
        {
            GPPresenceUtility.UpdatePresenceLink(this.ResultGridElementId);
        }
        if (this.Info.ViewFields.ContainsBy('UcPresence', 'ViewType'))
        {
            UCPresenceController.GetInstance().UpdatePresenceStyles(this.ResultGridElementId, function ()
            {
                // ToDo:
            });
        }
        if (this.Info.ViewFields.ContainsBy('GraphPresence', 'ViewType'))
        {
            GraphPresenceController.GetInstance().UpdatePresenceStyles(this.ResultGridElementId, function ()
            {
                // ToDo:
            });
        }

        // ProfileImageの更新
        if (this.Info.ViewFields.ContainsBy('ProfileImage', 'ViewType') && GPContext.Configuration.GetSetting('ProfileImageAPI').toUpperCase() == 'Graph'.toUpperCase())
        {
            GraphProfileImageController.GetInstance().UpdateGraphProfileImages(this.ResultGridElementId);
        }
    },


    SelectionChangedEventHandler: null,
    OnSelectionChanged: function ()
    {
        // 選択状態の変更を通知
        if (this.SelectionChangedEventHandler)
        {
            this.SelectionChangedEventHandler(this);
        }
    },

    ItemSelectedEventHandler: null,
    OnItemSelected: function ()
    {
        // 選択状態の変更を通知
        if (this.ItemSelectedEventHandler)
        {
            this.ItemSelectedEventHandler(this);
        }
    },


    GetSelectedItems: function ()
    {
        var returnItems = [];
        (function ($, view)
        {
            // Treeの場合
            if (view.ActiveControl == "Tree")
            {
                returnItems.push(view.SelectedListEntity);
            }

            // Gridの場合
            else if (view.ActiveControl == "Grid")
            {
                var selectedEntities = [];
            
                for (var i = 0; i < view.TempGridItems.length; i++)
                {
                    for (j = 0; j < view.SelectedGridSids.length; j++)
                    {
                        if (view.TempGridItems[i]["EntityId"] == view.SelectedGridSids[j])
                        {
                            selectedEntities.push(view.TempGridItems[i]["Entity"]);
                        }
                    }
                }

                returnItems = selectedEntities;
            }

        })(ig$, this);

        return returnItems;
    },

    GetParentEntities: function(entity, callback)
    {
        var query = this.BuildParentEntitiesQuery(entity);

        GPGridUtility.GetEntities(this.DataSource, query, callback);
    },

    BuildParentEntitiesQuery: function (entity)
    {
        var query = new ISSPQuery();
        query.TryQuery = false;

        var queryTemplete = "<Query>"
                          +   "<Where>"
                          +     "%Where%"
                          +   "</Where>"
                          +   "<OrderBy>"
                          +     "%OrderByConfigs%"
                          +   "</OrderBy>"
                          + "</Query>";

        // Whare句
        var whereCondition = '';

        var field = GPContext.Configuration.Fields.Get('EntityId');
        var ids = entity.Properties['MemberOf'].split('|');
        for (var i = 0; i < ids.length; i++)
        {
            var parentId = ids[i];
            if (iString.IsNullOrEmpty(parentId))
            {
                continue;
            }

            var condition = SPQueryBuilder.BuildEqualQueryCondition(field.InternalName, field.Type, parentId);
            if (iString.IsNullOrEmpty(whereCondition))
            {
                whereCondition = condition;
            }
            else
            {
                whereCondition = SPQueryBuilder.BuildOrQueryCondition(whereCondition + condition);
            }
        }

        // Query句の設定
        query.Query = queryTemplete.replace("%Where%", whereCondition);

        // OrderByのquery組み立て
        var orderByConfigs = "";
        for (var i = 0; i < this.Info.SortOrders.length; i++)
        {
            var orderByTemplete = "<FieldRef Name='%OrderByName%' Ascending='%OrderByAscending%'/>";
            orderByTemplete = orderByTemplete.replace("%OrderByName%", this.Info.SortOrders[i].FieldName);
            orderByTemplete = orderByTemplete.replace("%OrderByAscending%", this.Info.SortOrders[i].Ascending);
            orderByConfigs += orderByTemplete;
        }
        query.Query = query.Query.replace("%OrderByConfigs%", orderByConfigs);

        // ViewField設定 
        var fieldRefs = '';

        // 組織マスタの場合はViewFieldsを設定せず全ての列を取得する
        // 拡張した列などに対応する為
        for (var i = 0; i < this.Info.ViewFields.GetLength() ; i++)
        {
            var field = this.Info.ViewFields.Get(i);
            fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
        }
        query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

        return query;
    },

    GetChildEntities: function (parentEntity, callback)
    {
        // MemberOfIndex列が確認されていない場合
        if (this.MemberOfIdFields == null)
        {
            this.EnsureMemberOfIdFields();
        }

        // 高速化クエリが有効な場合とその他でスイッチする
        var enable = iBoolean.TryParse(this.Info.Options.Get('EnableMemberOfMultipleQuery'), false);
        var hasManyRefChild = parentEntity.Properties.HasManyRefChild ? parentEntity.Properties.HasManyRefChild
                                                                      : "false";
        if (enable &&                                    // 高速化クエリの有効化オプションの確認
            this.MemberOfIdFields.length > 0 &&          // MemberOfIndex列が存在する
            !ISBoolean.TryParse(hasManyRefChild, false)) // MemberOfId列数を超える兼務エンティティを保持していない
        {
            this.GetChildEntitiesFast(parentEntity, callback);
        }
        else
        {
            this.GetChildEntitiesBase(parentEntity, callback);
        }
    },

    GetChildEntitiesFast: function (parentEntity, callback)
    {
        // MemberOfIndex列のEQクエリを並列に実行する
        var queryCount = this.MemberOfIdFields.length;
        var queries =[];

        var entitiesPreSort;

        for(var i = 0; i < queryCount; i++)
        {
            // クエリの作成
            var field = this.MemberOfIdFields[i];
            var memberOfQuery = SPQueryBuilder.BuildEqualQueryCondition(field.InternalName, field.Type, parentEntity.Properties.EntityId);
            var query = this.BuildChildEntitiesQuery(parentEntity, memberOfQuery);
            query.TryQuery = true;

            queries.push(query);
        }

        (function (view)
        {
            GPGridUtility.GetEntitiesParallel(view.DataSource, queries, function (items)
            {
                callback(items);
            });
        })(this);
    },

    GetChildEntitiesBase: function (parentEntity, callback)
    {
        // MemberOfQuery組み立て
        var parentSID = parentEntity.Properties.EntityId;
        var parentId = "|" + parentSID + "|";
        var memberOfQuery = SPQueryBuilder.BuildContainsQueryCondition("MemberOf", "Note", parentId);

        var query = this.BuildChildEntitiesQuery(parentEntity, memberOfQuery);

        (function (view)
        {
            GPGridUtility.GetEntities(view.DataSource, query, function(items)
            {
                callback(items);
            });
        })(this);
    },

    BuildChildEntitiesQuery: function (parentEntity, memberOfQuery)
    {
        var query = new ISSPQuery();
        query.TryQuery = false;

        var queryTemplete   = "<Query>"
                            +   "<Where>"
                            +     "%Where%"
                            +   "</Where>"
                            +   "<OrderBy>"
                            +     "%OrderByConfigs%"
                            +   "</OrderBy>"
                            + "</Query>";

        // Whare句
        var whereQuery = memberOfQuery;

        // ToDo:ShowInView
        /*
        var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "OrganizationView");
        var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
        var showInViewQuery = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);
        where = SPQueryBuilder.BuildAndQueryCondition(memberOfQuery + showInViewQuery);
        */

        // EnableVisibleGroups=trueの場合、CurrentUserのVisibleGroupsを検索条件に追加する
        var enableVisibleGroups = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableVisibleGroups'), false);
        if (enableVisibleGroups)
        {
            whereQuery = GPCamlQueryCondition.AddVisibleGroupsCondition(whereQuery, GPViewContext.CurrentUserEntity);
        }

        // Query句の設定
        query.Query = queryTemplete.replace("%Where%", whereQuery);

        // OrderByのquery組み立て
        var orderByConfigs = "";
        for (var i = 0; i < this.Info.SortOrders.length; i++)
        {
            var orderByTemplete = "<FieldRef Name='%OrderByName%' Ascending='%OrderByAscending%'/>";
            orderByTemplete = orderByTemplete.replace("%OrderByName%", this.Info.SortOrders[i].FieldName);
            orderByTemplete = orderByTemplete.replace("%OrderByAscending%", this.Info.SortOrders[i].Ascending);
            orderByConfigs += orderByTemplete;
        }
        query.Query = query.Query.replace("%OrderByConfigs%", orderByConfigs);

        // ViewField設定 
        var fieldRefs = '';

        // 組織マスタの場合はViewFieldsを設定せず全ての列を取得する
        // 拡張した列などに対応する為
        if (this.Info.Id != "Infoshare.GroupPicker.OrganizationManagement.MemberSearchView")
        {
            for(var i = 0; i < this.Info.ViewFields.GetLength(); i++)
            {
                var field = this.Info.ViewFields.Get(i);
                fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
            }     
        }   
        query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

        return query;
    },
    
    EnsureMemberOfIdFields: function ()
    {
        this.MemberOfIdFields = [];

        var fields = GPContext.Configuration.Fields;
        // 以下のプレフィックス付のMemberOf列をカウントする
        var memberOfIdFieldName = "MemberOfId";

        for(var i = 0; i < fields.GetLength(); i++)
        {
            var field = fields.Get(i);
            if (ISString.StartsWith(field.InternalName, memberOfIdFieldName, true))
            {
                this.MemberOfIdFields.push(field);
            }
        }
    },


    OnPageChanged: function ()
    {
        this.UpdateGrid();
    },

    OnResultPaneResize: function()
    {
        // 結果リストの高さ調整
        var treeContainer = this.ResultAreaPanel.Containers[0].GetElement();
        var containerHeight = treeContainer.style.height.replace('px', '');
        if (containerHeight > 0)
        {
            this.ResultList.style.height = containerHeight - 5 + 'px';
        }

        // 結果グリッドの幅調整
        var width = GPGridUtility.GetGridWidth(this.ResultAreaPanel);
        this.ResultAreaPanel.Style.ContainerStyles[1].Size.Width = width;
        
        // グリッドのサイズ調整
        (function ($, view)
        {
            // IE8(ブラウザバージョン8互換の場合のスタイルずれの補正
            var height = iDomAccessor.GetInnerHeight(view.ResultGridPanel.Containers[0].GetElement());
            if (iBrowser.GetBrowserVersion() == 7)
            {
                height -= 17;
            }
            // グリッドが初期化済みの場合サイズ変更する
            if ($('#' + view.ResultGridElementId).data('igGrid') != null)
            {
                $('#' + view.ResultGridElementId).igGrid({
                    width: width,
                    height: height
                });
            }
        }(ig$, this));
    },


    Searcher: null,
    OnSearch: function()
    {
        if (!this.Searcher)
        {
            this.Searcher = new GPEntitySearcher(this.DataSource, this.Info.ViewFields, this.Info.SortOrders, this.Columns);
        }

        var keywords = this.SearchTextBox.TextBox.GetValue();
        var filter   = new GPEntitySearcherFilter(this.GroupFilter.IsChecked(), this.UserFilter.IsChecked());

        var ref = this;
        this.Searcher.Search(keywords, filter, function (items)
        {
            // 同一条件などで検索を中止した場合は、undefinedが返ってくるため、状態を更新しない
            // ToDo(skomatsu): 結果の意図が伝達できるように修正
            if (items == undefined)
            {
                return;
            }

            var message = '';
            if (items == null) // 閾値を超えて検索
            {
                message = iResxResource.GetString('PickerDialog.SearchView.MessageLabel.ThresholdOverResults');

            }
            else if (items.length <= 0) // 検索結果ゼロ
            {
                message = ISString.Format(iResxResource.GetString('PickerDialog.SearchView.MessageLabel.ResultNull'),
                                          ref.SearchTextBox.TextBox.GetValue());
            }

            // メッセージ表示
            if (!iString.IsNullOrEmpty(message)) { ref.ShowGridMessage(message); }
            else                                 { ref.HideGridMessage(); }

            // 結果表示
            ref.UpdateListData(items);
            ref.ClearGridData();
        });
    },


    GridMessageLabel: null,
    ShowGridMessage: function(message)
    {
        (new iNotifyer()).Notify(message, 5000);
        return;

        // リスト部分は表示内容が限られるため、この実装では期待通りの表示が困難
        // 旧実装としてコードは残すが方針は要検討
        if (!this.GridMessageLabel)
        {
            // Gridテーブル内にMessage表示用のlabelを追加
            this.GridMessageLabel = document.createElement('label');
            this.GridMessageLabel.style.visibility = 'hidden';
            this.ResultGrid.appendChild(this.GridMessageLabel);
            //this.ResultList.appendChild(this.GridMessageLabel);
        }

        this.GridMessageLabel.innerText = message;
        this.GridMessageLabel.style.visibility = 'visible';
    },

    HideGridMessage: function()
    {
        if (this.GridMessageLabel)
        {
            this.GridMessageLabel.innerText = '';
            this.GridMessageLabel.style.visibility = 'hidden';
        }
    }
}


// -----------------------------------------------------------------------
//  TreeObject
// -----------------------------------------------------------------------
Infoshare.GroupPicker.MemberSearchView.TreeObject = function InfoInfoshare$GroupPicker$MemberSearchView$TreeObject(entity) 
{
    this.Entity = entity;

    if (this.Entity)
    {
        this.EntityId = this.Entity.Properties.EntityId;
        this.ImageUrl = ISString.TrimEnd(GPContext.ImagesPath, '/') + '/infoshare.InfoCall/' + this.Entity.Properties['Type'] + '.png';
        this.GroupName = this.Entity.Properties.EntityDisplayName;

        var hasSubTree = ISBoolean.TryParse(this.Entity.Properties.HasSubTree, false);
        if (hasSubTree)
        {
            this.Groups = [];
            // ダミーノードを追加する
            this.Groups.push(GPMemberSearchViewTreeObject.GetDummyGroup());            
        }        
    }
}
GPMemberSearchViewTreeObject = Infoshare.GroupPicker.MemberSearchView.TreeObject;
GPMemberSearchViewTreeObject.GetDummyGroup = function ()
{
    var dummyObject = new GPMemberSearchViewTreeObject(null);
    dummyObject.EntityId = "Dummy";

    return dummyObject;
};

GPMemberSearchViewTreeObject.prototype = {
    Entity: null,
    ChildNodeEnsured: false,
    ImageUrl: null,
    GroupName: "",
    EntityId: null,
    Groups: [],

    SetGroup: function(entity)
    {
        var entities = [entity];
        this.SetGroups[entities];
    },

    SetGroups: function(entities)
    {
        // ダミーノードが含まれる為再度作成する
        this.Groups = [];

        for(var i = 0; i < entities.length; i++)
        {
            var entity = entities[i];

            var type = entity.Properties.Type;
            var showInTree = ISBoolean.TryParse(entity.Properties.ShowInTree, false);

            if (ISString.Equals(type, "Group", true) &&
                showInTree)
            {
                var treeObject = new GPMemberSearchViewTreeObject(entity);
                this.Groups.push(treeObject);
            }
        }
    }
};
                             
