// -----------------------------------------------------------------------
//  MailToSelectionView
// -----------------------------------------------------------------------
Infoshare.GroupPicker.MailToSelectionView = function InfoInfoshare$GroupPicker$MailToSelectionView() { }
GPMailToSelectionView = Infoshare.GroupPicker.MailToSelectionView;
GPMailToSelectionView.TypeName = 'Infoshare.GroupPicker.MailToSelectionView';

GPMailToSelectionView.prototype = {
    TypeName: GPMailToSelectionView.TypeName,
    GridDataSource: [],

    Info: null,
    GridParentElement: null,
    GridTableElement: null,

    GridElementId: 'Infoshare_GroupPicker_MailToSelectionView_Grid',
    ValidatedEntities: [],

    HeaderIndex: {
        To:  null,
        CC:  null,
        BCC: null
    },
    CheckStateChangeEventHandler: null,
    
    // チェックボックスの排他制御オプション（デフォルトはfalseで排他処理をさせない）
    EnableExclusiveOption: true,

    // MailtoUrlの文字列長を確認するか否かのフラグ（イベントハンドリング用のキャッシュ用フラグ）
    CheckUrlLength: true,

    Render: function(parentElement)
    {
        // ToDo(skomatsu): 実装場所検討（Renderの前に初期化プロセスがあるとよいか）
        // チェックボックスの排他制御オプションを確認
        if (this.Info.Options.Contains('EnableExclusiveOption'))
        {
            this.EnableExclusiveOption = iBoolean.TryParse(this.Info.Options.Get('EnableExclusiveOption'), true);
        }

        // 分割パネル
        var panel = new iSplitPanel(new GPActionDialogViewSplitPanel());
        panel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
        panel.Style.StretchOption = iPanelStyle.StretchOption.Both;

        // 分割パネル: ヘッダー、グリッド、フッターの3分割
        var alertLabelInfo = this.Info.AlertLabels ? this.Info.AlertLabels : null;

        panel.Style.ContainerStyles = [new iPanelStyle(), new GPSearchViewGridContainerPanelStyle(), new iPanelStyle()];
        panel.Style.ContainerStyles[0].Size.Height = alertLabelInfo && alertLabelInfo.length > 0 ? alertLabelInfo.length * 15 : 0;
        panel.Style.ContainerStyles[2].Size.Height = 0;
        
        // ヘッダーパネルに警告用アラートパネルを追加
        if (alertLabelInfo && alertLabelInfo.length > 0)
        {
            var alertPanel = new iSplitPanel(new iPanelStyle()); 
            alertPanel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
            alertPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
            alertPanel.Style.ContainerStyles = [];
            
            for (var i = 0; i < alertLabelInfo.length; i++)
            {
                alertPanel.Style.ContainerStyles.push(new iPanelStyle());
                alertPanel.Style.ContainerStyles[i].Size.Height = 15;
            }

            // ヘッダパネルに追加;
            panel.AppendChildControlForContainer(0, alertPanel);

            // アラートパネルを
            for (var i = 0; i < alertLabelInfo.length; i++)
            {
                var label = new iLabel(new GPActionDialogAlertMessageLabel());
                label.Text = alertLabelInfo[i];

                alertPanel.AppendChildControlForContainer(i, label);
            }
        }
               
        // 分割パネルレンダリング
        panel.Render(parentElement.Element);
        
        // Gridの親要素をキャッシュ
        this.GridParentElement = panel.Containers[1].GetElement();

        // グリッド用のテーブルを描画
        var table = document.createElement('table');
        table.id = this.GridElementId;
        table.oncontextmenu = function() { return false; }; // コンテキストメニューを無効化
        table.style.whiteSpace = "nowrap"; // 折り返しを禁止
        this.GridParentElement.appendChild(table);
        this.GridTableElement = table;

        // グリッド描画
        (function($, view)
        {
            // DataSourceの初期化
            view.GridDataSource.clear();
            view.Columns = GPGridUtility.BuildColumns(view.Info.ViewFields);

            // igGridを描画
            $('#' + view.GridElementId).igGrid({
                columns: view.Columns,
                width:  ISDomAccessor.GetInnerWidth(view.GridParentElement)  + 'px',
                height: "100px", // 値に意味は無し（Headerを固定する為に指定する必要がある）
                dataSource: view.GridDataSource,
                alternateRowStyles: false,
                autofitLastColumn : false,
                primaryKey: "EntityId",
                features: view.Info.IGGridFeatures
            });

            // 種別ヘッダーのスタイルを修正（表示名列と結合して見えるようにborder-rightを削除する）
            // CSSから実装を移行
            GPGridUtility.DeleteHeaderBorder(view.GridElementId + "_Type");
        }(ig$, this));

        // サイズ調整のためリサイズ
        this.OnResize();
    },

    UpdateGrid: function(entities)
    {
        this.ValidatedEntities = entities;

        var items = GPGridUtility.BuildGridItems(entities, this.Columns);

        (function ($, view)
        {            
            // DataBindの際に定義したArrayを参照するので配列要素を詰め替える
            view.GridDataSource.clear();
          
            for (var i = 0; i < items.length; i++)
            {
                view.GridDataSource.push(items[i]);
            }                        

            $("#" + view.GridElementId).igGrid("dataBind");
        })(ig$, this);
        
        // チェックボックスの初期化
        this.InitializeCheckBox();

        // Disabled項目の処理
        this.DisableRows(entities);
    },

    GetGridRows: function()
    {
        var rows = [];

        var table = document.getElementById(this.GridElementId);
        rows = table.getElementsByTagName("tbody")[0].children;
        return rows;
    },

    DisableRows: function(entities)
    {
        // Disabled項目の種別アイコンを修正用に種別列インデックスを取得
        var typeHeader = ISDomAccessor.GetElement(this.GridElementId + "_Type");
        var typeHeaderCellIndex = typeHeader.cellIndex;

        for (var i = 0; i < entities.length; i++)
        {
            var entity = entities[i];
            if (!entity.Valid)
            {
                var entityId = entity.Properties['EntityId'];
                var selector = "#" + this.GridTableElement.id
                             + " "
                             + "[data-id='" + entityId +  "']";

                var row = i$(selector)[0];
                row.disabled = true;
                row.style["color"] = "grey";
                var inputs = i$("input", row);
                for (var j = 0; j < inputs.length; j++)
                {
                    var input = inputs[j];
                    input.disabled = true;
                    input.checked = false;
                }
            }
        }
    },

    InitializeCheckBox: function()
    {
        // ヘッダーにチェックボックスを追加
        var toCheckBox = this.CreateHeaderCheckBox('To');
        var toChildCheckBoxes = this.ReplaceRowCheckBox(toCheckBox);
        toCheckBox.ChildCheckBoxes = toChildCheckBoxes;
        // ToをデフォルトでCheck状態にする
        toCheckBox.Check(true); 
        
        var ccCheckBox = this.CreateHeaderCheckBox('CC');
        var ccChildCheckBoxes = this.ReplaceRowCheckBox(ccCheckBox);
        ccCheckBox.ChildCheckBoxes = ccChildCheckBoxes;

        var bccCheckBox = this.CreateHeaderCheckBox('BCC');
        var bccChildCheckBoxes = this.ReplaceRowCheckBox(bccCheckBox);
        bccCheckBox.ChildCheckBoxes = bccChildCheckBoxes;

        // 横チェックボックスのキャッシュ
        toCheckBox.SiblingsCheckBoxes =  [ccCheckBox, bccCheckBox];
        ccCheckBox.SiblingsCheckBoxes =  [toCheckBox, bccCheckBox];
        bccCheckBox.SiblingsCheckBoxes = [toCheckBox, ccCheckBox];

        // 子チェックボックスの横チェックボックスのキャッシュ
        for (var i = 0; i < toChildCheckBoxes.length; i++)
        {
            var toChildChekBox = toChildCheckBoxes[i];
            var ccChildChekBox = ccChildCheckBoxes[i];
            var bccChildChekBox = bccChildCheckBoxes[i];

            toChildChekBox.SiblingsCheckBoxes =  [ccChildChekBox, bccChildChekBox];
            ccChildChekBox.SiblingsCheckBoxes =  [toChildChekBox, bccChildChekBox];
            bccChildChekBox.SiblingsCheckBoxes = [toChildChekBox, ccChildChekBox];
        }
    },

    ReplaceRowCheckBox: function(parentCheckBox)
    {
        var checkBoxes = [];

        // Rowの取得
        var rows = this.GetGridRows();

        for (var i = 0; i < rows.length; i++)
        {
            var row = rows[i];
            var cellIndex = parentCheckBox.cellIndex;

            var nativeCheckBox = row.children[cellIndex];

            // iCheckBoxに置き換える
            var checkBox = new iCheckBox();
            checkBox.Render(nativeCheckBox);
            checkBox.cellIndex = cellIndex;

            // Toの場合デフォルトをtrueにする
            if (cellIndex == this.HeaderIndex.To &&
                !checkBox.Element.parentElement.parentElement.disabled)
            {
                checkBox.Check();
            }

            // Changeイベント追加
            checkBox.AddEvent("change", ISFunction.CreateDelegate(this.RowCheckBoxOnChange, this, checkBox));
            
            // 子CheckBoxをキャッシュ
            checkBoxes.push(checkBox);
            checkBox.ParentCheckBox = parentCheckBox;
        }

        return checkBoxes;
    },

    CreateHeaderCheckBox: function(fieldName)
    {
        // ヘッダーにチェックボックス用のdivを追加
        var header = ISDomAccessor.GetElement('Infoshare_GroupPicker_MailToSelectionView_Grid_' + fieldName);
        var div = document.createElement('div');
        div.style.display = "inline";
        header.insertBefore(div, header.firstChild);

        // iCheckBoxを追加する
        var checkBox = new iCheckBox();
        checkBox.Render(div);
        var headerIndex = header.cellIndex;
        checkBox.cellIndex = headerIndex;

        // ヘッダーのインデックスをキャッシュ
        switch (fieldName.toUpperCase())
        {
            case "TO":
                this.HeaderIndex.To = headerIndex;
                break;
            case "CC":
                this.HeaderIndex.CC = headerIndex;
                break;
            case "BCC":
                this.HeaderIndex.BCC = headerIndex;
                break;
        }

        // Changeイベント追加
        checkBox.AddEvent("change", ISFunction.CreateDelegate(this.HeaderCheckBoxOnChange, this, checkBox));

        // スタイル調整
        checkBox.Element.parentElement.parentElement.style["text-align"] = "left";
        checkBox.Element.parentElement.parentElement.style["padding-left"] = "2px";

        return checkBox;
    },

    HeaderCheckBoxOnChange: function(checkBox)
    {
        var currentState = checkBox.IsChecked();
        // 子チェックボックスにてURL制限長の確認を行わせない
        this.CheckUrlLength = false;

        // 横チェックボックス操作
        if (this.EnableExclusiveOption)
        {
            for (var i = 0; i < checkBox.SiblingsCheckBoxes.length; i++)
            {
                var siblingCheckBox = checkBox.SiblingsCheckBoxes[i];
                if (currentState)
                {
                    // 横チェックボックスのOnChangeを呼ばせない（子チェックボックス毎に横の制御を行う）
                    siblingCheckBox.UnCheck(true);
                }
            }
        }

        // 子チェックボックス操作
        for (var i = 0; i < checkBox.ChildCheckBoxes.length; i++)
        {
            // Disabldeなチェックボックスは処理しない
            if (checkBox.ChildCheckBoxes[i].Element.parentElement.parentElement.disabled)
            {
                continue;
            }

            if (currentState)
            {
                // 子チェックボックスのOnChangeを呼ばせて、RowCheckBoxOnChange内で排他処理の判断を行う
                checkBox.ChildCheckBoxes[i].Check();
            }
            else
            {
                checkBox.ChildCheckBoxes[i].UnCheck(true);
            }            
        }

        // アクションボタンの有効・無効の判断ロジック
        this.CheckUrlLength = true;
        var actionButtonEnable = this.CanOpenMailForm();
        this.CheckStateChangeEventHandler(actionButtonEnable);        
    },

    RowCheckBoxOnChange: function(checkBox)
    {
        var currentState = checkBox.IsChecked();

        // Checkの場合
        if (currentState)
        {
            if (this.EnableExclusiveOption) // 排他制御を行う場合
            {
                // 横チェックボックス操作
                for (var i = 0; i < checkBox.SiblingsCheckBoxes.length; i++)
                {
                    var siblingCheckBox = checkBox.SiblingsCheckBoxes[i];
                    if (currentState)
                    {
                        siblingCheckBox.UnCheck();
                    }
                }
            }
        }

        // UnCheckの場合ヘッダーチェックボックスをUnCheckにする
        else
        {
            // ParentCheckBoxのOnChangeを呼ばせない
            checkBox.ParentCheckBox.UnCheck(true);
        }

        // アクションボタンの有効・無効の判断ロジック
        var actionButtonEnable = this.CanOpenMailForm();
        this.CheckStateChangeEventHandler(actionButtonEnable);
    },

    OnResize: function()
    {
        // IE8(ブラウザバージョン8互換の場合のスタイルずれの補正
        var height = ISDomAccessor.GetInnerHeight(this.GridParentElement);
        if (ISBrowser.GetBrowserVersion() == 7)
        {
            height -= 17;
        }

        (function($, view)
        {
            $('#' + view.GridElementId).igGrid({
                width: ISDomAccessor.GetInnerWidth(view.GridParentElement) + 'px',
                height: height + 'px'
            });
        })(ig$, this);
    },

    GetMailtoEntities: function()
    {
        var mailToEntities = {
            To: [],
            CC: [],
            BCC: []};

        for (var i = 0; i < this.ValidatedEntities.length; i++)
        {
            var entity = this.ValidatedEntities[i];

            if (entity.Valid)
            {
                var entityId = entity.Properties['EntityId'];
                var selector = "#" + this.GridTableElement.id
                             + " "
                             + "[data-id='" + entityId + "']"
                             + " "
                             + "input:checked";

                var result = i$(selector);
                if (result.length < 1)
                {
                    continue;
                }

                for (var j = 0; j < result.length; j++)
                {
                    var checkBoxElement = result[j];
                    var cellIndex = checkBoxElement.parentElement.cellIndex;

                    switch (cellIndex)
                    {
                        case this.HeaderIndex.To:
                            mailToEntities.To.push(entity);
                            break;
                        case this.HeaderIndex.CC:
                            mailToEntities.CC.push(entity);
                            break;
                        case this.HeaderIndex.BCC:
                            mailToEntities.BCC.push(entity);
                            break;
                    }
                }
            }
        }

        return mailToEntities;
    },

    CanOpenMailForm: function()
    {
        var enable = false;

        // チェックされたエンティティが存在するかを確認
        var hasCheckedBox = this.HasCheckedBox();
        enable = hasCheckedBox;
        if (hasCheckedBox &&
            this.CheckUrlLength &&
            !GPContext.GPOutlookExtension.Platform) // OutlookAddinでは確認を行わない
                                                   // ToDo: OutlookAddinの制限長の確認
        {

            // 文字数制限のチェック
            if (this.ExceedUrlLength())
            {
                enable = false;
                var message = iResxResource.GetString("GPMailDialog.Alert.LengthLimit");
                alert(message);
            }          
        }

        return enable;
    },

    HasCheckedBox: function()
    {
        var hasCheckedBox = false;

        // GridTable全体からCheckされたCheckBoxが存在するか確認する
        var selector = "#" + this.GridTableElement.id
                        + " "
                        + "input:checked";  

        var result = i$(selector);
        if (result.length > 0)
        {
            hasCheckedBox = true;
        }

        return hasCheckedBox;
    },

    ExceedUrlLength: function ()
    {
        var exceed = false;

        var actionType = this.Dialog.ActionButtonInfo.ActionType;
        var entitiesForAction = this.GetMailtoEntities();
        var linker = GPMailAction.CreateMailLinker(entitiesForAction, actionType);
        var url = linker.BuildUrl();
        if (actionType == GPMailAction.ActionType.Mail)
        {
            if (url.length > iBrowser.MailtoMaxUrlLangth)
            {
                exceed = true;
            }
        }
        else if (actionType == GPMailAction.ActionType.OutlookWeb)
        {
            if (url.length > ISBrowser.GetMaxUrlLength())
            {
                exceed = true;
            }
        }
        return exceed;
    }
}
                             
