Infoshare.GroupPicker.SkypeDisplayView = function InfoInfoshare$GroupPicker$SkypeDisplayView() { }
GPSkypeDisplayView = Infoshare.GroupPicker.SkypeDisplayView;
GPSkypeDisplayView.TypeName = 'Infoshare.GroupPicker.SkypeDisplayView';

GPSkypeDisplayView.prototype = {
    TypeName: GPSkypeDisplayView.TypeName,
    GridDataSource: [],

    Info: null,
    GridParentElement: null,
    GridTableElement: null,

    GridElementId: 'Infoshare_GroupPicker_SkypeDisplayView_Grid',
    ValidatedEntities: [],

    UpdateGrid: function(entities)
    {
        this.ValidatedEntities = entities;

        var items = GPGridUtility.BuildGridItems(entities, this.Columns);

        (function ($, view)
        {            
            // DataBindの際に定義したArrayを参照するので配列要素を詰め替える
            view.GridDataSource.clear();
          
            for (var i = 0; i < items.length; i++)
            {
                view.GridDataSource.push(items[i]);
            }                        

            $("#" + view.GridElementId).igGrid("dataBind");
        })(ig$, this);

        // Disabled項目の処理
        this.DisableRows(entities);
    }
}

GPSkypeDisplayView.prototype.Render = GPMailToSelectionView.prototype.Render;

GPSkypeDisplayView.prototype.DisableRows = GPMailToSelectionView.prototype.DisableRows;

GPSkypeDisplayView.prototype.OnResize = GPMailToSelectionView.prototype.OnResize;
                             
