Infoshare.GroupPicker.MobileView = function Infoshare$GroupPicker$MobileView() { }
GPMobileView = Infoshare.GroupPicker.MobileView;

GPMobileView.RenderEntityView = function(entity)
{
    // ハッシュの更新
    location.hash = "#EntityInfomationPage";

    // エンティティの表示ページを更新
    var entityInfomationPageDiv = document.getElementById("GPMobileView_#EntityInfomationPage");
    entityInfomationPageDiv.innerHTML = "";
    entityInfomationPageDiv.style.display = "";

    // View情報の取得
    var viewInfo = GPContext.Configuration.Views.Get("Infoshare.GroupPicker.EntityView");
    if (viewInfo)
    {
        var view = new GPEntityView(entity, viewInfo);
        view.Render(entityInfomationPageDiv, null);
        this.EntityView = view;
    }
}

GPMobileView.ValidateDataSource = function(dataSource)
{
    var valid = true;

    if (!dataSource.DataSourceList) 
    {
        alert(iResxResource.GetString('PickerDialog.OpenTabError.DataSourceListNotFound'));
        valid = false;
    }
    else if (!dataSource.RootTreeEntities ||
             dataSource.RootTreeEntities.length <= 0)
    {
        iSPAlert.Alert(iResxResource.GetString('PickerDialog.OpenTabError.RootNotFound'));
        valid = false;
    }

    return valid;
}

GPMobileView.prototype = {
    LayoutPanel: null,
    ViewsTabPanel: null,
    Pages: null,
    ActiveTabCache: null,
    SearchControl: null,
    Initialize: function ()
    {
        // ビューの初期化
        this.EnsureViews();

        // ビューの情報設定
        this.EnsureViewContextInfo();

        // ハッシュの更新
        location.hash = "#TopPage";

        // ページ制御のイベント
        window.onhashchange = ISFunction.CreateDelegate(this.OnPageChage, this);

        // ローテーションのイベント登録
        // orientationchangeでは端末によって動作しないなどが発生するので、resizeを使用する
        window.onresize = ISFunction.CreateDelegate(this.OnResize, this);

        // ブラウザバック（スワイプ）無効
        window.onpopstate = ISFunction.CreateDelegate(function()
        {
            history.go(1);
        }, this);
    },

    EnsureViews: function()
    {
        // ビューの初期化
        this.Views = new ISDictionary();
        for (var i = 0; i < GPContext.Configuration.MobileViews.GetLength(); i++)
        {
            var viewInfo = GPContext.Configuration.MobileViews.Get(i);
            viewInfo.DisplayName            = viewInfo.DisplayName;
            viewInfo.DisplayNameResourceKey = viewInfo.DisplayNameResourceKey;
            if (ISString.IsNullOrEmpty(viewInfo.DisplayName))
            {
                viewInfo.DisplayName = iResxResource.GetString(viewInfo.DisplayNameResourceKey);
            }

            // ビュー初期化
            var view = iClass.New(viewInfo.Class);
            view.Info = viewInfo;
            view.Indexes = view.Info.Indexes;

            if (viewInfo.Id == "Infoshare.GroupPicker.JapaneaseIndexView")
            {
                view.IndexType = GPMobileIndexView.IndexType.Japanease;
            }
            else if (viewInfo.Id == "Infoshare.GroupPicker.EnglishIndexView")
            {
                view.IndexType = GPMobileIndexView.IndexType.English;
            }

            this.Views.Add(viewInfo.Id, view);
        }
    },

    EnsureViewContextInfo: GPFinder.prototype.EnsureViewContextInfo,

    OnPageChage: function()
    {
        // 子要素を一度すべて非表示にする
        var pages = i$("[id^=GPMobileView]");
        for (var i = 0; i < pages.length; i++)
        {
            pages[i].style.display = "none";                
        }
        
        // 現在のハッシュから表示すべきページを表示する
        var divId = "GPMobileView_" + location.hash;
        var targetDiv = document.getElementById(divId);
        if (targetDiv)
        {
            targetDiv.style.display = "";
        }

        // リサイズ
        if (location.hash == "#EntityInfomationPage")
        {
            GPMobileView.EntityView.LayoutPanel.OnResize();
        }
        else
        {
            this.LayoutPanel.OnResize();
        }

        // ページ表示位置が下がる場合に備えた調整
        setTimeout(function() 
        {
            window.scrollTo(0,0); 
        }, 200);
    },

    OnResize: function ()
    {
        var view = this;
        // タイミングイシューで変更後の幅・高さが取得出来ない場合があるため待つ
        setTimeout(function ()
        {
            view.OnPageChage();
        }, 100);        
    },

    Render: function (parentElement)
    {
        // ページコンテナの作成
        // メインページ
        var topPageDiv = document.createElement("div");
        topPageDiv.id = "GPMobileView_#TopPage";
        var entityInfomationPageDiv = document.createElement("div");
        entityInfomationPageDiv.id = "GPMobileView_#EntityInfomationPage";
        parentElement.appendChild(topPageDiv);
        parentElement.appendChild(entityInfomationPageDiv);

        var pageTitle = iResxResource.GetString('Mobile.PageTitle');
        document.title = pageTitle;

        // レイアウト：ヘッダー、ボディー、フッター
        var layoutPanel  = new iSplitPanel(new GPMobileViewStyle());
        this.LayoutPanel = layoutPanel;
        layoutPanel.Style.Mode  = iSplitPanelStyle.Mode.Horizontal;
        layoutPanel.DisplayType = iPanelStyle.DisplayType.Block;
                
        layoutPanel.Style.StretchOption   = iPanelStyle.StretchOption.Both;
        layoutPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle(), new iPanelStyle()];
        layoutPanel.Style.ContainerStyles[0].Size.Height = 40;
        layoutPanel.Style.ContainerStyles[2].Size.Height = 0;

        // ヘッダー
        var header  = new GPMobileViewHeader();
        layoutPanel.AppendChildControlForContainer(0, header);

        // ボディー（スプリットパネル）
        var bodyPanel  = new iSplitPanel();
        bodyPanel.Style.Mode  = iSplitPanelStyle.Mode.Horizontal;
        bodyPanel.DisplayType = iPanelStyle.DisplayType.Block;                
        bodyPanel.Style.StretchOption   = iPanelStyle.StretchOption.Both;
        bodyPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
        bodyPanel.Style.ContainerStyles[0].Size.Height = 36;

        layoutPanel.AppendChildControlForContainer(1, bodyPanel);

        // ボディー（検索コントロール）
        var searchControl = new GPMobileSearchTextBox();
        searchControl.AddEvent(GPMobileSearchTextBox.EventName.Search, ISFunction.CreateDelegate(this.OnSearch, this));
        searchControl.AddEvent(GPMobileSearchTextBox.EventName.Clear,  ISFunction.CreateDelegate(this.HideSearchView, this));
        bodyPanel.AppendChildControlForContainer(0, searchControl);
        this.SearchControl = searchControl;

        // ボディー（タブパネル）
        var tabPanel = new iTabPanel(new GPMobileViewTabPanelStyle());
        tabPanel.Style.StretchOption = iPanelStyle.StretchOption.Both;
        // タブの初期化
        for(var i = 0; i < this.Views.GetLength(); i++)
        {
            var view = this.Views.Get(i);
            var tabInfo = new iTabInfo(null, view.Info.DisplayName)
            tabPanel.Tabs.push(tabInfo);
        }
        this.ViewsTabPanel = tabPanel;

        // ビュー部分にタブパネルを追加
        bodyPanel.AppendChildControlForContainer(1, tabPanel);        
        
        // フッター
        var footer = new GPMobileViewFooter();
        layoutPanel.AppendChildControlForContainer(2, footer);

        layoutPanel.Render(topPageDiv);

        // ビュー レンダリング
        this.RenderViews();
    },

    
    RenderViews: function()
    {
        // ビューのレンダリング
        for (var i = 0; i < this.Views.GetLength(); i++)
        {
            var view = this.Views.Get(i);
            var tab = this.ViewsTabPanel.Tabs[i];
            view.InitializeView();
            view.Render(tab.Container.GetElement(), tab.Container);
        }
    },

    OnSearch: function()
    {
        if (!this.ActiveTabCache)
        {
            // 元々表示されていたタブをキャッシュ        
            for (var i = 0; i < this.ViewsTabPanel.Tabs.length; i++)
            {
                var tab = this.ViewsTabPanel.Tabs[i];
                if (tab.Active)
                {
                    this.ActiveTabCache = tab;
                    break;
                }
            }
        }

        // 検索結果の表示
        var searchView = this.Views.Get("Infoshare.GroupPicker.MobileSearchView");
        for (var i = 0; i < this.ViewsTabPanel.Tabs.length; i++)
        {
            var tab = this.ViewsTabPanel.Tabs[i];
            if (tab.Container == searchView.ParentPanel)
            {
                searchView.OnSearchEnd = ISFunction.CreateDelegate(function (items)
                {
                    // ヘッダーを非表示にする
                    this.ViewsTabPanel.Header.Hide();

                    // 検索コントロールの"キャンセル" ボタンを表示にする
                    this.SearchControl.Anchor.style.display = "";

                    // 検索タブを表示する
                    this.ViewsTabPanel.ActivateTab(tab.Tab)
                }, this);

                // 検索実行
                var keywordValue = this.SearchControl.GetValue();
                searchView.TrySearch(keywordValue);
                break;
            }
        } 
    },

    HideSearchView: function()
    {
        // ヘッダーを表示にする
        this.ViewsTabPanel.Header.Show();

        // 元々表示されていたタブを表示
        this.ViewsTabPanel.ActivateTab(this.ActiveTabCache.Tab);

        // アクティブタブのキャッシュを削除
        this.ActiveTabCache = null;

        // 検索コントロールの"キャンセル" ボタンを非表示にする
        this.SearchControl.Anchor.style.display = "none";

        // 検索文字列をクリア
        this.SearchControl.Input.value = "";
    }
}

