//  MobileIndexView
// -----------------------------------------------------------------------
Infoshare.GroupPicker.MobileIndexView = function Infoshare$GroupPicker$MobileIndexView() { }
GPMobileIndexView = Infoshare.GroupPicker.MobileIndexView;

GPMobileIndexView.IndexType = {
    English  : "English",
    Japanease: "Japanease"
}

GPMobileIndexView.prototype = {
    IndexType: null,
    Indexes: null,
    ValidateDataSource: GPMobileView.ValidateDataSource,
    ParentPanel: null,
    ParentElement: null,
    Containers: null,
    ActiveContainer: null,
    IndexQueryInfo: null,
    ListItemCollectionPositionNext: "",

    InitializeView: function()
    {
        if (this.Initialized)
        {
            return;
        }

        // データソースのバリデーション
        var valid = this.ValidateDataSource(this.DataSource);
        if (!valid)
        {
            this.Initialized = true;
            return;
        }

        // コンテナのディクショナリを作成
        this.Containers = new ISDictionary();

        // インデックスのクエリ参照情報を作成
        this.EnsureIndexQueryInfo();
    },

    EnsureIndexQueryInfo: function()
    {
        this.IndexQueryInfo = new ISDictionary();

        // ToDo: インデックスがない場合でも動作するように調整（組織Viewだけ動けばよい）
        if (!this.Indexes)
        {
            return;
        }

        for (var i = 0; i < this.Indexes.GetLength(); i++)
        {
            var indexInfo = this.Indexes.GetEntry(i);
            var indexQueryInfo = {
                StartIndex: indexInfo.Key,
                EndIndex: null
            }
            this.IndexQueryInfo.Add(indexInfo.Key, indexQueryInfo);
        }

        for (var i = 0; i < this.IndexQueryInfo.GetLength(); i++)
        {
            var queryInfo = this.IndexQueryInfo.Get(i);
            var endIndex = 9999;
            if (this.IndexQueryInfo.Contains(i + 1))
            {
                var nextQueryInfo = this.IndexQueryInfo.Get(i + 1);
                endIndex = nextQueryInfo.StartIndex - 1;
            }

            queryInfo.EndIndex = endIndex;
        }      
    },

    Render: function (parentElement, parentControl)
    {
        this.ParentPanel   = parentControl;
        this.ParentElement = parentElement;

        // ToDo: インデックスがない場合でも動作するように調整（組織Viewだけ動けばよい）
        if (!this.Indexes)
        {
            return;
        }

        // リストコンテナー
        var listContainer = new iListContainer(new GPMobileIndexViewListContainerStyle())
        
        var containerItems = [];
        for (var i = 0; i < this.Indexes.GetLength(); i++)
        {
            var indexInfo = this.Indexes.GetEntry(i);
            var containerItem = new GPListContainerIndexItem(null, indexInfo);
            // MobileIndexViewEntityの有効インデックスからインデックス有効/無効を行う
            var enabledIndexes = [];
            if (this.DataSource.MobileIndexViewEntity)
            {
                if (this.IndexType == GPMobileIndexView.IndexType.Japanease)
                {
                    enabledIndexes = this.DataSource.MobileIndexViewEntity.Properties.EnabledJapaneaseIndex.split(",");
                }
                else if (this.IndexType == GPMobileIndexView.IndexType.English)
                {
                    enabledIndexes = this.DataSource.MobileIndexViewEntity.Properties.EnabledEnglishIndex.split(",");
                }

                if (ISArray.Contains(enabledIndexes, indexInfo.Key.toString()))
                {
                    containerItem.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnContainerIndexItemClick, this));
                }
                else
                {
                    containerItem.Enabled = false;
                }
            }
            else
            {
                containerItem.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnContainerIndexItemClick, this));
            }

            containerItems.push(containerItem);
        }

        listContainer.Items = containerItems;
        listContainer.Render(parentElement);

        var containerKey = "Root";
        this.Containers.Add(containerKey, listContainer);
        this.ActiveContainer = listContainer;
    },

    OnContainerIndexItemClick: function(containerItem)
    {
        // クリックされたインデックスのコンテナを表示する
        if (containerItem.IndexInfo)
        {
            this.UpdateContainerView(containerItem.IndexInfo);
        }
    },

    UpdateContainerView: function(indexInfo)
    {
        // アクティブコンテナを非表示にする
        if (this.ActiveContainer)
        {
            this.ActiveContainer.Hide();
            this.ActiveContainer = null;
        }
        
        // コンテナの作成
        if (!this.Containers.Contains(indexInfo.Value))
        {
            var listContainer = new iListContainer(new GPMobileIndexViewListContainerWithHeaderStyle())
            listContainer.Header = new GPListContainerIndexHeaderItem(null, indexInfo);
            listContainer.Header.OnClickBackButton = ISFunction.CreateDelegate(function ()
            {
                this.UpdateContainerView({ Key: "Root", Value: "Root"});
            }, this);
            
            // Itemsは非同期でセットする
            listContainer.RetrieveItems = ISFunction.CreateDelegate(function (callback)
            {
                this.RetrieveIndexItems(indexInfo, callback);
            }, this);

            this.Containers.Add(indexInfo.Value, listContainer);
        }

        var container = this.Containers.Get(indexInfo.Value);
        this.ActiveContainer = container;
        // レンダリングされている場合
        if (container.GetElement())
        {
            container.Show();
        }
        else
        {
            container.Render(this.ParentElement);
        }
    },

    RetrieveIndexItems: function(indexInfo, callback)
    {
        this.GetItems(indexInfo, ISFunction.CreateDelegate(function (results, responseMetaData)
        {
            var items = [];
            // 閾値を超えて検索
            if (responseMetaData == null)
            {
                var message = iResxResource.GetString('PickerDialog.SearchView.MessageLabel.ThresholdOverResults');
                var errorItem = new GPListContainerItem(new GPListContainerErrorEntityItemStyle(), message);
                items.push(errorItem);
                callback(items);
                return;
            }

            // 次ページのオブジェクトが存在する場合
            if (this.Info.PageSize == responseMetaData.ItemCount &&
                !ISString.IsNullOrEmpty(responseMetaData.ListItemCollectionPositionNext))
            {
                // 次のページのクエリ情報をキャッシュ
                this.ActiveContainer.ListItemCollectionPositionNext = responseMetaData.ListItemCollectionPositionNext;
                
                // スクロール終了のタイミングで次ページを取得する
                var view = this;
                this.ActiveContainer.OnScrolledToBottom = function(endCallBack)
                {
                    view.RetrieveIndexItems(indexInfo, function (items)
                    {
                        view.ActiveContainer.Append(items);

                        // 完了タイミングの通知用
                        endCallBack();
                    });
                };
            }
            else
            {
                this.ActiveContainer.ListItemCollectionPositionNext = "";
                this.ActiveContainer.OnScrolledToBottom = function () {};
            }

            for (var i = 0; i < results.length; i++)
            {
                var result = results[i];
                var item = new GPListContainerEntityItem(null, result);
                item.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnContainerEntityItemClick, this));

                items.push(item);
            }

            callback(items);
        }, this));
    },

    GetItems: function(indexInfo, callback)
    {
        var queryInfo = this.IndexQueryInfo.Get(indexInfo.Key.toString());

        var startIndex = queryInfo.StartIndex;
        var endIndex   = queryInfo.EndIndex;
        var fieldName  = this.IndexType == GPMobileIndexView.IndexType.English ? "EnglishIndex"
                                                                               : "JapaneaseIndex";

        var query = new ISSPQuery();
        query.TryQuery = false;

        // ルート組織から辿ることが可能
        var rootTreeEntity = this.DataSource.RootTreeEntities[0];
        var rootEntityHierarchicalId = rootTreeEntity.Properties.HierarchicalId;
        var rootEntityHierarchicalIdArray = rootEntityHierarchicalId.split("|");
        var rootQuery = '|' + rootEntityHierarchicalIdArray[1];

        var where = '';
        var startIndexQuery = SPQueryBuilder.BuildGreaterThanEqualQueryCondition(fieldName, "Integer", startIndex);
        var endIndexQuery = SPQueryBuilder.BuildLessThanEqualQueryCondition(fieldName, "Integer", endIndex);
        where = SPQueryBuilder.BuildAndQueryCondition(startIndexQuery + endIndexQuery);
        var typeQuery = SPQueryBuilder.BuildEqualQueryCondition("Type", "Text", "User");
        where = SPQueryBuilder.BuildAndQueryCondition(where + typeQuery);
        var hierarchicalIdQuery = SPQueryBuilder.BuildContainsQueryCondition("HierarchicalId", "Note", rootQuery);
        where = SPQueryBuilder.BuildAndQueryCondition(where + hierarchicalIdQuery);
        // ToDo:ShowInView
        /*
        var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "MobileIndexView");
        var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
        var showInViewQuery = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);
        where = SPQueryBuilder.BuildAndQueryCondition(where + showInViewQuery);
        */

        // EnableVisibleGroups=trueの場合、CurrentUserのVisibleGroupsを検索条件に追加する
        var enableVisibleGroups = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableVisibleGroups'), false);
        if (enableVisibleGroups)
        {
            where = GPCamlQueryCondition.AddVisibleGroupsCondition(where, GPViewContext.CurrentUserEntity);
        }

        // OrderBy句
        var orderby = '';
        for (var i = 0; i < this.Info.SortOrders.length; i++)
        {
            var order = this.Info.SortOrders[i];
            orderby += SPQueryBuilder.BuildOrderByFieldRef(order.FieldName, order.Ascending);
        }

        query.Query = SPQueryBuilder.BuildQuery(orderby, where);

        // ViewField設定
        var fieldRefs = '';
        for(var i = 0; i < GPContext.Configuration.Fields.GetLength(); i++)
        {
            var field = GPContext.Configuration.Fields.Get(i);
            fieldRefs += SPQueryBuilder.BuildFieldRef(field.InternalName);
        }
        query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

        var options = SPQueryBuilder.BuildQueryOptions(SPQueryBuilder.BuildMandatoryColumnsOption(false));
        if (!ISString.IsNullOrEmpty(this.ActiveContainer.ListItemCollectionPositionNext))
        {
            // &をエスケープしないと400エラーになる
            // <Paging ListItemCollectionPositionNext='Paged=TRUE&amp;p_SeniorityIndex=0&amp;p_ID=10' />
            options += SPQueryBuilder.BuildListItemCollectionPositionNextOption(iXml.Escape(this.ActiveContainer.ListItemCollectionPositionNext));
        }
        query.QueryOptions = SPQueryBuilder.BuildQueryOptions(options);
        query.RowLimit     = this.Info.PageSize;
        if (this.Info.Options.Get('PageSize'))
        {
            var pageSize = this.Info.Options.Get('PageSize');
            this.Info.PageSize = pageSize;
            query.RowLimit = pageSize;
        }
        
        iVxService.RetrieveItems(this.DataSource.WebUrl, this.DataSource.DataSourceList, query, false, callback);
    },

    OnContainerEntityItemClick: function(entityItem)
    {
        GPMobileView.RenderEntityView(entityItem.Entity);
    }
}

