// -----------------------------------------------------------------------
//  MobileOrganizationView
// -----------------------------------------------------------------------
Infoshare.GroupPicker.MobileOrganizationView = function Infoshare$GroupPicker$MobileOrganizationView() { }
GPMobileOrganizationView = Infoshare.GroupPicker.MobileOrganizationView;

GPMobileOrganizationView.prototype = {
    ValidateDataSource: GPMobileView.ValidateDataSource,
    ParentPanel: null,
    ParentElement: null,
    Containers: null,
    ActiveContainer: null,
    InitializeView: function ()
    {
        // ToDo: 初期化時に設定（構成ファイル置きする）
        // 今の所からを設定して、すべて取得されるようにする
        this.Info.ViewFields = new ISDictionary();

        // コンテナのディクショナリを作成
        this.Containers = new ISDictionary();
    },
    Render: function(parentElement, parentControl)
    {
        this.ParentPanel   = parentControl;
        this.ParentElement = parentElement;

        // オプションに応じて初期表示を行う
        this.ExpandNodeByOption();
    },

    ExpandNodeByOption: GPOrganizationView.prototype.ExpandNodeByOption,

    // ToDo: 要不要検討
    FixMyOrganization: GPOrganizationView.prototype.FixMyOrganization,
    GetMyOrganizationEntity: GPOrganizationView.prototype.FixMyOrganization,

    ExpandRootNode: function()
    {
        // リストコンテナー
        var listContainer = new iListContainer(new GPMobileOrganizationViewListContainerStyle())
        var rootEntity = this.DataSource.RootTreeEntities[0];
        listContainer.Header = new GPListContainerEntityHeaderItem(null, rootEntity);

        // Itemsは非同期でセットする
        listContainer.RetrieveItems = ISFunction.CreateDelegate(function (callback)
        {
            this.RetrieveChildItems(listContainer, rootEntity, callback);
        }, this);

        listContainer.Render(this.ParentElement);

        var containerKey = rootEntity.Properties.EntityId;
        this.Containers.Add(containerKey, listContainer);
        this.ActiveContainer = listContainer;

        return true;
    },

    ExpandForMyOrganization: GPOrganizationView.prototype.ExpandForMyOrganization,
    ExpandForMyOrganizationInternal: function(userHierarchicalId)
    {
        // ルートから始まる階層IDを取得
        var targetRootEntity = this.DataSource.RootTreeEntities[0];
        var hierarchicalIdStartRoot = GPHierarchicalIdUtility.GetChildId(userHierarchicalId, targetRootEntity.Properties.EntityId);
        var hierarchicalId = GPHierarchicalIdUtility.GetParentId(hierarchicalIdStartRoot);

        // 階層IDを元に組織一覧を取得する
        GPHierarchicalIdUtility.GetEntitiesByHierarchicalId(this, hierarchicalId, false, targetRootEntity, ISFunction.CreateDelegate(function(entityDictionary)
        {
            var entitiesLength = entityDictionary.GetLength();
            for (var i = 0; i < entitiesLength; i++)
            {
                // keyにStringを持っている
                var entity = entityDictionary.Get(i.toString())[0];
                // 親グループをセット（ルート以外）
                if (!ISBoolean.TryParse(entity.Properties.IsRootOrganization, false))
                {
                    var parentEntity = entityDictionary.Get((i - 1).toString())[0];
                    entity.ParentGroup = parentEntity;
                }

                // リストコンテナー
                var listContainer = new iListContainer(new GPMobileOrganizationViewListContainerStyle())
                listContainer.Header = this.CreateHeaderItem(entity);

                var containerKey = entity.Properties.EntityId;
                this.Containers.Add(containerKey, listContainer);
            }

            // parentGroupのコンテナを初期表示する
            var parentGroup = entityDictionary.Get((entitiesLength - 1).toString())[0];
            this.UpdateContainerView(parentGroup);
        }, this));
    },

    CreateHeaderItem: function(entity)
    {
        var header = new GPListContainerEntityHeaderItem(null, entity);
        
        header.OnClickBackButton = ISFunction.CreateDelegate(function ()
        {
            this.UpdateContainerView(entity.ParentGroup);
        }, this);

        // ルート組織は戻るボタンを非表示にする
        if (ISBoolean.TryParse(entity.Properties.IsRootOrganization, false))
        {
            header.HideBackButton = true;
        }

        // エンティティ情報ボタン
        header.HideInformationButton = false;
        header.OnClickInformationButton = ISFunction.CreateDelegate(function ()
        {
            this.OnContainerEntityItemClick(header.Entity);
        }, this);

        return header;
    },

    RetrieveChildItems: function(container, parentGroup)
    {
        this.GetChildEntities(parentGroup, ISFunction.CreateDelegate(function(results)
        {
            var items = [];
            for (var i = 0; i < results.length; i++)
            {
                var result = results[i];
                var item = new GPListContainerEntityItem(new GPListContainerOrganizationViewEntityItemStyle(), result);
                item.HideInformationButton = false;
                item.OnClickInformationButton = ISFunction.CreateDelegate(function (containerItem)
                {
                    this.OnContainerEntityItemClick(containerItem.Entity);
                }, this);

                item.Entity.ParentGroup = parentGroup;
                // アイテムの更新
                item.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnContainerItemClick, this));

                items.push(item);
            }

            container.Append(items);
        }, this));
    },

    OnContainerItemClick: function(containerItem)
    {
        // eventのpathを確認して imgが先頭の場合（imgがクリックされた場合）には、スルーしてOnClickInformationButtonを実行させる
        var path = event.path || (event.composedPath && event.composedPath());
        if (path &&
            path[0].tagName == "IMG")
        {
            return;
        }

        if (ISString.Equals(containerItem.Entity.Properties.Type, "Group", true))
        {
            this.UpdateContainerView(containerItem.Entity);
        }
        else
        {
            this.OnContainerEntityItemClick(containerItem.Entity);
        }        
    },

    UpdateContainerView: function(entity)
    {
        // アクティブコンテナを非表示にする
        if (this.ActiveContainer)
        {
            this.ActiveContainer.Hide();
            this.ActiveContainer = null;
        }
        
        // コンテナの作成
        if (!this.Containers.Contains(entity.Properties.EntityId))
        {
            var listContainer = new iListContainer(new GPMobileOrganizationViewListContainerStyle())
            listContainer.Header = this.CreateHeaderItem(entity);

            this.Containers.Add(entity.Properties.EntityId, listContainer);
        }

        var container = this.Containers.Get(entity.Properties.EntityId);
        this.ActiveContainer = container;

        container.RetrieveItems = ISFunction.CreateDelegate(function (callback)
        {
            this.RetrieveChildItems(container, entity, callback);
        }, this);        

        // レンダリングされている場合
        if (container.GetElement())
        {
            container.Show();
        }
        else
        {
            container.Render(this.ParentElement);
        }
    },

    OnContainerEntityItemClick: function(entity)
    {
        GPMobileView.RenderEntityView(entity);
    },

    GetChildEntities : function(parentEntity, callback)
    {
        // MemberOfQuery組み立て
        var parentSID = parentEntity.Properties.EntityId;
        var parentId = "|" + parentSID + "|";
        var memberOfQuery = SPQueryBuilder.BuildContainsQueryCondition("MemberOf", "Note", parentId);
        var query = this.BuildChildEntitiesQuery(parentEntity, memberOfQuery);

        (function (view)
        {
            GPGridUtility.GetEntities(view.DataSource, query, function(items)
            {
                callback(items);
            });
        })(this);
    },
    BuildChildEntitiesQuery  : function (parentEntity, memberOfQuery)
    {
        var query = new ISSPQuery();
        query.TryQuery = false;

        var queryTemplete   = "<Query>"
                            +   "<Where>"
                            +     "%Where%"
                            +   "</Where>"
                            +   "<OrderBy>"
                            +     "%OrderByConfigs%"
                            +   "</OrderBy>"
                            + "</Query>";

        // Whare句
        var whereQuery = memberOfQuery;

        // ToDo:ShowInView
        /*
        var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "OrganizationView");
        var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
        var showInViewQuery = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);
        where = SPQueryBuilder.BuildAndQueryCondition(memberOfQuery + showInViewQuery);
        */

        // EnableVisibleGroups=trueの場合、CurrentUserのVisibleGroupsを検索条件に追加する
        var enableVisibleGroups = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableVisibleGroups'), false);
        if (enableVisibleGroups)
        {
            whereQuery = GPCamlQueryCondition.AddVisibleGroupsCondition(whereQuery, GPViewContext.CurrentUserEntity);
        }

        // Query句の設定
        query.Query = queryTemplete.replace("%Where%", whereQuery);

        // OrderByのquery組み立て
        var orderByConfigs = "";
        for (var i = 0; i < this.Info.SortOrders.length; i++)
        {
            var orderByTemplete = "<FieldRef Name='%OrderByName%' Ascending='%OrderByAscending%'/>";
            orderByTemplete = orderByTemplete.replace("%OrderByName%", this.Info.SortOrders[i].FieldName);
            orderByTemplete = orderByTemplete.replace("%OrderByAscending%", this.Info.SortOrders[i].Ascending);
            orderByConfigs += orderByTemplete;
        }
        query.Query = query.Query.replace("%OrderByConfigs%", orderByConfigs);

        // ViewField設定 
        var fieldRefs = '';
        query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

        return query;
    }
}

                            
