// -----------------------------------------------------------------------
//  MobileSearchView
// -----------------------------------------------------------------------
Infoshare.GroupPicker.MobileSearchView = function Infoshare$GroupPicker$MobileSearchView() { }
GPMobileSearchView = Infoshare.GroupPicker.MobileSearchView;

GPMobileSearchView.prototype = {
    IndexType: null,
    Indices: null,
    ValidateDataSource: GPMobileView.ValidateDataSource,
    ParentPanel: null,
    ParentElement: null,
    IndexQueryInfo: null,
    Container: null,
    ListItemCollectionPositionNext: "",
    KeywordValidateOption :{
        SameKeyword: false,
        EmptyKeyword: true,
        SystemKeyword: true,
        SurrogatePair: true,
        LengthKeyword: true,
        CountKeyword: true
    },

    InitializeView: function()
    {
        if (this.Initialized)
        {
            return;
        }

        // データソースのバリデーション
        var valid = this.ValidateDataSource(this.DataSource);
        if (!valid)
        {
            this.Initialized = true;
            return;
        }

        // 検索フィルタ
        //this.SearchTypeFilters = this.Info.ViewXml.attributes.SearchType.value.split(",");
        this.SearchTypeFilters = iXml.GetAttributeValue(this.Info.ViewXml, 'SearchType').split(",");

        // 表示列情報
        //this.InfomationFields = this.Info.ViewXml.attributes.InfomationFields.value.split(",");
        this.InfomationFields = iXml.GetAttributeValue(this.Info.ViewXml, 'InfomationFields').split(",");
    },

    Render: function (parentElement, parentControl)
    {
        this.ParentPanel   = parentControl;
        this.ParentElement = parentElement;

        // リストコンテナー
        var listContainer = new iListContainer(new GPMobileSearchViewListContainerStyle())
        this.Container = listContainer;
    },
    
    OnContainerEntityItemClick: function(entityItem)
    {
        GPMobileView.RenderEntityView(entityItem.Entity);
    },
    
    TrySearch: function(keywordValue)
    {
        var keyword = this.GetKeyword(keywordValue);
        var keywords = keyword.GetKeywords();

        // ページング情報をクリア
        this.ListItemCollectionPositionNext = "";

        // クリア
        // ToDo: ListContainerクラスを修正して、Clearは不要にしたい
        this.Container.Clear();

        var listContainer = new iListContainer(new GPMobileSearchViewListContainerStyle())
        this.Container = listContainer;
        this.Container.RetrieveItems = ISFunction.CreateDelegate(function (callback)
        {
            if (!iObject.IsNullOrUndefined(keywords) &&
                keywords.length > 0)
            {
                var view = this;
                this.RetrieveSearchResultItems(keywords, function (items)
                {
                    if (!items || items.length <= 0)
                    {
                        var message = iString.Format(iResxResource.GetString('PickerDialog.SearchView.MessageLabel.ResultNull'), iXml.Escape(keywordValue));
                        var errorItem = new GPListContainerItem(new GPListContainerErrorEntityItemStyle(), message);
                        items.push(errorItem);
                    }

                    // 検索完了のイベント通知
                    view.OnSearchEnd(items);
                    callback(items);
                });
            }
            else
            {
                var items = [];
                var errorItem = new GPListContainerItem(new GPListContainerErrorEntityItemStyle(), keyword.ErrorMessage);
                items.push(errorItem);

                // 検索完了のイベント通知
                this.OnSearchEnd(items);
                callback(items);
            }
        }, this);

        // 更新
        this.Container.Render(this.ParentElement);
    },

    OnSearchEnd: function () { },

    GetKeyword: GPSearchView.prototype.GetKeyword,

    RetrieveSearchResultItems: function (keywords, callback)
    {
        // 検索フィルタの設定
        var filters = this.SearchTypeFilters;
        this.GetItems(filters, keywords, ISFunction.CreateDelegate(function (results, responseMetaData)
        {
            var items = [];
            // 閾値を超えて検索
            if (responseMetaData == null)
            {
                var message = iResxResource.GetString('PickerDialog.SearchView.MessageLabel.ThresholdOverResults');
                var errorItem = new GPListContainerItem(new GPListContainerErrorEntityItemStyle(), message);
                items.push(errorItem);
                callback(items);
                return;

            }
            // 次ページのオブジェクトが存在する場合
            if (this.Info.PageSize == responseMetaData.ItemCount &&
                !ISString.IsNullOrEmpty(responseMetaData.ListItemCollectionPositionNext))
            {
                // 次のページのクエリ情報をキャッシュ
                this.ListItemCollectionPositionNext = responseMetaData.ListItemCollectionPositionNext;
                
                // スクロール終了のタイミングで次ページを取得する
                var view = this;
                this.Container.OnScrolledToBottom = function(endCallBack)
                {
                    view.RetrieveSearchResultItems(keywords, function (items)
                    {
                        view.Container.Append(items);

                        // 完了タイミングの通知用
                        endCallBack();
                    });
                };
            }
            else
            {
                this.ListItemCollectionPositionNext = "";
                this.Container.OnScrolledToBottom = function () {};
            }

            for (var i = 0; i < results.length; i++)
            {
                var result = results[i];
                var item = new GPListContainerEntityWithInfomationItem(null, result, this.InfomationFields);

                // アイテムの更新
                item.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnContainerEntityItemClick, this));

                items.push(item);
            }

            callback(items);
        }, this));
    },

    GetItems: function(typeValue, keywords, callback)
    {
        // Where句
        var where = this.BuildWhereQuery(typeValue, keywords, true);

        // OrderBy句
        var orderby = '';
        for (var i = 0; i < this.Info.SortOrders.length; i++)
        {
            var order = this.Info.SortOrders[i];
            orderby += SPQueryBuilder.BuildOrderByFieldRef(order.FieldName, order.Ascending);
        }

        // ViewField設定 
        var fieldRefs = '';

        // クエリ組み立て
        var query = new ISSPQuery();
        query.Query        = SPQueryBuilder.BuildQuery(orderby, where);
        query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);


        var options = SPQueryBuilder.BuildQueryOptions(SPQueryBuilder.BuildMandatoryColumnsOption(false));
        if (!ISString.IsNullOrEmpty(this.ListItemCollectionPositionNext))
        {
            // &をエスケープしないと400エラーになる
            // <Paging ListItemCollectionPositionNext='Paged=TRUE&amp;p_SeniorityIndex=0&amp;p_ID=10' />
            options += SPQueryBuilder.BuildListItemCollectionPositionNextOption(iXml.Escape(this.ListItemCollectionPositionNext));
        }
        query.QueryOptions = SPQueryBuilder.BuildQueryOptions(options);
        query.RowLimit     = this.Info.PageSize;
        if (this.Info.Options.Get('PageSize'))
        {
            var pageSize = this.Info.Options.Get('PageSize');
            this.Info.PageSize = pageSize;
            query.RowLimit = pageSize;
        }

        iVxService.RetrieveItems(this.DataSource.WebUrl, this.DataSource.DataSourceList, query, false, callback);
    },

    BuildWhereQuery: GPSearchView.prototype.BuildWhereQuery
}

