// -----------------------------------------------------------------------
//  EntityView
// -----------------------------------------------------------------------
Infoshare.GroupPicker.EntityView = function Infoshare$GroupPicker$EntityView(entity, viewInfo)
{
    this.Entity = entity;
    this.Info   = viewInfo;
}
GPEntityView = Infoshare.GroupPicker.EntityView;

GPEntityView.prototype = {
    ParentElement: null,
    Entity: null,
    Info: null,

    Render: function (parentElement, parentControl)
    {
        this.ParentElement = parentElement;

        // レイアウト：ヘッダー、ボディー
        var layoutPanel  = new iSplitPanel(new GPEntityViewStyle());
        this.LayoutPanel = layoutPanel;
        layoutPanel.Style.Mode  = iSplitPanelStyle.Mode.Horizontal;
        layoutPanel.DisplayType = iPanelStyle.DisplayType.Block;
                
        layoutPanel.Style.StretchOption   = iPanelStyle.StretchOption.Both;
        layoutPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
        layoutPanel.Style.ContainerStyles[0].Size.Height = 80;

        // ヘッダー
        var header  = new GPEntityViewHeader(this.Entity);
        layoutPanel.AppendChildControlForContainer(0, header);

        // ボディー（スプリットパネル：アクション、詳細）
        var bodyPanel  = new iSplitPanel();
        bodyPanel.Style.Mode  = iSplitPanelStyle.Mode.Horizontal;
        bodyPanel.DisplayType = iPanelStyle.DisplayType.Block;                
        bodyPanel.Style.StretchOption   = iPanelStyle.StretchOption.Both;
        bodyPanel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle()];
        bodyPanel.Style.ContainerStyles[0].Size.Height = 90;
        layoutPanel.AppendChildControlForContainer(1, bodyPanel);

        // アクションパネル
        this.EnsureActions();
        var actionsPanel = new GPEntityViewActionPanel(this.Info.Actions);
        bodyPanel.AppendChildControlForContainer(0, actionsPanel);

        // 詳細情報パネル
        var infomationPanel = new GPEntityViewInformationPanel(this.Entity, this.Info.ViewFields);
        bodyPanel.AppendChildControlForContainer(1, infomationPanel);

        layoutPanel.Render(parentElement);

        // ProfileImageを表示
        if (this.Info.Options.Get('ProfileImageHeight') && this.Info.Options.Get('ProfileImagePosition'))
        {
            var div = document.createElement('div');
            div.style.textAlign = 'center';
            var img = document.createElement('img');
            if (GPContext.Configuration.GetSetting('ProfileImageAPI').toUpperCase() == 'SharePoint'.toUpperCase()) {
                img.setAttribute('src', GPContext.SiteUrl + "/_layouts/15/userphoto.aspx?size=M&accountname=" + this.Entity.Properties['Sip']);
            }
            else if (GPContext.Configuration.GetSetting('ProfileImageAPI').toUpperCase() == 'Graph'.toUpperCase()) {
                img.setAttribute('src', GPContext.SiteUrl + "/_layouts/15/images/personPlaceholder.96x96x32.png");
                GraphProfileImageController.GetInstance().UpdateGraphProfileImage(this.Entity.Properties.EntityId, img);
            }
            else {
                img.setAttribute('src', GPContext.SiteUrl + "/_layouts/15/images/personPlaceholder.96x96x32.png");
            }

            img.setAttribute('onerror', "this.src='" + GPContext.SiteUrl + "/_layouts/15/images/personPlaceholder.96x96x32.png'");
            img.setAttribute('height', this.Info.Options.Get("ProfileImageHeight") + "px");
            div.appendChild(img);
            if (this.Info.Options.Get('ProfileImagePosition').toUpperCase() == 'top'.toUpperCase())
            {
                layoutPanel.Containers[0].Element.children[1].prepend(div);
            }
            else if (this.Info.Options.Get('ProfileImagePosition').toUpperCase() == 'bottom'.toUpperCase())
            {
                layoutPanel.Containers[0].Element.children[1].append(div);
            }
            layoutPanel.Style.ContainerStyles[0].Size.Height = layoutPanel.Style.ContainerStyles[0].Size.Height + ISNumber.Parse(this.Info.Options.Get("ProfileImageHeight"));
        }

        // Workaround for alpha
        // 詳細情報パネルのスタイルを修正（情報量/画面サイズによって一部の情報が表示できなくなるため）
        var infomationPanelHeight = window.innerHeight
                                  - layoutPanel.Style.ContainerStyles[0].Size.Height
                                  - layoutPanel.Separators[0].Style.Size.Height
                                  - bodyPanel.Style.ContainerStyles[0].Size.Height
                                  - bodyPanel.Separators[0].Style.Size.Height
                                  - 10; // paddingtop
        ISDomAccessor.SetHeight(bodyPanel.Containers[1].GetElement(), infomationPanelHeight);
        bodyPanel.Containers[1].GetElement().style.overflow = 'auto';
    },

    EnsureActions: function()
    {
        // ViewInfo内ではActionの情報は初期化しないのでこちらで検証する
        if (this.Info)
        {
            this.Info.Actions = [];

            var actionElements = this.Info.ViewXml.getElementsByTagName('Action');
            for (var i = 0; i < actionElements.length; i++)
            {
                var actionElement = actionElements[i];
                var type                   = iXml.GetAttributeValue(actionElement, 'Type');
                var internalName           = iXml.GetAttributeValue(actionElement, 'InternalName');
                var image                  = iXml.GetAttributeValue(actionElement, 'Image');
                var displayName            = iXml.GetAttributeValue(actionElement, 'DisplayName');
                var displayNameResourceKey = iXml.GetAttributeValue(actionElement, 'DisplayNameResourceKey');
                
                var title = !ISString.IsNullOrEmpty(displayName) ? displayName
                                                                 : iResxResource.GetString(displayNameResourceKey);
                // Valueが空の物はfalseにする
                var enabled = true;
                var href = "";
                var hrefValue = this.Entity.Properties[internalName];
                if (ISString.IsNullOrEmpty(hrefValue))
                {
                    enabled = false;
                }
                else
                {
                    if (ISString.Equals(type, "MailTo", true))
                    {
                        href = 'ms-outlook://emails/new?to=' + hrefValue;
                    }
                    else if (ISString.Equals(type, "Sip", true))
                    {
                        href = "sip:" + hrefValue;
                    }
                    else if (ISString.Equals(type, "Tel", true))
                    {
                        href = "tel:" + hrefValue;
                    }
                    else if (ISString.Equals(type, "TeamsChat", true))
                    {
                        href = "msteams:/l/chat/0/0?users=" + hrefValue;
                    }
                    else if (ISString.Equals(type, "TeamsCall", true))
                    {
                        href = "msteams:/l/call/0/0?users=" + hrefValue;
                    }
                }

                // ImageUrl
                // ToDo: Disableの対応
                var baseUrl  = GPContext.SourcesPath + "/Infoshare.InfoCall/";
                var imageUrl = baseUrl + image + "?rev=" + GPPackageInfo.PackageTimestamp;

                var actionInfo = {
                    Type     : type,
                    Title    : title,
                    Href     : href,
                    ImageUrl : imageUrl,
                    Enabled  : enabled
                }

                this.Info.Actions.push(actionInfo);
            }
        }
    }
}

