// -----------------------------------------------------------------------
//  GPEntityViewInformationPanel
// -----------------------------------------------------------------------
Infoshare.GroupPicker.EntityViewInformationPanel = function Infoshare$GroupPicker$EntityViewInformationPanel(entity, fields)
{    
    Infoshare.Web.Control.Panel.apply(this, arguments);
    this.Style = new GPEntityViewInformationPanelStyle();

    this.Entity = entity;
    this.Fields = fields;
}
GPEntityViewInformationPanel = Infoshare.GroupPicker.EntityViewInformationPanel;

GPEntityViewInformationPanel.prototype = new Infoshare.Web.Control.Panel();
GPEntityViewInformationPanel.prototype.RenderingMode = iControl.RenderingMode.Append;

GPEntityViewInformationPanel.prototype.Entity = null;
GPEntityViewInformationPanel.prototype.Fields = null;
GPEntityViewInformationPanel.prototype.RenderMarkup = function(writer)
{
    writer[writer.length] = "<div id='" + this.GetElementId() + "' ";
    writer[writer.length] =   "class='" + this.GetClassName() + "'>";

    // 要素をレンダリング
    for (var i = 0; i < this.Fields.GetLength(); i++)
    {
        var fieldInfo = this.Fields.Get(i);

        if (fieldInfo.ViewType &&
            ISString.Equals(fieldInfo.ViewType, "Hidden", true))
        {
            continue;
        }

        var labelText = !ISString.IsNullOrEmpty(fieldInfo.DisplayName) ? fieldInfo.DisplayName : iResxResource.GetString(fieldInfo.DisplayNameResourceKey);
        var internalName = fieldInfo.InternalName;
        var value = this.Entity.Properties[internalName];

        writer[writer.length] = "<div />";

        writer[writer.length] =     "<div contentType='Label'>";
        writer[writer.length] =     labelText;
        writer[writer.length] =     "</div>";

        writer[writer.length] =     "<div contentType='Value'>";
        // ValueはViewFieldによりタイプ分けする
        if (!fieldInfo.ViewType ||
            ISString.Equals(fieldInfo.ViewType, "Text", true))
        {
            writer[writer.length] = value;
        }
        else if (!fieldInfo.ViewType ||
                 ISString.Equals(fieldInfo.ViewType, "MailTo", true))
        {
            writer[writer.length] = "<a href='";
            writer[writer.length] = 'ms-outlook://emails/new?to=' + value;
            writer[writer.length] = "' > ";
            writer[writer.length] = value;
            writer[writer.length] = "</a>";
        }
        else if (!ISString.IsNullOrEmpty(value))
        {
            writer[writer.length] = "<a href='";
            writer[writer.length] = fieldInfo.ViewType + ":" + value;
            writer[writer.length] = "' > ";
            writer[writer.length] = value;
            writer[writer.length] = "</a>";
        }
        writer[writer.length] =     "</div>";

        writer[writer.length] = "</div>";
    }

    writer[writer.length] = "</div>";
}
                            
