GPMenuAction = Infoshare.GroupPicker.MenuAction;
GPMenuAction.TypeName = 'Infoshare.GroupPicker.MenuAction';

GPMenuAction.prototype = new GPHeaderAction();
GPMenuAction.prototype.TypeName = GPMenuAction.TypeName;
