{
};

GPMenuAction.prototype.BasePostRender = GPMenuAction.prototype.PostRender;
GPMenuAction.prototype.PostRender = function(control)
{
    this.BasePostRender(control);

    var menu = new iMenu();
    menu.Action = this;
    menu.Alignment = iMenu.Alignment.TopRight;
    var menuItemsElement = iXml.SelectNodeByPath(this.ActionInfo.ActionXml, 'MenuItems');
    var menuItemElements = iXml.GetChildElements(menuItemsElement, function (childElement)
    {
        return iString.Equals(childElement.nodeName, 'MenuItem', true)
    });

    for (var i = 0; i < menuItemElements.length; i++)
    {
        var menuItemElement = menuItemElements[i];
        var item = new iMenuItem.FromXml(menu, menuItemElement);
        menu.MenuItems.Add(item.Id, item);
    }

    menu.RegisterOpenEvent(this.ActionButton.GetElement());

    this.Menu = menu;
}
                                 
