// -----------------------------------------------------------------------
//  Menu.CopyItemAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.CopyItemAction = function Infoshare$GroupPicker$CopyItemAction()
{
    Infoshare.Web.Control.MenuItemAction.apply(this, arguments);
}
GPCopyItemAction = Infoshare.GroupPicker.CopyItemAction;
GPCopyItemAction.TypeName = 'Infoshare.GroupPicker.CopyItemAction';

GPCopyItemAction.prototype = new Infoshare.Web.Control.MenuItemAction();
GPCopyItemAction.prototype.TypeName = GPCopyItemAction.TypeName;

GPCopyItemAction.prototype.IsEnabled = function ()
{
    return !iObject.IsNullOrUndefined(this.getSelectedItems());
}

GPCopyItemAction.prototype.ExecuteAction = function (menuItem)
{
    // 選択されているアイテムを取得する
    var items = this.getSelectedItems();
    if (!items)
    {
        ISTrace.TraceWarning('[WARNING] GPCopyItemAction.ExecuteAction: There is no item selected.');
        return;
    }

    // アイテムごとに表示フィールド（ViewFields)の設定に従って、属性を取得
    var builder = new Array();
    var view = this.getActiveView();
    var fieldIds = view.Info.ViewFields.GetKeys();
    for (var i = 0; i < items.length; i++)
    {
        var item = items[i];
        for (var j = 0; j < fieldIds.length; j++)
        {
            var fieldId = fieldIds[j];
            var viewField = view.Info.ViewFields.Get(fieldId);
            if (iString.Equals(viewField.ViewType, 'text', true) ||
                iString.Equals(viewField.ViewType, 'link', true))
            {
                var fieldValue = item.Properties[viewField.InternalName];
                if (!iString.IsNullOrEmpty(fieldValue))
                {
                    builder[builder.length] = fieldValue;
                }
                builder[builder.length] = ',';
            }
        }

        // 最後のカンマを取り除き改行
        if (builder.length > 0)
        {
            builder.pop();
            builder[builder.length] = '\r\n';
        }
    }

    // クリップボードにコピー
    var text = builder.join('');
    (new iClipboard()).Set(text);
}

GPCopyItemAction.prototype.getSelectedItems = function ()
{
    var selectedItems = null;
    var view = this.getActiveView();
    if (view)
    {
        var items = view.GetSelectedItems();
        if (items && items.length > 0)
        {
            selectedItems = items;
        }
    }

    return selectedItems;
}

GPCopyItemAction.prototype.getActiveView = function ()
{
    var view = this.MenuItem.Menu.Action.View.ViewsTabPanel.SelectedTab.View;

    return view;
}
                                 
