// -----------------------------------------------------------------------
//  Menu.SetMyOrganizationAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.SetMyOrganizationAction = function Infoshare$GroupPicker$SetMyOrganizationAction()
{
    Infoshare.Web.Control.MenuItemAction.apply(this, arguments);
}
GPSetMyOrganizationAction = Infoshare.GroupPicker.SetMyOrganizationAction;
GPSetMyOrganizationAction.TypeName = 'Infoshare.GroupPicker.SetMyOrganizationAction';

GPSetMyOrganizationAction.prototype = new Infoshare.Web.Control.MenuItemAction();
GPSetMyOrganizationAction.prototype.TypeName = GPSetMyOrganizationAction.TypeName;

GPSetMyOrganizationAction.prototype.IsEnabled = function ()
{
    return iPersonalConfiguration.HasEditPermission && !iObject.IsNullOrUndefined(this.getSelectedOrganization());
}

GPSetMyOrganizationAction.prototype.ExecuteAction = function (menuItem)
{
    var stopwatch = new ISStopwatch();
    stopwatch.Start();
    ISTrace.TraceVerbose('[BEGIN] GPUpdateMyOrganizationMenuItemAction.ExecuteAction');

    // 選択されている組織を取得する
    var selectedOrganization = this.getSelectedOrganization();
    if (!selectedOrganization)
    {
        ISTrace.TraceWarning('[WARNING] GPUpdateMyOrganizationMenuItemAction.ExecuteAction: There is no organization selected.');
        return;
    }

    var ref = this;
    var service = new iPersonalConfigurationService()
    service.Load(function (config)
    {
        // 個人設定が取得できない場合
        // 更新処理が実施できないため、この時点で処理を中断
        if (!config)
        {
            var message = iResxResource.GetString('Menu.SetMyOrganizationMenuItemAction.FailedToAccessConfigListMessage');
            (new iNotifyer()).Notify(message, 5000);

            return;
        }

        // 現在のView取得
        var view = ref.getActiveOrganizationView();

        // 現在のViewに紐づいた組織情報を取得
        var myOrganizationSetting = null;
        var settings = config.GetSettings(function (setting)
        {
            return iString.Equals(setting.Category, iPersonalSetting.Category.MyOrganization, true) &&
                   iString.Equals(setting.Properties[GPMyOrganizationSetting.AttributeName.View], view.Info.Id);
        });
        if (settings && settings.length > 0)
        {
            myOrganizationSetting = settings[0];
        }

        // 情報がない場合は新規に作成
        var createNew = false;
        if (!myOrganizationSetting)
        {
            myOrganizationSetting = new GPMyOrganizationSetting();
            createNew = true;
        }

        // 所属組織情報を設定
        myOrganizationSetting.Properties[GPMyOrganizationSetting.AttributeName.View]  = view.Info.Id;
        myOrganizationSetting.Properties[GPMyOrganizationSetting.AttributeName.Field] = ref.Options['FieldName'];
        myOrganizationSetting.Properties[GPMyOrganizationSetting.AttributeName.Value] = selectedOrganization.Properties[ref.Options['FieldName']];

        // just for debugging
        myOrganizationSetting.Properties['DisplayName'] = selectedOrganization.Properties['EntityDisplayName'];

        // 新規作成の場合はconfigに追加
        if (createNew)
        {
            config.Settings.push(myOrganizationSetting);
        }

        // 設定情報を保存
        service.Save(config, function (items, result)
        {
            // エラー確認
            if (result && result.length > 0 && result[0].Error)
            {
                var message = iResxResource.GetString('Menu.SetMyOrganizationMenuItemAction.FailedToAccessConfigListMessage');
                (new iNotifyer()).Notify(message, 5000);
            }
            else
            {
                var message = iResxResource.GetString('Menu.SetMyOrganizationMenuItemAction.SaveCompletedMessage');
                (new iNotifyer()).Notify(message, 5000);
            }

            ISTrace.TraceVerbose('[END] GPUpdateMyOrganizationMenuItemAction.ExecuteAction (spent: ' + stopwatch.Stop() + ')');
        });
    });
}

GPSetMyOrganizationAction.prototype.getSelectedOrganization = function ()
{
    var selectedOrganization = null;
    var view = this.getActiveOrganizationView();
    if (view)
    {
        var items = view.GetSelectedItems();
        if (items && items.length > 0 &&
            iString.Equals(items[0].Properties['Type'], 'Group', true))
        {
            selectedOrganization = items[0];
        }
    }

    return selectedOrganization;
}

GPSetMyOrganizationAction.prototype.getActiveOrganizationView = function ()
{
    var view = null;
    var activeView = this.MenuItem.Menu.Action.View.ViewsTabPanel.SelectedTab.View;
    if (iString.Equals(activeView.Info.Class.Name, 'Infoshare.InfoCall.OrganizationView', true) ||
        iString.Equals(activeView.Info.Class.Name, 'Infoshare.GroupPicker.OrganizationView', true) ||
        iString.Equals(activeView.Info.Class.Name, 'Infoshare.InfoCall.ExtendedOrganizationView', true) ||
        iString.Equals(activeView.Info.Class.Name, 'Infoshare.GroupPicker.ExtendedOrganizationView', true))
    {
        view = activeView;
    }

    return view;
}
                                                
