Infoshare.GroupPicker.FavoriteService = function Infoshare$GroupPicker$FavoriteService()
{
    // スレッドセーフに初期化処理を実施できるように、Initialize関数を拡張
    iAsyncInitializableExtender.Extend(this);
}
GPFavoriteService = Infoshare.GroupPicker.FavoriteService;
GPFavoriteService.Instance = null;
GPFavoriteService.GetInstance = function()
{
    var instance = GPFavoriteService.Instance;
    if (!instance)
    {
        // ToDo: 初期化場所検討
        instance = new GPFavoriteService();
        GPFavoriteService.Instance = instance;
    }

    return instance;
}

GPFavoriteService.prototype = {
    PersonalConfigurationService: null,
    PersonalConfiguration: null,


    Load: function(callback)
    {
        var ref = this;
        this.ensurePersonalConfiguration(function()
        {
            // 個人構成からお気に入りの情報のみ取り出す
            var favorites = new Array();
            var settings = ref.PersonalConfiguration.GetSettingsByCategory(iPersonalSetting.Category.Favorite)
            for (var i = 0; i < settings.length; i++)
            {
                var favorite = GPFavorite.FromSetting(settings[i]);
                favorites.push(favorite);
            }

            callback(favorites);
        });
    },

    Save: function(favorites, callback)
    {
        var ref = this;
        this.ensurePersonalConfiguration(function()
        {
            var settings = new Array();

            // すべてのお気に入りを削除して新しい配列を作成
            // お気に入り以外を配列に詰める
            settings = ref.PersonalConfiguration.GetSettings(function (setting)
            {
                return !iString.Equals(setting.Category, iPersonalSetting.Category.Favorite, true);
            });

            // お気に入りを配列に追加
            settings = settings.concat(favorites);

            // 個人設定を更新
            ref.PersonalConfiguration.Settings = settings;
            ref.PersonalConfigurationService.Save(ref.PersonalConfiguration, function ()
            {
                // 新規作成時にはアイテムの再取得が必要（ItemIDがわからないと更新処理ができない）
                // そのため、アイテムを採取とするようにキャッシュを破棄
                if (!ref.PersonalConfiguration.Item.Id)
                {
                    ref.PersonalConfiguration = null;
                }

                callback();
            });
        });
    },

    Initialize: function(callback)
    {
        var instance = this;
        this.PersonalConfigurationService = new iPersonalConfigurationService();
        this.PersonalConfigurationService.Initialize(function()
        {
            callback();
        });
    },

    ensurePersonalConfiguration: function(callback)
    {
        if (!this.PersonalConfiguration)
        {
            var service = this;
            this.Initialize(function()
            {
                service.PersonalConfigurationService.Load(function(config)
                {
                    service.PersonalConfiguration = config;
                    callback();
                });
            });
        }
        else
        {
            setTimeout(callback, 1);
        }
    }
};


