GPFavorite.FromSetting = function(setting)
{
    var favorite = new GPFavorite();
    favorite.Properties = setting.Properties;

    // 基底クラスのコンストラクタで新しいIDが設定されるため、ここでも初期化が必要
    favorite.Id    = favorite.Properties[iPersonalSetting.AttributeName.Id];
    favorite.Type  = favorite.Properties[GPFavorite.AttributeName.Type];
    favorite.Title = favorite.Properties[GPFavorite.AttributeName.Title];
    favorite.Value = favorite.Properties[GPFavorite.AttributeName.Value];

    return favorite;
}

