{
    Infoshare.GroupPicker.FavoriteDialog.apply(this, arguments);
}

GPEditFavoriteDialog = Infoshare.GroupPicker.EditFavoriteDialog;
GPEditFavoriteDialog.prototype = new GPFavoriteDialog();
GPEditFavoriteDialog.prototype.DefaultWidth  = 300;
GPEditFavoriteDialog.prototype.DefaultHeight = 400;
GPEditFavoriteDialog.prototype.Favorite = null;

GPEditFavoriteDialog.prototype.OriginalRenderView = GPEditFavoriteDialog.prototype.RenderView;
GPEditFavoriteDialog.prototype.RenderView = function(entities)
{
    // View側の処理で更新されても問題にように、複製しておく
    this.View.Favorite = this.Favorite.Clone();   
    this.OriginalRenderView(entities);
}

GPEditFavoriteDialog.prototype.InitializeFooter = function ()
{
    if (!this.Option.FooterEnabled)
    {
        return;
    }

    // フッタ
    this.Footer = new iPanel(this.Style.FooterStyle);
    this.AppendChildControl(this.Footer);

    // OKボタン
    var okButton = new iButton(new GPActionDialogButtonStyle());
    okButton.Title = iResxResource.GetString('Favorite.EditFavoriteDialog.OKButton.Text');
    okButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OKClose, this));

    // キャンセル ボタン
    var cancelButton = new iButton(new GPActionDialogButtonStyle());
    cancelButton.Title = iResxResource.GetString('Favorite.EditFavoriteDialog.CancelButton.Text');
    cancelButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.CancelClose, this));
    
    // ボタンエリア
    this.FooterButtonArea = new iPanel(this.Style.FooterStyle.ButtonAreaStyle);
    this.FooterButtonArea.AppendChildControl(okButton);
    this.FooterButtonArea.AppendChildControl(cancelButton);
    this.Footer.AppendChildControl(this.FooterButtonArea);
};
GPEditFavoriteDialog.prototype.OKClose = function()
{
    var title       = this.View.TitleTextBox.GetValue();
    var memberCount = this.View.Entities.GetLength();
    if (ISString.IsNullOrEmpty(title) || memberCount <= 0)
    {
        var message = iResxResource.GetString('Favorite.EditFavoriteDialog.SaveVaridationMessage');
        alert(message);

        return;
    }

    this.Close(iDialogResult.ResultType.OK);
}
GPEditFavoriteDialog.prototype.OnClose = function(result)
{
    if (result.Result != iDialogResult.ResultType.OK)
    {
        return;
    }

    // お気に入り情報を更新
    // ※現時点ではフォルダータイプのみの対応
    this.Favorite.Properties[GPFavorite.AttributeName.Type]  = GPFavorite.Type.Folder;
    this.Favorite.Properties[GPFavorite.AttributeName.Title] = this.View.TitleTextBox.GetValue();

    // Viewで選択されているもののIdを取得して、セパレーターでつなげる
    var value = '';
    var keys = this.View.Entities.GetKeys();
    for (var i = 0; i < this.View.Entities.GetLength(); i++)
    {
        var key = keys[i];
        var entity = this.View.Entities.Get(key);

        value += entity.Properties[this.View.EntityId] + GPFavorite.ValueSeparator;
    }
    ISString.TrimEnd(value, GPFavorite.ValueSeparator);
    this.Favorite.Properties[GPFavorite.AttributeName.Value] = value;
}
                                         
