GPEditFavoriteView = Infoshare.GroupPicker.EditFavoriteView;
GPEditFavoriteView.TypeName = 'Infoshare.GroupPicker.EditFavoriteView';

GPEditFavoriteView.prototype = new Infoshare.GroupPicker.BaseFavoriteView();
GPEditFavoriteView.prototype.TypeName = GPEditFavoriteView.TypeName;
GPEditFavoriteView.prototype.Favorite = null;
GPEditFavoriteView.prototype.TitleTextBox = null;
GPEditFavoriteView.prototype.AddButton = null;
GPEditFavoriteView.prototype.RemoveButton = null;
GPEditFavoriteView.prototype.Render = function(parentElement)
{
    // 分割パネル
    var panel = new iSplitPanel(new GPActionDialogViewSplitPanel());
    panel.Style.Mode = iSplitPanelStyle.Mode.Horizontal;
    panel.Style.StretchOption = iPanelStyle.StretchOption.Both;

    // 分割パネル: ツールバー、タイトル、グリッドの3分割
    panel.Style.ContainerStyles = [new iPanelStyle(), new iPanelStyle(), new GPSearchViewGridContainerPanelStyle()];
    panel.Style.ContainerStyles[0].Size.Height = 35;
    panel.Style.ContainerStyles[1].Size.Height = 28;
        
    // ---------------------------------------------------------------
    //  ツールバー
    // ---------------------------------------------------------------
    var addButton = new iButton(new GPActionDialogButtonStyle());
    addButton.Title = iResxResource.GetString('Favorite.EditFavoriteView.AddButton.Text');
    addButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnAdd, this));
    this.AddButton = addButton;

    var removeButton = new iButton(new GPActionDialogButtonStyle());
    removeButton.Title = iResxResource.GetString('Favorite.EditFavoriteView.RemoveButton.Text');
    removeButton.Enabled = false;
    removeButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnRemove, this));
    this.RemoveButton = removeButton;

    panel.AppendChildControlForContainer(0, [addButton, removeButton]);
               
    // ---------------------------------------------------------------
    //  タイトル
    // ---------------------------------------------------------------
    var titleTextBox = new iTextBox();
    titleTextBox.Watermark = iResxResource.GetString('Favorite.EditFavoriteView.TitleTextBox.Watermark');
    if (this.Favorite && !ISString.IsNullOrEmpty(this.Favorite.Properties[GPFavorite.AttributeName.Title]))
    {
        titleTextBox.Value = this.Favorite.Properties[GPFavorite.AttributeName.Title];
    }
    this.TitleTextBox = titleTextBox;

    panel.AppendChildControlForContainer(1, titleTextBox);


    // 分割パネルレンダリング
    panel.Render(parentElement.Element);

    // ToDo: コントロールの調整ロジック検討
    // テキストボックスのサイズ調整
    this.TitleTextBox.GetElement().style.width = '390px';

    // ---------------------------------------------------------------
    //  グリッド
    // ---------------------------------------------------------------
    // Gridの親要素をキャッシュ
    this.GridParentElement = panel.Containers[2].GetElement();
    this.initializeGrid();

    if (this.Favorite && !ISString.IsNullOrEmpty(this.Favorite.Properties[GPFavorite.AttributeName.Value]))
    {
        var view = this;
        this.retrieveEntities(function(items){
            view.UpdateGrid(items);
        });
    }

    // サイズ調整のためリサイズ
    this.OnResize();
}
GPEditFavoriteView.prototype.OnSelectionChanged = function()
{
    var selectedEntities = this.GetSelectedEntities();
    if (selectedEntities && selectedEntities.length > 0)
    {
        this.RemoveButton.Enable();
    }
    else
    {
        this.RemoveButton.Disable();
    }
}
GPEditFavoriteView.prototype.OnAdd = function()
{
    var view = this;
    var dialog = GPDialog.CreatePickerDialog();
    dialog.EntitySelection = new iUserFieldEntitySelection();
    dialog.EntitySelection.AllowSecurityGroupSelection   = false;
    dialog.EntitySelection.AllowSharePointGroupSelection = false;
    dialog.AddCloseEvent(function(result)
    {
        if (result.Result != iDialogResult.ResultType.OK)
        {
            return;
        }

        // ToDo: view.Entitiesを更新しない方がよいか
        // 重複して選択されたものを除外して、グリッドに表示する
        for (var i = 0; i < result.SelectedEntities.length; i++)
        {
            var selectedEntity = result.SelectedEntities[i];
            if (view.Entities.Contains(selectedEntity.Properties[view.EntityId]))
            {
                continue;
            }

            view.Entities.Add(selectedEntity.Properties[view.EntityId], selectedEntity);
        }

        view.UpdateGrid(view.Entities.GetValues());
    });

    // モダンUIの場合、CoreCssが適用されずスタイルが崩れるため、CoreCssより作成したスタイルを適用する
    if (iVxContext.GetViewExperience() == iVxContext.ViewExperienceType.Modern)
    {
        dialog.Dialog.Style.EnableClassName = "is-gp-ModernDialog-FromCoreCSS";
    }

    GPDialog.Open(dialog);
}
GPEditFavoriteView.prototype.OnRemove = function()
{
    var selectedEntities = this.GetSelectedEntities();
    if (!selectedEntities || selectedEntities.length <= 0)
    {
        return;
    }

    // 削除前の警告を表示
    var message = iResxResource.GetString('Favorite.EditFavoriteView.DeleteItemConfamationMessage');
    if (!confirm(message))
    {
        return;
    }

    // ToDo: view.Entitiesを更新しない方がよいか
    // 選択されたものを除外して、グリッドを更新
    for (var i = 0; i < selectedEntities.length; i++)
    {
        var selectedEntity = selectedEntities[i];
        if (!this.Entities.Contains(selectedEntity.Properties[this.EntityId]))
        {
            continue;
        }

        this.Entities.Remove(selectedEntity.Properties[this.EntityId]);
    }

    this.UpdateGrid(this.Entities.GetValues());
    this.RemoveButton.Disable();
}
GPEditFavoriteView.prototype.retrieveEntities = function(callback)
{
    var ids = this.Favorite.Properties[GPFavorite.AttributeName.Value];
    ids = ISString.Split(ids, GPFavorite.ValueSeparator);

    var webUrl     = iVxContext.WebUrl;
    var list       = GPViewContext.DataSources.Get(0).DataSourceList; // ToDo: 適切なデータソースを選択
    var keys       = ids
    var fieldName  = this.EntityId;
    var fieldType  = 'Text';
    var viewFields = [];
    var service = this;
    iVxService.RetrieveItemsByKeys(webUrl, list, keys, fieldName, fieldType, viewFields, function(items)
    {
        callback(items);
    });
}
                                         
