GPFavoriteAction = Infoshare.GroupPicker.FavoriteAction;

GPFavoriteAction.TypeName = 'Infoshare.GroupPicker.FavoriteAction';
GPFavoriteAction.prototype = new GPHeaderAction();
GPFavoriteAction.prototype.TypeName = GPFavoriteAction.TypeName;
GPFavoriteAction.prototype.ViewInfo = null;
GPFavoriteAction.prototype.ViewDataSource = null;
GPFavoriteAction.prototype.ExecuteAction = function ()
{
    // ダイアログ初期化
    var dialog = GPDialog.CreateDialog(this.DialogTypeName);
    dialog.Option.AllowMaximize = false;

    // イベント接続
    var action = this;
    dialog.AddEvent(iDialog.EventName.Close, function(result)
    {
        if (result.Result != iDialogResult.ResultType.OK)
        {
            return;
        }

        // 選択されているお気に入りを取得
        var entities = dialog.View.GetSelectedEntities();

        // id配列を組み立てる
        // 複数のお気に入りの中に、同一の項目が含まれている可能性があるため、ディクショナリを利用して重複を排除
        var ids = new ISDictionary();
        for (var i = 0; i < entities.length; i++)
        {
            var entity = entities[i];

            // お気に入りフォルダの内容を取得
            var favIds = entity.Favorite.Properties[GPFavorite.AttributeName.Value];
            favIds = ISString.Split(favIds, GPFavorite.ValueSeparator);
            for (var j = 0; j < favIds.length; j++)
            {
                var favId = favIds[j];
                ids.Set(favId, favId);
            }
        }

        var webUrl     = iVxContext.WebUrl;
        var list       = GPViewContext.DataSources.Get(0).DataSourceList; // ToDo: 適切なデータソースを選択
        var keys       = ids.GetKeys();
        var fieldName  = 'EntityId';
        var fieldType  = 'Text';
        var viewFields = [];
        var service = this;
        iVxService.RetrieveItemsByKeys(webUrl, list, keys, fieldName, fieldType, viewFields, function(items)
        {
            // ToDo: 依存関係を検討
            action.View.Selector.AddCandidateInternal(items);
        });
    });

    dialog.Open();
};

