// -----------------------------------------------------------------------
//  SettingPage
// -----------------------------------------------------------------------
Infoshare.GroupPicker.Teams.SettingPage = function Infoshare$GroupPicker$Teams$SettingPage() { };
iTeamsSettingPage = Infoshare.GroupPicker.Teams.SettingPage;
iTeamsSettingPage.TypeName = 'Infoshare.GroupPicker.Teams.SettingPage';

iTeamsSettingPage.Mode = { New:  'New', 
                           Edit: 'Edit' };

iTeamsSettingPage.prototype = {
    TypeName: iTeamsSettingPage.TypeName,

    Teams: null,
    Context: null,

    Mode: null,
    TabNameValueTextBox: null,
    TabNameValueLabel: null,
    SiteUrlValueTextBox: null,

    Initialize: function (callback)
    {
        var ref = this;
        iTeams.IsInTeams(function (isInTeams)
        {
            if (isInTeams)
            {
                ref.Teams = new iTeams();

                var teams = ref.Teams;
                teams.Initialize(function () {
                    // コンテキストを取得して、画面描画
                    teams.GetContext(function (context) {
                        ref.Context = context;
                        ref.Mode    = iString.IsNullOrEmpty(context.EntityId) ? iTeamsSettingPage.Mode.New : iTeamsSettingPage.Mode.Edit;

                        if (ref.Mode == iTeamsSettingPage.Mode.New)
                        {
                            var tabName = 'InfoCall';
                            var siteUrl = ref.extractSiteUrl(location.href);
                            ref.InitializeControl(tabName, siteUrl);

                            if (iType.GetType(callback) == iType.BuiltinType.Function)
                            {
                                callback();
                            }
                        }
                        else
                        {
                            teams.GetTabInstances(function (tabs) {
                                // entityId を手掛かりに選択されているタブを特定する
                                var selectedTab = null;
                                for (var i = 0; i < tabs.length; i++)
                                {
                                    var tab = tabs[i];
                                    if (iString.Equals(context.EntityId, tab.EntityId, true))
                                    {
                                        selectedTab = tab;
                                        break;
                                    }
                                }

                                var tabName = selectedTab.TabName;
                                var siteUrl = ref.extractSiteUrl(selectedTab.Url);
                                ref.InitializeControl(tabName, siteUrl);

                                if (iType.GetType(callback) == iType.BuiltinType.Function)
                                {
                                    callback();
                                }
                            });
                        }
                    });

                    // 設定保存時の関数を設定
                    teams.Settings.RegisterOnSaveHandler(iFunction.CreateDelegate(ref.OnSave, ref));

                    // 保存ボタンの有効化
                    teams.Settings.SetValidityState(true);
                });
            }
            else
            {
                var message = 'iTeamsSettingPage.Initialize - Failed to initialize setting page, since this page is not opend by Teams.';
                ISTestTrace.TraceError(message);
            }
        });
    },

    InitializeControl: function (tabName, siteUrl)
    {
        // レイアウト用パネル
        var panel = new iPanel();
        panel.Attributes.Add('style', 'padding: 8px;');
        panel.Style.StretchOption = iPanelStyle.StretchOption.Horizontal;

        // タブ名: 項目ラベル
        var tabNameLabel = new iLabel();
        tabNameLabel.Text = iResxResource.GetString('Teams.AppSettingPage.TabName');
        panel.AppendChildControl(tabNameLabel);
        panel.AppendChildControl(new iLiteral(null, '<br />'));

        var tabNameValueControl = null;
        if (this.Mode == iTeamsSettingPage.Mode.New)
        {
            // タブ名: テキストボックス
            var tabNameValueTextBox = new iTextBox();
            tabNameValueTextBox.Value = tabName;
            tabNameValueTextBox.Attributes.Add('style', 'width: 100%;');

            this.TabNameValueTextBox = tabNameValueTextBox;
            tabNameValueControl = tabNameValueTextBox;
        }
        else if (this.Mode == iTeamsSettingPage.Mode.Edit)
        {
            // タブ名: ラベル
            var tabNameValueLabel = new iLabel();
            tabNameValueLabel.Text = tabName;

            this.TabNameValueLabel = tabNameValueLabel;
            tabNameValueControl = tabNameValueLabel;
        }
        panel.AppendChildControl(tabNameValueControl);
        panel.AppendChildControl(new iLiteral(null, '<br /><br />'));


        // サイト URL: 項目ラベル
        var siteUrlLabel = new iLabel();
        siteUrlLabel.Text = iResxResource.GetString('Teams.AppSettingPage.SiteUrl');
        panel.AppendChildControl(siteUrlLabel);
        panel.AppendChildControl(new iLiteral(null, '<br />'));

        // サイト URL: テキストボックス
        var siteUrlValueTextBox = new iTextBox();
        siteUrlValueTextBox.Value = siteUrl;
        siteUrlValueTextBox.Attributes.Add('style', 'width: 100%;');
        this.SiteUrlValueTextBox = siteUrlValueTextBox;
        panel.AppendChildControl(siteUrlValueTextBox);
        panel.AppendChildControl(new iLiteral(null, '<br />'));

        // サイト URL: 説明
        var siteUrlDescriptionLabel = new iLabel();
        siteUrlDescriptionLabel.Text = iResxResource.GetString('Teams.AppSettingPage.SiteUrlDescription');
        siteUrlDescriptionLabel.Attributes.Add('style', 'color: gray;');
        panel.AppendChildControl(siteUrlDescriptionLabel);
        panel.AppendChildControl(new iLiteral(null, '<br />'));


        panel.Render();
    },

    OnSave: function(saveEvent)
    {
        // EntityId
        // タブ識別のため一意のIDを指定する
        var entityId = this.Context.EntityId;
        if (iString.IsNullOrEmpty(entityId))
        {
            entityId = 'InfoCall_' + iGuid.New();
        }

        // タブ名
        var tabName = '';
        if      (this.Mode == iTeamsSettingPage.Mode.New)  { tabName = this.TabNameValueTextBox.GetValue(); }
        else if (this.Mode == iTeamsSettingPage.Mode.Edit) { tabName = this.TabNameValueLabel.Text; }

        // サイト URL
        var siteUrl = this.SiteUrlValueTextBox.GetValue();
        siteUrl = this.extractSiteUrl(siteUrl);
                
        // アドレス帳 URL
        var addressBookUrl = iString.TrimEnd(siteUrl, '/')
                            + '/InfoshareProductLibrary/Sources/Infoshare.InfoCall/InfoCall.aspx'
                            + '?FinderClass=Infoshare.GroupPicker.TeamsFinder';
        addressBookUrl = this.insertTeamsLogon(addressBookUrl);

        // 設定
        var settings = { entityId:             entityId,
                         suggestedDisplayName: tabName,
                         contentUrl:           addressBookUrl,
                         websiteUrl:           addressBookUrl };
        this.Teams.Settings.SetSettings(settings);

        // ToDo: 無条件に通知を送ってよいのか確認
        // 完了通知
        saveEvent.notifySuccess();
        //saveEvent.notifyFailure();
    },

    extractSiteUrl: function (url)
    {
        var siteUrl = '';
        try
        {
            var plainUrl = this.removeTeamsLogon(url);
            var uri = iUri.Parse(plainUrl);
            for (;;)
            {
                // サブ サイト コレクションのトップ レベル サイト
                if (!iString.IsNullOrEmpty(uri.Authority) &&
                    iString.StartsWith(uri.Path, '/sites/', true))
                {
                    siteUrl = uri.Scheme + '://' + uri.Authority
                            + '/' + uri.Path.split('/')[1]  // 管理パス(sites)
                            + '/' + uri.Path.split('/')[2]; // サイト名

                    break;
                }

                // ルート サイト コレクションのトップ レベル サイト
                if (!iString.IsNullOrEmpty(uri.Authority))
                {
                    siteUrl = uri.Scheme + '://' + uri.Authority;

                    break;
                }

                break;
            }
        }
        catch (e)
        {
            var message = iString.Format('iTeamsSettingPage.extractSiteUrl - Failed to extract site url from specified url. (url: {0} | error: {1}, {2})',
                                         url, e.name, e.message);
            ISTestTrace.TraceError(message);
        }

        return siteUrl;
    },

    insertTeamsLogon: function (url)
    {
        var insertedUrl = '';
        try
        {
            // 重複挿入を避ける
            insertedUrl = this.removeTeamsLogon(url);

            // Authrity の直後にログオン用のURLを挿入し、以下の書式のURLを生成する
            // https://tenantName.SharePoint.com/_layouts/15/TeamsLogon.aspx?spfx=true&dest=%2Fsites%2FsiteName%2FLibrary%2FFolder%2Fpage.aspx%3Fkey1%3Dval1
            var uri = iUri.Parse(insertedUrl);
            insertedUrl = uri.Scheme + '://' + uri.Authority
                        + '/_layouts/15/teamslogon.aspx?spfx=true&dest='
                        + (iString.IsNullOrEmpty(uri.Path)     ? '' : iUri.EscapeComponent(uri.Path))
                        + (iString.IsNullOrEmpty(uri.Query)    ? '' : iUri.EscapeComponent(uri.Query))
                        + (iString.IsNullOrEmpty(uri.Fragment) ? '' : iUri.EscapeComponent(uri.Fragment));
        }
        catch (e)
        {
            var message = iString.Format('iTeamsSettingPage.insertTeamsLogon - Failed to insert teams logon url to specified url. (url: {0} | error: {1}, {2})',
                                         url, e.name, e.message);
            ISTestTrace.TraceError(message);
        }

        return insertedUrl;
    },

    removeTeamsLogon: function(url)
    {
        var removedUrl = url;
        try
        {
            if (iString.Contains(url, '/_layouts/15/TeamsLogon.aspx', true))
            {
                // teamslogon.aspx を含場合、
                // ホストアドレスと dest パラメータの値のみを取り出して結合することで、TeamsLogon.aspx を経由しないURLを生成する
                // 【例】
                // https://tenantName.SharePoint.com/_layouts/15/TeamsLogon.aspx?spfx=true&dest=%2Fsites%2FsiteName%2FLibrary%2FFolder%2Fpage.aspx%3Fkey1%3Dval1
                // https://tenantName.SharePoint.com/_layouts/15/teamslogon.aspx?dest=%2Fsites%2FsiteName%2FLibrary%2FFolder%2Fpage.aspx%3Fkey1%3Dval1&spfx=true
                
                var uri   = iUri.Parse(url);
                var query = iUriParameter.Parse(uri.Query);
                var destValue = query.Get('dest');
                destValue = iUri.UnescapeComponent(destValue);

                removedUrl = uri.Scheme + '://' + uri.Authority
                           + '/' + iString.TrimStart(destValue, '/');
            }
        }
        catch (e)
        {
            var message = iString.Format('iTeamsSettingPage.removeTeamsLogon - Failed to remove teams logon url to specified url. (url: {0} | error: {1}, {2})',
                                         url, e.name, e.message);
            ISTestTrace.TraceError(message);
        }

        return removedUrl;
    }
};
                           
