// -----------------------------------------------------------------------
//  PrintAddress
//
// そろそろ真面目に、HTMLで帳票を描く話をしようか
// https://qiita.com/cognitom/items/d39d5f19054c8c8fd592
//
// 印刷用CSSのメモ
// https://chaika.hatenablog.com/entry/2017/12/13/090000
// -----------------------------------------------------------------------
Infoshare.GroupPicker.PrintAddressView = function InfoInfoshare$GroupPicker$PrintAddressView()
{
    this.ButtonControlPosition = GPPrintAddressView.DefaultButtonControlPosition;

    // スレッドセーフに初期化処理を実施できるように、Initialize関数を拡張
    iAsyncInitializableExtender.Extend(this);
}
GPPrintAddressView = Infoshare.GroupPicker.PrintAddressView;
GPPrintAddressView.TypeName = 'Infoshare.GroupPicker.PrintAddressView';
GPPrintAddressView.ButtonControlPosition = { Right: 'right',
                                             Left:  'left' };
GPPrintAddressView.DefaultButtonControlPosition = GPPrintAddressView.ButtonControlPosition.Right;
GPPrintAddressView.prototype = {
    ContentsAreaId: '',
    ControlsAreaId: '',
    ControlsAreaClass: 'is-nonPrintable',

    Controls: null,
    Entities: null,

    EditButton: null,
    PreviewButton: null,
    PrintButton: null,
    CancelButton: null,

    ButtonControlPosition: GPPrintAddressView.DefaultButtonControlPosition,


    Initialize: function(callback)
    {
        // ID初期化
        this.ContentsAreaId = 'iPrintContents_' + iGuid.New();
        this.ControlsAreaId = 'iPrintControls_' + iGuid.New();

        // テンプレート読み込み
        var templateUrl = '../../Template/Template.PrintAddress.aspx';

        var view = this;
        var file = new iWebFile();
        file.Download(templateUrl, function (result, contents, status)
        {
            view.renderView(contents, callback);
        });
    },

    GetEntity: function(id)
    {
        var entity = null;
        if (id == 'Me')
        {
            entity = window.opener.GPViewContext.CurrentUserEntity;
        }
        else
        {
            var actionId = iQueryString.GetValue(GPPrintAddressAction.UrlParameter.ActionId);
            var action = window.opener.GPAction.GetInstance(actionId);

            entity = action.SelectedEntities.Get(id);
        }

        return entity;
    },

    renderView: function(contents, callback)
    {
        // ---------------------------------------------------------------
        // 基本構造を描画
        // ---------------------------------------------------------------
        var builder = new Array();
        builder[builder.length] = "<div id='" + this.ContentsAreaId + "'>";
        builder[builder.length] = '</div>';
        builder[builder.length] = "<div id='"    + this.ControlsAreaId + "' ";
        builder[builder.length] =      "class='" + this.ControlsAreaClass + "' ";
        builder[builder.length] =      "style='height: 40px; margin-right: 10px;' >";
        builder[builder.length] = '</div>';
        document.body.innerHTML = builder.join('');

        // レンダリングを待って各コントロールを描画
        var view = this;
        setTimeout(function ()
        {
            view.renderContents(contents);
            view.renderControls();

            if (typeof callback == 'function')
            {
                callback();
            }
        }, 1);
    },

    renderContents: function (contents)
    {
        // ---------------------------------------------------------------
        // コンテンツ領域描画
        // ---------------------------------------------------------------
        var doc = iXml.LoadXml(contents);
        var element = iXml.GetDocumentElement(doc);

        var style = iXml.SelectNodeByPath(element, 'head/style');
        var body = iXml.SelectNodeByPath(element, 'body');

        var area = ISDomAccessor.GetElement(this.ContentsAreaId);
        area.innerHTML += iXml.GetOuterXml(style) + iXml.GetInnerXml(body);

        // ---------------------------------------------------------------
        // Placeholder更新
        // ---------------------------------------------------------------
        this.Controls = new iDictionary();
        var placeholders = document.getElementsByTagName('placeholder');
        for (var i = 0; i < placeholders.length; i++)
        {
            var placeholder = new GPPlaceholderControl(placeholders[i]);
            var control = GPPrintControl.Create(this, placeholder);
            if (control)
            {
                control.Render();

                this.Controls.Add(control.GetId(), control);
            }
        }
    },

    renderControls: function()
    {
        // ---------------------------------------------------------------
        // コントロール領域描画
        // ---------------------------------------------------------------
        var cancelButton = new iButton();
        cancelButton.Title = iResxResource.GetString('Print.View.CancelButtonText');
        cancelButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnCancel, this));
        this.CancelButton = cancelButton;

        var printButton = new iButton();
        printButton.Title = iResxResource.GetString('Print.View.PrintButtonText');
        printButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnPrint, this));
        this.PrintButton = printButton;

        var previewButton = new iButton();
        previewButton.Title = iResxResource.GetString('Print.View.PreviewButtonText');
        previewButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnPreview, this));
        this.PreviewButton = previewButton;

        var editButton = new iButton();
        editButton.Title = iResxResource.GetString('Print.View.EditButtonText');
        editButton.AddEvent(iControl.DomEventName.Click, ISFunction.CreateDelegate(this.OnEdit, this));
        this.EditButton = editButton;

        var panel = new iPanel();
        if (this.ButtonControlPosition == GPPrintAddressView.ButtonControlPosition.Left)
        {
            panel.AppendChildControl(this.EditButton);
            panel.AppendChildControl(this.PreviewButton);
            panel.AppendChildControl(this.PrintButton);
            panel.AppendChildControl(this.CancelButton);
            panel.Render(this.ControlsAreaId);
        }
        else if (this.ButtonControlPosition == GPPrintAddressView.ButtonControlPosition.Right)
        {
            panel.AppendChildControl(this.CancelButton);
            panel.AppendChildControl(this.PrintButton);
            panel.AppendChildControl(this.PreviewButton);
            panel.AppendChildControl(this.EditButton);
            panel.Render(this.ControlsAreaId);

            this.CancelButton.GetElement().style.float  = this.ButtonControlPosition;
            this.PrintButton.GetElement().style.float   = this.ButtonControlPosition;
            this.PreviewButton.GetElement().style.float = this.ButtonControlPosition;
            this.EditButton.GetElement().style.float    = this.ButtonControlPosition;
        }

        panel.GetElement().style.paddingLeft = '9px';
        this.EditButton.Hide();
    },

    changeControlMode: function(mode)
    {
        for (var i = 0; i < this.Controls.GetLength() ; i++)
        {
            var control = this.Controls.Get(i);
            control.ChangeMode(mode);
        }
    },

    // ToDo: isVaridのほうが適切か
    // ToDo: 複数一気に結果を処理する方法を考える
    validateControls: function()
    {
        var result = new GPPrintControlValidateResult(true);
        for (var i = 0; i < this.Controls.GetLength(); i++)
        {
            var control = this.Controls.Get(i);
            var ret = control.Validate();
            if (!ret.Succeeded)
            {
                result = ret;
                break;
            }
        }

        return result;
    },

    OnEdit: function()
    {
        this.changeControlMode(GPPrintControl.Mode.Screen);

        this.PreviewButton.Show();
        this.EditButton.Hide();
    },

    OnPreview: function()
    {
        this.changeControlMode(GPPrintControl.Mode.Print);

        this.PreviewButton.Hide();
        this.EditButton.Show();
    },

    OnPrint: function()
    {
        var result = this.validateControls();
        if (!result.Succeeded)
        {
            alert(result.Message);
            return;
        }

        this.OnPreview();
        window.print();
    },

    OnCancel: function()
    {
        window.close();
    }
};
