Infoshare.GroupPicker.PlaceholderControl = function InfoInfoshare$GroupPicker$PlaceholderControl(element)
{
    this.Element = element;
}
GPPlaceholderControl = Infoshare.GroupPicker.PlaceholderControl;
GPPlaceholderControl.Type = { Label: 'Label',
                              Text:  'Text',
                              Note:  'Note' };
GPPlaceholderControl.DataType = { Date:   'Date',
                                  Object: 'Object' };
GPPlaceholderControl.prototype = {
    Element: null,

    GetId: function()
    {
        return this.getPlaceholderAttribute('id');
    },

    GetType: function()
    {
        var type = null;
        var typeText = this.getPlaceholderType();
        if      (iString.Equals(typeText, GPPlaceholderControl.Type.Label, true)) { type = GPPlaceholderControl.Type.Label; }
        else if (iString.Equals(typeText, GPPlaceholderControl.Type.Text, true))  { type = GPPlaceholderControl.Type.Text; }
        else if (iString.Equals(typeText, GPPlaceholderControl.Type.Note, true))  { type = GPPlaceholderControl.Type.Note; }

        return type;
    },

    getPlaceholderControlClass: function ()
    {
        return this.getPlaceholderAttribute('controlClass');
    },

    getPlaceholderType: function()
    {
        return this.getPlaceholderAttribute('type');
    },

    getPlaceholderData: function ()
    {
        return this.getPlaceholderAttribute('data');
    },

    getPlaceholderFormat: function ()
    {
        return this.getPlaceholderAttribute('format');
    },

    getPlaceholderClass: function ()
    {
        return this.getPlaceholderAttribute('class');
    },

    getPlaceholderStyle: function ()
    {
        return this.getPlaceholderAttribute('style');
    },

    getPlaceholderAttribute: function(key)
    {
        var value = '';
        switch(key)
        {
            //case 'class': value = this.Element.className; break;
            default:      value = this.Element.getAttribute(key); break;
        }

        return value;
    }
};


// -----------------------------------------------------------------------
//  PrintControl
// -----------------------------------------------------------------------
Infoshare.GroupPicker.PrintControl = function InfoInfoshare$GroupPicker$PrintControl(view, placeholder)
{
    this.Mode = GPPrintControl.Mode.Screen;

    this.View        = view;
    this.Placeholder = placeholder;
}
GPPrintControl = Infoshare.GroupPicker.PrintControl;
GPPrintControl.Mode = { Screen: 'Screen',
                        Print:  'Print' };
GPPrintControl.Create = function (view, placeholder)
{
    var control = null;
    var className = placeholder.getPlaceholderControlClass();
    if (className)
    {
        control = iClass.New(className);
        control.Mode        = GPPrintControl.Mode.Screen;
        control.View        = view;
        control.Placeholder = placeholder;
    }
    else
    {
        var type = placeholder.GetType();
        switch(type)
        {
            case GPPlaceholderControl.Type.Label: control = new GPPrintLabelControl(view, placeholder); break;
            case GPPlaceholderControl.Type.Text:  control = new GPPrintTextControl(view, placeholder);  break;
            case GPPlaceholderControl.Type.Note:  control = new GPPrintNoteControl(view, placeholder);  break;
        }
    }

    return control;
}

GPPrintControl.prototype = {
    Mode: null,

    View: null,
    Placeholder: null,

    ScreenElement: null,
    PrintElement: null,

    GetId: function()
    {
        return this.Placeholder.GetId();
    },

    Render: function()
    {
        this.ensureElements();
        this.dataBind();

        this.Placeholder.Element.style.display = 'none';
        this.ChangeMode(this.Mode);
    },

    ChangeMode: function(mode)
    {
        if (this.ScreenElement && this.PrintElement)
        {
            if (mode == GPPrintControl.Mode.Screen)
            {
                this.ScreenElement.style.display = '';
                this.PrintElement.style.display  = 'none'
            }
            else if (mode == GPPrintControl.Mode.Print)
            {
                this.ScreenElement.style.display = 'none';
                this.PrintElement.style.display  = ''
            }
        }
    },

    GetValue: function()
    {
        // 各継承クラスで実装
    },

    SetValue: function()
    {
        // 各継承クラスで実装
    },

    Validate: function()
    {
        // 各継承クラスで実装
        return new GPPrintControlValidateResult(true);
    },

    ensureElements: function()
    {
        // 各継承クラスで実装
    },

    dataBind: function()
    {
        this.SetValue(this.getData());
    },

    getData: function()
    {
        var data = '';
        var dataType = this.Placeholder.getPlaceholderData();
        var format = this.Placeholder.getPlaceholderFormat();
        if (dataType == GPPlaceholderControl.DataType.Date)
        {
            data = iDate.Format(new Date(), format);
        }
        else if (dataType == GPPlaceholderControl.DataType.Object)
        {
            var target    = format.split('.')[0];
            var attribute = format.split('.')[1];

            var entity = null;
            if (target == 'Destination')
            {
                var destinationId = iQueryString.GetValue(GPPrintAddressAction.UrlParameter.DestinationId);
                entity = this.View.GetEntity(destinationId);
            }
            else if (target == 'Me')
            {
                entity = this.View.GetEntity('Me');
            }

            if (entity)
            {
                if (!iObject.IsNullOrUndefined(entity.Properties[attribute]))
                {
                    data = entity.Properties[attribute];
                }
            }
        }

        return data;
    },

    applyStyles: function(element)
    {
        var cssClass = this.Placeholder.getPlaceholderClass();
        if (cssClass) { element.setAttribute('class', cssClass); }

        var style = this.Placeholder.getPlaceholderStyle();
        if (style) { element.setAttribute('style', style); }

        var rows = this.Placeholder.getPlaceholderAttribute('rows');
        if (rows) { element.setAttribute('rows', rows); }
    },

    insertElement: function(element)
    {
        var parent = ISDomAccessor.GetParentElement(this.Placeholder.Element);
        parent.insertBefore(element, this.Placeholder.Element);
    }
};

// -----------------------------------------------------------------------
//  PrintControlValidateResult
// -----------------------------------------------------------------------
Infoshare.GroupPicker.PrintControlValidateResult = function InfoInfoshare$GroupPicker$PrintControlValidateResult(succeeded, message)
{
    this.Succeeded = succeeded;
    this.Message   = iString.IsNullOrEmpty(message) ? '' : message;
}
GPPrintControlValidateResult = Infoshare.GroupPicker.PrintControlValidateResult;
GPPrintControlValidateResult.prototype = {
    Succeeded: true,
    Message: ''
}

