// -----------------------------------------------------------------------
//  PrintTextControl
// -----------------------------------------------------------------------
Infoshare.GroupPicker.PrintTextControl = function InfoInfoshare$GroupPicker$PrintTextControl(view, placeholder)
{
    Infoshare.GroupPicker.PrintControl.apply(this, arguments);
}
GPPrintTextControl = Infoshare.GroupPicker.PrintTextControl;
GPPrintTextControl.prototype = new Infoshare.GroupPicker.PrintControl();
GPPrintTextControl.prototype.GetValue = function ()
{
    return this.ScreenElement.value;
}
GPPrintTextControl.prototype.SetValue = function (value)
{
    this.ScreenElement.value = value;
    this.dataSync();
}
GPPrintTextControl.prototype.ensureElements = function ()
{
    // -------------------------------------------------------------------
    // 編集用コントロール
    // -------------------------------------------------------------------
    var editable = document.createElement('input');
    editable.setAttribute('type', 'text');

    this.applyStyles(editable);
    this.insertElement(editable);

    this.ScreenElement = editable;

    // -------------------------------------------------------------------
    // 印刷用コントロール
    // -------------------------------------------------------------------
    var printable = document.createElement('div');
    this.applyStyles(printable);
    this.insertElement(printable);

    this.PrintElement = printable;

    // 高さ調整
    //var height = ISDomAccessor.GetHeight(this.ScreenElement);
    //var height = ISDomAccessor.GetOuterHeight(this.ScreenElement);
    var height = ISDomAccessor.GetInnerHeight(this.ScreenElement);
    ISDomAccessor.SetHeight(this.PrintElement, height);

    // -------------------------------------------------------------------
    // イベント
    // -------------------------------------------------------------------
    ISDomAccessor.AttachEvent(this.ScreenElement, 'blur', iFunction.CreateDelegate(this.dataSync, this));
}
GPPrintTextControl.prototype.dataSync = function()
{
    var value = this.ScreenElement.value;
    if (iString.Contains(value, '\r\n')) { value = iString.Replace(value, '\r\n', '<br />'); }
    if (iString.Contains(value, '\r'))   { value = iString.Replace(value, '\r',   '<br />'); }
    if (iString.Contains(value, '\n'))   { value = iString.Replace(value, '\n',   '<br />'); }

    this.PrintElement.innerHTML = value;
}


