//  PrintAddressAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.PrintAddressAction = function InfoInfoshare$GroupPicker$PrintAddressAction()
{
    Infoshare.GroupPicker.Action.apply(this, arguments);

    this.ValidateInfo.Set('IsUser',
                          { 'ValidateFunction': this.IsUser,
                            'InValidMessageKey': 'GPPrintAddress.Alert.User',
                            'Valid': true });

    this.SkipActionDialog = true;
    this.SkipActionWhenNoValidEntity = true;

    this.ActionButtonInfo = {
        'Type': 'Text',
        'Text': '' // コンストラクタの初期化タイミングではActionInfoが取得できない為CreateButtonのタイミングで設定する
    };
}
GPPrintAddressAction = Infoshare.GroupPicker.PrintAddressAction;
GPPrintAddressAction.TypeName = 'Infoshare.GroupPicker.PrintAddressAction';
GPPrintAddressAction.UrlParameter = { ViewClass:     'ViewClass',
                                      ActionId:      'ActionId',
                                      DestinationId: 'DestinationId' };
GPPrintAddressAction.prototype = new GPAction();
GPPrintAddressAction.prototype.SelectedEntities = null;
GPPrintAddressAction.prototype.ExecuteAction = function (entities)
{
    var baseUrl = iString.Format('{0}/Infoshare.InfoCall/Print.aspx', iString.TrimEnd(GPContext.SourcesPath, '/'));

    var option = new iNavigationOption();
    option.Width           = 850;
    option.EnableMenubar   = false;
    option.EnableLocation  = false;
    option.EnableToolbar   = false;
    option.EnableStatusbar = false;
    option.Resizable       = true;
    option.Scrollable      = true;

    var options = new Array();
    this.SelectedEntities = new iDictionary();
    for (var i = 0; i < entities.length; i++)
    {
        var entity = entities[i];
        this.SelectedEntities.Add(entity.Id, entity);

        // /Print.aspx?ViewClass=[ViewClassName]&ActionId=[ActionId]&DestinationId=[DestinationId]
        var url = iString.Format('{0}?{1}={2}&{3}={4}&{5}={6}',
                                 baseUrl,
                                 GPPrintAddressAction.UrlParameter.ViewClass, GPPrintAddressView.TypeName,
                                 GPPrintAddressAction.UrlParameter.ActionId, this.InstanceId,
                                 GPPrintAddressAction.UrlParameter.DestinationId, entity.Id);

        options.push(new iNavigationBulkOpenOption(url, '_blank', option));
    }

    iNavigation.BulkOpenWindow(options);
}
GPPrintAddressAction.prototype.IsUser = function (entities)
{
    var valid = false;
    for (var i = 0; i < entities.length; i++)
    {
        var isUser = false;

        var entity = entities[i];
        if (iString.Equals(entity.Properties.Type, 'user', true) &&
            !(iString.Equals(entity.Properties.SubType, 'RoomMailbox', true) ||
              iString.Equals(entity.Properties.SubType, 'EquipmentMailbox', true)))
        {
            isUser = true;
            valid = true;
        }

        // 複数のValidatorからフラグ付けされる為、すでに無効と判断されているエンティティはフラグを更新しない
        if (entity.Valid === false)
        {
            continue;
        }

        entity.Valid = isUser;
    }

    if (!valid)
    {
        alert(iResxResource.GetString('Print.Action.NoUserSelectedMessage'));
    }

    return valid;
};
													
															
