Infoshare.GroupPicker.OrganizationManagement.MasterListFormExtender = function Infoshare$GroupPicker$OrganizationManagement$MasterListFormExtender()
{
    Infoshare.SharePoint.ListFormExtender.apply(this, arguments);
}
GPMasterListFormExtender = Infoshare.GroupPicker.OrganizationManagement.MasterListFormExtender;
GPMasterListFormExtender.TypeName = 'Infoshare.GroupPicker.OrganizationManagement.MasterListFormExtender';
GPMasterListFormExtender.ExtenderType = iBehaviorExtender.ExtenderType.Page;
GPMasterListFormExtender.ClassInfo = null;

GPMasterListFormExtender.FormType = {
    EntityMaster     : "EntityMaster",
    Permissionmaster : "Permissionmaster"
}

GPMasterListFormExtender.FieldExtensionType = {
    Text:	  "Text",
    Picker:	  "Picker",
    Hidden:	  "Hidden",
    Select:	  "Select",
	CheckBox: "CheckBox",
	Note:     "Note"	
}
GPMasterListFormExtender.FakeControlSuffix = "_FakeControl";

GPMasterListFormExtender.Initialize = function()
{
    iBehaviorExtender.AddExtender(Infoshare.SharePoint.PageExtender, GPMasterListFormExtender.TypeName, GPMasterListFormExtender.TypeName);    
}
GPMasterListFormExtender.CanExtend = function()
{
    // 機能が無効な場合には拡張しない
    if (typeof GPSettings == "undefined" ||
        !GPSettings.OrganizationManagementFeature)
    {
        ISTrace.TraceWarning('[CANCELLED] GPMasterListFormExtender.Extend（Organization Management feature is inactive）');
        return false;
    }

    return GPMasterListFormExtender.IsEntityMasterForm() ||
           GPMasterListFormExtender.IsPermissionMasterForm();
}

GPMasterListFormExtender.IsEntityMasterForm = function () 
{
    return iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.EntityMasterForm.NewForm) ||
           iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.EntityMasterForm.EditForm);
}

GPMasterListFormExtender.IsPermissionMasterForm = function () 
{
    return iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.PermissionMasterForm.NewForm) ||
           iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.PermissionMasterForm.EditForm);
}

GPMasterListFormExtender.IsNewForm = function () 
{
    return iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.EntityMasterForm.NewForm) ||
           iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.PermissionMasterForm.NewForm);
}

GPMasterListFormExtender.IsEditForm = function () 
{
    return iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.EntityMasterForm.EditForm) ||
           iSPListFormExtender.IsTargetForm(GPMasterListFormExtender.FormFileName.PermissionMasterForm.EditForm);
}

GPMasterListFormExtender.HideForm = function()
{
    // 要素の非表示
    var bodyContainer = document.getElementById("s4-bodyContainer");
    if (bodyContainer)
    {
        bodyContainer.style.display = "none";
    }

    // スクリーンのブロック
    iScreenBlockerUtility.Show();

    // リボンを非表示にする
    GPMasterListFormExtender.HideRibbonMenue();
}

GPMasterListFormExtender.ShowForm = function()
{
    // 要素の表示
    var bodyContainer = document.getElementById("s4-bodyContainer");
    if (bodyContainer)
    {
        bodyContainer.style.display = "";
    }

    // スクリーンブロックの解除
    iScreenBlockerUtility.Hide();

    // リサイズ
    GPMasterListFormExtender.ResizeForm();
}

GPMasterListFormExtender.HideRibbonMenue = function ()
{
    // リボンを非表示
    var ribbonElm = document.getElementById("s4-ribbonrow");
    ribbonElm.style.display = "none";

    // フォームのリサイズ
    GPMasterListFormExtender.ResizeForm();
}

GPMasterListFormExtender.ResizeForm = function ()
{
    // 要素の非表示
    var bodyContainer = document.getElementById("s4-bodyContainer");
    if (bodyContainer)
    {
        // リサイズ時のサイズずれ問題対応
        bodyContainer.style.width = "";
    }

    // SharePointがIframeのダイアログを開く際にキャッシュするオブジェクトのリサイズ関数を呼ぶ
    var frameElm = window.frameElement;
    if (frameElm)
    {
        frameElm.autoSize();
    }  
}

// 編集フォームの編集者情報を非表示にする
GPMasterListFormExtender.HideEditInfoBlock = function()
{
    var editBlock1 = document.getElementById("onetidinfoblock1");
    if (editBlock1)
    {
        editBlock1.parentElement.parentElement.parentElement.style.display = "none";
    }
}

GPMasterListFormExtender.FormFileName = {
    // エンティティマスタリスト定義
    EntityMasterForm: {
        NewForm     : 'SupplementMaster/NewForm.aspx',
        EditForm    : 'SupplementMaster/EditForm.aspx',
        DisplayForm : 'SupplementMaster/DispForm.aspx'
    },
    // 権限管理マスタリスト定義
    PermissionMasterForm: {
        NewForm     : 'Permissions/NewForm.aspx',
        EditForm    : 'Permissions/EditForm.aspx',
        DisplayForm : 'Permissions/DispForm.aspx'
    }
}

GPMasterListFormExtender.DataType = {
    Base: "Base",
    Fake: "Fake",
    DataSource: "DataSource"
}

GPMasterListFormExtender.prototype = new iSPListFormExtender();
GPMasterListFormExtender.prototype.TypeName = GPMasterListFormExtender.TypeName;
GPMasterListFormExtender.prototype.ExtenderType = GPMasterListFormExtender.ExtenderType;

GPMasterListFormExtender.prototype.ListName = null;

GPMasterListFormExtender.prototype.AddressBookDataSourceEntity = null;

GPMasterListFormExtender.prototype.Settings = {
    Fields: null
}

GPMasterListFormExtender.prototype.SaveButtons = null;
GPMasterListFormExtender.prototype.SaveButtonNativeOnclick = null;
GPMasterListFormExtender.prototype.SaveEventHandlers = [];
GPMasterListFormExtender.prototype.PreSave = null;
GPMasterListFormExtender.prototype.DialogType = null;

GPMasterListFormExtender.prototype.AddressBookItem = null;
GPMasterListFormExtender.prototype.FakeControls = null;

GPMasterListFormExtender.prototype.CanExtend = GPMasterListFormExtender.CanExtend;
GPMasterListFormExtender.prototype.ExtendInternal = function()
{
    // ライセンスが無効な場合拡張を止める
    var license = GPContext.OrganizationManagementLicense;    
    if (!license ||
        !license.Valid)
    {
        GPMasterListFormExtender.ShowForm();
        return;
    }

    // フォーム情報を取得
    // ToDo: 親の関数をEnsureと変更
    this.GetFormFieldInfos();
    
    // 偽コントロールの初期化
    this.FakeControls = new ISDictionary();

    var childExtender = null;

    // フォームタイプの設定
    if (GPMasterListFormExtender.IsEntityMasterForm())
    {
        // EntityMasterListExtenderを実行
        childExtender = new GPEntityMasterListFormExtender();
    }
    else if (GPMasterListFormExtender.IsPermissionMasterForm())
    {
        childExtender = new GPPermissionMasterListFormExtender();
    }
    
    if (!childExtender) 
    {
        return;
    }

    // 子エクステンダの初期化
    childExtender.ParentExtender = this;
    childExtender.FormFieldInfos = this.FormFieldInfos;
    childExtender.Settings       = this.Settings;
    childExtender.FakeControls   = this.FakeControls;

    if (GPMasterListFormExtender.IsEntityMasterForm())
    {
        var formInfo = GPContext.Configuration.Forms.Get("Infoshare.GroupPicker.OrganizationManagement.SupplementMasterForm");
        childExtender.Settings.Fields = formInfo.Fields;

        // システム列の属性を設定する
        childExtender.Settings.Fields.Get("EntityDisplayName").Required     = "true";
        childExtender.Settings.Fields.Get("MemberOf").Required              = "true";
        childExtender.Settings.Fields.Get("ShowInAddressBook").DefaultValue = "true";
        childExtender.Settings.Fields.Get("ShowInTree").DefaultValue        = "true";
    }
    else if (GPMasterListFormExtender.IsPermissionMasterForm())
    {
        childExtender.Settings.Fields = GPPermissionMasterListFormExtender.Settings.Fields;
    }

    // 初期表示関数の実行
    childExtender.Load();
}

GPMasterListFormExtender.prototype.Load = function () 
{
    // フォームのオーバーライド
    this.OverrideForm();

    // 編集フォームの場合にはAddressBookDataSourceEntityを取得し、初期値の設定を行う
    var entityIdControlValue = this.GetBaseValue("EntityId");
    if (GPMasterListFormExtender.IsEditForm() &&
        !ISString.IsNullOrEmpty(entityIdControlValue))
    {
        this.EnsureAddressBookDataSourceEntity(entityIdControlValue, ISFunction.CreateDelegate(function () 
        {
            // コントロールの値を更新する
            this.UpdateFakeValues();

            // 要素を表示して、スクリーンブロックを解除する
            GPMasterListFormExtender.ShowForm();
        }, this));
    }

    // EntityManagement.aspxから開かれた場合
    else if (window.parent.GPOMHeaderAction.CurrentEntity)
    {
        this.AddressBookDataSourceEntity = window.parent.GPOMHeaderAction.CurrentEntity;

        // コントロールの値を更新する
        this.UpdateFakeValues();

        // 要素を表示して、スクリーンブロックを解除する
        GPMasterListFormExtender.ShowForm();
    }

    // 初期値のセット
    else if (GPMasterListFormExtender.IsNewForm())
    {
        // コントロールの値を更新する
        this.UpdateFakeValues();

        // 要素を表示して、スクリーンブロックを解除する
        GPMasterListFormExtender.ShowForm();
    }
}

GPMasterListFormExtender.prototype.Save = function (eventArgs) 
{
    if (typeof this.PreSave == "function")
    {
        this.PreSave();
    }

    // バリデーション
    var valid = this.Validate();
    if (!valid) 
    {
        return;
    }

    // 元の保存関数の実行
    this.SaveButtonNativeOnclick(eventArgs);
}

GPMasterListFormExtender.prototype.Update = function () 
{
    // 選択されたアイテムによってページを更新する
    var currentEntity = this.GetCurrentEntity();
    var entityId = currentEntity.Properties.EntityId;

    // 現在のEntityIdの値を各々のマスタに問い合わせ
    this.GetMasterListEntity(entityId, ISFunction.CreateDelegate(function (entity)
    {
        // アイテムが存在する場合編集ページに遷移させる
        if (entity)
        {
            // アイテムIDより編集ページを開く
            // https://tenant.sharepoint.com/teams/OMAInfoCall/Lists/SupplementMaster/EditForm.aspx
            // ?ID=1&Source=https%3A%2F%2Ftenant%2Esharepoint%2Ecom%2Fteams%2FOMAInfoCall%2FLists%2FSupplementMaster%2FAllItems%2Easpx&ContentTypeId=0x0100A071B8A819BC9742B079EF406D06A607
                        
            var formUrl = iVxContext.SiteUrl 
            + "/Lists/"
            + this.ListName
            +"/EditForm.aspx?ID="
            + entity.Id;

            // querystring
            var queryValues = ISString.Split(location.search, "&")
            for (var i = 1; i < queryValues.length; i++)
            {
                var query = queryValues[i];
                formUrl += "&" + query;
            }
            
            location.href = formUrl;
        }
        else
        {
            // CurrentEntityをAddressBookDataSourceEntityとして
            // FakeControlの値を初期化
            this.AddressBookDataSourceEntity = currentEntity;
            if (GPMasterListFormExtender.IsEntityMasterForm())
            {
                this.UpdateFakeValues();
            }

            // それぞれのマスタ毎に必要なアップデート処理を行う
            this.UpdateInternal();
        }
    }, this));
}

GPMasterListFormExtender.prototype.UpdateInternal = function () { }

GPMasterListFormExtender.prototype.GetMasterListEntity = function(entityId, callback)
{
    var extender = this;

    // マスタからアイテムを取得
    iVxService.GetListByUrlName(iVxContext.SiteUrl, this.ListName, function (list) 
    {
        if (list) 
        {
            var query = extender.BuildMasterListQuery(entityId);                
            iVxService.RetrieveItems(iVxContext.SiteUrl, list, query, true, function (items) 
            {
                var entity = items.length === 1 ? items[0]
                                                : null;
                callback(entity);
            });
        }
    });   
}

GPMasterListFormExtender.prototype.BuildMasterListQuery = function(entityId) 
{
    var query = new ISSPQuery();
    query.Query = "<Query>"
                +   "<Where>"
                +     "%Where%"
                +   "</Where>"
                + "</Query>";

    var whereQuery = SPQueryBuilder.BuildEqualQueryCondition("EntityId", "text", entityId);
    query.Query = query.Query.replace("%Where%", whereQuery);

    // ViewField設定
    var fieldRefs = '';
    query.ViewFields = SPQueryBuilder.BuildViewFields(fieldRefs);

    return query;
}

GPMasterListFormExtender.prototype.GetBaseControl = function (fieldName) 
{
    var control = null;
    var fieldInfo = this.FormFieldInfos.Get(fieldName);
    if (fieldInfo) 
    {
        control = fieldInfo.BodyElement.children[0].children[0];
    }
    return control;
}

GPMasterListFormExtender.prototype.GetFakeControl = function (fieldName) 
{
    var control = null;
    var fieldInfo = this.FormFieldInfos.Get(fieldName);
    if (fieldInfo) 
    {
        control = fieldInfo.BodyElement.children[0].children[2];
    }
    return control;
}

GPMasterListFormExtender.prototype.GetBaseValue = function (fieldName) 
{
    var control = this.GetBaseControl(fieldName);
    return control ? control.value : null;
}

GPMasterListFormExtender.prototype.GetFakeValue = function (fieldName) 
{
    var control = this.GetFakeControl(fieldName);
    return control ? control.value : null;
}

GPMasterListFormExtender.prototype.GetFakeValueAsText = function (fieldName) 
{
    var control = this.FakeControls.Get(fieldName);
    return control.GetValue();
}

GPMasterListFormExtender.prototype.GetFakeValueAsCheck = function (fieldName)
{
    var control = this.FakeControls.Get(fieldName);
    return control.IsChecked();
}

GPMasterListFormExtender.prototype.GetFakeValueAsPickerEntity = function (fieldName) 
{
    var control = this.FakeControls.Get(fieldName);
    return control.GetEntities();
}

GPMasterListFormExtender.prototype.GetDataSourceValue = function (fieldName) 
{
    var value = this.AddressBookDataSourceEntity ? this.AddressBookDataSourceEntity.Properties[fieldName]
                                                 : null;
    return value;
}

GPMasterListFormExtender.prototype.IsDirtyValue = function (fieldName) 
{
    var dirty = false;
    var control = this.FakeControls.Get(fieldName);
    var extensionType = this.GetFieldExtensionType(fieldName);
    if (extensionType == GPMasterListFormExtender.FieldExtensionType.Text ||
        extensionType == GPMasterListFormExtender.FieldExtensionType.Picker ||
        extensionType == GPMasterListFormExtender.FieldExtensionType.Note ||
        extensionType == GPMasterListFormExtender.FieldExtensionType.CheckBox)
    {
        dirty = control.Dirty;
    }

    return dirty;
}

GPMasterListFormExtender.prototype.SetBaseValue = function (fieldName, value) 
{
    var control = this.GetBaseControl(fieldName);
    if (control) control.value = value;
}

GPMasterListFormExtender.prototype.SetFakeValue = function (fieldName, value) 
{
    var control = this.GetFakeControl(fieldName);
    if (control) control.value = value;
}

GPMasterListFormExtender.prototype.SetFakeValueAsText = function (fieldName, value)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl) 
    {
        fakeControl.SetValue(value);
    }
}

GPMasterListFormExtender.prototype.SetFakeValueAsWaterMark = function (fieldName, value)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl) 
    {
        fakeControl.Watermark = value;
        fakeControl.Dirty = false;
        fakeControl.OnBlur();
        fakeControl.Dirty = false;
    }
}

GPMasterListFormExtender.prototype.SetFakeValueAsCheck = function (fieldName, value)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl && value)
    {
        if (ISBoolean.Parse(value))
        {
            fakeControl.Check(true);
        }
        else if (!ISBoolean.Parse(value))
        {
            fakeControl.UnCheck(true);
        }        
    }
}

GPMasterListFormExtender.prototype.SetFakeValueAsPickerEntity = function (fieldName, value)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl) 
    {
        this.GetAddressBookDataSourceEntities(value, ISFunction.CreateDelegate(function (entities) 
        {
            fakeControl.SetEntities(entities);
            fakeControl.Dirty = false;
        }, this));
    }
}

GPMasterListFormExtender.prototype.SetFakeValueAsPickerEntityWithEntity = function (fieldName, entity)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl) 
    {
        fakeControl.SetEntities([entity]);
        fakeControl.Dirty = true;
    }
}

GPMasterListFormExtender.prototype.DeleteTextFakeValue = function (fieldName)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl)
    {
        fakeControl.SetValue("");
        fakeControl.Dirty = false;
    }
}

GPMasterListFormExtender.prototype.DeletePickerEntityFakeValue = function (fieldName)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl) 
    {
        // 削除
        fakeControl.ClearEntities();
        fakeControl.Dirty = false;
    }
}

GPMasterListFormExtender.prototype.GetFieldExtensionType = function (fieldName) 
{
    var type = null;
    var fieldInfo = this.Settings.Fields.Get(fieldName);
    if (fieldInfo) 
    {
        type = fieldInfo.ViewType;
    }
    return type;
}

// 実際の列の required属性ではなく、拡張後の定義として評価する
// 見た目を変えたリ、バリデーションにて利用する
GPMasterListFormExtender.prototype.IsRequiredFiled = function (fieldName) 
{
    var required = false;
    var fieldInfo = this.Settings.Fields.Get(fieldName);
	if (fieldInfo) 
    {
        required = fieldInfo.Required;
	}

    required = ISBoolean.TryParse(required, false);
    return required;
}

GPMasterListFormExtender.prototype.EnsureAddressBookDataSourceEntity = function (entityId, callback) 
{
    this.GetAddressBookDataSourceEntities(entityId, ISFunction.CreateDelegate(function (entities)
    {
        var entity = entities.length > 0 ? entities[0] : null;
        this.AddressBookDataSourceEntity = entity;
        callback();
    }, this));
}

GPMasterListFormExtender.prototype.GetAddressBookDataSourceEntities = function (entityIds, callback) 
{
    // コンテキストが初期化済の場合
    if (GPViewContext.Initialized) 
    {
        this.GetAddressBookDataSourceEntitiesInternal(entityIds, callback);
    }
    else
    {
        GPViewContext.RegisterFunctionToNotifyInitialized(ISFunction.CreateDelegate(function () 
        {
            this.GetAddressBookDataSourceEntitiesInternal(entityIds, callback);
        }, this));
    }    
}

GPMasterListFormExtender.prototype.GetAddressBookDataSourceEntitiesInternal = function (entityIds, callback) 
{
    if (typeof entityIds == "string")
    {
        // Arrayに変換
        entityIds = GPHierarchicalIdUtility.GetIdCollections(entityIds);
    }

    // Entityを元に問い合わせる
    var dataSourceBaseName = GPContext.Configuration.GetSetting('OrganizationMasterReferenceListBaseName');
    var dataSourceInfo = null;
    for (var i = 0; i < GPViewContext.DataSources.GetLength(); i++)
    {
        var dataSource = GPViewContext.DataSources.Get(i);
        if (ISString.Equals(dataSource.BaseListName, dataSourceBaseName, true))
        {                    
            dataSourceInfo = dataSource;
            break;
        }
    }

    if (!dataSourceInfo)
    {
        ISTrace.TraceWarning('[Warning] GPMasterListFormExtender.prototype.GetAddressBookDataSourceEntitiesInternal（DataSourceList not found. ListName: ' + dataSourceBaseName);
        return;
    }

    // AddressBookデータソース、補助マスタに問い合わせてマージする
    var context = {
        // AddressBookDataSourceから取得されたEntities
        BaseEntities: null,
        // SupplementMasterから取得されたEntities
        SupplementMasterEntities: null,

        BaseEntitiesEnsured: false,
        SupplementMasterEntitiesEnsured: false,

        Completed: function () {
            var complete = this.BaseEntitiesEnsured &&
                           this.SupplementMasterEntitiesEnsured;
            return complete;
        }
    };

    var extender = this;
    var completeCallback = function()
    {
        if (context.Completed())
        {
            // マージする
            GPViewContext.MargeEntitiesForSupplementMasterEntities(
            context.BaseEntities,
            context.SupplementMasterEntities,
            dataSourceInfo.WebUrl,
            dataSourceInfo.DataSourceList,
            function (effectiveEntities)
            {
                // entityIdsの並び順でソートする
                var dictionary = new ISDictionary();
                for (var i = 0; i < effectiveEntities.length; i++)
                {
                    var entity = effectiveEntities[i];
                    dictionary.Add(entity.Properties.EntityId, entity);
                }
                
                var sortedEntities = [];
                for (var i = 0; i < entityIds.length; i++)
                {
                    var key = entityIds[i];
                    if (dictionary.Contains(key))
                    {
                        var entity = dictionary.Get(key);
                        sortedEntities.push(entity);
                    }
                }

                // コールバック
                callback(sortedEntities);
            });    
        }
    };

    // AddressBookData
    GPViewContext.GetEntitiesByEntityIds(dataSourceInfo.WebUrl, dataSourceInfo.DataSourceList, entityIds, function (baseEntities)
    {
        context.BaseEntitiesEnsured = true;
        context.BaseEntities = baseEntities;
        completeCallback();      
    });

    // SupplementMaster
    GPViewContext.GetEntitiesByEntityIds(iVxContext.MasterSiteAbsolutePath, GPViewContext.SupplemenntMasterList, entityIds, function (supllementMasterEntities)
    {
        context.SupplementMasterEntitiesEnsured = true;
        context.SupplementMasterEntities = supllementMasterEntities;
        completeCallback();
    });
}

GPMasterListFormExtender.prototype.OverrideForm = function () 
{
    // 編集情報を非表示にする
    GPMasterListFormExtender.HideEditInfoBlock();

    // コントロールをオーバーライド
    this.OverrideFormControl();

    // 保存アクションをオーバーライド
    this.OverrideDefaultSaveAction();
}

GPMasterListFormExtender.prototype.OverrideFormControl = function()
{
    // 元のTableRow属性を更新する
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var extensionType = this.GetFieldExtensionType(fieldName);

        // 必須属性：スタイルを変更して見た目上必須のように見せる
        if (this.IsRequiredFiled(fieldName))
        {
            this.AppendRequireIcon(info);
        }

        // 非表示
        if (extensionType == GPMasterListFormExtender.FieldExtensionType.Hidden)
        {
            this.HideRow(fieldName);
        }   

        // テキストフィールドは元のフィールドを非表示にして、フェイクのコントロールを追加
        else if (extensionType == GPMasterListFormExtender.FieldExtensionType.Text)
        {
            // 元コントロールを非表示
            this.HideBaseControl(info);  

            // 偽コントロール作成
            var baseControl = this.GetBaseControl(info.InternalName);
            var spanElm = info.BodyElement.children[0];   

            var fakeControl = new iTextBox();
            fakeControl.RenderingMode = iControl.RenderingMode.Append;
            fakeControl.Render(spanElm);
            fakeControl.Element.id = baseControl.id + GPMasterListFormExtender.FakeControlSuffix;  
            fakeControl.Element.style.width = "386px";

            // テキストコントロールをキャッシュ
            this.FakeControls.Set(fieldName, fakeControl);
        }

        // ノートフィールド
        else if (extensionType == GPMasterListFormExtender.FieldExtensionType.Note)
        {
            // 元コントロールを非表示
            this.HideBaseControl(info);  

            // 偽コントロール作成
            var baseControl = this.GetBaseControl(info.InternalName);
            var spanElm = info.BodyElement.children[0];   

            var fakeControl = new iTextArea();
            fakeControl.RenderingMode = iControl.RenderingMode.Append;
            fakeControl.Render(spanElm);
            fakeControl.Element.id = baseControl.id + GPMasterListFormExtender.FakeControlSuffix;  

            // テキストコントロールをキャッシュ
            this.FakeControls.Set(fieldName, fakeControl);
        }

        // チェックボックス
        else if (extensionType == GPMasterListFormExtender.FieldExtensionType.CheckBox)
        {
            // 元コントロールを非表示
            this.HideBaseControl(info);

            // 偽コントロール作成
            var baseControl = this.GetBaseControl(info.InternalName);
            var spanElm = info.BodyElement.children[0];

            var fakeControl = new iCheckBox();
            fakeControl.RenderingMode = iControl.RenderingMode.Append;
            fakeControl.Render(spanElm);
            fakeControl.Element.id = baseControl.id +GPMasterListFormExtender.FakeControlSuffix;            
                       
            // テキストコントロールをキャッシュ
            this.FakeControls.Set(fieldName, fakeControl);
        }
    }

    // 継承クラス特融の上書きを実行
    this.OverrideFormControlInternal();
}

GPMasterListFormExtender.prototype.AppendRequireIcon = function(info)
{
    var labelSpan = info.RowElement.getElementsByClassName("ms-standardheader");
    if (labelSpan.length < 1)
    {
        return;
    }

    var nobrElm = labelSpan[0].children[0];
    var iconSpan = document.createElement("span");
    iconSpan.className = "ms-accentText";
    iconSpan.innerText = " *";
    nobrElm.appendChild(iconSpan);
}

GPMasterListFormExtender.prototype.RenderPickerSelectControl = function (info, allowUserSelection, allowGroupSelection, allowMultipleSelection, disableTagItemDeleteButton) 
{
    // spanにdivを追加
    var spanElm = info.BodyElement.children[0];
    var div = document.createElement("div");
    spanElm.appendChild(div);

    // ピッカーコントロールを追加    
    var pickerControl = new GPPickerSelectControl();

    // 選択制御
    pickerControl.EntitySelection.AllowUserSelection          = allowUserSelection;
    pickerControl.EntitySelection.AllowSecurityGroupSelection = allowGroupSelection;
    pickerControl.EntitySelection.AllowMultipleSelection      = allowMultipleSelection;

    // タグアイテムの削除制御
    if (disableTagItemDeleteButton)
    {
        pickerControl.DisableTagItemDeleteButton = true; 
    }

    // ダイアログのクラス設定（DialgTypeでスイッチさせる）
    if (this.DialogType) 
    {
        pickerControl.DialogType = this.DialogType;
    }
        
    pickerControl.Render(div);
    this.FakeControls.Set(info.InternalName, pickerControl);    

    // イベント登録
    // タグが変更された場合にはフォームをリサイズする（複数のみ）
    if (allowMultipleSelection)
    {
        pickerControl.TagChangedEventHandler = GPMasterListFormExtender.ResizeForm;
    }    
    // EntityIdにインプットがあった場合には、フォーム全体を更新する
    if (info.InternalName == "EntityId")
    {
        pickerControl.InputEventHandler = ISFunction.CreateDelegate(this.Update, this);
    }
}

GPMasterListFormExtender.prototype.OverrideDefaultSaveAction = function () 
{
    this.EnsureSaveButton();
        
    for (var i = 0; i < this.SaveButtons.length; i++) 
    {
        saveButton = this.SaveButtons[i];

        // リボンの保存ボタン
        if (this.SaveButtons.length > 1 &&
            i == 0) 
        {
            saveButton.disabled = true;
            continue;
        }

        // フォームの保存ボタン
        this.SaveButtonNativeOnclick = saveButton.onclick;
        saveButton.onclick = ISFunction.CreateDelegate(this.Save, this);        
    }    
}

GPMasterListFormExtender.prototype.EnsureSaveButton = function ()
{
    if (this.SaveButtons)
    {
        return;
    }

    // リボンメニューのボタンも取得される
    var saveButton = i$("input[accesskey='O']");
    if (saveButton.length > 1)
    {
        this.SaveButtons = saveButton;
    } 
}

GPMasterListFormExtender.prototype.HideRow = function (fieldName) 
{
    var info = this.FormFieldInfos.Get(fieldName);
    var row = info.RowElement;
    row.style.display = "none";
}

GPMasterListFormExtender.prototype.DisplayRow = function (fieldName) 
{
    var info = this.FormFieldInfos.Get(fieldName);
    var row = info.RowElement;
    row.style.display = "";
}

GPMasterListFormExtender.prototype.DisableRow = function (fieldName) 
{
    var info = this.FormFieldInfos.Get(fieldName);
    var row = info.RowElement;

    // Row以下のすべてのコントロールを無効化する
    i$(row).find("*").attr('disabled', true);
}

GPMasterListFormExtender.prototype.HideBaseControl = function (fieldInfo)
{
    var bodyElement = fieldInfo.BodyElement;    
    var spanElm = bodyElement.children[0];
    if (spanElm.children.length > 0) 
    {
        var baseControl = spanElm.children[0];
        baseControl.style.display = "none";
        var blankElement = spanElm.children[1];
        blankElement.style.display = "none";
    }    
}

GPMasterListFormExtender.prototype.UpdateFakeValues = function () 
{
    // 非同期でデータをセットする
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var fieldSetting = this.Settings.Fields.Get(fieldName);
        var extensionType = this.GetFieldExtensionType(fieldName);
        // テキスト、ノート
        if (extensionType == GPMasterListFormExtender.FieldExtensionType.Text ||
            extensionType == GPMasterListFormExtender.FieldExtensionType.Note)
        {
            // 値をクリア
            this.DeleteTextFakeValue(fieldName);

            var baseValue = this.GetBaseValue(fieldName);
            var dataSourceValue = this.GetDataSourceValue(fieldName);

            if (!ISString.IsNullOrEmpty(baseValue)) 
            {
                this.SetFakeValueAsText(fieldName, baseValue);
            }
            else if (!ISString.IsNullOrEmpty(dataSourceValue))
            {
                this.SetFakeValueAsWaterMark(fieldName, dataSourceValue);
            }
        }

        // チェックボックス
        else if (extensionType == GPMasterListFormExtender.FieldExtensionType.CheckBox)
        {
            var baseValue = this.GetBaseValue(fieldName);
            var dataSourceValue = this.GetDataSourceValue(fieldName);

            var valueForSet = !ISString.IsNullOrEmpty(baseValue) ? baseValue : dataSourceValue;
            this.SetFakeValueAsCheck(fieldName, valueForSet);

            // デフォルト値
            if (fieldSetting &&
                fieldSetting.DefaultValue &&
                ISString.IsNullOrEmpty(baseValue)) // 元の値が空の場合
            {
                this.SetFakeValueAsCheck(fieldName, fieldSetting.DefaultValue);
                var control = this.FakeControls.Get(fieldName);
                control.Dirty = true;
            }     
        }

        // ピッカー
        else if (extensionType == GPMasterListFormExtender.FieldExtensionType.Picker)
        {
            // 値をクリア
            this.DeletePickerEntityFakeValue(fieldName);

            var baseValue = this.GetBaseValue(fieldName);
            var dataSourceValue = this.GetDataSourceValue(fieldName);

            // EntityId
            if (fieldName == "EntityId") 
            {
                // アドレス帳に存在しないエンティティ（マスタにのみ存在する場合）
                if (!this.AddressBookDataSourceEntity)
                {
                    if (ISString.IsNullOrEmpty(baseValue)) continue;

                    var entity ={
                        Properties: {
                            EntityId : baseValue,
                            EntityDisplayName: this.GetBaseValue("EntityDisplayName"),
                            Type: this.GetBaseValue("Type"),
                            SubType: this.GetBaseValue("SubType"),
                            Original: this.GetBaseValue("Original")
                        }
                    };
                    
                    this.SetFakeValueAsPickerEntityWithEntity(fieldName, entity);
                }
                else
                {
                    this.SetFakeValueAsPickerEntityWithEntity(fieldName, this.AddressBookDataSourceEntity);
                }                
            }
            else
            {
                if (!ISString.IsNullOrEmpty(baseValue)) 
                {
                    this.SetFakeValueAsPickerEntity(fieldName, baseValue);
                }
                else if (!ISString.IsNullOrEmpty(dataSourceValue))
                {
                    this.SetFakeValueAsPickerEntity(fieldName, dataSourceValue);
                }
            }
        }
    }

    // 継承クラスのUpdateFakeValues
    this.UpdateFakeValuesInternal();
}

GPMasterListFormExtender.prototype.UpdateFakeValuesInternal = function () {}

GPMasterListFormExtender.prototype.PreSave = function ()
{
    // 継承クラスのPreSave処理
    this.PreSaveInternal();

    // Baseコントロールに値を設定
    this.UpdateBaseValues();
}

GPMasterListFormExtender.prototype.PreSaveInternal = function () {};

GPMasterListFormExtender.prototype.UpdateBaseValues = function () 
{
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var extensionType = this.GetFieldExtensionType(fieldName);
        // ピッカーコントロール
        if (extensionType == GPMasterListFormExtender.FieldExtensionType.Picker)
        {            
            if (!this.IsDirtyValue(fieldName)) 
            {
                continue;
            }

            this.UpdateBaseValueAsPicker(info);
        }

        // チェックボックスコントロール
        if (extensionType == GPMasterListFormExtender.FieldExtensionType.CheckBox)
        {            
            if (!this.IsDirtyValue(fieldName)) 
            {
                continue;
            }

            this.UpdateBaseValueAsCheckBox(info);
        }

        // テキストコントロール
        else if (extensionType == GPMasterListFormExtender.FieldExtensionType.Text ||
                 extensionType == GPMasterListFormExtender.FieldExtensionType.Note)
        {
			// Textコントロールが空セット時にDirtyにならないので、直接セットする
			// ToDo：テキストコントロール側の修正を検討
			var fakeValue = this.GetFakeValueAsText(fieldName);
			if (ISString.IsNullOrEmpty(fakeValue)) 
			{
				this.UpdateBaseValueAsText(info);
			}

            if (!this.IsDirtyValue(fieldName)) 
            {
                continue;
            }

            this.UpdateBaseValueAsText(info);
        }        
    }

    // 継承クラスのUpdateBaseValues
    this.UpdateBaseValuesInternal();
}

GPMasterListFormExtender.prototype.UpdateBaseValuesInternal = function () { };

GPMasterListFormExtender.prototype.UpdateBaseValueAsPicker = function (fieldInfo) 
{
    var fieldName = fieldInfo.InternalName;
    var fakeControl = this.FakeControls.Get(fieldName);
    
    // FakeコントロールのEntity
    var fakeEntities = fakeControl.GetEntities();
    
    var valueForSet = "";  
    if (fieldName == "EntityId") 
    {
        if (fakeEntities.length === 1) 
        {
            valueForSet = fakeEntities[0].Properties.EntityId;               
        }        
    }

    else
    {
        for (var i = 0; i < fakeEntities.length; i++) 
        {
            valueForSet += "|";
            valueForSet += fakeEntities[i].Properties.EntityId;
        }

        if (!ISString.IsNullOrEmpty(valueForSet)) 
        {
            valueForSet += "|";
        }
    }
    
    this.SetBaseValue(fieldName, valueForSet);
}

GPMasterListFormExtender.prototype.UpdateBaseValueAsText = function (fieldInfo) 
{
    var fieldName = fieldInfo.InternalName;
    var fakeValue = this.GetFakeValueAsText(fieldName);
	this.SetBaseValue(fieldName, fakeValue);
}

GPMasterListFormExtender.prototype.UpdateBaseValueAsCheckBox = function (fieldInfo)
{
    var fieldName = fieldInfo.InternalName;
    var fakeValue = this.GetFakeValueAsCheck(fieldName);
    this.SetBaseValue(fieldName, fakeValue);
}

GPMasterListFormExtender.prototype.GetCurrentEntity = function () 
{
    var entity = null;    
    var pickerControl = this.FakeControls.Get("EntityId");
    var entities = pickerControl.GetEntities();
    if (entities.length == 1) 
    {
        entity = entities[0];
    }

    return entity;
}

GPMasterListFormExtender.prototype.Validate = function() 
{
    var valid = true;
    return valid;
}															
