// -----------------------------------------------------------------------
Infoshare.GroupPicker.OrganizationManagement.EntityMasterListFormExtender = function Infoshare$GroupPicker$OrganizationManagement$EntityMasterListFormExtender()
{
    Infoshare.GroupPicker.OrganizationManagement.MasterListFormExtender.apply(this, arguments);
}
GPEntityMasterListFormExtender = Infoshare.GroupPicker.OrganizationManagement.EntityMasterListFormExtender;
GPEntityMasterListFormExtender.TypeName = 'Infoshare.GroupPicker.OrganizationManagement.EntityMasterListFormExtender';
GPEntityMasterListFormExtender.ExtenderType = iBehaviorExtender.ExtenderType.Page;
GPEntityMasterListFormExtender.ClassInfo = null;

GPEntityMasterListFormExtender.Target =
{
    UserOnly: "UserOnly",
    GroupOnly: "GroupOnly"
}

GPEntityMasterListFormExtender.CanExtend = function()
{
    return GPMasterListFormExtender.IsEntityMasterForm();
}

// {0}：ユーザー
// {1}：グループ
GPEntityMasterListFormExtender.TypeOptionHtml = 
"<option value='" + GPEntityType.Type.User  + "'>{0}</option>" +
"<option value='" + GPEntityType.Type.Group + "'>{1}</option>";

GPEntityMasterListFormExtender.prototype = new GPMasterListFormExtender();
GPEntityMasterListFormExtender.prototype.TypeName = GPEntityMasterListFormExtender.TypeName;
GPEntityMasterListFormExtender.prototype.ExtenderType = GPEntityMasterListFormExtender.ExtenderType;
GPEntityMasterListFormExtender.prototype.DialogType = GPDialog.Type.EntityMaster;
GPEntityMasterListFormExtender.prototype.ListName = "SupplementMaster";

GPEntityMasterListFormExtender.prototype.OverrideFormControlInternal = function () 
{ 
    // 元のTableRow属性を更新する
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var extensionType = this.GetFieldExtensionType(fieldName);

        // ピッカーセレクトコントロールを表示
        if (extensionType == GPMasterListFormExtender.FieldExtensionType.Picker)
        {            
            // 元コントロールを非表示
            this.HideBaseControl(info);  

            var allowUserSelection = true;
            var allowMultipleSelection = true;
            var allowGroupSelection = true;
            var disableTagItemDeleteButton = false;

            // エンティティID
            if (fieldName == "EntityId") 
            {
                allowMultipleSelection = false;
                // 削除禁止
                disableTagItemDeleteButton = true;
            }
            // MemberOf
            else if (fieldName == "MemberOf") 
            {
                allowUserSelection = false;
            }        
            // PrimaryGroupEntityId
            else if (fieldName == "PrimaryGroupEntityId") 
            {
                allowUserSelection = false;
                allowMultipleSelection = false;
            }
            // PersonalRootOrganization
            else if (fieldName == "PersonalRootOrganization") 
            {
                allowUserSelection = false;
                allowMultipleSelection = false;
            }    

            this.RenderPickerSelectControl(info, allowUserSelection, allowGroupSelection, allowMultipleSelection, disableTagItemDeleteButton);
        }

        // Selectコントロールは元のフィールドを非表示にして、フェイクのSelectコントロールを追加
        else if (extensionType == GPMasterListFormExtender.FieldExtensionType.Select)
        {
            // 元コントロールを非表示
            this.HideBaseControl(info);

            // 偽コントロール作成
            var baseControl = this.GetBaseControl(fieldName);
            var spanElm = info.BodyElement.children[0];   
            var optionHtml = "";
            var onChangeFunction = function () {};
            if (fieldName == "Type") 
            {
                optionHtml = this.GetTypeOptionHtml();
                onChangeFunction = ISFunction.CreateDelegate(function () 
                {
                    var currentType = this.GetFakeValue("Type");

                    // タイプに応じて表示項目を変更する
                    this.UpdateDisplayByType(currentType);

                    // ダイアログのリサイズ
                    GPMasterListFormExtender.ResizeForm();
                }, this);
            }

            var fakeSelectControl = document.createElement("select");   
            spanElm.appendChild(fakeSelectControl);
            fakeSelectControl.innerHTML = optionHtml;            
            fakeSelectControl.onchange = onChangeFunction;

            this.FakeControls.Set(fieldName, fakeSelectControl);
        }       
    }

    // フォーム毎の表示制御
    // EntityId列を非表示にする（更新させないように）
    this.HideRow("EntityId");
    // 編集フォーム
    if (GPMasterListFormExtender.IsEditForm() ||
        window.parent.GPOMHeaderAction.CurrentEntity)
    {
        // Type列をDisabledにする
        this.DisableRow("Type");
    }
    // 新規フォーム
    else if (GPMasterListFormExtender.IsNewForm())
    {
        // 初期表示時にはユーザーのみ表示項目を表示する
        this.UpdateDisplayByType(GPEntityType.Type.User);
    }
}

GPEntityMasterListFormExtender.prototype.UpdateDisplayByType = function(entityType)
{
    for (var i = 0; i < this.FormFieldInfos.GetLength() ; i++)
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var extensionType = this.GetFieldExtensionType(fieldName);

        var fieldSetting = this.Settings.Fields.Get(fieldName);
        if (!fieldSetting) continue;

        // ユーザーのみのフィールド
        if (fieldSetting.Target == GPEntityMasterListFormExtender.Target.UserOnly)
        {
            if (ISString.Equals(entityType, GPEntityType.Type.User, true))
            {
                if (extensionType != GPMasterListFormExtender.FieldExtensionType.Hidden)
                {
                    this.DisplayRow(fieldName);
                }            
            }
            else
            {
                this.HideRow(fieldName);
            }
        }
        // グループのみのフィールド
        else if (fieldSetting.Target == GPEntityMasterListFormExtender.Target.GroupOnly)
        {
            if (ISString.Equals(entityType, GPEntityType.Type.Group, true))
            {
                if (extensionType != GPMasterListFormExtender.FieldExtensionType.Hidden)
                {
                    this.DisplayRow(fieldName);
                }            
            }
            else
            {
                this.HideRow(fieldName);
            }
        }
    }
}

GPEntityMasterListFormExtender.prototype.GetTypeOptionHtml = function ()
{
    var typeOptionHtml = GPEntityMasterListFormExtender.TypeOptionHtml;
    // リソース変換
    typeOptionHtml = ISString.Format(typeOptionHtml,
                                     iResxResource.GetString('EntityType.Type.User'),
                                     iResxResource.GetString('EntityType.Type.Group'));

    return typeOptionHtml;
}

GPEntityMasterListFormExtender.prototype.UpdateInternal = function ()
{
    // Type列をDisabledにする
    this.DisableRow("Type");
}

GPEntityMasterListFormExtender.prototype.UpdateFakeValuesInternal = function()
{
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        
        // セレクトコントロール
        if (this.GetFieldExtensionType(fieldName) == GPMasterListFormExtender.FieldExtensionType.Select) 
        {
            var baseValue = this.GetBaseValue(fieldName);
            var dataSourceValue = this.GetDataSourceValue(fieldName);

            if (!ISString.IsNullOrEmpty(baseValue)) 
            {
                this.SetFakeValueAsSelectOption(fieldName, baseValue);
            }
            else if (!ISString.IsNullOrEmpty(dataSourceValue))
            {
                this.SetFakeValueAsSelectOption(fieldName, dataSourceValue);
            }
        }
    }

    // 種別に応じて表示項目を変更する
    var typeValue = this.GetFakeValue("Type");
    this.UpdateDisplayByType(typeValue);
}

GPEntityMasterListFormExtender.prototype.SetFakeValueAsSelectOption = function(fieldName, value)
{
    var fakeControl = this.FakeControls.Get(fieldName);
    if (fakeControl) 
    {
        for (var i = 0; i < fakeControl.options.length; i++)
        {
            var option = fakeControl.options[i];
            if (ISString.Equals(option.value, value, true)) 
            {
                // 内部値はLowerCaseで統一する
                fakeControl.value = value.toLowerCase();
                fakeControl.onchange();
                break;
            }
        }
    }
}

GPEntityMasterListFormExtender.prototype.PreSaveInternal = function ()
{
    var currentType = this.GetFakeValue("Type");

    // ユーザーオンリー、グループオンリーのフィールドはDirtyのフラグを外す
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var fieldSetting = this.Settings.Fields.Get(fieldName);

        if (fieldSetting &&
            fieldSetting.Target)
        {
            var setDirtyFalse = false
            if (fieldSetting.Target == GPEntityMasterListFormExtender.Target.UserOnly)
            {
                setDirtyFalse = ISString.Equals(currentType, "group", true);
            }
            else if (fieldSetting.Target == GPEntityMasterListFormExtender.Target.GroupOnly)
            {
                setDirtyFalse = ISString.Equals(currentType, "user", true);
            }

            if (setDirtyFalse)
            {
                var control = this.FakeControls.Get(fieldName);
                if (control) control.Dirty = false;
            }
        }
    }
};

GPEntityMasterListFormExtender.prototype.UpdateBaseValuesInternal = function () 
{
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;

        // セレクトコントロール
        if (this.GetFieldExtensionType(fieldName) == GPMasterListFormExtender.FieldExtensionType.Select) 
        {
            var fakeValue = this.GetFakeValue(fieldName);
            this.SetBaseValue(fieldName, fakeValue);
        }
    }

    // 上書きフィールド以外の値もセットする
    this.SetRelationalFieldValues();
}

GPEntityMasterListFormExtender.prototype.SetRelationalFieldValues = function () 
{
    // Entityを取得
    var entity = this.GetCurrentEntity();

    if (GPMasterListFormExtender.IsNewForm() &&
        !entity)    
    {
        // 新規作成アイテムの場合にはEntityIdに新しいGuidを設定
        var guid = ISGuid.New();
        var type = this.GetFakeValue("Type");
        var subType = ISString.Equals(type, GPEntityType.Type.User, true) ? GPEntityType.UserSubType.Contact
                                                                          : GPEntityType.GroupSubType.Distribution;
        this.SetBaseValue("EntityId", guid);
        entity = {
            Properties: {
                EntityId: guid,
                EntityDisplayName: "",
                MemberOf: "",
                Type: type,
                SubType: subType,
                Original: "true"
            }
        };
    }

    if (!entity) return;

    // PrincipalName
    var principalNameValue = entity.Properties.PrincipalName;
    if (principalNameValue) 
    {
        this.SetBaseValue("PrincipalName", principalNameValue);
    }

    // EffectiveEntityDisplayName（JSからは参照しないが、同期ツールのログで必要になるため）
    var dataSourceDisplayName = entity.Properties.EntityDisplayName;
    var currentDisplayName = this.GetFakeValueAsText("EntityDisplayName");
    var effectiveEntityDisplayNameValue = ISString.IsNullOrEmpty(currentDisplayName) ? dataSourceDisplayName
                                                                                     : currentDisplayName;
    this.SetBaseValue("EffectiveEntityDisplayName", effectiveEntityDisplayNameValue);
     
        
    // HierarchicalId（階層IDは権限チェック用に利用）
    if (this.IsDirtyValue("MemberOf"))
    {
        var currentMemberOfEntities = this.GetFakeValueAsPickerEntity("MemberOf");
        var currentMemberOfValue = GPHierarchicalIdUtility.GetMemberOfString(currentMemberOfEntities);
        var hierarchicalIdValue = "";
        if (!ISString.IsNullOrEmpty(currentMemberOfValue)) 
        {
            hierarchicalIdValue = GPHierarchicalIdUtility.CreateHierarchialId(currentMemberOfEntities, entity.Properties.EntityId);        
        }
        this.SetBaseValue("HierarchicalId", hierarchicalIdValue);
    }

    // SubType
    this.SetBaseValue("SubType", entity.Properties.SubType);

    // Original 
    if (ISBoolean.TryParse(entity.Properties.Original, false))
    {
        this.SetBaseValue("Original", "true");
    }

    // SearchKey
    this.SetSearchKeyValue();
}

GPEntityMasterListFormExtender.prototype.SetSearchKeyValue = function() 
{
    var searchKeyValue = "|";

    // 種別プレフィックス
    var type = this.GetFakeValue("Type");
    var typeSearchKey = ISString.Equals(type, GPEntityType.Type.User, true) ? GPSearchView.SearchTypePrefixUser
                                                                            : GPSearchView.SearchTypePrefixGroup;
    searchKeyValue += typeSearchKey
                    + "|";

    // Fieldsのキーフィールド定義から検索キーを列挙する
    for (var i = 0; i < GPContext.Configuration.Fields.GetLength(); i++)
    {
        var fieldInfo = GPContext.Configuration.Fields.Get(i);
        if (!fieldInfo.IsKey)
        {
            continue;
        }

        // セットする値：コントロールの値を保存する（元々の値はセットしない）
        var baseValue = this.GetBaseValue(fieldInfo.InternalName);
        if (!ISString.IsNullOrEmpty(baseValue))
        {
            searchKeyValue += baseValue
                            + "|";
        }
    }

    // セパレーターを修正
    searchKeyValue = searchKeyValue.replace("||", "|");
    // 文字長の修正
    searchKeyValue = searchKeyValue.substring(0, 255);
    this.SetBaseValue("SearchKey", searchKeyValue);

    // シノニム変換
    var synonymSearchKeyValue = searchKeyValue;
    for (var i = 0; i < GPContext.Configuration.Synonyms.length; i++)
    {
        var synonymInfo = GPContext.Configuration.Synonyms[i];
        var representingValue = synonymInfo.RepresentingValue;
        for (var j = 0; j < synonymInfo.Values.length; j++)
        {
            var synonymValue = synonymInfo.Values[j];
            synonymSearchKeyValue = ISString.Replace(synonymSearchKeyValue, synonymValue, representingValue);
        }
    }
    this.SetBaseValue("SynonymSearchKey", synonymSearchKeyValue);
}

GPEntityMasterListFormExtender.prototype.Validate = function() 
{
    var valid = true;
    var isOriginal = this.IsOriginal();
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var baseControl = this.GetBaseControl(info.InternalName);
        var errorResult = {
            errorMessage: "",
            validationError: false
        };

        // オリジナルのエンティティは以下二つをバリデーションする
        if (isOriginal)
        {
            // EntityDisplayName：表示する為に必須
            if (fieldName == "EntityDisplayName") 
            {
                var displayName = this.GetBaseValue("EntityDisplayName");
                if (ISString.IsNullOrEmpty(displayName)) 
                {
                    valid = false;
                    var message = iResxResource.GetString("OrganizationManagement.MasterList.Validate.Required");
                    errorResult.validationError = true;
                    errorResult.errorMessage = message;
                    SPFormControl_AppendValidationErrorMessage(baseControl.id, errorResult);
                }
                else 
                {
                    // クリアする
                    SPFormControl_AppendValidationErrorMessage(baseControl.id, errorResult);
                }
            }

            // MemberOf：権限の確認の際に不整合が発生する可能性があるため、空のエンティティは作成させない
            else if (fieldName == "MemberOf") 
            {
                var memberOf = this.GetBaseValue("MemberOf");
                if (ISString.IsNullOrEmpty(memberOf)) 
                {
                    valid = false;
                    var message = iResxResource.GetString("OrganizationManagement.MasterList.Validate.Required");
                    errorResult.validationError = true;
                    errorResult.errorMessage = message;
                    SPFormControl_AppendValidationErrorMessage(baseControl.id, errorResult);
                }
                else 
                {
                    // クリアする
                    SPFormControl_AppendValidationErrorMessage(baseControl.id, errorResult);
                }
            }  
        }
    }

    return valid;
}

GPEntityMasterListFormExtender.prototype.IsOriginal = function() 
{
    var isOriginal = false;
    
    var currentEntity = this.GetCurrentEntity();
    if (currentEntity)
    {
        var originalValue = currentEntity.Properties["Original"];
        isOriginal = ISBoolean.TryParse(originalValue, false);
    }
    else
    {
        isOriginal = true;
    }

    return isOriginal;
}

// -----------------------------------------------------------------------
//  EntityMasterValidator
//
//  マスタ管理リストの場合には、以下二つのフィールドにて選択制御する
//  ① EntityId（対象）列
//  ② MemberOf（所属）列
//  
//  非管理者はPermissionマスタで権限設定されている対象のユーザー・グループのみ設定可能
// -----------------------------------------------------------------------
Infoshare.GroupPicker.OrganizationManagement.EntityMasterValidator = function Infoshare$GroupPicker$OrganizationManagement$EntityMasterValidator(entitySelection)
{
    Infoshare.GroupPicker.PickerSelectControlValidator.apply(this, arguments);
    this.EntitySelection = entitySelection;
}

GPEntityMasterValidator = Infoshare.GroupPicker.OrganizationManagement.EntityMasterValidator;

GPEntityMasterValidator.IsValidPermission = function(entities)
{
    // 管理者は検証不要
    if (GPContext.IsSiteAdmin) 
    {
        return true;
    }

    // GPContextのAuthrizedEntitiesを元に対象の選択権限を確認する
    var valid = true;
    for (var i = 0; i < entities.length; i++)
    {
        var hasPermission = false;
        hasPermission = GPEntityMasterValidator.HasPermission(entities[i]);

        if (hasPermission)
        {
            continue;
        }
        else
        {
            valid = false;
            break;
        }
    }

    if (!valid)
    {
        var message = iResxResource.GetString("PickerDialog.EntitiySelector.Validation.HasNotPermissions");
        throw new Error(message);
    }

    return valid;
}

GPEntityMasterValidator.HasPermission = function (entity) 
{
    // 管理者は検証不要
    if (GPContext.IsSiteAdmin) 
    {
        return true;
    }

    var hasPermission = false;
    if (!GPContext.MasterListEntities) 
    {
        return false;
    }
    
    for (; ;) 
    {
        // MemberOfで確認
        if (GPContext.MasterListEntities.Directory &&
            GPContext.MasterListEntities.Directory.length > 0) 
        {
            hasPermission = GPEntityMasterValidator.HasPermissionForDirectory(entity);
            if (hasPermission) break;   
        }

        // HierarchicalIdで確認
        if (GPContext.MasterListEntities.Recursive &&
            GPContext.MasterListEntities.Recursive.length > 0) 
        {
            hasPermission = GPEntityMasterValidator.HasPermissionForRecursive(entity);
            if (hasPermission) break;   
        }

        break;
    }

    return hasPermission;
}

GPEntityMasterValidator.HasPermissionForDirectory = function (entity) 
{
    var hasPermission = false;
    var memberOf = entity.Properties.MemberOf;
    var entityId = entity.Properties.EntityId;
    if (GPContext.MasterListEntities.Directory)
    {
        for (var i = 0; i < GPContext.MasterListEntities.Directory.length; i++) 
        {
            var parentGroup = GPContext.MasterListEntities.Directory[i];
            hasPermission = (!ISString.IsNullOrEmpty(memberOf) && ISString.Contains(memberOf, parentGroup)) ||
                            ISString.Equals(entityId, parentGroup, true);
            if (hasPermission)
            {
                break;
            }        
        }
    }
    return hasPermission;
}

GPEntityMasterValidator.HasPermissionForRecursive = function (entity) 
{
    var hasPermission = false;
    var hierarchicalId = entity.Properties.HierarchicalId;
    if (hierarchicalId) 
    {
        for (var i = 0; i < GPContext.MasterListEntities.Recursive.length; i++) 
        {
            var parentGroup = GPContext.MasterListEntities.Recursive[i];
            hasPermission = ISString.Contains(hierarchicalId, parentGroup);
            if (hasPermission) break;
        }
    }
    return hasPermission;
}

// 選択されたグループと同じグループは選択できない
GPEntityMasterValidator.IsNotSameGroup = function (entities)
{
    // InfoCalEntityManagement.aspxで選択されたエンティティ（GPOMHeaderAction.CurrentEntity）と比較する
    var valid = true;

    var currentEntityId = null;
    if (GPOMHeaderAction.CurrentEntity)
    {
        currentEntityId = GPOMHeaderAction.CurrentEntity.Properties["EntityId"];
    }

    if (!ISString.IsNullOrEmpty(currentEntityId))
    {
        for (var i = 0; i < entities.length; i++)
        {
            var entityId = entities[i].Properties["EntityId"];
            if (ISString.Equals(entityId, currentEntityId, true))
            {
                valid = false;
                break;
            }
        }
    }

    if (!valid)
    {
        var message = iResxResource.GetString("PickerDialog.EntitiySelector.Validation.IsNotSameGroup");
        throw new Error(message);
    }

    return valid;
}

GPEntityMasterValidator.prototype = new GPPickerSelectControlValidator();
GPEntityMasterValidator.prototype.Validate = function(entities, selectedCount)
{
    var valid = this.IsValidCount(entities, selectedCount) &&
                this.IsValidType(entities) &&
                GPEntityMasterValidator.IsValidPermission(entities) &&
                GPEntityMasterValidator.IsNotSameGroup(entities);

    return valid;
}

// -----------------------------------------------------------------------
//  PermissionMasterValidator
//
//  アクセス権マスタ用のバリデータ
// -----------------------------------------------------------------------
Infoshare.GroupPicker.OrganizationManagement.PermissionMasterValidator = function Infoshare$GroupPicker$OrganizationManagement$PermissionMasterValidator(entitySelection)
{
    Infoshare.GroupPicker.PickerSelectControlValidator.apply(this, arguments);
    this.EntitySelection = entitySelection;
}

GPPermissionMasterValidator = Infoshare.GroupPicker.OrganizationManagement.PermissionMasterValidator;
GPPermissionMasterValidator.prototype = new GPPickerSelectControlValidator();
GPPermissionMasterValidator.prototype.Validate = function(entities, selectedCount)
{
    var valid = this.IsValidCount(entities, selectedCount) &&
                this.IsValidType(entities) &&
                this.IsValidSubType(entities);

    return valid;
}

GPPermissionMasterValidator.prototype.IsValidSubType = function(entities)
{
    var valid = true;
    var invalidTypeName = '';
    for (var i = 0; i < entities.length; i++)
    {
        var entity = entities[i];
        // 連絡先は選択不可
        if (ISString.Equals(entity.Properties.Type, 'user', true) &&
            entity.Properties.SubType &&
            ISString.Equals(entity.Properties.SubType, 'contact', true))
        {
            valid = false;
            invalidTypeName = iResxResource.GetString('PickerDialog.EntityType.Contact');  
            break;
        }
    }

    if (!valid)
    {
        var message = ISString.Format(iResxResource.GetString('PickerDialog.EntitiySelector.Validation.Type'), invalidTypeName);
        throw new Error(message);
    }

    return valid;
}															
