GPPermissionMasterListFormExtender.prototype.OverrideFormControlInternal = function () 
{ 
    // 元のTableRow属性を更新する
    for (var i = 0; i < this.FormFieldInfos.GetLength(); i++) 
    {
        var info = this.FormFieldInfos.Get(i);
        var fieldName = info.InternalName;
        var row = info.RowElement;
        
        // ピッカーセレクトコントロールを表示
        if (this.GetFieldExtensionType(fieldName) == GPMasterListFormExtender.FieldExtensionType.Picker)
        {          
            // 元コントロールを非表示
            this.HideBaseControl(info);
            
            var allowUserSelection = true;
            var allowMultipleSelection = true;
            var allowGroupSelection = true;

            // エンティティID
            if (fieldName == "EntityId") 
            {
                allowMultipleSelection = false;
                allowGroupSelection 　 = false;
            }
            // 対象
            else if (fieldName == "TargetEntityIds")
            {
                allowUserSelection = false;
            }

            this.RenderPickerSelectControl(info, allowUserSelection, allowGroupSelection, allowMultipleSelection);
        }    
    }

    // フォーム毎の表示制御
    // 編集フォーム
    if (GPMasterListFormExtender.IsEditForm())
    {
        // EntityId列を非表示にする（更新させないように）
        this.HideRow("EntityId");

        // EntityDisplayName列をDisabledにする
        this.DisableRow("EntityDisplayName");
        
    }
    // 新規フォーム
    else if (GPMasterListFormExtender.IsNewForm())
    {
        // EntityDisplayName列を非表示にする
        this.HideRow("EntityDisplayName");
    }
}

GPPermissionMasterListFormExtender.prototype.UpdateBaseValuesInternal = function () 
{
    // 上書きフィールド以外の値もセットする
    this.SetRelationalFieldValues();
}

GPPermissionMasterListFormExtender.prototype.SetRelationalFieldValues = function () 
{
    // Entityを取得
    var entity = this.GetCurrentEntity();

    if (!entity) 
    {
        return;
    }

    // PrincipalName
    this.SetBaseValue("SpPrincipalName", entity.Properties.SpPrincipalName);

    // EntityDisplayName
    this.SetBaseValue("EntityDisplayName", entity.Properties.EntityDisplayName);

    // TargetEntityDisplayNames
    var targetEntities = this.GetFakeValueAsPickerEntity("TargetEntityIds");
    var targetEntityDisplayNames = "";
    for (var i = 0; i < targetEntities.length; i++)
    {
        targetEntityDisplayNames += targetEntities[i].Properties.EntityDisplayName;
        targetEntityDisplayNames += ",";
    }
    targetEntityDisplayNames = ISString.TrimEnd(targetEntityDisplayNames, ",");
    this.SetBaseValue("TargetEntityDisplayNames", targetEntityDisplayNames);
}
															
