GPOMOrganizationView.prototype.GetChildEntities = function (parentEntity, contentsType, callback)
{
    // AddressBookDataSource, SupplementMasterからデータを取得してマージ、クライアントソートする
    var context = {
        // AddressBookDataSourceのSearchKeyから取得するEntities
        BaseEntities: null,
        // SupplementMasterのSearchKeyから取得するEntities
        SupplementMasterEntities: null,

        BaseEntitiesEnsured: false,
        SupplementMasterEntitiesEnsured: false,

        Completed: function () {
            var complete = this.BaseEntitiesEnsured &&
                           this.SupplementMasterEntitiesEnsured;
            return complete;
        }
    };

    var view = this;
    var completeCallback = function()
    {
        if (context.Completed())
        {
            // マージする
            GPViewContext.MargeEntitiesForSupplementMasterEntities(
            context.BaseEntities,
            context.SupplementMasterEntities,
            view.DataSource.WebUrl,
            view.DataSource.DataSourceList,
            function (effectiveEntities)
            {
                // 属性を更新する
                effectiveEntities = view.OverWriteEntities(effectiveEntities);

                // フィルターする
                effectiveEntities = view.FillterEntities(effectiveEntities, contentsType, parentEntity);

                // ソートする
                effectiveEntities = view.SortEntities(effectiveEntities);

                if (ISString.Equals(contentsType, "Tree", null))
                {
                    view.EntityItems.TreeItems = effectiveEntities;
                }
                else if (ISString.Equals(contentsType, "Grid", null))
                {
                    view.EntityItems.GridItems = effectiveEntities;
                }

                // コールバック
                callback(effectiveEntities);
            });    
        }
    };

    // AddressBookData
    this.GetChildEntitiesBase(parentEntity, this.DataSource.WebUrl, this.DataSource.DataSourceList, function (baseEntities)
    {
        context.BaseEntitiesEnsured = true;
        context.BaseEntities = baseEntities;
        completeCallback();
    });        

    // SupplementMaster
    this.GetChildEntitiesBase(parentEntity, iVxContext.MasterSiteAbsolutePath, GPViewContext.SupplemenntMasterList, function (supllementMasterEntities)
    {
        context.SupplementMasterEntitiesEnsured = true;
        context.SupplementMasterEntities = supllementMasterEntities;
        completeCallback();
    });
};

GPOMOrganizationView.prototype.OverWriteEntities = function(baseEntities)
{
    var entities = [];

    for (var i = 0; i < baseEntities.length; i++)
    {
        var currentEntity = baseEntities[i];
        // サブツリーはすべて表示させる（変更を管理できない為）
        if (!ISString.IsNullOrEmpty(currentEntity.Properties.Type) &&
            ISString.Equals(currentEntity.Properties.Type, "group", true))
        {
            currentEntity.Properties["HasSubTree"] = "true";
        }

        // ExSortDisplayNameの決定
        var entityDisplayName         = currentEntity.Properties["EntityDisplayName"];
        var phoneticEntityDisplayName = currentEntity.Properties["PhoneticEntityDisplayName"];
        var sortDisplayName = "";
        if (!ISString.IsNullOrEmpty(entityDisplayName))
        {
            sortDisplayName = entityDisplayName;
        }
        if (!ISString.IsNullOrEmpty(phoneticEntityDisplayName))
        {
            sortDisplayName = phoneticEntityDisplayName;
        }
        currentEntity.Properties["ExSortDisplayName"] = sortDisplayName;

        entities.push(currentEntity);
    }

    return entities;
};

GPOMOrganizationView.prototype.FillterEntities = function(baseEntities, contentsType, parentEntity)
{    
    var entities = [];

    for (var i = 0; i < baseEntities.length; i++)
    {
        var currentEntity = baseEntities[i];

        if (parentEntity)
        {
            // MemberOfのチェック（補助マスタで上書きされている場合は除外する）
            var memberOf = currentEntity.Properties.MemberOf;
            if (!ISString.Contains(memberOf, parentEntity.Properties.EntityId))
            {
                continue;
            }
        }

        // ShowInAddressBookがtrue
        if (!ISBoolean.TryParse(currentEntity.Properties.ShowInAddressBook, false))
        {
            continue;
        }
        
        // contentsType（Tree, Grid）が一致
        var showInTree = currentEntity.Properties.ShowInTree;
        if (ISString.Equals(contentsType, "Tree", true) &&
            !ISBoolean.TryParse(showInTree, false))
        {
            continue;
        }
        else if (ISString.Equals(contentsType, "Grid", true) &&
                 ISBoolean.TryParse(showInTree, false))
        {
            continue;
        }

        entities.push(currentEntity);
    }

    return entities;
};

GPOMOrganizationView.prototype.SortEntities = function(baseEntities)
{
    var entities = baseEntities;
    var sortFields = [];
    for (var i = 0; i < this.Info.SortOrders.length; i++)
    {
        var fieldName = this.Info.SortOrders[i].FieldName;
        var field = this.DataSource.DataSourceList.Fields.Get(fieldName);
        if (field)
        {
            field.Ascending = this.Info.SortOrders[i].Ascending;
            sortFields.push(field);
        }        
    }

    if (sortFields.length > 0)
    {
        entities = SPListItemRetriever.Sort(baseEntities, sortFields);
    }

    return entities;
};

GPOMOrganizationView.prototype.GetChildEntitiesBase = function (parentEntity, webUrl, list, callback)
{
    // MemberOfQuery組み立て
    var parentEntityId = parentEntity.Properties.EntityId;
    var parentId = "|" + parentEntityId + "|";
    var memberOfQuery = SPQueryBuilder.BuildContainsQueryCondition("MemberOf", "Note", parentId);

    var query = this.BuildChildEntitiesQuery(parentEntity, memberOfQuery);

    iVxService.RetrieveItems(webUrl, list, query, true, function(items)
    {
        callback(items);
    });
};

GPOMOrganizationView.prototype.BuildChildEntitiesQuery = function (parentEntity, memberOfQuery)
{
    var query = new ISSPQuery();
    query.TryQuery = false;

    var queryTemplete   = "<Query>"
                        +   "<Where>"
                        +     "%Where%"
                        +   "</Where>"
                        +   "<OrderBy>"
                        +     "%OrderByConfigs%"
                        +   "</OrderBy>"
                        + "</Query>";
    
    // ToDo:ShowInView
    /*
    var showInViewContainsQuery = SPQueryBuilder.BuildContainsQueryCondition("ShowInView", "Text", "OrganizationView");
    var showInViewEmptyQuery = SPQueryBuilder.BuildIsNullQueryCondition("ShowInView");
    var showInViewQuery = SPQueryBuilder.BuildOrQueryCondition(showInViewContainsQuery + showInViewEmptyQuery);
    where = SPQueryBuilder.BuildAndQueryCondition(memberOfQuery + showInViewQuery);
    */

    // EnableVisibleGroups=trueの場合、CurrentUserのVisibleGroupsを検索条件に追加する
    var enableVisibleGroups = iBoolean.TryParse(GPContext.Configuration.GetSetting('EnableVisibleGroups'), false);
    if (enableVisibleGroups)
    {
        memberOfQuery = GPCamlQueryCondition.AddVisibleGroupsCondition(memberOfQuery, GPViewContext.CurrentUserEntity);
    }

    // Query句の設定
    query.Query = queryTemplete.replace("%Where%", memberOfQuery);

    // OrderByのquery組み立て
    var orderByConfigs = "";
    for (var i = 0; i < this.Info.SortOrders.length; i++)
    {
        var orderByTemplete = "<FieldRef Name='%OrderByName%' Ascending='%OrderByAscending%'/>";
        orderByTemplete = orderByTemplete.replace("%OrderByName%", this.Info.SortOrders[i].FieldName);
        orderByTemplete = orderByTemplete.replace("%OrderByAscending%", this.Info.SortOrders[i].Ascending);
        orderByConfigs += orderByTemplete;
    }
    query.Query = query.Query.replace("%OrderByConfigs%", orderByConfigs);

    // ViewField設定 
    query.ViewFields = SPQueryBuilder.BuildViewFields("");

    return query;
};

