Infoshare.GroupPicker.OrganizationManagement.SearchView = function InfoInfoshare$GroupPicker$OrganizationManagement$SearchView()
{
    Infoshare.GroupPicker.SearchView.apply(this, arguments);
}
GPOMSearchView = Infoshare.GroupPicker.OrganizationManagement.SearchView;
GPOMSearchView.TypeName = 'Infoshare.GroupPicker.OrganizationManagement.SearchView';

GPOMSearchView.prototype = new Infoshare.GroupPicker.SearchView();
GPOMSearchView.prototype.TypeName = GPOMSearchView.TypeName;
GPOMSearchView.prototype.Features = [
{ name: "Selection",
  multipleSelection: true},
{ name: "Resizing",
  allowDoubleClickToResize: true,
  columnSettings: [{ columnKey: "Type", allowResizing: false },
                   { columnKey: "Presence", allowResizing: false },
                   { columnKey: "Profile", allowResizing: false }]
}];
GPOMSearchView.prototype.ValidateDataSource = GPOMOrganizationView.ValidateDataSource;
GPOMSearchView.prototype.SortEntities = GPOMOrganizationView.prototype.SortEntities;

GPOMSearchView.prototype.GetItems = function(typeValue, keywords, callback)
{
    // AddressBookDataSource, SupplementMasterからデータを取得してマージ、クライアントソートする
    var context = {
        // AddressBookDataSourceのSearchKeyから取得するEntities
        BaseEntities: null,
        // SupplementMasterのSearchKeyから取得するEntities
        SupplementMasterEntities: null,

        BaseEntitiesEnsured: false,
        SupplementMasterEntitiesEnsured: false,

        Completed: function () {
            var complete = this.BaseEntitiesEnsured &&
                           this.SupplementMasterEntitiesEnsured;
            return complete;
        }
    };

    var view = this;
    var completeCallback = function()
    {
        if (context.Completed())
        {
            // 閾値越えの場合（500エラー）nullを返す
            if (context.BaseEntities == null ||
                context.SupplementMasterEntities == null)
            {
                callback(null);
            }

            else
            {
                // マージする
                GPViewContext.MargeEntitiesForSupplementMasterEntities(
                context.BaseEntities,
                context.SupplementMasterEntities,
                view.DataSource.WebUrl,
                view.DataSource.DataSourceList,
                function (effectiveEntities)
                {
                    // 属性を更新する
                    effectiveEntities = view.OverWriteEntities(effectiveEntities);

                    // ソートする
                    effectiveEntities = view.SortEntities(effectiveEntities);

                    // グリッド表示用に変換
                    effectiveEntities = GPGridUtility.BuildGridItems(effectiveEntities, view.Columns);

                    // コールバック
                    callback(effectiveEntities);
                });           
            }
        }
    };

    // AddressBookData
    this.GetItemsInternal(this.DataSource.WebUrl, this.DataSource.DataSourceList, typeValue, keywords, function (baseEntities)
    {
        context.BaseEntitiesEnsured = true;
        context.BaseEntities = baseEntities;
        completeCallback();
    });

    // SupplementMaster
    this.GetItemsInternal(iVxContext.MasterSiteAbsolutePath, GPViewContext.SupplemenntMasterList, typeValue, keywords, function (supllementMasterEntities)
    {
        context.SupplementMasterEntitiesEnsured = true;
        context.SupplementMasterEntities = supllementMasterEntities;
        completeCallback();
    });
};

GPOMSearchView.prototype.OverWriteEntities = function (baseEntities)
{
    var entities = [];

    for (var i = 0; i < baseEntities.length; i++)
    {
        var currentEntity = baseEntities[i];

        // ExSortDisplayNameの決定
        var entityDisplayName         = currentEntity.Properties["EntityDisplayName"];
        var phoneticEntityDisplayName = currentEntity.Properties["PhoneticEntityDisplayName"];
        var sortDisplayName = "";
        if (!ISString.IsNullOrEmpty(entityDisplayName))
        {
            sortDisplayName = entityDisplayName;
        }
        if (!ISString.IsNullOrEmpty(phoneticEntityDisplayName))
        {
            sortDisplayName = phoneticEntityDisplayName;
        }
        currentEntity.Properties["ExSortDisplayName"] = sortDisplayName;

        entities.push(currentEntity);
    }

    return entities;
};

GPOMSearchView.prototype.GetItemsInternal = function(webUrl, list, typeValue, keywords, callback)
{
    // Where句
    var where = this.BuildWhereQuery(typeValue, keywords, false);
    
    // ViewField設定 
    var fieldRefs = '';

    // クエリ組み立て
    var query = new ISSPQuery();
    query.Query        = SPQueryBuilder.BuildQuery(null, where);
    query.ViewFields   = SPQueryBuilder.BuildViewFields(fieldRefs);
    query.QueryOptions = SPQueryBuilder.BuildQueryOptions(SPQueryBuilder.BuildMandatoryColumnsOption(false));

    // 閾値を超えるアイテムのクエリを設定する
    query.EnableIterativeQueries = ISBoolean.TryParse(GPContext.Configuration.GetSetting('EnableLargeSearchQuery'), false);

    iVxService.RetrieveItems(webUrl, list, query, true, function(items)
    {
        callback(items);
    });
};

