// -----------------------------------------------------------------------
//  OrganizationManagementAction: GPHeaderAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.OrganizationManagement.Action = function InfoInfoshare$GroupPicker$OrganizationManagement$Action()
{
}
GPOMHeaderAction = Infoshare.GroupPicker.OrganizationManagement.Action;

GPOMHeaderAction.CloseEvent = {
    Save: 1,
    Cancel: 0
};

// iFrameダイアログからの参照用
GPOMHeaderAction.CurrentEntity = null;
GPOMHeaderAction.GetSupplementMasterItemId = function(entity)
{
    var itemId = null;
    if (entity)
    {
        itemId = entity.Properties["SupplementMasterItemId"];
    }

    return itemId;
}

GPOMHeaderAction.prototype = new GPHeaderAction();
GPOMHeaderAction.prototype.ActionButtonInfo = null;
GPOMHeaderAction.prototype.ActionButton = null;
GPOMHeaderAction.prototype.PostRender = function(control)
{

};
GPOMHeaderAction.prototype.ExecuteAction = function()
{
    // キャッシュをクリア
    GPOMHeaderAction.CurrentEntity = null;

    var entities = this.CurrentView.GetSelectedItems();
    var entity = null;
    if (entities != null && 
        entities.length > 0)
    {
        entity = entities[0];        
    }

    this.ExecuteActionInternal(entity);
};
    
GPOMHeaderAction.prototype.ExecuteActionInternal = function(entity)
{
    // 継承クラスで実装
};

GPOMHeaderAction.prototype.OpenNewFormDialog = function()
{
	var formUrl = iVxContext.SiteUrl
		        + "/Lists/SupplementMaster/NewForm.aspx"
		        + "?Source="
		        + encodeURIComponent(location.href);
    
	ShowPopupDialogWithCallback(formUrl, ISFunction.CreateDelegate(this.OnClose, this));
};

GPOMHeaderAction.prototype.OpenEditFormDialog = function(itemId)
{
	var formUrl = iVxContext.SiteUrl
			    + "/Lists/SupplementMaster/EditForm.aspx?ID="
			    + itemId
			    + "&Source="
			    + encodeURIComponent(location.href);
    
	ShowPopupDialogWithCallback(formUrl, ISFunction.CreateDelegate(this.OnClose, this));
};

GPOMHeaderAction.prototype.OnClose = function(closeEvent)
{
    if (closeEvent === GPOMHeaderAction.CloseEvent.Cancel)
    {
        // キャッシュをクリア
        GPOMHeaderAction.CurrentEntity = null;
    }
    else if(closeEvent === GPOMHeaderAction.CloseEvent.Save)
    {
        // リロード
        this.ReloadPage();
    }
};

GPOMHeaderAction.prototype.ReloadPage = function()
{
    // 組織ビューの場合、現在の選択組織を展開状態で表示する
    if (this.CurrentView.SelectedTreeEntity)
    {
        var uri = iUri.Parse(window.location.href);
        var parameter = new iUriParameter();
        parameter.Set("GPDefaultViewId", "Infoshare.GroupPicker.OrganizationManagement.EntityManagementOrganizationView");
        parameter.Set("GPSelectGroup", "true");
        parameter.Set("GPSearchField", "EntityId");
        parameter.Set("GPSearchValue", this.CurrentView.SelectedTreeEntity.Properties.EntityId);

        var newUrl = uri.Origin + uri.Path
                   + "?" + parameter.ToString();

        window.location.href = newUrl;
    }
    // 検索ビューの場合、現在の検索条件で再検索して表示する
    else if (this.CurrentView.SearchTextBox)
    {
        var uri = iUri.Parse(window.location.href);
        var parameter = iUriParameter.Parse(window.location.href);
        parameter.Set("GPDefaultViewId", "Infoshare.GroupPicker.OrganizationManagement.EntityManagementSearchView");
        parameter.Set("GPKeyword", this.CurrentView.PreviousKeyword);
        parameter.Set("GPUserFilter", this.CurrentView.UserFilter.IsChecked());
        parameter.Set("GPGroupFilter", this.CurrentView.GroupFilter.IsChecked());

        var newUrl = uri.Origin + uri.Path
                   + "?" + parameter.ToString();

        window.location.href = newUrl;
    }
};

GPOMHeaderAction.prototype.OnSelectedTabChanged = function(view)
{
    this.CurrentView = view;
    this.OnViewSelectionChanged(view);
};

GPOMHeaderAction.prototype.HasPermissionForSupplementMaster = function()
{
    var hasPermission = GPViewContext.SupplemenntMasterList.HasEditPermission;
    if(!hasPermission)
    {
        var message = iResxResource.GetString("GPOMHeaderAction.HasNotPermissionsForSupplementMasterList");
        alert(message);
    }

    return hasPermission;
};

GPOMHeaderAction.prototype.HasPermission = function(entity)
{
    var entities = [entity];
    var hasPermission = false;
    try
    {
        hasPermission = GPEntityMasterValidator.IsValidPermission(entities);
    }
    catch(e)
    {
        hasPermission = false;
        alert(e.message);
        ISTrace.TraceVerbose(e.stack);
    }

    return hasPermission;
};

GPOMHeaderAction.prototype.OnViewSelectionChanged = function(view)
{
    this.CurrentView = view;
    var entities = this.CurrentView.GetSelectedItems();
    var entity = null;
    if (entities && entities.length > 0)
    {
        entity = entities[0];
    }

    this.OnViewSelectionChangedInternal(entity);
};

GPOMHeaderAction.prototype.OnViewSelectionChangedInternal = function(entity)
{
    // 継承クラスで実装
};


// -----------------------------------------------------------------------
//  OrganizationManagementNewEntityAction: GPOMHeaderAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.OrganizationManagement.NewEntityAction = function InfoInfoshare$GroupPicker$OrganizationManagement$NewEntityAction()
{
    this.ActionButtonInfo = {
        Type: "Text",
        Style: new GPOMActionButtonStyle(),
        Text: iResxResource.GetString("GPOMHeaderAction.NewButtonText")
    };
}
GPOMHeaderNewEntityAction = Infoshare.GroupPicker.OrganizationManagement.NewEntityAction;
GPOMHeaderNewEntityAction.prototype = new GPOMHeaderAction();

GPOMHeaderNewEntityAction.prototype.ExecuteActionInternal = function (entity)
{
    if (this.HasPermissionForSupplementMaster())
    {
        // 新規フォームを開く
        this.OpenNewFormDialog();
    }
};

GPOMHeaderNewEntityAction.prototype.OnViewSelectionChangedInternal = function(entity)
{
    // 常に有効化
    this.ActionButton.Enable();
};


// -----------------------------------------------------------------------
//  OrganizationManagementEditEntityAction: GPOMHeaderAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.OrganizationManagement.EditEntityAction = function InfoInfoshare$GroupPicker$OrganizationManagement$EditEntityAction()
{
    this.ActionButtonInfo = {
        Type: "Text",
        Style: new GPOMActionButtonStyle(),
        Text: iResxResource.GetString("GPOMHeaderAction.EditButtonText")
    };
}
GPOMHeaderEditEntityAction = Infoshare.GroupPicker.OrganizationManagement.EditEntityAction;
GPOMHeaderEditEntityAction.prototype = new GPOMHeaderAction();

GPOMHeaderEditEntityAction.prototype.ExecuteActionInternal = function (entity)
{
    // 権限がない場合
    if (!this.HasPermissionForSupplementMaster() ||
        !this.HasPermission(entity))
    {
        return;
    }

    var itemId = GPOMHeaderAction.GetSupplementMasterItemId(entity);

    // 補助マスタにアイテムが存在する場合はItemIdから編集フォームを開く
    if (itemId)
    {
        GPOMHeaderAction.CurrentEntity = entity;
        this.OpenEditFormDialog(itemId);
    }
    // 存在しない場合は、選択されたエンティティをグローバル変数にキャッシュして、新規フォームを開く
    // キャッシュされたエンティティは新規フォームのExtender内で処理し初期値として設定する
    else
    {
        GPOMHeaderAction.CurrentEntity = entity;
        this.OpenNewFormDialog();
    }
};

GPOMHeaderEditEntityAction.prototype.OnViewSelectionChangedInternal = function(entity)
{
    if (entity)
    {
        this.ActionButton.Enable();
    }
    else
    {
        this.ActionButton.Disable();
    }   
};


// -----------------------------------------------------------------------
//  OrganizationManagementDeleteEntityAction: GPOMHeaderAction
// -----------------------------------------------------------------------
Infoshare.GroupPicker.OrganizationManagement.DeleteEntityAction = function InfoInfoshare$GroupPicker$OrganizationManagement$DeleteEntityAction()
{
    this.ActionButtonInfo = {
        Type: "Text",
        Style: new GPOMActionButtonStyle(),
        Text: iResxResource.GetString("GPOMHeaderAction.RemoveButtonText")
    };
}
GPOMHeaderDeleteEntityAction = Infoshare.GroupPicker.OrganizationManagement.DeleteEntityAction;
GPOMHeaderDeleteEntityAction.prototype = new GPOMHeaderAction();

GPOMHeaderDeleteEntityAction.prototype.ExecuteActionInternal = function (entity)
{
    // 権限がない場合
    if (!this.HasPermissionForSupplementMaster() ||
        !this.HasPermission(entity))
    {
        return;
    }

    var itemId = GPOMHeaderAction.GetSupplementMasterItemId(entity);
	if (itemId) 
	{
	    // 削除確認メッセージの、リソース
	    // Original（AD上の存在するか否かのフラグ）によってスイッチ
        var original = ISBoolean.TryParse(entity.Properties["Original"], false);
        var confirmMessageResourceKey = original ? "GPOMHeaderAction.RemoveItem.Confirm.Original"
                                                 : "GPOMHeaderAction.RemoveItem.Confirm";

	    var confirmMessage = iResxResource.GetString(confirmMessageResourceKey);
        var result = confirm(confirmMessage);
        if (result)
        {
			// アイテム情報作成
			var item = new ISSPItem();
			item.Properties["ID"] = itemId;

			// アイテム削除
			var ref = this;
			iVxService.UpdateItems(iVxContext.SiteUrl, GPViewContext.SupplemenntMasterList, item, function()
			{
			    ref.ReloadPage();
			});
        }
	}
};

GPOMHeaderDeleteEntityAction.prototype.OnViewSelectionChangedInternal = function(entity)
{
    var itemId = GPOMHeaderAction.GetSupplementMasterItemId(entity);
    if (itemId)
    {      
        this.ActionButton.Enable();
    }
    else
    {
        this.ActionButton.Disable();
    }   
};
															
