Infoshare.GroupPicker.LicensedClassListUpdater = function Infoshare$GroupPicker$LicensedClassListUpdater() { }
GPLicensedClassListUpdater = Infoshare.GroupPicker.LicensedClassListUpdater;
GPLicensedClassListUpdater.TypeName = 'Infoshare.GroupPicker.LicensedClassListUpdater';

GPLicensedClassListUpdater.prototype = {
    Update: function()
    {
        // GroupPicker
        iLicenseValidator.AddLicensedClassList(iLicense.GroupPickerKey, [ GPIcFeature.TypeName,
                                                                          GPIcPickerFeature.TypeName,

                                                                          // views
                                                                          GPFinder.TypeName,
                                                                          GPTeamsFinder.TypeName,
                                                                          GPOrganizationView.TypeName,
                                                                          GPSearchView.TypeName ]);

        // InfoCall
        iLicenseValidator.AddLicensedClassList(iLicense.InfoCallKey, iLicenseValidator.GetLicensedClassList(iLicense.GroupPickerKey));
        iLicenseValidator.AddLicensedClassList(iLicense.InfoCallKey, [ GPIcwpFeature.TypeName,

                                                                       // views
                                                                       GPTeamsFinder.TypeName,
                                                                       GPNavigation.TypeName,
                                                                       GPExtendedOrganizationView.TypeName,

                                                                       // actions
                                                                       GPMailAction.TypeName,
                                                                       GPScheduleAction.TypeName,
                                                                       GPSkypeAction.TypeName,
                                                                       GPTeamsChatAction.TypeName,
                                                                       GPTeamsMeetingAction.TypeName,
                                                                       GPOutlookAddinMailAction.TypeName,
                                                                       GPOutlookAddinScheduleAction.TypeName,
                                                                       GPCancelAction.TypeName,
                                                                       GPMenuAction.TypeName,
                                                                       GPFavoriteAction.TypeName,

                                                                       // othres
                                                                       GPMailToSelectionView.TypeName,
                                                                       GPScheduleDisplayView.TypeName,
                                                                       GPSkypeDisplayView.TypeName,
                                                                       GPTeamsChatDisplayView.TypeName,
                                                                       GPTeamsMeetingDisplayView.TypeName,
                                                                       GPFavoriteView.TypeName,
                                                                       GPEditFavoriteView.TypeName ]);

        // Organization Management
        iLicenseValidator.AddLicensedClassList(iLicense.InfoCallOrganizationManagementKey, [ GPOmFeature.TypeName,
                                                                                             GPOMFinder.TypeName,
                                                                                             GPOMEntityManagementOrganizationView.TypeName,
                                                                                             GPOMEntityManagementSearchView.TypeName,
                                                                                             GPOMOrganizationView.TypeName,
                                                                                             GPOMSearchView.TypeName,
                                                                                             GPEntityManagementView.TypeName ]);

        // Smartphone View
        iLicenseValidator.AddLicensedClassList(iLicense.InfoCallSmartphoneViewKey, []);

        // Outlook VSTO Add-In
        iLicenseValidator.AddLicensedClassList(iLicense.InfoCallOutlookVSTOAddInKey, []);

        // Member Search
        iLicenseValidator.AddLicensedClassList(iLicense.InfoCallMemberSearchKey, [ GPIcFeature.TypeName,
                                                                                   GPIcwpFeature.TypeName,

                                                                                   // views
                                                                                   GPFinder.TypeName,
                                                                                   GPMemberSearchView.TypeName,

                                                                                   // actions
                                                                                   GPMailAction.TypeName] );
    }
};

